/**
 * AICommandMenu Component
 *
 * A sharp-styled AI prompt modal that appears when selecting
 * "AI Generate" from the CommandMenu. Streams AI-generated content
 * into the editor as live blocks.
 *
 * @packageDocumentation
 */

'use client';

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Sparkles, X, Loader2 } from 'lucide-react';
import type { AIProvider } from './ai/types';
import { useEditorAI } from './hooks/useEditorAI';

// ─── Props ────────────────────────────────────────────────────────────────────

export interface AICommandMenuProps {
  /** Whether the menu is open. */
  isOpen: boolean;
  /** Called when the menu should close (Escape, click-outside, after submit). */
  onClose: () => void;
  /** The AI provider to use for generation. */
  provider: AIProvider;
  /** Default system prompt for generation. */
  defaultSystemPrompt?: string;
  /** ID of the block to insert AI content after. */
  targetNodeId: string;
  /** The DOM element to position the menu relative to. */
  anchorElement: HTMLElement | null;
}

/**
 * AICommandMenu — a sharp-styled AI prompt input.
 *
 * Activated via the CommandMenu's "AI Generate" option. The user types
 * a prompt, presses Enter (or clicks Generate), and AI content streams
 * in below the current block.
 */
export function AICommandMenu({
  isOpen,
  onClose,
  provider,
  defaultSystemPrompt,
  targetNodeId,
  anchorElement,
}: AICommandMenuProps) {
  const [prompt, setPrompt] = useState('');
  const inputRef = useRef<HTMLTextAreaElement>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  const { generateContent, isGenerating, abort } = useEditorAI({
    provider,
    defaultSystemPrompt,
  });

  // ── Focus input when menu opens ──────────────────────────────────────────
  useEffect(() => {
    if (isOpen) {
      setPrompt('');
      const timer = setTimeout(() => {
        inputRef.current?.focus();
      }, 50);
      return () => clearTimeout(timer);
    }
  }, [isOpen]);

  // ── Close on Escape ──────────────────────────────────────────────────────
  useEffect(() => {
    if (!isOpen) return;

    function handleKeyDown(e: KeyboardEvent) {
      if (e.key === 'Escape') {
        e.preventDefault();
        e.stopPropagation();
        if (isGenerating) {
          abort();
        } else {
          onClose();
        }
      }
    }

    document.addEventListener('keydown', handleKeyDown, true);
    return () => document.removeEventListener('keydown', handleKeyDown, true);
  }, [isOpen, isGenerating, abort, onClose]);

  // ── Close on click outside ───────────────────────────────────────────────
  useEffect(() => {
    if (!isOpen) return;

    function handleClickOutside(e: MouseEvent) {
      if (
        menuRef.current &&
        !menuRef.current.contains(e.target as Node) &&
        anchorElement &&
        !anchorElement.contains(e.target as Node)
      ) {
        if (isGenerating) {
          abort();
        }
        onClose();
      }
    }

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isOpen, isGenerating, abort, onClose, anchorElement]);

  // ── Submit handler ───────────────────────────────────────────────────────
  const handleSubmit = useCallback(async () => {
    const trimmed = prompt.trim();
    if (!trimmed || isGenerating) return;

    try {
      await generateContent(trimmed, undefined, targetNodeId);
    } catch {
      // Error is already logged inside useEditorAI
    } finally {
      onClose();
    }
  }, [prompt, isGenerating, generateContent, targetNodeId, onClose]);

  // ── Keyboard shortcut: Enter to submit, Shift+Enter for newline ─────────
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSubmit();
      }
    },
    [handleSubmit],
  );

  // ── Position calculation ─────────────────────────────────────────────────
  const [position, setPosition] = useState<{ top: number; left: number }>({
    top: 0,
    left: 0,
  });

  useEffect(() => {
    if (!isOpen || !anchorElement) return;

    const rect = anchorElement.getBoundingClientRect();
    setPosition({
      top: rect.bottom + window.scrollY + 8,
      left: rect.left + window.scrollX,
    });
  }, [isOpen, anchorElement]);

  // ── Don't render when closed ─────────────────────────────────────────────
  if (!isOpen || !anchorElement) return null;

  return (
    <div
      ref={menuRef}
      className="fixed z-50 w-[420px] border border-border bg-background/60 backdrop-blur-xl backdrop-saturate-150 p-4 text-foreground shadow-2xl dark:bg-background/40 dark:border-border"
      style={{ top: position.top, left: position.left }}
    >
      {/* Header */}
      <div className="mb-3 flex items-center gap-2.5">
        <div className="flex h-7 w-7 items-center justify-center bg-foreground">
          <Sparkles className="h-3.5 w-3.5 text-background" />
        </div>
        <span className="text-sm font-semibold tracking-wide">AI Generate</span>
        <button
          type="button"
          onClick={onClose}
          className="ml-auto p-1 text-muted-foreground transition-colors hover:bg-accent hover:text-foreground"
        >
          <X className="h-3.5 w-3.5" />
        </button>
      </div>

      {/* Prompt input */}
      <textarea
        ref={inputRef}
        value={prompt}
        onChange={(e) => setPrompt(e.target.value)}
        onKeyDown={handleKeyDown}
        placeholder="Describe what you want to write..."
        disabled={isGenerating}
        rows={3}
        className="w-full resize-none border border-border bg-background/50 px-3.5 py-2.5 text-sm placeholder:text-muted-foreground/60 focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-foreground/30 disabled:cursor-not-allowed disabled:opacity-50 transition-shadow"
      />

      {/* Actions */}
      <div className="mt-3 flex items-center justify-between">
        <span className="text-xs text-muted-foreground/70">
          {isGenerating ? (
            <span className="flex items-center gap-1.5">
              <Loader2 className="h-3 w-3 animate-spin" />
              Generating...
            </span>
          ) : (
            'Enter to generate, Esc to cancel'
          )}
        </span>
        <div className="flex gap-2">
          {isGenerating ? (
            <button
              type="button"
              onClick={abort}
              className="inline-flex items-center bg-red-500/20 px-3.5 py-1.5 text-xs font-medium text-red-400 transition-all hover:bg-red-500/30 active:scale-95"
            >
              Stop
            </button>
          ) : (
            <>
              <button
                type="button"
                onClick={onClose}
                className="inline-flex items-center border border-border px-3.5 py-1.5 text-xs font-medium transition-all hover:bg-accent active:scale-95"
              >
                Cancel
              </button>
              <button
                type="button"
                onClick={handleSubmit}
                disabled={!prompt.trim()}
                className="inline-flex items-center gap-1.5 bg-foreground px-3.5 py-1.5 text-xs font-medium text-background transition-all hover:bg-foreground/90 active:scale-95 disabled:pointer-events-none disabled:opacity-40"
              >
                <Sparkles className="h-3 w-3" />
                Generate
              </button>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

/**
 * AISelectionMenu Component
 *
 * A Notion-style AI editing menu that appears when clicking the AI button
 * in the SelectionToolbar. Provides preset actions (rephrase, fix grammar,
 * change tone) and custom prompts for AI-powered text replacement.
 * Supports styled mode for AI-powered formatting (bold, italic, code).
 *
 * @packageDocumentation
 */

'use client';

import React, { useState, useRef, useCallback } from 'react';
import {
  Sparkles,
  RefreshCw,
  Check,
  X,
  Loader2,
  PenLine,
  SpellCheck,
  Minimize2,
  Maximize2,
  Briefcase,
  MessageCircle,
  Highlighter,
  Type,
  Code,
} from 'lucide-react';
import type { AIProvider } from './ai/types';
import type { SelectionInfo, InlineText } from './types';
import { useEditorAI } from './hooks/useEditorAI';
import { useEditorDispatch, EditorActions } from '.';

// ─── Preset Actions ──────────────────────────────────────────────────────────

interface PresetAction {
  label: string;
  icon: React.ReactNode;
  prompt: string;
  styled?: boolean;
}

const rewritePresets: PresetAction[] = [
  {
    label: 'Rephrase',
    icon: <PenLine className="h-3.5 w-3.5" />,
    prompt: 'Rephrase this text differently while keeping the same meaning',
  },
  {
    label: 'Fix grammar',
    icon: <SpellCheck className="h-3.5 w-3.5" />,
    prompt: 'Fix any grammar and spelling errors in this text',
  },
  {
    label: 'Make shorter',
    icon: <Minimize2 className="h-3.5 w-3.5" />,
    prompt: 'Make this text shorter while keeping the key message',
  },
  {
    label: 'Make longer',
    icon: <Maximize2 className="h-3.5 w-3.5" />,
    prompt: 'Expand this text with more detail while maintaining the same tone',
  },
  {
    label: 'Professional',
    icon: <Briefcase className="h-3.5 w-3.5" />,
    prompt: 'Rewrite this text in a professional, formal tone',
  },
  {
    label: 'Casual',
    icon: <MessageCircle className="h-3.5 w-3.5" />,
    prompt: 'Rewrite this text in a casual, friendly tone',
  },
];

const stylePresets: PresetAction[] = [
  {
    label: 'Emphasize key words',
    icon: <Highlighter className="h-3.5 w-3.5" />,
    prompt: 'Add **bold** to the most important words/phrases. Keep text otherwise identical.',
    styled: true,
  },
  {
    label: 'Add emphasis',
    icon: <Type className="h-3.5 w-3.5" />,
    prompt: 'Add **bold** and *italic* to emphasize key concepts. Keep text otherwise identical.',
    styled: true,
  },
  {
    label: 'Code terms',
    icon: <Code className="h-3.5 w-3.5" />,
    prompt: 'Wrap technical terms, function names, and code references in `backticks`. Keep text otherwise identical.',
    styled: true,
  },
];

// ─── Rich Preview Component ─────────────────────────────────────────────────

function RichPreview({ children }: { children: InlineText[] }) {
  return (
    <span>
      {children.map((segment, i) => {
        let el: React.ReactNode = segment.content;
        if (segment.bold) el = <strong key={i}>{el}</strong>;
        if (segment.italic) el = <em key={i}>{el}</em>;
        if (segment.code) el = <code key={i} className="rounded bg-muted px-1 py-0.5 text-[11px] font-mono">{el}</code>;
        if (segment.strikethrough) el = <s key={i}>{el}</s>;
        if (segment.underline) el = <u key={i}>{el}</u>;
        // If none of the above wrapped, use a fragment with key
        if (typeof el === 'string') el = <span key={i}>{el}</span>;
        return el;
      })}
    </span>
  );
}

// ─── Types ───────────────────────────────────────────────────────────────────

type MenuState = 'idle' | 'generating' | 'preview';

export interface AISelectionMenuProps {
  selection: SelectionInfo;
  provider: AIProvider;
  defaultSystemPrompt?: string;
  onClose: () => void;
}

// ─── Component ───────────────────────────────────────────────────────────────

export function AISelectionMenu({
  selection,
  provider,
  defaultSystemPrompt,
  onClose,
}: AISelectionMenuProps) {
  const [menuState, setMenuState] = useState<MenuState>('idle');
  const [customPrompt, setCustomPrompt] = useState('');
  const [lastPrompt, setLastPrompt] = useState('');
  const [lastStyled, setLastStyled] = useState(false);
  const [result, setResult] = useState('');
  const [isStyledResult, setIsStyledResult] = useState(false);
  const [resultChildren, setResultChildren] = useState<InlineText[]>([]);
  const inputRef = useRef<HTMLInputElement>(null);
  const dispatch = useEditorDispatch();

  const {
    replaceSelectionWithAI,
    isGenerating,
    streamingPreview,
    streamingPreviewChildren,
    resetPreview,
    abort,
  } = useEditorAI({ provider, defaultSystemPrompt });

  // ── Run AI ─────────────────────────────────────────────────────────────────
  const runAI = useCallback(
    async (prompt: string, styled = false) => {
      setLastPrompt(prompt);
      setLastStyled(styled);
      setMenuState('generating');
      setIsStyledResult(styled);
      resetPreview();

      try {
        const { text, children } = await replaceSelectionWithAI(prompt, selection, { styled });
        if (text) {
          setResult(text);
          setResultChildren(children);
          setMenuState('preview');
        } else {
          setMenuState('idle');
        }
      } catch {
        setMenuState('idle');
      }
    },
    [replaceSelectionWithAI, selection, resetPreview],
  );

  // ── Accept result ──────────────────────────────────────────────────────────
  const handleAccept = useCallback(() => {
    if (!result) return;
    if (isStyledResult && resultChildren.length > 0) {
      dispatch(
        EditorActions.replaceSelectionWithInlines(
          selection.nodeId,
          selection.start,
          selection.end,
          resultChildren,
        ),
      );
    } else {
      dispatch(
        EditorActions.replaceSelectionText(
          selection.nodeId,
          selection.start,
          selection.end,
          result,
        ),
      );
    }
    onClose();
  }, [result, isStyledResult, resultChildren, dispatch, selection, onClose]);

  // ── Discard ────────────────────────────────────────────────────────────────
  const handleDiscard = useCallback(() => {
    setResult('');
    setResultChildren([]);
    setIsStyledResult(false);
    resetPreview();
    setMenuState('idle');
  }, [resetPreview]);

  // ── Retry ──────────────────────────────────────────────────────────────────
  const handleRetry = useCallback(() => {
    if (lastPrompt) {
      runAI(lastPrompt, lastStyled);
    }
  }, [lastPrompt, lastStyled, runAI]);

  // ── Custom prompt submit ───────────────────────────────────────────────────
  const handleCustomSubmit = useCallback(() => {
    const trimmed = customPrompt.trim();
    if (!trimmed) return;
    runAI(trimmed);
    setCustomPrompt('');
  }, [customPrompt, runAI]);

  const handleCustomKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter') {
        e.preventDefault();
        handleCustomSubmit();
      }
      if (e.key === 'Escape') {
        e.preventDefault();
        e.stopPropagation();
        onClose();
      }
    },
    [handleCustomSubmit, onClose],
  );

  // ── Preset button renderer ────────────────────────────────────────────────
  const renderPreset = (action: PresetAction) => (
    <button
      key={action.label}
      type="button"
      onClick={() => runAI(action.prompt, action.styled)}
      className="flex w-full items-center gap-2.5 px-3 py-1.5 text-xs text-foreground transition-colors hover:bg-accent"
    >
      <span className="text-muted-foreground">{action.icon}</span>
      {action.label}
    </button>
  );

  // ── Idle State ─────────────────────────────────────────────────────────────
  if (menuState === 'idle') {
    return (
      <div className="w-[280px] border border-border bg-background/60 backdrop-blur-xl backdrop-saturate-150 shadow-2xl dark:bg-background/40">
        {/* Header */}
        <div className="flex items-center gap-2 px-3 py-2 border-b border-border">
          <Sparkles className="h-3.5 w-3.5 text-muted-foreground" />
          <span className="text-xs font-medium text-muted-foreground tracking-wide">AI Edit</span>
        </div>

        {/* Selected text preview */}
        <div className="px-3 py-2 border-b border-border">
          <p className="text-xs text-muted-foreground/60 mb-1">Selected text:</p>
          <p className="text-xs text-foreground/80 line-clamp-2">&ldquo;{selection.text}&rdquo;</p>
        </div>

        {/* Rewrite presets */}
        <div className="py-1">
          <p className="text-[10px] uppercase tracking-wider text-muted-foreground/50 px-3 pt-2 pb-1">Rewrite</p>
          {rewritePresets.map(renderPreset)}
        </div>

        {/* Style presets */}
        <div className="py-1 border-t border-border">
          <p className="text-[10px] uppercase tracking-wider text-muted-foreground/50 px-3 pt-2 pb-1">Style</p>
          {stylePresets.map(renderPreset)}
        </div>

        {/* Custom prompt */}
        <div className="border-t border-border px-3 py-2">
          <input
            ref={inputRef}
            type="text"
            value={customPrompt}
            onChange={(e) => setCustomPrompt(e.target.value)}
            onKeyDown={handleCustomKeyDown}
            placeholder="Custom instruction..."
            className="w-full bg-transparent text-xs placeholder:text-muted-foreground/50 focus:outline-none"
            autoFocus
          />
        </div>
      </div>
    );
  }

  // ── Generating State ───────────────────────────────────────────────────────
  if (menuState === 'generating') {
    return (
      <div className="w-[320px] border border-border bg-background/60 backdrop-blur-xl backdrop-saturate-150 shadow-2xl dark:bg-background/40">
        {/* Header */}
        <div className="flex items-center gap-2 px-3 py-2 border-b border-border">
          <Loader2 className="h-3.5 w-3.5 animate-spin text-muted-foreground" />
          <span className="text-xs font-medium text-muted-foreground tracking-wide">Generating...</span>
          <button
            type="button"
            onClick={() => {
              abort();
              setMenuState('idle');
            }}
            className="ml-auto text-xs text-red-400 hover:text-red-300 transition-colors"
          >
            Stop
          </button>
        </div>

        {/* Live preview */}
        <div className="px-3 py-3 max-h-[200px] overflow-y-auto">
          {isStyledResult && streamingPreviewChildren.length > 0 ? (
            <span className="text-xs text-foreground/80">
              <RichPreview>{streamingPreviewChildren}</RichPreview>
            </span>
          ) : (
            <p className="text-xs text-foreground/80 whitespace-pre-wrap">
              {streamingPreview || '...'}
            </p>
          )}
        </div>
      </div>
    );
  }

  // ── Preview State ──────────────────────────────────────────────────────────
  return (
    <div className="w-[340px] border border-border bg-background/60 backdrop-blur-xl backdrop-saturate-150 shadow-2xl dark:bg-background/40">
      {/* Header */}
      <div className="flex items-center gap-2 px-3 py-2 border-b border-border">
        <Sparkles className="h-3.5 w-3.5 text-muted-foreground" />
        <span className="text-xs font-medium text-muted-foreground tracking-wide">AI Result</span>
      </div>

      {/* Original */}
      <div className="px-3 py-2 border-b border-border">
        <p className="text-[10px] font-medium text-muted-foreground/50 uppercase tracking-wider mb-1">Original</p>
        <p className="text-xs text-foreground/50 line-through line-clamp-2">{selection.text}</p>
      </div>

      {/* Result */}
      <div className="px-3 py-2 border-b border-border">
        <p className="text-[10px] font-medium text-muted-foreground/50 uppercase tracking-wider mb-1">Replacement</p>
        {isStyledResult && resultChildren.length > 0 ? (
          <span className="text-xs text-foreground">
            <RichPreview>{resultChildren}</RichPreview>
          </span>
        ) : (
          <p className="text-xs text-foreground">{result}</p>
        )}
      </div>

      {/* Actions */}
      <div className="flex items-center gap-1.5 px-3 py-2">
        <button
          type="button"
          onClick={handleAccept}
          className="inline-flex items-center gap-1 bg-foreground px-2.5 py-1 text-[11px] font-medium text-background transition-all hover:bg-foreground/90 active:scale-95"
        >
          <Check className="h-3 w-3" />
          Accept
        </button>
        <button
          type="button"
          onClick={handleDiscard}
          className="inline-flex items-center gap-1 border border-border px-2.5 py-1 text-[11px] font-medium text-muted-foreground transition-all hover:bg-accent active:scale-95"
        >
          <X className="h-3 w-3" />
          Discard
        </button>
        <button
          type="button"
          onClick={handleRetry}
          className="inline-flex items-center gap-1 border border-border px-2.5 py-1 text-[11px] font-medium text-muted-foreground transition-all hover:bg-accent active:scale-95"
        >
          <RefreshCw className="h-3 w-3" />
          Retry
        </button>
      </div>
    </div>
  );
}

/**
 * AddBlockButton Component
 *
 * Shows a button between blocks to add new content
 * Appears on hover for better UX
 */

"use client";

import React, { useState } from "react";
import { Plus } from "lucide-react";
import { Button } from "@/registry/new-york-v4/ui/button";

interface AddBlockButtonProps {
  onAdd: () => void;
  position?: "before" | "after";
}

export function AddBlockButton({
  onAdd,
}: AddBlockButtonProps) {
  const [isHovered, setIsHovered] = useState(false);

  return (
    <div
      className="group mx-30 relative h-1 flex items-center justify-center transition-all"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      {/* Hover area - full width */}
      <div className="absolute inset-0 w-full" />

      {/* Add button - shows on hover */}
      <Button
        variant="outline"
        size="sm"
        className={`
          relative z-10 gap-1 h-6 px-2 transition-all shadow-sm
          ${
            isHovered
              ? "opacity-100 scale-100"
              : "opacity-0 scale-95 pointer-events-none"
          }
        `}
        onClick={(e) => {
          e.stopPropagation();
          onAdd();
        }}
      >
        <Plus className="h-3 w-3" />
        <span className="text-xs">Add block</span>
      </Button>
    </div>
  );
}

/**
 * Block Component - Zustand Version
 *
 * Represents a single editable block (paragraph, heading, etc.)
 * Handles its own rendering, editing, and event handling.
 * Supports recursive rendering of nested blocks via ContainerNode.
 *
 * ZUSTAND VERSION - Uses selective subscriptions for optimal performance
 * CONTEXT VERSION - Reads stable editor-wide values from EditorContext
 *                   instead of receiving them as props, eliminating 30+
 *                   props and simplifying the memo comparator to 4 fields.
 */

"use client";

import React, { useRef, useEffect, useState, useCallback } from "react";
import { WrapText, ArrowRightLeft } from "lucide-react";
import {
  TextNode,
  getNodeTextContent,
} from ".";
import { ImageBlock } from "./ImageBlock";
import { VideoBlock } from "./VideoBlock";
import { CommandMenu } from "./CommandMenu";
import {
  useBlockNode,
  useEditorDispatch,
  useContainerGetter,
} from "./store/editor-store";
import { BlockContextMenu } from "./BlockContextMenu";
import { BlockContainer } from "./BlockContainer";
import { BlockDragHandle } from "./BlockDragHandle";
import { useEditorContext } from "./hooks/useEditorContext";

// Import all block handlers and utilities
import {
  buildHTML,
  createHandleCompositionStart,
  createHandleCompositionEnd,
  createHandleInput,
  createHandleKeyDown,
  createHandleClick,
  createHandleCommandSelect,
  createHandleBackgroundColorChange,
  getTypeClassName,
} from "./handlers/block";
import { getCharacterOffset, restoreCursorByOffset } from "./utils/dom-reconciler";
import { getNodeRenderType } from "./handlers/block/block-renderer";

/**
 * BlockProps — only block-specific values.
 * All stable editor-wide callbacks now live in EditorContext.
 */
export interface BlockProps {
  nodeId: string;
  isActive: boolean;
  isFirstBlock?: boolean;
  depth?: number;
}


export const Block = React.memo(function Block({
  nodeId,
  isActive,
  isFirstBlock = false,
  depth = 0,
}: BlockProps) {
  // ✅ OPTIMIZATION: Subscribe to ONLY this node's data.
  // Thanks to structural sharing, this only causes a re-render when THIS node changes.
  const node = useBlockNode(nodeId);

  // Determine how to render this node EARLY - before any conditional returns
  const renderType = node ? getNodeRenderType(node) : null;

  // If node not found, return null (shouldn't happen but safe guard)
  if (!node) {
    return null;
  }

  // Read all stable editor-wide values from context.
  // These never trigger a re-render of Block because the memo comparator
  // does not compare them — they are intentionally excluded from props.
  const {
    readOnly,
    notionBased,
    onUploadImage,
    onUploadVideo,
    onInput: ctxOnInput,
    onKeyDown: ctxOnKeyDown,
    onNodeClick,
    onDeleteNode,
    onCreateNested,
    onChangeBlockType,
    onInsertImage,
    onCreateList,
    onCreateTable,
    selectedImageIds,
    onToggleImageSelection,
    onClickWithModifier,
    onBlockDragStart,
    onImageDragStart,
    onSetDragOverNodeId,
    onSetDropPosition,
    onSetDraggingNodeId,
    registerNodeRef,
    hasCoverImage,
    onUploadCoverImage,
    onAISelect: ctxOnAISelect,
  } = useEditorContext();

  // Handle container nodes (recursive rendering) — delegate to BlockContainer
  if (
    renderType === "table" ||
    renderType === "flex" ||
    renderType === "nested-container"
  ) {
    return (
      <BlockContainer
        node={node}
        renderType={renderType}
        BlockComponent={Block}
        depth={depth}
        isActive={isActive}
      />
    );
  }

  // Cast to TextNode for remaining cases
  const textNode = node as TextNode;

  const localRef = useRef<HTMLElement | null>(null);
  const isComposingRef = useRef(false);
  const shouldPreserveSelectionRef = useRef(false);

  // ZUSTAND: Get dispatch function (never changes, no re-renders)
  const dispatch = useEditorDispatch();

  // ZUSTAND: Stable getter for the current container (avoids re-renders)
  const getContainer = useContainerGetter();

  // Command menu state
  const [showCommandMenu, setShowCommandMenu] = useState(false);
  const [commandMenuAnchor, setCommandMenuAnchor] =
    useState<HTMLElement | null>(null);

  // Bind context callbacks to this block's nodeId so the internal handlers
  // keep the same (element) / (e) signature they expect.
  const onInput = useCallback(
    (element: HTMLElement) => ctxOnInput(nodeId, element),
    [ctxOnInput, nodeId]
  );

  const onKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLElement>) => ctxOnKeyDown(e, nodeId),
    [ctxOnKeyDown, nodeId]
  );

  const onClick = useCallback(
    () => onNodeClick(nodeId),
    [onNodeClick, nodeId]
  );

  const onDelete = useCallback(
    (id?: string) => onDeleteNode(id ?? nodeId),
    [onDeleteNode, nodeId]
  );

  // Build HTML callback (declare this hook for ALL render paths to maintain hook order)
  const memoizedBuildHTML = useCallback(() => {
    return buildHTML(textNode, readOnly);
  }, [textNode, readOnly]);

  // Update content when needed
  useEffect(() => {
    if (!localRef.current) return;
    if (isComposingRef.current || shouldPreserveSelectionRef.current) return;

    const element = localRef.current;
    const newHTML = memoizedBuildHTML();

    if (element.innerHTML !== newHTML) {
      const hadFocus = document.activeElement === element;
      let charOffset = -1;
      if (hadFocus) {
        charOffset = getCharacterOffset(element);
      }
      element.innerHTML = newHTML;
      if (hadFocus && charOffset >= 0) {
        try { restoreCursorByOffset(element, charOffset); } catch {}
      }
    }
  }, [memoizedBuildHTML]);

  // Create all handlers
  const handleCompositionStart = useCallback(
    createHandleCompositionStart()(isComposingRef),
    []
  );

  const handleCompositionEnd = useCallback(
    createHandleCompositionEnd()(isComposingRef, onInput, localRef),
    [onInput]
  );

  const handleInput = useCallback(
    createHandleInput({
      textNode,
      readOnly,
      onInput,
      onChangeBlockType,
      showCommandMenu,
      setShowCommandMenu,
      setCommandMenuAnchor,
      shouldPreserveSelectionRef,
      dispatch,
    }),
    [textNode, readOnly, onInput, onChangeBlockType, showCommandMenu, dispatch]
  );

  const handleKeyDown = useCallback(
    createHandleKeyDown({
      textNode,
      readOnly,
      onInput,
      onKeyDown,
      onClick,
      onCreateNested,
      onChangeBlockType,
      onInsertImage,
      onCreateList,
      // ✅ Pass getter function - only called when needed, doesn't cause re-renders
      currentContainer: getContainer,
      dispatch,
      localRef,
      isComposingRef,
      shouldPreserveSelectionRef,
      showCommandMenu,
      setShowCommandMenu,
      setCommandMenuAnchor,
    }),
    [
      textNode,
      readOnly,
      onKeyDown,
      onCreateNested,
      showCommandMenu,
      dispatch,
    ]
  );

  const handleClick = useCallback(createHandleClick({ readOnly, onClick }), [
    readOnly,
    onClick,
  ]);

  const handleCommandSelect = useCallback(
    createHandleCommandSelect({
      textNode,
      onChangeBlockType,
      onInsertImage,
      onCreateList,
      onCreateTable,
      localRef,
      setShowCommandMenu,
      setCommandMenuAnchor,
    }),
    [textNode, onChangeBlockType, onInsertImage, onCreateList, onCreateTable]
  );

  const handleBackgroundColorChange = useCallback(
    createHandleBackgroundColorChange(textNode, dispatch),
    [textNode, dispatch]
  );

  // Code block word-wrap toggle
  const isCodeBlock = textNode.type === 'code';
  const wordWrap = textNode.attributes?.wordWrap !== false; // default: wrapped
  const handleToggleWrap = useCallback(() => {
    dispatch({
      type: 'UPDATE_NODE',
      payload: {
        id: textNode.id,
        updates: { attributes: { ...textNode.attributes, wordWrap: !wordWrap } } as any,
      },
    });
  }, [dispatch, textNode.id, textNode.attributes, wordWrap]);

  // Check if block is empty
  const textContent = getNodeTextContent(textNode);
  const isEmpty = !textContent || textContent.trim() === "";

  // Get placeholder from attributes
  const placeholder = textNode.attributes?.placeholder as string | undefined;

  // Show command menu placeholder only if no custom placeholder is set
  const showCommandPlaceholder = isEmpty && isActive && !readOnly && !placeholder;

  // Determine which HTML element to render based on type
  const ElementType =
    textNode.type === "li"
      ? "li"
      : textNode.type === "ol"
      ? "ol"
      : textNode.type === "h1"
      ? "h1"
      : textNode.type === "h2"
      ? "h2"
      : textNode.type === "h3"
      ? "h3"
      : textNode.type === "h4"
      ? "h4"
      : textNode.type === "h5"
      ? "h5"
      : textNode.type === "h6"
      ? "h6"
      : textNode.type === "p"
      ? "p"
      : textNode.type === "blockquote"
      ? "blockquote"
      : textNode.type === "code"
      ? "pre"
      : "div";

  const isListItem = textNode.type === "li" || textNode.type === "ol";

  // Get custom class from attributes
  const customClassName = textNode.attributes?.className || "";
  const isHexColor =
    typeof customClassName === "string" && customClassName.startsWith("#");
  const textColor = isHexColor ? customClassName : "";
  const className = isHexColor ? "" : customClassName;

  // Get background color from attributes
  const backgroundColor = textNode.attributes?.backgroundColor as
    | string
    | undefined;

  // ⚠️ IMPORTANT: Handle special block types AFTER all hooks are declared
  // This ensures React's Rules of Hooks are followed (hooks must be called in the same order every render)

  // BR elements render as empty space
  if (textNode.type === "br") {
    return (
      <div
        key={textNode.id}
        data-node-id={textNode.id}
        className="h-6"
        onClick={onClick}
      />
    );
  }

  // Image nodes render as ImageBlock
  if (textNode.type === "img") {
    return (
      <ImageBlock
        node={textNode}
        isActive={isActive}
        onClick={onClick}
        onDelete={onDelete}
        onDragStart={onImageDragStart}
        isSelected={selectedImageIds?.has(textNode.id)}
        onToggleSelection={onToggleImageSelection}
        onClickWithModifier={onClickWithModifier}
      />
    );
  }

  // Video nodes render as VideoBlock
  if (textNode.type === "video") {
    return (
      <VideoBlock
        node={textNode}
        isActive={isActive}
        onClick={onClick}
        onDelete={onDelete}
        onDragStart={onImageDragStart}
        isSelected={selectedImageIds?.has(textNode.id)}
        onToggleSelection={onToggleImageSelection}
        onClickWithModifier={onClickWithModifier}
      />
    );
  }

  // Human-readable block type label for screen readers
  const blockTypeLabel: Record<string, string> = {
    p: "paragraph",
    h1: "heading 1",
    h2: "heading 2",
    h3: "heading 3",
    h4: "heading 4",
    h5: "heading 5",
    h6: "heading 6",
    blockquote: "blockquote",
    code: "code",
    li: "list item",
    ol: "ordered list",
    br: "line break",
  };
  const blockAriaLabel = `${blockTypeLabel[textNode.type] ?? textNode.type} block`;

  // Common props for all elements
  const commonProps = {
    key: textNode.id,
    "data-node-id": textNode.id,
    "data-node-type": textNode.type,
    "data-show-command-placeholder": showCommandPlaceholder ? "true" : undefined,
    contentEditable: !readOnly,
    suppressContentEditableWarning: true,
    "aria-label": blockAriaLabel,
    ...(placeholder ? { placeholder } : {}),
    className: `lg:!ml-5
      ${isListItem ? "relative" : ""}
      ${getTypeClassName(textNode.type)}
      ${isCodeBlock && !wordWrap ? "!whitespace-pre !overflow-x-auto !break-normal" : ""}
      ${className}
      ${readOnly ? "" : "outline-none"}
      ${isListItem ? "px-3 py-0.5 mb-1" : textNode.type.startsWith('h') ? "px-3 py-2 mb-2" : "px-3 py-1.5 mb-2"}
      ${notionBased && isFirstBlock && textNode.type === 'h1' ? "lg:mt-8 pb-4" : ""}
      transition-all
      ${!readOnly && isActive ? "border-b bg-accent/5" : ""}
      ${!readOnly ? "hover:bg-accent/5" : ""}
      ${readOnly ? "cursor-default" : ""}
    `,
    style: {
      marginLeft: isListItem ? `${depth * 0.5 + 1.5}rem` : `${depth * 0.5}rem`,
      ...(textColor ? { color: textColor as string } : {}),
      ...(backgroundColor ? { backgroundColor: backgroundColor } : {}),
    },
    spellCheck: false,
  };

  return (
    <>
      <BlockContextMenu
        readOnly={readOnly}
        onBackgroundColorChange={handleBackgroundColorChange}
        currentBackgroundColor={backgroundColor}
      >
        <div
          className={`relative group transition-all flex flex-col gap-3`}
          style={{
            borderTop: '2px solid transparent',
            borderBottom: '2px solid transparent',
          }}
        >
          {/* Drag Handle & Add Button */}
          {!readOnly && onBlockDragStart && (
            <BlockDragHandle
              textNode={textNode}
              isFirstBlock={isFirstBlock}
              notionBased={notionBased}
              hasCoverImage={hasCoverImage}
              onUploadCoverImage={onUploadCoverImage}
              onBlockDragStart={onBlockDragStart}
              onSetDragOverNodeId={onSetDragOverNodeId}
              onSetDropPosition={onSetDropPosition}
              onSetDraggingNodeId={onSetDraggingNodeId}
            />
          )}

          {/* Code block word-wrap toggle */}
          {isCodeBlock && !readOnly && (
            <button
              type="button"
              onClick={handleToggleWrap}
              className="absolute top-2 right-2 z-10 p-1 rounded bg-secondary/80 hover:bg-secondary text-muted-foreground hover:text-foreground opacity-0 group-hover:opacity-100 transition-opacity"
              title={wordWrap ? 'Disable word wrap' : 'Enable word wrap'}
              aria-label={wordWrap ? 'Disable word wrap' : 'Enable word wrap'}
            >
              {wordWrap ? <ArrowRightLeft className="w-3.5 h-3.5" /> : <WrapText className="w-3.5 h-3.5" />}
            </button>
          )}

          <ElementType
            {...commonProps}
            key={textNode.id}
            ref={(el: HTMLElement | null) => {
              localRef.current = el;
              // Register this element with the editor's nodeRefs map.
              // Use the data-node-id attribute as the key (handles container
              // children whose id may differ from the top-level nodeId).
              if (el) {
                const elementNodeId = el.getAttribute("data-node-id");
                if (elementNodeId) {
                  registerNodeRef(elementNodeId, el);
                }
              } else {
                registerNodeRef(nodeId, null);
              }
            }}
            onInput={readOnly ? undefined : (e) => handleInput(e as any)}
            onKeyDown={readOnly ? undefined : (e) => handleKeyDown(e as any)}
            onClick={(e) => handleClick(e as any)}
            onCompositionStart={readOnly ? undefined : handleCompositionStart}
            onCompositionEnd={readOnly ? undefined : handleCompositionEnd}
          />
        </div>
      </BlockContextMenu>

      {/* Command Menu */}
      {!readOnly && (
        <CommandMenu
          isOpen={showCommandMenu}
          onClose={() => setShowCommandMenu(false)}
          onSelect={handleCommandSelect}
          anchorElement={commandMenuAnchor}
          nodeId={textNode.id}
          onUploadImage={onUploadImage}
          onUploadVideo={onUploadVideo}
          onAISelect={ctxOnAISelect ? () => ctxOnAISelect(nodeId) : undefined}
        />
      )}
    </>
  );
}, (prevProps, nextProps) => {
  // Custom comparison function for React.memo.
  // Returns true if props are equal (skip re-render), false if different (re-render).
  //
  // All stable editor-wide values are now in context (not props), so we only
  // need to compare the 4 block-specific props here.
  // Node content changes are handled by useBlockNode() subscribing to the
  // store internally.

  if (prevProps.nodeId !== nextProps.nodeId) return false;
  if (prevProps.isActive !== nextProps.isActive) return false;
  if (prevProps.isFirstBlock !== nextProps.isFirstBlock) return false;
  if (prevProps.depth !== nextProps.depth) return false;

  return true;
});

"use client";

import React from "react";
import { EditorNode, ContainerNode } from ".";
import { FlexContainer } from "./FlexContainer";
import { TableBuilder } from "./TableBuilder";
import { getContainerClasses } from "./handlers/block/block-renderer";
import { useEditorDispatch } from "./store/editor-store";
import { useEditorContext } from "./hooks/useEditorContext";

// Import Block lazily to avoid circular dependency at module load time
// (BlockContainer is rendered by Block, and Block renders BlockContainer)
// The actual Block component is passed in as a prop.
import type { BlockProps } from "./Block";

/**
 * BlockContainerProps
 *
 * Now only carries the node, its render type, the depth/isActive values
 * that are block-specific, and the BlockComponent pass-through to avoid
 * a circular module dependency.
 *
 * All stable editor-wide callbacks are read from EditorContext inside this
 * component, so they no longer need to be threaded through as props.
 */
export interface BlockContainerProps {
  node: EditorNode;
  renderType: "table" | "flex" | "nested-container";
  /** depth of this container (children will be rendered at depth + 1) */
  depth?: number;
  /** whether any child of this container is the active node */
  isActive: boolean;
  BlockComponent: React.ComponentType<BlockProps>;
}

/**
 * BlockContainer
 *
 * Handles the early-return rendering paths for container nodes:
 *   - "table"            → renders <TableBuilder>
 *   - "flex"             → renders <FlexContainer> with child <Block>s
 *   - "nested-container" → renders a div with child <Block>s
 *
 * Accepts `BlockComponent` as a prop so Block.tsx can pass itself in,
 * breaking the circular-import at component level (not module level).
 */
export function BlockContainer({
  node,
  renderType,
  depth = 0,
  isActive,
  BlockComponent,
}: BlockContainerProps) {
  const dispatch = useEditorDispatch();

  // Read stable callbacks from context instead of receiving them as props
  const {
    readOnly,
    onDeleteNode,
    onBlockDragStart,
    onFlexContainerDragOver,
    onFlexContainerDragLeave,
    onFlexContainerDrop,
    dragOverFlexId,
    flexDropPosition,
  } = useEditorContext();

  if (renderType === "table") {
    const containerNode = node as ContainerNode;
    return (
      <TableBuilder
        key={node.id}
        node={containerNode}
        onUpdate={(id, updates) => {
          if (dispatch) {
            dispatch({
              type: "UPDATE_NODE",
              payload: { id, updates },
            });
          }
        }}
        readOnly={readOnly}
        onBlockDragStart={onBlockDragStart}
        onDelete={(nodeId?: string) => onDeleteNode(nodeId ?? node.id)}
      />
    );
  }

  if (renderType === "flex") {
    const containerNode = node as ContainerNode;
    return (
      <FlexContainer
        key={node.id}
        node={containerNode}
        onDragOver={(e, position) => {
          onFlexContainerDragOver(e, node.id, position);
        }}
        onDragLeave={onFlexContainerDragLeave}
        onDrop={(e, position) => {
          onFlexContainerDrop(e, node.id, position);
        }}
        dragOverPosition={dragOverFlexId === node.id ? flexDropPosition : null}
      >
        {containerNode.children.map((childNode) => (
          <div key={childNode.id} className="flex-1 min-w-[280px] max-w-full">
            <BlockComponent
              nodeId={childNode.id}
              isActive={isActive}
              depth={depth + 1}
            />
          </div>
        ))}
      </FlexContainer>
    );
  }

  // nested-container
  const containerNode = node as ContainerNode;
  const containerClasses = getContainerClasses(false, isActive);

  return (
    <div
      key={node.id}
      data-node-id={node.id}
      data-node-type="container"
      className={containerClasses}
    >
      {containerNode.children.map((childNode: EditorNode) => (
        <BlockComponent
          key={childNode.id}
          nodeId={childNode.id}
          isActive={isActive}
          depth={depth + 1}
        />
      ))}
    </div>
  );
}

"use client";

import React, { useState, useMemo } from "react";
import { useTheme } from "next-themes";
import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuTrigger,
} from "@/registry/new-york-v4/ui/context-menu";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/registry/new-york-v4/ui/dialog";
import {
  ColorPicker as ShadcnColorPicker,
  ColorPickerAlpha,
  ColorPickerEyeDropper,
  ColorPickerFormat,
  ColorPickerHue,
  ColorPickerOutput,
  ColorPickerSelection,
} from "./_color-picker";
import { Button } from "@/registry/new-york-v4/ui/button";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/registry/new-york-v4/ui/tabs";
import { PaintBucket } from "lucide-react";

interface BlockContextMenuProps {
  children: React.ReactNode;
  onBackgroundColorChange: (color: string) => void;
  currentBackgroundColor?: string;
  readOnly?: boolean;
}

// Light mode colors - subtle, light backgrounds
const lightModeColors = [
  { name: "None", hex: "transparent" },
  { name: "Red", hex: "#fef2f2" },
  { name: "Orange", hex: "#fff7ed" },
  { name: "Yellow", hex: "#fefce8" },
  { name: "Green", hex: "#f0fdf4" },
  { name: "Blue", hex: "#eff6ff" },
  { name: "Indigo", hex: "#eef2ff" },
  { name: "Purple", hex: "#faf5ff" },
  { name: "Pink", hex: "#fdf2f8" },
  { name: "Teal", hex: "#f0fdfa" },
  { name: "Cyan", hex: "#ecfeff" },
  { name: "Gray", hex: "#f9fafb" },
];

// Dark mode colors - warm-toned darker backgrounds
const darkModeColors = [
  { name: "None", hex: "transparent" },
  { name: "Red", hex: "#4a1215" },
  { name: "Orange", hex: "#4a1c0a" },
  { name: "Yellow", hex: "#47260a" },
  { name: "Green", hex: "#0f2e1a" },
  { name: "Blue", hex: "#1a2544" },
  { name: "Indigo", hex: "#231e42" },
  { name: "Purple", hex: "#301558" },
  { name: "Pink", hex: "#4a0f28" },
  { name: "Teal", hex: "#0e2f2a" },
  { name: "Cyan", hex: "#1a4452" },
  { name: "Warm Gray", hex: "#2a2520" },
];

export function BlockContextMenu({
  children,
  onBackgroundColorChange,
  currentBackgroundColor,
  readOnly = false,
}: BlockContextMenuProps) {
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [customColor, setCustomColor] = useState("#ffffff");
  const [displayColor, setDisplayColor] = useState("#ffffff");

  // Get current theme
  const { theme, resolvedTheme } = useTheme();

  // Determine which color preset to use based on theme
  // resolvedTheme is 'light' or 'dark' (resolves 'system' to actual theme)
  const presetColors = useMemo(() => {
    const currentTheme = resolvedTheme || theme;
    return currentTheme === "dark" ? darkModeColors : lightModeColors;
  }, [theme, resolvedTheme]);

  const handleCustomColorChange = (value: any) => {
    let hexColor = "#ffffff";

    if (typeof value === "string") {
      hexColor = value;
    } else if (Array.isArray(value)) {
      // Extract RGB values (ignore alpha - it's the 4th element)
      const [r, g, b] = value;

      // Ensure RGB values are valid numbers, clamp to 0-255 range
      const rValue = Math.max(0, Math.min(255, Math.round(r || 0)));
      const gValue = Math.max(0, Math.min(255, Math.round(g || 0)));
      const bValue = Math.max(0, Math.min(255, Math.round(b || 0)));

      hexColor = `#${rValue.toString(16).padStart(2, "0")}${gValue
        .toString(16)
        .padStart(2, "0")}${bValue.toString(16).padStart(2, "0")}`;
    }

    setCustomColor(hexColor);
    setDisplayColor(hexColor);
  };

  const handlePresetColorSelect = (color: string) => {
    onBackgroundColorChange(color);
    setIsDialogOpen(false);
  };

  const handleApplyCustomColor = () => {
    onBackgroundColorChange(customColor);
    setIsDialogOpen(false);
  };

  return (
    <React.Fragment key={readOnly ? 'readonly' : 'editable'}>
      {readOnly ? (
        children
      ) : (
        <ContextMenu>
          <ContextMenuTrigger asChild>{children}</ContextMenuTrigger>
          <ContextMenuContent className="w-56">
            <ContextMenuItem
              onClick={() => setIsDialogOpen(true)}
              className="gap-2"
            >
              <PaintBucket className="size-4" />
              <span>Change Background Color</span>
            </ContextMenuItem>
          </ContextMenuContent>
        </ContextMenu>
      )}

      {!readOnly && <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
        <DialogContent className="sm:max-w-[450px] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Block Background Color</DialogTitle>
            <DialogDescription>
              Choose a background color for this block
            </DialogDescription>
          </DialogHeader>

          <Tabs defaultValue="preset" className="w-full">
            <TabsList className="grid w-full grid-cols-2">
              <TabsTrigger value="preset">Preset Colors</TabsTrigger>
              <TabsTrigger value="custom">Custom Color</TabsTrigger>
            </TabsList>

            <TabsContent value="preset" className="space-y-3 pt-4">
              <h4 className="font-medium text-sm">Background Colors</h4>
              <div className="grid grid-cols-4 gap-2">
                {presetColors.map((color) => (
                  <button
                    key={color.hex}
                    onClick={() => handlePresetColorSelect(color.hex)}
                    className={`h-16 rounded-md border-2 transition-all hover:scale-105 hover:shadow-md ${
                      currentBackgroundColor === color.hex
                        ? "border-primary ring-2 ring-primary ring-offset-2"
                        : "border-border"
                    }`}
                    title={color.name}
                    style={{
                      backgroundColor: color.hex,
                      backgroundImage:
                        color.hex === "transparent"
                          ? "linear-gradient(45deg, #ccc 25%, transparent 25%, transparent 75%, #ccc 75%, #ccc), linear-gradient(45deg, #ccc 25%, transparent 25%, transparent 75%, #ccc 75%, #ccc)"
                          : "none",
                      backgroundSize:
                        color.hex === "transparent" ? "10px 10px" : "auto",
                      backgroundPosition:
                        color.hex === "transparent"
                          ? "0 0, 5px 5px"
                          : "initial",
                    }}
                  >
                    <span className="text-xs font-medium text-foreground/60">
                      {color.name}
                    </span>
                  </button>
                ))}
              </div>
            </TabsContent>

            <TabsContent value="custom" className="space-y-3 pt-4">
              <ShadcnColorPicker
                defaultValue="#ffffff"
                onChange={handleCustomColorChange}
                className="w-full rounded-md border bg-background p-3 shadow-sm"
              >
                <ColorPickerSelection className="" />
                <div className="flex items-center gap-2 mt-2">
                  <ColorPickerEyeDropper />
                  <div className="grid w-full gap-1">
                    <ColorPickerHue />
                    <ColorPickerAlpha />
                  </div>
                </div>
                <div className="flex items-center gap-2 mt-2">
                  <ColorPickerOutput className="flex-1" />
                  <ColorPickerFormat />
                </div>
              </ShadcnColorPicker>

              <div className="flex items-center justify-between gap-3">
                <div className="flex items-center gap-2 flex-1 min-w-0">
                  <div
                    className="h-8 w-8 rounded border shrink-0"
                    style={{ backgroundColor: displayColor }}
                  />
                  <span className="font-mono text-xs font-medium truncate">
                    {displayColor}
                  </span>
                </div>
                <Button
                  onClick={handleApplyCustomColor}
                  size="sm"
                  className="shrink-0"
                >
                  Apply
                </Button>
              </div>
            </TabsContent>
          </Tabs>
        </DialogContent>
      </Dialog>}
    </React.Fragment>
  );
}

"use client";

import React, { useRef, useState } from "react";
import { TextNode } from ".";
import { GripVertical, Plus, ImageIcon } from "lucide-react";
import { Popover, PopoverContent, PopoverTrigger } from "@/registry/new-york-v4/ui/popover";
import { Button } from "@/registry/new-york-v4/ui/button";
import { ELEMENT_OPTIONS } from "@/lib/elements";
import {
  Type,
  Heading1,
  Heading2,
  Heading3,
  Quote,
  Code,
  List,
  ListOrdered,
} from "lucide-react";
import { useEditorDispatch } from "./store/editor-store";
import {
  createHandleBlockDragStart,
  createHandleBlockDragEnd,
} from "./handlers/block";

// Icon mapping
const iconMap: Record<string, React.ComponentType<{ className?: string }>> = {
  Type,
  Heading1,
  Heading2,
  Heading3,
  Code,
  Quote,
  List,
  ListOrdered,
};

export interface BlockDragHandleProps {
  textNode: TextNode;
  isFirstBlock: boolean;
  notionBased: boolean;
  hasCoverImage: boolean;
  onUploadCoverImage?: (file: File) => Promise<string>;
  onBlockDragStart?: (nodeId: string) => void;
  onSetDragOverNodeId?: (nodeId: string | null) => void;
  onSetDropPosition?: (position: "before" | "after" | "left" | "right" | null) => void;
  onSetDraggingNodeId?: (nodeId: string | null) => void;
}

/**
 * BlockDragHandle
 *
 * Renders the absolute-positioned row that appears on hover containing:
 *   - Cover image upload button (first block in Notion mode only)
 *   - Add block popover
 *   - Drag/grip handle (desktop + touch)
 */
export function BlockDragHandle({
  textNode,
  isFirstBlock,
  notionBased,
  hasCoverImage,
  onUploadCoverImage,
  onBlockDragStart,
  onSetDragOverNodeId,
  onSetDropPosition,
  onSetDraggingNodeId,
}: BlockDragHandleProps) {
  const dispatch = useEditorDispatch();
  const coverImageInputRef = useRef<HTMLInputElement>(null);
  const [isUploadingCover, setIsUploadingCover] = useState(false);
  const [addBlockPopoverOpen, setAddBlockPopoverOpen] = useState(false);
  const touchStartRef = useRef<{ x: number; y: number } | null>(null);
  const [isDraggingTouch, setIsDraggingTouch] = useState(false);

  // Cover image upload
  const handleCoverImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !onUploadCoverImage) return;

    setIsUploadingCover(true);
    try {
      const url = await onUploadCoverImage(file);
      const { EditorActions } = await import("./reducer/actions");
      dispatch(EditorActions.setCoverImage({
        url,
        alt: file.name,
        position: 50,
      }));
    } catch (error) {
      console.error("Failed to upload cover image:", error);
    } finally {
      setIsUploadingCover(false);
      if (coverImageInputRef.current) {
        coverImageInputRef.current.value = "";
      }
    }
  };

  // Drag handlers
  const handleBlockDragStartFn = createHandleBlockDragStart(textNode, onBlockDragStart);

  const handleBlockDragEndFn = createHandleBlockDragEnd(() => {
    if (onSetDragOverNodeId && onSetDropPosition && onSetDraggingNodeId) {
      onSetDragOverNodeId(null);
      onSetDropPosition(null);
      onSetDraggingNodeId(null);
    }
  });

  // Touch handlers
  const handleTouchStart = (e: React.TouchEvent) => {
    e.preventDefault();
    e.stopPropagation();
    const touch = e.touches[0];
    touchStartRef.current = { x: touch.clientX, y: touch.clientY };
    setIsDraggingTouch(true);
    if (onBlockDragStart && textNode?.id) {
      onBlockDragStart(textNode.id);
    }
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    if (!touchStartRef.current || !isDraggingTouch) return;
    e.preventDefault();
    e.stopPropagation();
    const touch = e.touches[0];
    const elementBelow = document.elementFromPoint(touch.clientX, touch.clientY);
    const targetBlock = elementBelow?.closest("[data-node-id]");
    if (targetBlock && onSetDragOverNodeId && onSetDropPosition) {
      const targetId = targetBlock.getAttribute("data-node-id");
      if (targetId && targetId !== textNode?.id) {
        onSetDragOverNodeId(targetId);
        onSetDropPosition("after");
      } else {
        onSetDragOverNodeId(null);
        onSetDropPosition(null);
      }
    }
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    const touch = e.changedTouches[0];
    const elementBelow = document.elementFromPoint(touch.clientX, touch.clientY);
    const targetBlock = elementBelow?.closest("[data-node-id]");
    if (targetBlock && textNode?.id) {
      const targetId = targetBlock.getAttribute("data-node-id");
      if (targetId && targetId !== textNode.id && dispatch) {
        dispatch({
          type: "MOVE_NODE",
          payload: {
            nodeId: textNode.id,
            targetId,
            position: "after",
          },
        });
      }
    }
    touchStartRef.current = null;
    setIsDraggingTouch(false);
    if (onSetDragOverNodeId && onSetDropPosition) {
      onSetDragOverNodeId(null);
      onSetDropPosition(null);
    }
  };

  const handleTouchCancel = () => {
    touchStartRef.current = null;
    setIsDraggingTouch(false);
    if (onSetDragOverNodeId && onSetDropPosition) {
      onSetDragOverNodeId(null);
      onSetDropPosition(null);
    }
  };

  return (
    <div className="flex lg:absolute items-center gap-0.5 mb-1 lg:mb-0 lg:left-0 lg:top-1/2 lg:-translate-y-1/2 lg:-ml-[4.5rem] lg:opacity-0 lg:group-hover:opacity-100 transition-opacity duration-200">
      {/* Cover image button - first block in Notion mode only */}
      {notionBased && isFirstBlock && !hasCoverImage && onUploadCoverImage && (
        <>
          <input
            ref={coverImageInputRef}
            type="file"
            accept="image/*"
            className="hidden"
            onChange={handleCoverImageUpload}
          />
          <button
            className="p-0.5 rounded hover:bg-accent transition-colors duration-200"
            onClick={(e) => {
              e.stopPropagation();
              coverImageInputRef.current?.click();
            }}
            onMouseDown={(e) => e.stopPropagation()}
            disabled={isUploadingCover}
            title="Add Cover"
          >
            {isUploadingCover ? (
              <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-primary" />
            ) : (
              <ImageIcon
                className="h-5 w-5 text-muted-foreground hover:text-foreground transition-colors duration-200"
                strokeWidth={1.5}
              />
            )}
          </button>
        </>
      )}

      {/* Add Block Button */}
      <Popover open={addBlockPopoverOpen} onOpenChange={setAddBlockPopoverOpen}>
        <PopoverTrigger asChild>
          <button
            className="p-0.5 rounded hover:bg-accent transition-colors duration-200"
            onClick={(e) => e.stopPropagation()}
            onMouseDown={(e) => e.stopPropagation()}
          >
            <Plus
              className="h-5 w-5 text-muted-foreground hover:text-foreground transition-colors duration-200"
              strokeWidth={1.5}
            />
          </button>
        </PopoverTrigger>
        <PopoverContent className="w-56 p-2" align="start">
          <div className="flex flex-col gap-1">
            {ELEMENT_OPTIONS.map((element) => {
              const IconComponent = element.icon ? iconMap[element.icon] : null;
              return (
                <Button
                  key={element.value}
                  variant="ghost"
                  size="sm"
                  className="justify-start gap-2"
                  onClick={() => {
                    dispatch({
                      type: "INSERT_NODE",
                      payload: {
                        node: {
                          id: `${element.value}-${Date.now()}`,
                          type: element.value as TextNode["type"],
                          content: "",
                        },
                        targetId: textNode.id,
                        position: "after",
                      },
                    });
                    setAddBlockPopoverOpen(false);
                  }}
                >
                  {IconComponent && (
                    <IconComponent className={element.iconSize || "h-4 w-4"} />
                  )}
                  <span>{element.label}</span>
                </Button>
              );
            })}
          </div>
        </PopoverContent>
      </Popover>

      {/* Drag Handle */}
      <div
        draggable
        onDragStart={handleBlockDragStartFn}
        onDragEnd={handleBlockDragEndFn}
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
        onTouchCancel={handleTouchCancel}
        className={`p-0.5 cursor-grab active:cursor-grabbing ${isDraggingTouch ? "opacity-50" : ""}`}
        style={{ touchAction: "none" }}
        onClick={(e) => e.stopPropagation()}
        onMouseDown={(e) => e.stopPropagation()}
      >
        <GripVertical
          className="h-5 w-5 text-muted-foreground hover:text-foreground transition-colors duration-200"
          strokeWidth={1.5}
        />
      </div>
    </div>
  );
}

/**
 * Mina Rich Editor - CollaborationProvider
 *
 * Convenience wrapper component that activates real-time collaboration
 * for all descendant editor components. Must be placed **inside** an
 * `<EditorProvider>`.
 *
 * ## Usage
 *
 * ```tsx
 * import { EditorProvider, CompactEditor } from '@mina-editor/core';
 * import { CollaborationProvider } from '@mina-editor/core';
 *
 * function App() {
 *   return (
 *     <EditorProvider initialContent={content}>
 *       <CollaborationProvider
 *         roomId="doc-123"
 *         serverUrl="wss://collab.example.com"
 *         user={{ name: "Alice", color: "#e66" }}
 *       >
 *         <CompactEditor />
 *       </CollaborationProvider>
 *     </EditorProvider>
 *   );
 * }
 * ```
 *
 * @packageDocumentation
 */

import React, { createContext, useContext } from 'react';
import { useCollaboration } from './hooks/useCollaboration';
import type { CollabOptions, CollabState } from './collaboration/types';

// ─── Context ──────────────────────────────────────────────────────────────────

const CollaborationContext = createContext<CollabState | null>(null);

/**
 * Read the current collaboration state from the nearest
 * `<CollaborationProvider>`. Returns `null` when collaboration is not
 * active (i.e. the component is rendered outside a provider).
 */
export function useCollaborationState(): CollabState | null {
  return useContext(CollaborationContext);
}

// ─── Props ────────────────────────────────────────────────────────────────────

export interface CollaborationProviderProps extends CollabOptions {
  children: React.ReactNode;
}

// ─── Component ────────────────────────────────────────────────────────────────

/**
 * Wraps children in a collaboration context that maintains a Y.js
 * connection and syncs editor state bidirectionally.
 *
 * Props are identical to `CollabOptions` plus `children`.
 */
export function CollaborationProvider({
  children,
  roomId,
  serverUrl,
  user,
}: CollaborationProviderProps) {
  const collabState = useCollaboration({ roomId, serverUrl, user });

  return React.createElement(
    CollaborationContext.Provider,
    { value: collabState },
    children
  );
}

