export { ELEMENT_OPTIONS };
export type { ElementType, ElementOption };

/**
 * FlexContainer Component
 *
 * Renders a flex container with drag-and-drop support for reordering/adding images
 * Shows visual indicators on left/right edges when dragging images
 */

"use client";

import React, { useState } from "react";
import { ContainerNode } from "./types";

interface FlexContainerProps {
  node: ContainerNode;
  children: React.ReactNode;
  onDragOver?: (e: React.DragEvent, position: "left" | "right" | null) => void;
  onDragLeave?: (e: React.DragEvent) => void;
  onDrop?: (e: React.DragEvent, position: "left" | "right" | null) => void;
  dragOverPosition?: "left" | "right" | null;
  className?: string;
}

export function FlexContainer({
  node,
  children,
  onDragOver,
  onDragLeave,
  onDrop,
  dragOverPosition,
  className = "",
}: FlexContainerProps) {
  const [localDragPosition, setLocalDragPosition] = useState<"left" | "right" | null>(null);

  const gap = node.attributes?.gap as string | undefined;
  const flexWrap = node.attributes?.flexWrap as string | undefined;

  const handleDragOver = (e: React.DragEvent) => {
    // Only prevent default and handle if we're in an edge zone
    // This allows images to be dragged out of the container

    // Get the container's bounding rectangle
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();

    // Define edge threshold (30% from each edge)
    const edgeThreshold = rect.width * 0.3;

    // Determine if we're near the left or right edge
    let position: "left" | "right" | null = null;

    if (e.clientX < rect.left + edgeThreshold) {
      position = "left";
    } else if (e.clientX > rect.right - edgeThreshold) {
      position = "right";
    }

    // Only handle if we're in an edge zone
    if (position) {
      e.preventDefault();
      e.stopPropagation();
      setLocalDragPosition(position);

      if (onDragOver) {
        onDragOver(e, position);
      }
    } else {
      // Not in an edge zone - clear any indicators but don't prevent default
      // This allows the drag to bubble up to parent handlers
      setLocalDragPosition(null);
    }
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();

    // Only clear if we're actually leaving the element (not entering a child)
    const relatedTarget = e.relatedTarget as HTMLElement;
    const currentTarget = e.currentTarget as HTMLElement;

    if (!currentTarget.contains(relatedTarget)) {
      setLocalDragPosition(null);

      if (onDragLeave) {
        onDragLeave(e);
      }
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    const position = localDragPosition;

    // Only handle the drop if we have a position (in an edge zone)
    if (position) {
      e.preventDefault();
      e.stopPropagation();

      if (onDrop) {
        onDrop(e, position);
      }
    }

    // Always clear the position indicator
    setLocalDragPosition(null);
  };

  const displayPosition = dragOverPosition ?? localDragPosition;

  return (
    <div
      data-node-id={node.id}
      data-node-type="container"
      data-layout-type="flex"
      className={`
        relative
        flex flex-row gap-${gap || "4"} items-start
        ${flexWrap === "wrap" ? "flex-wrap items-center" : ""}
        ${className}
      `}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
    >
      {/* Left edge indicator */}
      {displayPosition === "left" && (
        <div className="absolute inset-y-0 -left-1 w-1 bg-blue-500/50 rounded-full z-10 pointer-events-none" />
      )}

      {/* Right edge indicator */}
      {displayPosition === "right" && (
        <div className="absolute inset-y-0 -right-1 w-1 bg-blue-500/50 rounded-full z-10 pointer-events-none" />
      )}

      {children}
    </div>
  );
}

"use client";

import React, { useState, useEffect } from "react";
import { Button } from "@/registry/new-york-v4/ui/button";
import { Input } from "@/registry/new-york-v4/ui/input";
import { Minus, Plus } from "lucide-react";

interface FontSizePickerProps {
  disabled?: boolean;
  onFontSizeSelect: (fontSize: string) => void;
  currentFontSize?: string;
}

// Extract numeric value from inline style fontSize value
const extractFontSize = (fontSizeValue?: string): number => {
  if (!fontSizeValue) return 16; // default

  // Check if it's a pixel value
  if (fontSizeValue.includes("px")) {
    return parseInt(fontSizeValue.replace("px", "")) || 16;
  }

  // If it's just a number
  const parsed = parseInt(fontSizeValue);
  if (!isNaN(parsed)) {
    return parsed;
  }

  return 16;
};

export function FontSizePicker({
  disabled = false,
  onFontSizeSelect,
  currentFontSize,
}: FontSizePickerProps) {
  const [fontSize, setFontSize] = useState<number>(
    extractFontSize(currentFontSize)
  );

  // Update fontSize when currentFontSize changes (selection changes)
  useEffect(() => {
    const extractedSize = extractFontSize(currentFontSize);
    setFontSize(extractedSize);
  }, [currentFontSize]);

  const handleIncrement = () => {
    const newSize = Math.min(fontSize + 2, 128);
    setFontSize(newSize);
    onFontSizeSelect(`${newSize}px`);
  };

  const handleDecrement = () => {
    const newSize = Math.max(fontSize - 2, 8);
    setFontSize(newSize);
    onFontSizeSelect(`${newSize}px`);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = parseInt(e.target.value) || 16;
    const clampedValue = Math.max(8, Math.min(value, 128));
    setFontSize(clampedValue);
  };

  const handleInputBlur = () => {
    onFontSizeSelect(`${fontSize}px`);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === "Enter") {
      onFontSizeSelect(`${fontSize}px`);
      e.currentTarget.blur();
    }
  };

  return (
    <div className="flex items-center gap-0.5 bg-muted/50 rounded-md">
      <Button
        variant="ghost"
        size="icon"
        onClick={handleDecrement}
        disabled={disabled || fontSize <= 8}
        className="h-7 w-6 md:h-8 md:w-7 rounded-r-none hover:bg-muted"
        title="Decrease font size"
      >
        <Minus className="size-3 md:size-3.5" />
      </Button>

      <Input
        type="number"
        value={fontSize}
        onChange={handleInputChange}
        onBlur={handleInputBlur}
        onKeyDown={handleKeyDown}
        disabled={disabled}
        min={8}
        max={128}
        className="h-7 w-10 md:h-8 md:w-14 text-center text-xs md:text-sm border-0 bg-transparent focus-visible:ring-0 focus-visible:ring-offset-0 px-0.5 md:px-1 rounded-none [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none"
        title="Font size in pixels"
      />

      <Button
        variant="ghost"
        size="icon"
        onClick={handleIncrement}
        disabled={disabled || fontSize >= 128}
        className="h-7 w-6 md:h-8 md:w-7 rounded-l-none hover:bg-muted"
        title="Increase font size"
      >
        <Plus className="size-3 md:size-3.5" />
      </Button>
    </div>
  );
}

/**
 * FreeImageBlock Component
 *
 * Renders a free-positioned image that can be dragged anywhere on the canvas
 * and maintains its position via styles (x, y coordinates).
 * Resize logic is delegated to the useImageResize hook.
 */

"use client";

import React, { useState, useRef, useEffect, useCallback } from "react";
import { TextNode } from ".";
import { X, ImageIcon, Loader2, Move } from "lucide-react";
import { Button } from "@/registry/new-york-v4/ui/button";
import { useEditorDispatch } from "./store/editor-store";
import { EditorActions } from "@/lib/reducer/actions";
import { useImageResize } from "./hooks/useImageResize";

interface FreeImageBlockProps {
  node: TextNode;
  isActive: boolean;
  onClick: () => void;
  onDelete?: () => void;
  readOnly?: boolean;
}

export function FreeImageBlock({
  node,
  onClick,
  onDelete,
  readOnly = false,
}: FreeImageBlockProps) {
  const dispatch = useEditorDispatch();
  const [imageError, setImageError] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const [aspectRatio, setAspectRatio] = useState<number | null>(null);
  const [position, setPosition] = useState({
    x: parseFloat((node.attributes?.styles as any)?.left || "100") || 0,
    y: parseFloat((node.attributes?.styles as any)?.top || "100") || 0,
  });
  const dragRef = useRef<HTMLDivElement>(null);
  const startPosRef = useRef({ x: 0, y: 0, mouseX: 0, mouseY: 0 });

  const imageUrl = node.attributes?.src as string | undefined;
  const altText = node.attributes?.alt as string | undefined;
  const caption = node.content || "";
  const isUploading =
    node.attributes?.loading === "true" || node.attributes?.loading === true;
  const hasError =
    node.attributes?.error === "true" || node.attributes?.error === true;

  // Parse initial width from node attributes (px mode)
  const getInitialWidth = (): number => {
    const styles = node.attributes?.styles;
    if (styles && typeof styles === "object" && !Array.isArray(styles)) {
      const width = (styles as Record<string, string>).width;
      if (width) {
        const v = parseFloat(width);
        if (!isNaN(v)) return Math.max(200, Math.min(800, v));
      }
    }
    return 400;
  };

  const getNodeAttributes = useCallback(
    () => (node.attributes || {}) as Record<string, any>,
    [node.attributes]
  );

  const {
    currentWidth,
    isResizing,
    dimensionLabel,
    handlePointerDown,
    handlePointerMove,
    handlePointerUp,
    onKeyDown,
  } = useImageResize({
    nodeId: node.id,
    initialWidth: getInitialWidth(),
    unit: "px",
    minWidth: 200,
    maxWidth: 800,
    containerRef: dragRef as React.RefObject<HTMLElement>,
    dispatch,
    getNodeAttributes,
    aspectRatio,
  });

  const handleImageLoad = (e: React.SyntheticEvent<HTMLImageElement>) => {
    setImageError(false);
    const img = e.currentTarget;
    if (img.naturalWidth && img.naturalHeight) {
      setAspectRatio(img.naturalWidth / img.naturalHeight);
    }
  };

  const handleImageError = () => {
    setImageError(true);
  };

  // --- Drag (position) logic remains here since it's specific to FreeImageBlock ---
  const handleDragStart = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(true);
    startPosRef.current = {
      x: position.x,
      y: position.y,
      mouseX: e.clientX,
      mouseY: e.clientY,
    };
  };

  useEffect(() => {
    if (!isDragging) return;

    const handleMouseMove = (e: MouseEvent) => {
      const deltaX = e.clientX - startPosRef.current.mouseX;
      const deltaY = e.clientY - startPosRef.current.mouseY;

      const newX = startPosRef.current.x + deltaX;
      const newY = startPosRef.current.y + deltaY;

      setPosition({ x: newX, y: newY });
    };

    const handleMouseUp = () => {
      setIsDragging(false);

      const currentStyles = (node.attributes?.styles || {}) as Record<
        string,
        string
      >;
      const newStyles = {
        ...currentStyles,
        left: `${position.x}px`,
        top: `${position.y}px`,
        position: "fixed",
        zIndex: currentStyles.zIndex || "10",
      };

      dispatch(
        EditorActions.updateNode(node.id, {
          attributes: {
            ...node.attributes,
            styles: newStyles,
          },
        })
      );
    };

    window.addEventListener("mousemove", handleMouseMove);
    window.addEventListener("mouseup", handleMouseUp);

    return () => {
      window.removeEventListener("mousemove", handleMouseMove);
      window.removeEventListener("mouseup", handleMouseUp);
    };
  }, [isDragging, position, node.id, node.attributes, dispatch]);

  const handleClick = (_e: React.MouseEvent) => {
    if (!isDragging && !isResizing) {
      onClick();
    }
  };

  const showResizeHandles = !readOnly && !isUploading && !hasError && imageUrl;

  return (
    <div
      ref={dragRef}
      className={`
        absolute group rounded-lg overflow-hidden
        ${readOnly ? "cursor-default" : isDragging ? "cursor-grabbing" : isResizing ? "cursor-ew-resize" : "cursor-grab"}
      `}
      style={{
        left: `${position.x}px`,
        top: `${position.y}px`,
        width: `${currentWidth}px`,
        height: "auto",
        zIndex: isDragging || isResizing ? 1000 : 10,
      }}
      onClick={handleClick}
      onKeyDown={onKeyDown}
      tabIndex={0}
    >
      <div className="relative">
        {/* Dimension overlay during resize */}
        {isResizing && dimensionLabel && (
          <div className="absolute top-2 left-1/2 -translate-x-1/2 z-30 bg-black/75 text-white text-xs px-2 py-1 rounded pointer-events-none">
            {dimensionLabel}
          </div>
        )}

        {/* Drag handle - only in edit mode */}
        {!readOnly && (
          <div
            className="absolute top-2 left-2 z-20 cursor-grab active:cursor-grabbing opacity-0 group-hover:opacity-100 transition-opacity"
            onMouseDown={handleDragStart}
          >
            <Button
              variant="secondary"
              size="icon"
              className="h-8 w-8 bg-background/90 hover:bg-background"
            >
              <Move className="h-4 w-4" />
            </Button>
          </div>
        )}

        {/* Delete button - only in edit mode */}
        {!readOnly && onDelete && (
          <Button
            variant="destructive"
            size="icon"
            className="absolute top-2 right-2 h-8 w-8 opacity-0 group-hover:opacity-100 transition-opacity z-20"
            onClick={(e) => {
              e.stopPropagation();
              onDelete();
            }}
          >
            <X className="h-4 w-4" />
          </Button>
        )}

        {/* Image container */}
        <div className="relative w-full">
          {/* Uploading state */}
          {isUploading && (
            <div className="w-full h-64 flex flex-col items-center justify-center bg-muted/50 border-2 border-dashed border-primary/50">
              <Loader2 className="h-12 w-12 text-primary animate-spin mb-3" />
              <p className="text-sm font-medium text-foreground">
                Uploading image...
              </p>
            </div>
          )}

          {/* Error state */}
          {!isUploading && hasError && (
            <div className="w-full h-64 flex flex-col items-center justify-center bg-destructive/10 border-2 border-dashed border-destructive/50">
              <X className="h-12 w-12 text-destructive mb-2" />
              <p className="text-sm font-medium text-destructive">
                Upload Failed
              </p>
            </div>
          )}

          {/* Normal image */}
          {!isUploading && !hasError && (
            <>
              {imageError && (
                <div className="w-full h-64 flex flex-col items-center justify-center bg-muted border-2 border-dashed border-muted-foreground/25">
                  <ImageIcon className="h-12 w-12 text-muted-foreground/50 mb-2" />
                  <p className="text-sm text-muted-foreground">
                    Failed to load image
                  </p>
                </div>
              )}

              {imageUrl && (
                <img
                  src={imageUrl}
                  alt={altText || caption || "Free-positioned image"}
                  className="w-full h-auto rounded-lg object-cover"
                  onLoad={handleImageLoad}
                  onError={handleImageError}
                  draggable={false}
                />
              )}

              {caption && (
                <p className="text-sm text-muted-foreground text-center p-2 italic bg-background/50">
                  {caption}
                </p>
              )}
            </>
          )}
        </div>

        {/* Resize handles - only in edit mode */}
        {showResizeHandles && (
          <>
            {/* Left resize handle — large hit area (44px), small visual indicator */}
            <div
              className="absolute left-0 top-1/2 -translate-y-1/2 w-11 h-11 cursor-ew-resize opacity-0 group-hover:opacity-100 hover:!opacity-100 transition-opacity z-20 flex items-center justify-center"
              style={{ touchAction: "none" }}
              onPointerDown={(e) => handlePointerDown(e, "left")}
              onPointerMove={handlePointerMove}
              onPointerUp={handlePointerUp}
            >
              <div className="w-1.5 h-10 bg-primary/50 rounded-full hover:bg-primary transition-colors" />
            </div>

            {/* Right resize handle — large hit area (44px), small visual indicator */}
            <div
              className="absolute right-0 top-1/2 -translate-y-1/2 w-11 h-11 cursor-ew-resize opacity-0 group-hover:opacity-100 hover:!opacity-100 transition-opacity z-20 flex items-center justify-center"
              style={{ touchAction: "none" }}
              onPointerDown={(e) => handlePointerDown(e, "right")}
              onPointerMove={handlePointerMove}
              onPointerUp={handlePointerUp}
            >
              <div className="w-1.5 h-10 bg-primary/50 rounded-full hover:bg-primary transition-colors" />
            </div>
          </>
        )}
      </div>
    </div>
  );
}

/**
 * Group Images Button Component
 *
 * Floating button that appears when multiple images are selected
 * Allows grouping selected images into a flex container
 */

"use client";

import React from "react";
import { Button } from "@/registry/new-york-v4/ui/button";
import { Images, X, ArrowLeftRight, Package } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";

interface GroupImagesButtonProps {
  selectedCount: number;
  inSameFlex: boolean;
  onGroup: () => void;
  onReverse?: () => void;
  onExtract?: () => void;
  onClear: () => void;
}

export function GroupImagesButton({
  selectedCount,
  inSameFlex,
  onGroup,
  onReverse,
  onExtract,
  onClear,
}: GroupImagesButtonProps) {
  if (selectedCount < 2) return null;

  return (
    <AnimatePresence>
      <motion.div
        initial={{ opacity: 0, y: 20, scale: 0.9 }}
        animate={{ opacity: 1, y: 0, scale: 1 }}
        exit={{ opacity: 0, y: 20, scale: 0.9 }}
        transition={{ duration: 0.2 }}
        className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50"
      >
        <div className="flex items-center gap-2 bg-background border border-border rounded-lg shadow-2xl p-2">
          {/* Selection count */}
          <div className="px-3 py-2 text-sm font-medium text-muted-foreground">
            {selectedCount} {selectedCount === 1 ? "image" : "images"} selected
          </div>

          {/* Show different actions based on whether in flex */}
          {inSameFlex ? (
            <>
              {/* Reverse button */}
              {onReverse && (
                <Button
                  onClick={onReverse}
                  size="sm"
                  variant="secondary"
                  className="gap-2"
                >
                  <ArrowLeftRight className="h-4 w-4" />
                  Reverse Order
                </Button>
              )}

              {/* Extract button */}
              {onExtract && (
                <Button
                  onClick={onExtract}
                  size="sm"
                  variant="secondary"
                  className="gap-2"
                >
                  <Package className="h-4 w-4" />
                  Extract from Flex
                </Button>
              )}
            </>
          ) : (
            /* Group button */
            <Button
              onClick={onGroup}
              size="sm"
              className="gap-2"
            >
              <Images className="h-4 w-4" />
              Group into Flex
            </Button>
          )}

          {/* Clear button */}
          <Button
            onClick={onClear}
            variant="ghost"
            size="icon"
            className="h-8 w-8"
          >
            <X className="h-4 w-4" />
          </Button>
        </div>
      </motion.div>
    </AnimatePresence>
  );
}

/**
 * ImageBlock Component
 *
 * Renders an image node with upload state, loading indicator, error handling,
 * and resize functionality via the useImageResize hook.
 */

"use client";

import React, { useState, useRef, useEffect, useCallback } from "react";
import { TextNode } from ".";
import { Card } from "@/registry/new-york-v4/ui/card";
import { X, ImageIcon, Loader2 } from "lucide-react";
import { Button } from "@/registry/new-york-v4/ui/button";
import { Checkbox } from "@/registry/new-york-v4/ui/checkbox";
import { useEditorDispatch } from "./store/editor-store";
import { useImageResize } from "./hooks/useImageResize";

interface ImageBlockProps {
  node: TextNode;
  isActive: boolean;
  onClick: () => void;
  onDelete?: () => void;
  onDragStart?: (nodeId: string) => void;
  isSelected?: boolean;
  onToggleSelection?: (nodeId: string) => void;
  onClickWithModifier?: (e: React.MouseEvent, nodeId: string) => void;
}

export function ImageBlock({
  node,
  isActive,
  onClick,
  onDelete,
  onDragStart,
  isSelected = false,
  onToggleSelection,
  onClickWithModifier,
}: ImageBlockProps) {
  const dispatch = useEditorDispatch();
  const [imageError, setImageError] = useState(false);
  const [aspectRatio, setAspectRatio] = useState<number | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Parse initial width from node attributes
  const getInitialWidth = (): number => {
    const styles = node.attributes?.styles;
    if (styles && typeof styles === "object" && !Array.isArray(styles)) {
      const width = (styles as Record<string, string>).width;
      if (width && typeof width === "string" && width.endsWith("%")) {
        const v = parseFloat(width);
        if (!isNaN(v)) return v;
      }
    }
    return 100;
  };

  const getNodeAttributes = useCallback(
    () => (node.attributes || {}) as Record<string, any>,
    [node.attributes]
  );

  const {
    currentWidth,
    isResizing,
    dimensionLabel,
    handlePointerDown,
    handlePointerMove,
    handlePointerUp,
    setWidthPreset,
    onKeyDown,
    setCurrentWidth,
  } = useImageResize({
    nodeId: node.id,
    initialWidth: getInitialWidth(),
    unit: "percent",
    minWidth: 20,
    maxWidth: 100,
    containerRef: containerRef as React.RefObject<HTMLElement>,
    dispatch,
    getNodeAttributes,
    aspectRatio,
  });

  // Sync width when node attributes change externally
  useEffect(() => {
    const styles = node.attributes?.styles;
    if (styles && typeof styles === "object" && !Array.isArray(styles)) {
      const width = (styles as Record<string, string>).width;
      if (width && typeof width === "string" && width.endsWith("%")) {
        const widthValue = parseFloat(width);
        if (!isNaN(widthValue) && !isResizing) {
          setCurrentWidth(widthValue);
        }
      }
    }
  }, [node.attributes?.styles, isResizing, setCurrentWidth]);

  const handleClick = (e: React.MouseEvent) => {
    if (isResizing) return;

    if (onClickWithModifier) {
      onClickWithModifier(e, node.id);
    }

    if (!e.ctrlKey && !e.metaKey) {
      onClick();
    }
  };

  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.effectAllowed = "move";
    e.dataTransfer.setData("text/plain", node.id);
    e.dataTransfer.setData(
      "application/json",
      JSON.stringify({
        nodeId: node.id,
        type: node.type,
        src: node.attributes?.src,
      })
    );
    if (onDragStart) {
      onDragStart(node.id);
    }
  };

  const handleDragEnd = (_e: React.DragEvent) => {};

  const imageUrl = node.attributes?.src as string | undefined;
  const altText = node.attributes?.alt as string | undefined;
  const caption = node.content || "";
  const isUploading =
    node.attributes?.loading === "true" || node.attributes?.loading === true;
  const hasError =
    node.attributes?.error === "true" || node.attributes?.error === true;

  const handleImageLoad = (e: React.SyntheticEvent<HTMLImageElement>) => {
    setImageError(false);
    const img = e.currentTarget;
    if (img.naturalWidth && img.naturalHeight) {
      setAspectRatio(img.naturalWidth / img.naturalHeight);
    }
  };

  const handleImageError = () => {
    setImageError(true);
  };

  const showResizeHandles = !isUploading && !hasError && imageUrl;

  return (
    <div
      ref={containerRef}
      className="relative mb-4"
      style={{ width: "100%" }}
      onKeyDown={onKeyDown}
      tabIndex={isActive ? 0 : undefined}
      data-node-id={node.id}
      data-node-type="img"
    >
      <Card
        draggable={!isResizing}
        onDragStart={handleDragStart}
        onDragEnd={handleDragEnd}
        className={`
          relative !border-0 p-4 duration-200 group
          ${!isResizing ? "cursor-move" : ""}
          ${isActive ? "ring-2 ring-primary/[0.05] bg-accent/5" : "hover:bg-accent/5"}
          ${isSelected ? "ring-2 ring-blue-500 bg-blue-500/10" : ""}
        `}
        style={{ width: `${currentWidth}%`, margin: "0 auto" }}
        onClick={handleClick}
      >
        {/* Selection checkbox */}
        {onToggleSelection && (
          <div
            className={`absolute top-2 left-2 z-10 transition-opacity ${
              isSelected ? "opacity-100" : "opacity-0 group-hover:opacity-100"
            }`}
            onClick={(e) => {
              e.stopPropagation();
            }}
          >
            <Checkbox
              checked={isSelected}
              onCheckedChange={() => onToggleSelection(node.id)}
              className="h-5 w-5 bg-background border-2"
            />
          </div>
        )}

        {/* Delete button */}
        {onDelete && (
          <Button
            variant="destructive"
            size="icon"
            className="absolute top-2 right-2 h-8 w-8 opacity-0 group-hover:opacity-100 transition-opacity z-10"
            onClick={(e) => {
              e.stopPropagation();
              onDelete();
            }}
          >
            <X className="h-4 w-4" />
          </Button>
        )}

        {/* Image container */}
        <div className="relative w-full">
          {/* Dimension overlay during resize */}
          {isResizing && dimensionLabel && (
            <div className="absolute top-2 left-1/2 -translate-x-1/2 z-30 bg-black/75 text-white text-xs px-2 py-1 rounded pointer-events-none">
              {dimensionLabel}
            </div>
          )}

          {/* Uploading state - show spinner overlay */}
          {isUploading && (
            <div className="w-full h-64 flex flex-col items-center justify-center bg-muted/50 rounded-lg border-2 border-dashed border-primary/50">
              <Loader2 className="h-12 w-12 text-primary animate-spin mb-3" />
              <p className="text-sm font-medium text-foreground">
                Uploading image...
              </p>
              <p className="text-xs text-muted-foreground mt-1">Please wait</p>
            </div>
          )}

          {/* Error state (from upload failure) */}
          {!isUploading && hasError && (
            <div className="w-full h-64 flex flex-col items-center justify-center bg-destructive/10 rounded-lg border-2 border-dashed border-destructive/50">
              <X className="h-12 w-12 text-destructive mb-2" />
              <p className="text-sm font-medium text-destructive">
                Upload Failed
              </p>
              <p className="text-xs text-muted-foreground mt-1">
                Please try again
              </p>
            </div>
          )}

          {/* Normal image loading/error states */}
          {!isUploading && !hasError && (
            <>
              {/* Error state */}
              {imageError && (
                <div className="w-full h-64 flex flex-col items-center justify-center bg-muted rounded-lg border-2 border-dashed border-muted-foreground/25">
                  <ImageIcon className="h-12 w-12 text-muted-foreground/50 mb-2" />
                  <p className="text-sm text-muted-foreground">
                    Failed to load image
                  </p>
                  {imageUrl && (
                    <p className="text-xs text-muted-foreground/70 mt-1 max-w-xs truncate">
                      {imageUrl}
                    </p>
                  )}
                </div>
              )}

              {/* Actual image */}
              {imageUrl && (
                <img
                  src={imageUrl}
                  alt={altText || caption || "Uploaded image"}
                  className="h-auto rounded-lg object-cover max-h-[600px]"
                  style={{ width: "auto", margin: "auto" }}
                  onLoad={handleImageLoad}
                  onError={handleImageError}
                />
              )}

              {/* Caption */}
              {caption && (
                <p className="text-sm text-muted-foreground text-center mt-3 italic">
                  {caption}
                </p>
              )}
            </>
          )}
        </div>

        {/* Resize handles */}
        {showResizeHandles && (
          <>
            {/* Left resize handle — large hit area (44px), small visual indicator */}
            <div
              className="absolute left-0 top-1/2 -translate-y-1/2 w-11 h-11 cursor-ew-resize opacity-0 group-hover:opacity-100 hover:!opacity-100 transition-opacity z-20 flex items-center justify-center"
              style={{ touchAction: "none" }}
              onPointerDown={(e) => handlePointerDown(e, "left")}
              onPointerMove={handlePointerMove}
              onPointerUp={handlePointerUp}
            >
              <div className="w-1.5 h-10 bg-primary/50 rounded-full hover:bg-primary transition-colors" />
            </div>

            {/* Right resize handle — large hit area (44px), small visual indicator */}
            <div
              className="absolute right-0 top-1/2 -translate-y-1/2 w-11 h-11 cursor-ew-resize opacity-0 group-hover:opacity-100 hover:!opacity-100 transition-opacity z-20 flex items-center justify-center"
              style={{ touchAction: "none" }}
              onPointerDown={(e) => handlePointerDown(e, "right")}
              onPointerMove={handlePointerMove}
              onPointerUp={handlePointerUp}
            >
              <div className="w-1.5 h-10 bg-primary/50 rounded-full hover:bg-primary transition-colors" />
            </div>
          </>
        )}
      </Card>

      {/* Width preset toolbar — shown when image is active */}
      {isActive && showResizeHandles && (
        <div className="flex items-center justify-center gap-1 mt-2">
          {([25, 50, 75, 100] as const).map((preset) => (
            <Button
              key={preset}
              variant="outline"
              size="sm"
              className={`h-7 px-3 text-xs ${
                Math.round(currentWidth) === preset
                  ? "bg-primary text-primary-foreground hover:bg-primary/90"
                  : ""
              }`}
              onClick={(e) => {
                e.stopPropagation();
                setWidthPreset(preset);
              }}
            >
              {preset}%
            </Button>
          ))}
        </div>
      )}
    </div>
  );
}

