/**
 * Walk a DOM element tree to find the first `Text` node.
 */
function findFirstTextNode(el: Node): Text | null {
  if (el.nodeType === Node.TEXT_NODE) return el as Text;
  for (let i = 0; i < el.childNodes.length; i++) {
    const found = findFirstTextNode(el.childNodes[i]);
    if (found) return found;
  }
  return null;
}

/**
 * SelectionToolbar Component
 *
 * A floating toolbar that appears above selected text, similar to Notion's selection menu.
 * Provides quick access to text formatting and styling options.
 */

"use client";

import React, { useEffect, useState, useRef } from "react";
import { type SelectionInfo } from ".";
import { Link as LinkIcon, Type, Sparkles } from "lucide-react";
import type { AIProvider } from "./ai/types";
import { AISelectionMenu } from "./AISelectionMenu";
import { Button } from "@/registry/new-york-v4/ui/button";
import { Separator } from "@/registry/new-york-v4/ui/separator";
import { ElementSelector, type ElementType } from "./ElementSelector";
import { Popover, PopoverContent, PopoverTrigger } from "@/registry/new-york-v4/ui/popover";
import { useEditorDispatch, EditorActions } from ".";
import { useToast } from "./hooks/use-toast";
import { tailwindClasses } from "./tailwind-classes";
import {
  getUserFriendlyClasses,
  searchUserFriendlyClasses,
} from "./class-mappings";
import {
  mergeClasses,
  getReplacementInfo,
} from "./utils/class-replacement";
import {
  LinkPopoverContent,
  CustomClassPopoverContent,
  FormatButtons,
} from "./_toolbar-components";
import { ColorPickerComponent } from "./ColorPicker";
import { FontSizePicker } from "./FontSizePicker";
import { cn } from "@/lib/utils";
import { AnimatePresence, motion } from "framer-motion";

interface SelectionToolbarProps {
  selection: SelectionInfo | null;
  selectedColor: string;
  onFormat: (format: "bold" | "italic" | "underline" | "strikethrough" | "code") => void;
  onTypeChange: (type: string) => void;
  onColorSelect: (color: string) => void;
  onFontSizeSelect: (fontSize: string) => void;
  aiProvider?: AIProvider;
  aiSystemPrompt?: string;
}

export function SelectionToolbar({
  selection,
  selectedColor,
  onFormat,
  onTypeChange,
  onColorSelect,
  onFontSizeSelect,
  aiProvider,
  aiSystemPrompt,
}: SelectionToolbarProps) {
  const dispatch = useEditorDispatch();
  const { toast } = useToast();
  const [position, setPosition] = useState({ top: 0, left: 0 });
  const [isVisible, setIsVisible] = useState(false);
  const toolbarRef = useRef<HTMLDivElement>(null);

  // Link popover state
  const [linkPopoverOpen, setLinkPopoverOpen] = useState(false);
  const [hrefInput, setHrefInput] = useState("");

  // Custom class popover state
  const [customClassPopoverOpen, setCustomClassPopoverOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [devMode, setDevMode] = useState(false);

  // AI menu state
  const [aiMenuOpen, setAiMenuOpen] = useState(false);

  // Store selection for link/class application
  const savedSelectionRef = useRef<typeof selection>(null);

  useEffect(() => {
    // Keep toolbar visible and position stable if either popover is open
    if (linkPopoverOpen || customClassPopoverOpen || aiMenuOpen) {
      return;
    }

    if (!selection || selection.text.length === 0) {
      setIsVisible(false);
      return;
    }

    // Save selection for later use in popovers
    savedSelectionRef.current = selection;

    // Pre-fill link input if selection has an existing link
    if (selection.href && !linkPopoverOpen) {
      setHrefInput(selection.href);
    }

    // Get the current selection range
    const domSelection = window.getSelection();
    if (!domSelection || domSelection.rangeCount === 0) {
      // Don't hide if we already have a position and saved selection
      if (savedSelectionRef.current && position.top !== 0) {
        return;
      }
      setIsVisible(false);
      return;
    }

    const range = domSelection.getRangeAt(0);
    const rect = range.getBoundingClientRect();

    // Don't update position if rect is empty/collapsed and we already have a good position
    if (rect.width === 0 && rect.height === 0 && position.top !== 0) {
      return;
    }

    // Calculate position above the selection
    const toolbarHeight = 44; // Approximate toolbar height
    const gap = 8; // Gap between selection and toolbar

    // Position toolbar centered above the selection
    let left = rect.left + rect.width / 2;
    const top = rect.top - toolbarHeight - gap;

    // Adjust horizontal position if toolbar would go off-screen
    if (toolbarRef.current) {
      const toolbarWidth = toolbarRef.current.offsetWidth;
      left = left - toolbarWidth / 2;

      // Keep toolbar within viewport
      const padding = 16;
      if (left < padding) {
        left = padding;
      } else if (left + toolbarWidth > window.innerWidth - padding) {
        left = window.innerWidth - toolbarWidth - padding;
      }
    }

    setPosition({ top, left });
    setIsVisible(true);
  }, [selection, linkPopoverOpen, customClassPopoverOpen, position.top]);

  // Link handlers
  const handleApplyLink = () => {
    if (!savedSelectionRef.current || !hrefInput.trim()) return;

    dispatch(EditorActions.setCurrentSelection(savedSelectionRef.current));

    requestAnimationFrame(() => {
      dispatch(EditorActions.applyLink(hrefInput.trim()));

      toast({
        title: "Link Applied",
        description: `Linked to: ${hrefInput}`,
      });

      setHrefInput("");
      setLinkPopoverOpen(false);
    });
  };

  const handleRemoveLink = () => {
    if (!savedSelectionRef.current) return;

    dispatch(EditorActions.setCurrentSelection(savedSelectionRef.current));

    requestAnimationFrame(() => {
      dispatch(EditorActions.removeLink());

      toast({
        title: "Link Removed",
        description: "Link has been removed from selection",
      });

      setHrefInput("");
      setLinkPopoverOpen(false);
    });
  };

  // Custom class handlers with smart replacement
  const handleApplyCustomClass = (className: string) => {
    if (!savedSelectionRef.current) return;

    // Get current classes from selection
    const currentClassName = savedSelectionRef.current.className || "";

    // Get replacement info
    const replacementInfo = getReplacementInfo(currentClassName, className);

    // Merge classes intelligently (replaces same-category classes)
    const mergedClasses = mergeClasses(currentClassName, className);

    dispatch(
      EditorActions.setCurrentSelection({
        ...savedSelectionRef.current,
        formats: { bold: false, italic: false, underline: false, strikethrough: false, code: false },
      })
    );

    requestAnimationFrame(() => {
      dispatch(EditorActions.applyCustomClass(mergedClasses));

      // Show appropriate toast message
      if (
        replacementInfo.willReplace &&
        replacementInfo.replacedClasses.length > 0
      ) {
        toast({
          title: "Class Replaced",
          description: `Replaced "${replacementInfo.replacedClasses.join(
            ", "
          )}" with "${className}"`,
        });
      } else {
        toast({
          title: "Custom Class Applied",
          description: `Applied class: ${className}`,
        });
      }

      setCustomClassPopoverOpen(false);
      setSearchQuery("");
    });
  };

  // Filter classes for custom class popover
  const filteredClasses = devMode
    ? searchQuery
      ? tailwindClasses
          .map((group) => ({
            ...group,
            classes: group.classes.filter((cls) =>
              cls.toLowerCase().includes(searchQuery.toLowerCase())
            ),
          }))
          .filter((group) => group.classes.length > 0)
      : tailwindClasses
    : searchQuery
    ? searchUserFriendlyClasses(searchQuery)
    : getUserFriendlyClasses();

  // Use savedSelection if current selection is lost but popovers are open
  const activeSelection = selection || savedSelectionRef.current;

  if (!activeSelection && !linkPopoverOpen && !customClassPopoverOpen && !aiMenuOpen) {
    return null;
  }

  const { formats } = activeSelection || {
    formats: { bold: false, italic: false, underline: false, strikethrough: false, code: false },
  };
  const hasExistingLink = Boolean(savedSelectionRef.current?.href);



  return (
    <AnimatePresence mode="wait">
      {position &&
        isVisible && ( // Keep toolbar visible if either popover is open, even if selection is lost
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            ref={toolbarRef}
            role="toolbar"
            aria-label="Text formatting"
            aria-orientation="horizontal"
            className={cn(
              "fixed z-[200] duration-200",
              "inline-flex items-stretch rounded-lg shadow-md pointer-events-auto",
              "bg-popover/95 backdrop-blur-sm border border-border/50",
              "text-sm leading-tight"
            )}
            style={{
              top: `${position.top}px`,
              left: `${position.left}px`,
              height: "40px",
              padding: "4px",
            }}
          >
            {/* Text Type Selector */}
            <ElementSelector
              value={activeSelection?.elementType as ElementType}
              onValueChange={(value) => onTypeChange(value)}
              variant="compact"
              showDescription={false}
              showIcon={false}
              className="mr-2"
            />

            {/* Format Buttons */}
            <FormatButtons formats={formats} onFormat={onFormat} size="sm" />

            <Separator
              orientation="vertical"
              className="h-6 my-auto mx-1.5 bg-border/50"
            />

            {/* Color Picker */}
            <ColorPickerComponent
              disabled={!activeSelection}
              onColorSelect={onColorSelect}
              selectedColor={selectedColor}
            />

            {/* Font Size Picker */}
            <FontSizePicker
              disabled={!activeSelection}
              onFontSizeSelect={onFontSizeSelect}
              currentFontSize={activeSelection?.styles?.fontSize || undefined}
            />

            <Separator
              orientation="vertical"
              className="h-6 my-auto mx-1.5 bg-border/50"
            />

            {/* Link Popover */}
            <Popover open={linkPopoverOpen} onOpenChange={setLinkPopoverOpen}>
              <PopoverTrigger asChild>
                <Button
                  variant="ghost"
                  size="icon"
                  aria-label={hasExistingLink ? "Edit link" : "Insert link"}
                  aria-haspopup="dialog"
                  aria-expanded={linkPopoverOpen}
                  className={cn(
                    "h-7 px-2 rounded-md hover:bg-accent/50 transition-colors duration-75 gap-1.5 min-w-fit",
                    hasExistingLink && "text-blue-500"
                  )}
                  onMouseDown={(e) => {
                    e.preventDefault();
                    e.stopPropagation();
                  }}
                >
                  <LinkIcon className="h-4 w-4" />
                </Button>
              </PopoverTrigger>
              <PopoverContent
                className="w-80"
                align="start"
                {...{ onOpenAutoFocus: (e: any) => e.preventDefault() }}
                {...{ onInteractOutside: (e: any) => {
                  const target = e.target as HTMLElement;
                  if (toolbarRef.current?.contains(target)) {
                    e.preventDefault();
                  }
                }}}
              >
                <LinkPopoverContent
                  hrefInput={hrefInput}
                  setHrefInput={setHrefInput}
                  hasExistingLink={hasExistingLink}
                  selectedText={savedSelectionRef.current?.text || ""}
                  onApply={handleApplyLink}
                  onRemove={handleRemoveLink}
                />
              </PopoverContent>
            </Popover>

            {/* Custom Class Popover */}
            <Popover
              open={customClassPopoverOpen}
              onOpenChange={setCustomClassPopoverOpen}
            >
              <PopoverTrigger asChild>
                <Button
                  variant="ghost"
                  size="icon"
                  aria-label="Apply custom class"
                  aria-haspopup="dialog"
                  aria-expanded={customClassPopoverOpen}
                  className="h-7 px-2 rounded-md hover:bg-accent/50 transition-colors duration-75 gap-1.5 min-w-fit"
                  onMouseDown={(e) => {
                    e.preventDefault();
                    e.stopPropagation();
                  }}
                >
                  <div className="flex items-center justify-center w-6 h-6 text-center font-medium rounded-md border border-border/50">
                    <Type className="h-3.5 w-3.5" />
                  </div>
                </Button>
              </PopoverTrigger>
              <PopoverContent
                className="w-96"
                align="start"
                {...{ onOpenAutoFocus: (e: any) => e.preventDefault() }}
                {...{ onInteractOutside: (e: any) => {
                  const target = e.target as HTMLElement;
                  if (toolbarRef.current?.contains(target)) {
                    e.preventDefault();
                  }
                }}}
              >
                <CustomClassPopoverContent
                  searchQuery={searchQuery}
                  setSearchQuery={setSearchQuery}
                  devMode={devMode}
                  setDevMode={setDevMode}
                  filteredClasses={filteredClasses}
                  onApplyClass={handleApplyCustomClass}
                />
              </PopoverContent>
            </Popover>

            <Separator
              orientation="vertical"
              className="h-6 my-auto mx-1.5 bg-border/50"
            />

            {/* AI Selection Menu */}
            {aiProvider && activeSelection && (
              <Popover open={aiMenuOpen} onOpenChange={setAiMenuOpen}>
                <PopoverTrigger asChild>
                  <Button
                    variant="ghost"
                    size="icon"
                    aria-label="AI edit"
                    aria-haspopup="dialog"
                    aria-expanded={aiMenuOpen}
                    className="h-7 px-2 rounded-md hover:bg-accent/50 transition-colors duration-75 gap-1.5 min-w-fit"
                    onMouseDown={(e) => {
                      e.preventDefault();
                      e.stopPropagation();
                    }}
                  >
                    <Sparkles className="h-3.5 w-3.5" />
                  </Button>
                </PopoverTrigger>
                <PopoverContent
                  className="w-auto p-0 border-0 bg-transparent shadow-none"
                  align="end"
                  side="bottom"
                  sideOffset={8}
                  {...{ onOpenAutoFocus: (e: any) => e.preventDefault() }}
                  {...{ onInteractOutside: (e: any) => {
                    const target = e.target as HTMLElement;
                    if (toolbarRef.current?.contains(target)) {
                      e.preventDefault();
                    }
                  }}}
                >
                  <AISelectionMenu
                    selection={activeSelection}
                    provider={aiProvider}
                    defaultSystemPrompt={aiSystemPrompt}
                    onClose={() => setAiMenuOpen(false)}
                  />
                </PopoverContent>
              </Popover>
            )}
          </motion.div>
        )}
    </AnimatePresence>
  );
}

"use client";

import React, { useState, useRef } from "react";
import {
  ContainerNode,
  StructuralNode,
  TextNode,
  type EditorNode,
} from "./types";
import { Button } from "@/registry/new-york-v4/ui/button";
import { Plus, X, GripVertical, Trash2 } from "lucide-react";
import { cn } from "@/lib/utils";

interface TableBuilderProps {
  node: ContainerNode;
  onUpdate: (id: string, updates: Partial<EditorNode>) => void;
  readOnly?: boolean;
  onBlockDragStart?: (nodeId: string) => void;
  onDelete?: (nodeId?: string) => void;
}

export function TableBuilder({
  node,
  onUpdate,
  readOnly = false,
  onBlockDragStart,
  onDelete,
}: TableBuilderProps) {
  const [hoveredCol, setHoveredCol] = useState<number | null>(null);
  const [hoveredRow, setHoveredRow] = useState<number | null>(null);
  const [showColControls, setShowColControls] = useState(false);
  const [showRowControls, setShowRowControls] = useState(false);
  const [isHovering, setIsHovering] = useState(false);
  const [columnWidths, setColumnWidths] = useState<number[]>([]);
  const [resizingCol, setResizingCol] = useState<number | null>(null);
  const [startX, setStartX] = useState(0);
  const [startWidth, setStartWidth] = useState(0);
  const [draggingCol, setDraggingCol] = useState<number | null>(null);
  const [draggingRow, setDraggingRow] = useState<number | null>(null);
  const [dragOverCol, setDragOverCol] = useState<number | null>(null);
  const [dragOverRow, setDragOverRow] = useState<number | null>(null);
  const tableRef = useRef<HTMLTableElement>(null);

  // Helper to find table structure
  const table = node.children.find((child) => child.type === "table") as
    | StructuralNode
    | undefined;
  if (!table) return null;

  const thead = table.children.find((child) => child.type === "thead") as
    | StructuralNode
    | undefined;
  const tbody = table.children.find((child) => child.type === "tbody") as
    | StructuralNode
    | undefined;

  const headerRow = thead?.children[0] as StructuralNode | undefined;
  const bodyRows = tbody?.children as StructuralNode[] | undefined;

  const numCols = headerRow?.children.length || 0;

  // Initialize column widths if not set (using 'auto' for natural sizing)
  React.useEffect(() => {
    if (columnWidths.length === 0 && numCols > 0) {
      // Start with auto-sizing (0 means auto)
      setColumnWidths(Array(numCols).fill(0));
    }
  }, [numCols, columnWidths.length]);

  // Handle resize start
  const handleResizeStart = (colIndex: number, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    // Get actual width from DOM if it's auto-sized (0)
    const actualWidth =
      columnWidths[colIndex] ||
      tableRef.current
        ?.querySelector(`th:nth-child(${colIndex + 1})`)
        ?.getBoundingClientRect().width ||
      150;

    setResizingCol(colIndex);
    setStartX(e.clientX);
    setStartWidth(actualWidth);
  };

  // Handle resize move
  React.useEffect(() => {
    if (resizingCol === null) return;

    const handleMouseMove = (e: MouseEvent) => {
      const diff = e.clientX - startX;
      const newWidth = Math.max(80, startWidth + diff); // Minimum width 80px

      setColumnWidths((prev) => {
        const newWidths = [...prev];
        newWidths[resizingCol] = newWidth;
        return newWidths;
      });
    };

    const handleMouseUp = () => {
      setResizingCol(null);
    };

    document.addEventListener("mousemove", handleMouseMove);
    document.addEventListener("mouseup", handleMouseUp);

    return () => {
      document.removeEventListener("mousemove", handleMouseMove);
      document.removeEventListener("mouseup", handleMouseUp);
    };
  }, [resizingCol, startX, startWidth]);

  // Column drag handlers
  const handleColumnDragStart = (colIndex: number, e: React.DragEvent) => {
    if (readOnly) return;
    e.stopPropagation();
    setDraggingCol(colIndex);
    e.dataTransfer.effectAllowed = "move";
  };

  const handleColumnDragOver = (colIndex: number, e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (draggingCol === null || draggingCol === colIndex) return;
    setDragOverCol(colIndex);
  };

  const handleColumnDrop = (targetColIndex: number, e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (draggingCol === null || draggingCol === targetColIndex || !headerRow || !bodyRows) return;

    // Swap columns in header
    const newHeaderChildren = [...headerRow.children];
    const [draggedHeader] = newHeaderChildren.splice(draggingCol, 1);
    newHeaderChildren.splice(targetColIndex, 0, draggedHeader);

    const newHeaderRow: StructuralNode = {
      ...headerRow,
      children: newHeaderChildren,
    };

    // Swap columns in all body rows
    const newBodyRows = bodyRows.map((row) => {
      const newRowChildren = [...row.children];
      const [draggedCell] = newRowChildren.splice(draggingCol, 1);
      newRowChildren.splice(targetColIndex, 0, draggedCell);
      return {
        ...row,
        children: newRowChildren,
      };
    });

    // Swap column widths
    const newWidths = [...columnWidths];
    const [draggedWidth] = newWidths.splice(draggingCol, 1);
    newWidths.splice(targetColIndex, 0, draggedWidth);
    setColumnWidths(newWidths);

    // Update table
    const newThead: StructuralNode = {
      ...thead!,
      children: [newHeaderRow],
    };

    const newTbody: StructuralNode = {
      ...tbody!,
      children: newBodyRows,
    };

    const newTable: StructuralNode = {
      ...table,
      children: [newThead, newTbody],
    };

    onUpdate(node.id, {
      children: [newTable],
    });

    setDraggingCol(null);
    setDragOverCol(null);
  };

  const handleColumnDragEnd = () => {
    setDraggingCol(null);
    setDragOverCol(null);
  };

  // Row drag handlers
  const handleRowDragStart = (rowIndex: number, e: React.DragEvent) => {
    if (readOnly) return;
    e.stopPropagation();
    setDraggingRow(rowIndex);
    e.dataTransfer.effectAllowed = "move";
  };

  const handleRowDragOver = (rowIndex: number, e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (draggingRow === null || draggingRow === rowIndex) return;
    setDragOverRow(rowIndex);
  };

  const handleRowDrop = (targetRowIndex: number, e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (draggingRow === null || draggingRow === targetRowIndex || !bodyRows) return;

    // Reorder rows
    const newBodyRows = [...bodyRows];
    const [draggedRow] = newBodyRows.splice(draggingRow, 1);
    newBodyRows.splice(targetRowIndex, 0, draggedRow);

    const newTbody: StructuralNode = {
      ...tbody!,
      children: newBodyRows,
    };

    const newTable: StructuralNode = {
      ...table,
      children: [thead!, newTbody],
    };

    onUpdate(node.id, {
      children: [newTable],
    });

    setDraggingRow(null);
    setDragOverRow(null);
  };

  const handleRowDragEnd = () => {
    setDraggingRow(null);
    setDragOverRow(null);
  };

  const addColumn = () => {
    if (!headerRow || !bodyRows || readOnly) return;

    // Add th to header
    const newHeader: StructuralNode = {
      ...headerRow,
      children: [
        ...headerRow.children,
        {
          id: `th-${Date.now()}`,
          type: "th" as const,
          content: `Column ${numCols + 1}`,
          attributes: {},
        } as TextNode,
      ],
    };

    // Add td to each body row
    const newBodyRows = bodyRows.map((row, idx) => ({
      ...row,
      children: [
        ...row.children,
        {
          id: `td-${Date.now()}-${idx}`,
          type: "td" as const,
          content: "",
          attributes: {},
        } as TextNode,
      ],
    }));

    const newThead: StructuralNode = {
      ...thead!,
      children: [newHeader],
    };

    const newTbody: StructuralNode = {
      ...tbody!,
      children: newBodyRows,
    };

    const newTable: StructuralNode = {
      ...table,
      children: [newThead, newTbody],
    };

    onUpdate(node.id, {
      children: [newTable],
    });

    // Add width for new column (default 150px for empty columns)
    setColumnWidths((prev) => [...prev, 150]);
  };

  const addRow = () => {
    if (!bodyRows || !headerRow || readOnly) return;

    const newCells = Array.from({ length: numCols }, (_, idx) => ({
      id: `td-${Date.now()}-${idx}`,
      type: "td" as const,
      content: "",
      attributes: {},
    }));

    const newRow: StructuralNode = {
      id: `tr-${Date.now()}`,
      type: "tr",
      children: newCells,
      attributes: {},
    };

    const newTbody: StructuralNode = {
      ...tbody!,
      children: [...bodyRows, newRow],
    };

    const newTable: StructuralNode = {
      ...table,
      children: [thead!, newTbody],
    };

    onUpdate(node.id, {
      children: [newTable],
    });
  };

  const removeColumn = (colIndex: number) => {
    if (!headerRow || !bodyRows || readOnly || numCols <= 1) return;

    const newHeader: StructuralNode = {
      ...headerRow,
      children: headerRow.children.filter((_, idx) => idx !== colIndex),
    };

    const newBodyRows = bodyRows.map((row) => ({
      ...row,
      children: row.children.filter((_, idx) => idx !== colIndex),
    }));

    const newThead: StructuralNode = {
      ...thead!,
      children: [newHeader],
    };

    const newTbody: StructuralNode = {
      ...tbody!,
      children: newBodyRows,
    };

    const newTable: StructuralNode = {
      ...table,
      children: [newThead, newTbody],
    };

    onUpdate(node.id, {
      children: [newTable],
    });

    // Remove width for deleted column
    setColumnWidths((prev) => prev.filter((_, idx) => idx !== colIndex));
  };

  const removeRow = (rowIndex: number) => {
    if (!bodyRows || readOnly || bodyRows.length <= 1) return;

    const newBodyRows = bodyRows.filter((_, idx) => idx !== rowIndex);

    const newTbody: StructuralNode = {
      ...tbody!,
      children: newBodyRows,
    };

    const newTable: StructuralNode = {
      ...table,
      children: [thead!, newTbody],
    };

    onUpdate(node.id, {
      children: [newTable],
    });
  };

  const handleCellChange = (
    rowIndex: number,
    colIndex: number,
    content: string,
    isHeader: boolean
  ) => {
    if (readOnly) return;

    if (isHeader && headerRow) {
      const newHeader: StructuralNode = {
        ...headerRow,
        children: headerRow.children.map((cell, idx) =>
          idx === colIndex ? { ...cell, content } : cell
        ),
      };

      const newThead: StructuralNode = {
        ...thead!,
        children: [newHeader],
      };

      const newTable: StructuralNode = {
        ...table,
        children: [newThead, tbody!],
      };

      onUpdate(node.id, {
        children: [newTable],
      });
    } else if (bodyRows) {
      const newBodyRows = bodyRows.map((row, rIdx) => {
        if (rIdx === rowIndex) {
          return {
            ...row,
            children: row.children.map((cell, cIdx) =>
              cIdx === colIndex ? { ...cell, content } : cell
            ),
          };
        }
        return row;
      });

      const newTbody: StructuralNode = {
        ...tbody!,
        children: newBodyRows,
      };

      const newTable: StructuralNode = {
        ...table,
        children: [thead!, newTbody],
      };

      onUpdate(node.id, {
        children: [newTable],
      });
    }
  };

  // Drag handlers for the entire table
  const handleTableDragStart = (e: React.DragEvent) => {
    if (readOnly || !onBlockDragStart) return;
    e.stopPropagation();
    e.dataTransfer.effectAllowed = "move";
    e.dataTransfer.setData("text/plain", node.id);
    e.dataTransfer.setData(
      "application/json",
      JSON.stringify({
        nodeId: node.id,
        type: "table",
      })
    );
    onBlockDragStart(node.id);
  };

  const handleTableDragEnd = () => {
    // Cleanup if needed
  };

  return (
    <div
      className="relative group/table"
      style={{
        paddingLeft: readOnly ? "0" : "28px",
        marginLeft: readOnly ? "0" : "-28px",
      }}
      onMouseEnter={() => {
        if (!readOnly) {
          setShowColControls(true);
          setShowRowControls(true);
          setIsHovering(true);
        }
      }}
      onMouseLeave={() => {
        setShowColControls(false);
        setShowRowControls(false);
        setHoveredCol(null);
        setHoveredRow(null);
        setIsHovering(false);
      }}
    >
      {/* Drag Handle for entire table */}
      {!readOnly && isHovering && onBlockDragStart && (
        <div
          draggable
          onDragStart={handleTableDragStart}
          onDragEnd={handleTableDragEnd}
          className="absolute left-1 top-8 cursor-grab active:cursor-grabbing opacity-0 group-hover/table:opacity-100 transition-opacity duration-200 z-20"
          onClick={(e) => e.stopPropagation()}
          onMouseDown={(e) => e.stopPropagation()}
        >
          <GripVertical
            className="h-4 w-4 text-muted-foreground hover:text-foreground transition-colors duration-200"
            strokeWidth={1.5}
          />
        </div>
      )}

      {/* Delete Button for entire table */}
      {!readOnly && isHovering && onDelete && (
        <div className="absolute right-0 top-2 z-20 opacity-0 group-hover/table:opacity-100 transition-opacity duration-200">
          <Button
            size="icon"
            variant="destructive"
            className="h-6 w-6"
            onClick={() => onDelete(node.id)}
            title="Delete table"
          >
            <Trash2 className="h-3 w-3" />
          </Button>
        </div>
      )}

      <div className="relative w-fit mx-auto">
      {/* Column controls - top */}
      {showColControls && (
        <div className="absolute top-0 left-8 right-0 flex justify-center gap-1 z-10">
          {Array.from({ length: numCols }).map((_, idx) => (
            <div
              key={idx}
              className="flex flex-col items-center"
              style={{ width: `${100 / numCols}%` }}
              onMouseEnter={() => setHoveredCol(idx)}
              onMouseLeave={() => setHoveredCol(null)}
            >
              {hoveredCol === idx && numCols > 1 && (
                <Button
                  size="icon"
                  variant="destructive"
                  className="h-5 w-5"
                  onClick={() => removeColumn(idx)}
                  title="Remove column"
                >
                  <X className="h-3 w-3" />
                </Button>
              )}
            </div>
          ))}
          <Button
            size="icon"
            variant="secondary"
            className="h-6 w-6 ml-1"
            onClick={addColumn}
            title="Add column"
          >
            <Plus className="h-3 w-3" />
          </Button>
        </div>
      )}

      {/* Row controls - left side */}
      {showRowControls && bodyRows && (
        <div className="absolute -left-2 top-0 bottom-0 flex flex-col justify-start gap-1 z-10 pt-10">
          {bodyRows.map((_, idx) => (
            <div
              key={idx}
              className="flex items-center justify-center"
              style={{ height: "40px" }}
              onMouseEnter={() => setHoveredRow(idx)}
              onMouseLeave={() => setHoveredRow(null)}
            >
              {hoveredRow === idx && bodyRows.length > 1 && (
                <Button
                  size="icon"
                  variant="destructive"
                  className="h-4 w-4"
                  onClick={() => removeRow(idx)}
                  title="Remove row"
                >
                  <X className="h-2.5 w-2.5" />
                </Button>
              )}
            </div>
          ))}
          <Button
            size="icon"
            variant="secondary"
            className="h-4 w-4 mt-1"
            onClick={addRow}
            title="Add row"
          >
            <Plus className="h-2.5 w-2.5" />
          </Button>
        </div>
      )}

      <div className="relative w-fit mx-auto py-5 overflow-x-auto">
        {/* Table */}
        <table
          ref={tableRef}
          className="border-collapse border border-border"
          style={{ width: "auto" }}
        >
           <thead>
             {headerRow && (
               <tr>
                 {headerRow.children.map((cell, colIdx) => (
                   <th
                     key={cell.id}
                     className={cn(
                       "border border-border bg-muted/50 p-2 font-semibold text-left relative group/cell",
                       hoveredCol === colIdx && "bg-muted",
                       dragOverCol === colIdx && draggingCol !== colIdx && "bg-primary/20"
                     )}
                     style={
                       columnWidths[colIdx]
                         ? {
                             width: columnWidths[colIdx],
                             minWidth: columnWidths[colIdx],
                             maxWidth: columnWidths[colIdx],
                           }
                         : {
                             whiteSpace: "nowrap",
                           }
                     }
                     draggable={!readOnly}
                     onDragStart={(e) => handleColumnDragStart(colIdx, e)}
                     onDragOver={(e) => handleColumnDragOver(colIdx, e)}
                     onDrop={(e) => handleColumnDrop(colIdx, e)}
                     onDragEnd={handleColumnDragEnd}
                   >
                     <div className="flex items-center gap-1">
                       {/* Drag handle for column */}
                       {!readOnly && (
                         <div
                           className="opacity-0 group-hover/cell:opacity-100 transition-opacity cursor-grab active:cursor-grabbing"
                           onMouseDown={(e) => e.stopPropagation()}
                         >
                           <GripVertical className="h-3 w-3 text-muted-foreground" />
                         </div>
                       )}

                      <input
                        type="text"
                        value={(cell as TextNode).content || ""}
                        onChange={(e) =>
                          handleCellChange(0, colIdx, e.target.value, true)
                        }
                        onKeyDown={(e) => {
                          if (e.key === "Backspace" && !(cell as TextNode).content && numCols > 1) {
                            e.preventDefault();
                            removeColumn(colIdx);
                          }
                        }}
                        readOnly={readOnly}
                        className="w-full bg-transparent border-none outline-none focus:outline-none focus:ring-0"
                        placeholder={`Column ${colIdx + 1}`}
                      />
                     </div>

                     {/* Resize handle */}
                     {!readOnly && (
                       <div
                         className={cn(
                           "absolute right-0 top-0 bottom-0 w-1 cursor-col-resize hover:bg-primary/50 transition-colors",
                           resizingCol === colIdx && "bg-primary"
                         )}
                         onMouseDown={(e) => handleResizeStart(colIdx, e)}
                         style={{ userSelect: "none" }}
                       >
                         <div className="absolute right-0 top-1/2 -translate-y-1/2 -translate-x-1/2 opacity-0 hover:opacity-100 transition-opacity">
                           <GripVertical className="h-4 w-4 text-muted-foreground" />
                         </div>
                       </div>
                     )}
                   </th>
                 ))}
               </tr>
             )}
           </thead>
           <tbody>
             {bodyRows?.map((row, rowIdx) => (
               <tr
                 key={row.id}
                 className={cn(
                   "group/row",
                   hoveredRow === rowIdx && "bg-muted/30",
                   dragOverRow === rowIdx && draggingRow !== rowIdx && "bg-primary/20"
                 )}
                 draggable={!readOnly}
                 onDragStart={(e) => handleRowDragStart(rowIdx, e)}
                 onDragOver={(e) => handleRowDragOver(rowIdx, e)}
                 onDrop={(e) => handleRowDrop(rowIdx, e)}
                 onDragEnd={handleRowDragEnd}
               >
                 {row.children.map((cell, colIdx) => (
                   <td
                     key={cell.id}
                     className={cn(
                       "border border-border p-2 relative",
                       hoveredCol === colIdx && "bg-muted/50"
                     )}
                     style={
                       columnWidths[colIdx]
                         ? {
                             width: columnWidths[colIdx],
                             minWidth: columnWidths[colIdx],
                             maxWidth: columnWidths[colIdx],
                           }
                         : {
                             whiteSpace: "nowrap",
                           }
                     }
                   >
                     <div className="flex items-center gap-1">
                       {/* Drag handle for row (only show in first column) */}
                       {!readOnly && colIdx === 0 && (
                         <div
                           className="opacity-0 group-hover/row:opacity-100 transition-opacity cursor-grab active:cursor-grabbing"
                           onMouseDown={(e) => e.stopPropagation()}
                         >
                           <GripVertical className="h-3 w-3 text-muted-foreground" />
                         </div>
                       )}

                       <input
                         type="text"
                         value={(cell as TextNode).content || ""}
                         onChange={(e) =>
                           handleCellChange(rowIdx, colIdx, e.target.value, false)
                         }
                         readOnly={readOnly}
                         className="w-full bg-transparent border-none outline-none focus:outline-none focus:ring-0"
                         placeholder="Enter text"
                       />
                     </div>
                   </td>
                 ))}
               </tr>
             ))}
           </tbody>
        </table>
      </div>
      </div>
    </div>
  );
}

"use client";

import React, { useState } from "react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/registry/new-york-v4/ui/dialog";
import { Button } from "@/registry/new-york-v4/ui/button";
import { Input } from "@/registry/new-york-v4/ui/input";
import { Label } from "@/registry/new-york-v4/ui/label";
import { Textarea } from "@/registry/new-york-v4/ui/textarea";
import { Checkbox } from "@/registry/new-york-v4/ui/checkbox";
import { Table, AlertCircle } from "lucide-react";
import { StructuralNode } from "./types";
import { parseMarkdownTable, isMarkdownTable } from "./utils/markdown-table-parser";

interface TableDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onCreateTable: (rows: number, cols: number) => void;
  onImportMarkdown: (table: StructuralNode) => void;
}

export function TableDialog({
  open,
  onOpenChange,
  onCreateTable,
  onImportMarkdown,
}: TableDialogProps) {
  const [rows, setRows] = useState(3);
  const [cols, setCols] = useState(3);
  const [useMarkdown, setUseMarkdown] = useState(false);
  const [markdownText, setMarkdownText] = useState("");
  const [error, setError] = useState<string | null>(null);

  const handleCreate = () => {
    if (useMarkdown) {
      // Parse and import markdown
      const result = parseMarkdownTable(markdownText);
      if (result.success && result.table) {
        onImportMarkdown(result.table);
        onOpenChange(false);
        // Reset
        setMarkdownText("");
        setUseMarkdown(false);
        setError(null);
      } else {
        setError(result.error || "Failed to parse markdown table");
      }
    } else {
      // Create empty table
      if (rows > 0 && cols > 0 && rows <= 20 && cols <= 10) {
        onCreateTable(rows, cols);
        onOpenChange(false);
        // Reset to defaults
        setRows(3);
        setCols(3);
        setError(null);
      }
    }
  };

  const handleMarkdownChange = (value: string) => {
    setMarkdownText(value);
    setError(null);
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[425px]">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Table className="h-5 w-5" />
            Create Table
          </DialogTitle>
          <DialogDescription>
            Create a new table or import from markdown
          </DialogDescription>
        </DialogHeader>
        <div className="grid gap-4 py-4">
          {/* Markdown checkbox */}
          <div className="flex items-center space-x-2">
            <Checkbox
              id="markdown"
              checked={useMarkdown}
              onCheckedChange={(checked) => {
                setUseMarkdown(checked as boolean);
                setError(null);
              }}
            />
            <Label
              htmlFor="markdown"
              className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70 cursor-pointer"
            >
              I have a markdown table
            </Label>
          </div>

          {useMarkdown ? (
            <>
              {/* Markdown input */}
              <div className="grid gap-2">
                <Label htmlFor="markdown-input">
                  Paste Markdown Table
                </Label>
                <Textarea
                  id="markdown-input"
                  placeholder={`| Header 1 | Header 2 | Header 3 |
|----------|----------|----------|
| Cell 1   | Cell 2   | Cell 3   |
| Cell 4   | Cell 5   | Cell 6   |`}
                  value={markdownText}
                  onChange={(e) => handleMarkdownChange(e.target.value)}
                  className="font-mono text-xs max-h-[400px] min-h-[150px]"
                />
                <div className="text-xs text-muted-foreground">
                  Paste your markdown table above. Must include header and separator rows.
                </div>
              </div>

              {/* Error message */}
              {error && (
                <div className="flex items-start gap-2 text-xs text-destructive bg-destructive/10 p-2 rounded">
                  <AlertCircle className="h-4 w-4 mt-0.5 flex-shrink-0" />
                  <span>{error}</span>
                </div>
              )}
            </>
          ) : (
            <>
              {/* Manual input */}
              <div className="grid grid-cols-4 items-center gap-4">
                <Label htmlFor="rows" className="text-right">
                  Rows
                </Label>
                <Input
                  id="rows"
                  type="number"
                  min="1"
                  max="20"
                  value={rows}
                  onChange={(e) => setRows(parseInt(e.target.value) || 1)}
                  className="col-span-3"
                />
              </div>
              <div className="grid grid-cols-4 items-center gap-4">
                <Label htmlFor="cols" className="text-right">
                  Columns
                </Label>
                <Input
                  id="cols"
                  type="number"
                  min="1"
                  max="10"
                  value={cols}
                  onChange={(e) => setCols(parseInt(e.target.value) || 1)}
                  className="col-span-3"
                />
              </div>
              <div className="text-xs text-muted-foreground px-1">
                Maximum: 20 rows × 10 columns
              </div>
            </>
          )}
        </div>
        <div className="flex justify-end gap-2">
          <Button
            variant="outline"
            onClick={() => onOpenChange(false)}
          >
            Cancel
          </Button>
          <Button
            onClick={handleCreate}
            disabled={
              useMarkdown
                ? !markdownText.trim() || !isMarkdownTable(markdownText)
                : rows <= 0 || cols <= 0 || rows > 20 || cols > 10
            }
          >
            {useMarkdown ? "Import Table" : "Create Table"}
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import React, { useState, useRef, useEffect } from "react";
import { Button } from "@/registry/new-york-v4/ui/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/registry/new-york-v4/ui/dialog";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/registry/new-york-v4/ui/alert-dialog";
import { cn } from "@/lib/utils";
import {
  FileText,
  Sparkles,
  BookOpen,
  Briefcase,
  User,
  Zap,
  Plus,
  Loader2,
} from "lucide-react";
import { getAllTemplateMetadata, getTemplateById, type TemplateMetadata } from "./templates";
import type { EditorState } from "./types";

interface TemplateSwitcherButtonProps {
  onTemplateChange: (state: EditorState) => void;
  currentState: EditorState;
}

// Category icons
const categoryIcons: Record<TemplateMetadata["category"], React.ComponentType<{ className?: string }>> = {
  productivity: Zap,
  creative: Sparkles,
  business: Briefcase,
  personal: User,
};


export function TemplateSwitcherButton({
  onTemplateChange,
  currentState,
}: TemplateSwitcherButtonProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [isHovered, setIsHovered] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState<TemplateMetadata["category"] | "all">("all");
  const [showConfirmDialog, setShowConfirmDialog] = useState(false);
  const [pendingTemplateId, setPendingTemplateId] = useState<string | null>(null);
  const [isApplying, setIsApplying] = useState(false);
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  const allTemplates = getAllTemplateMetadata();

  // Reset scroll position when category changes or dialog opens
  useEffect(() => {
    if (scrollContainerRef.current && isOpen) {
      scrollContainerRef.current.scrollTop = 0;
    }
  }, [selectedCategory, isOpen]);

  const filteredTemplates = selectedCategory === "all" 
    ? allTemplates 
    : allTemplates.filter(t => t.category === selectedCategory);

  const categories: Array<{ value: "all" | TemplateMetadata["category"]; label: string }> = [
    { value: "all", label: "All Templates" },
    { value: "productivity", label: "Productivity" },
    { value: "creative", label: "Creative" },
    { value: "business", label: "Business" },
    { value: "personal", label: "Personal" },
  ];

  // Check if there's existing content
  const hasExistingContent = () => {
    const container = currentState.current;
    if (!container || !container.children || container.children.length === 0) {
      return false;
    }

    // Check if there's any non-empty content
    return container.children.some((child) => {
      if ('content' in child && child.content && child.content.trim() !== '') {
        return true;
      }
      if ('children' in child && child.children && child.children.length > 0) {
        return true;
      }
      return false;
    });
  };

  const handleTemplateSelect = (templateId: string) => {
    // Set the pending template ID immediately for UI feedback
    setPendingTemplateId(templateId);

    // Check if there's existing content
    if (hasExistingContent()) {
      setShowConfirmDialog(true);
      return;
    }

    // No existing content, proceed directly
    applyTemplate(templateId);
  };

  const applyTemplate = async (templateId: string) => {
    const template = getTemplateById(templateId);
    if (!template) return;

    setIsApplying(true);

    // Small delay for smoother UX
    await new Promise(resolve => setTimeout(resolve, 150));

    // Create completely fresh state with template content
    // This ensures all editor state is properly reset
    const newState: EditorState = {
      version: "1.0.0",
      current: {
        id: "root",
        type: "container",
        children: template.content,
        attributes: {},
      },
      undoStack: [],
      redoStack: [],
      activeNodeId: null,
      hasSelection: false,
      selectionKey: 0,
      currentSelection: null,
      selectedBlocks: new Set<string>(),
      coverImage: template.coverImage || null,
      metadata: {
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
        templateId: template.metadata.id,
        templateName: template.metadata.name,
      },
    };

    // Apply the new state
    onTemplateChange(newState);

    // Close dialogs
    setIsOpen(false);
    setShowConfirmDialog(false);
    setPendingTemplateId(null);
    setIsApplying(false);

    // Force a complete cleanup and re-render
    setTimeout(() => {
      // Clear any browser selection and focus
      const selection = window.getSelection();
      if (selection) {
        selection.removeAllRanges();
      }

      // Remove focus from any active element
      const activeElement = document.activeElement as HTMLElement;
      if (activeElement && activeElement.blur) {
        activeElement.blur();
      }

      // Force scroll to top to show new template from the beginning
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }, 100);
  };

  const handleConfirmReplace = () => {
    if (pendingTemplateId) {
      applyTemplate(pendingTemplateId);
    }
  };

  const handleCancelReplace = () => {
    setShowConfirmDialog(false);
    setPendingTemplateId(null);
  };

  return (
    <>
      {/* Floating Button */}
      <div className="fixed bottom-6 left-6 z-50">
        <Button
          onClick={() => {
            setIsOpen(true);
            setSelectedCategory("all"); // Reset to all templates when opening
          }}
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
          className={cn(
            "h-12 w-12 rounded-full shadow-lg transition-all duration-200",
            "bg-primary hover:bg-primary/90",
            "hover:shadow-xl hover:scale-105",
            "group"
          )}
          size="icon"
          title="Switch Template"
        >
          <Plus className={cn(
            "h-5 w-5 transition-transform duration-200",
            isHovered && "scale-110"
          )} />
        </Button>
      </div>

      {/* Template Selector Dialog */}
      <Dialog open={isOpen} onOpenChange={setIsOpen}>
        <DialogContent className="max-w-6xl min-w-fit max-h-[85vh] overflow-hidden flex flex-col backdrop-blur-xl bg-background/95 border-border/50 shadow-2xl">
          <DialogHeader className="space-y-3 pb-6">
            <DialogTitle className="flex items-center gap-3 text-2xl">
              <div className="p-2 rounded-lg bg-primary/10">
                <FileText className="h-6 w-6 text-primary" />
              </div>
              Choose a Template
            </DialogTitle>
            <DialogDescription className="text-base">
              Select a template to get started quickly with pre-built layouts and content
            </DialogDescription>
          </DialogHeader>

          {/* Category Filter */}
          <div className="flex flex-wrap gap-2 pb-6 border-b border-border/50">
            {categories.map((category) => {
              const Icon = category.value === "all" ? BookOpen : categoryIcons[category.value as TemplateMetadata["category"]];
              const isActive = selectedCategory === category.value;

              return (
                <Button
                  key={category.value}
                  variant={isActive ? "default" : "outline"}
                  size="sm"
                  onClick={() => setSelectedCategory(category.value)}
                  className={cn(
                    "gap-2 transition-all duration-200",
                    isActive && "shadow-md scale-105"
                  )}
                >
                  <Icon className="h-4 w-4" />
                  {category.label}
                </Button>
              );
            })}
          </div>

          {/* Templates Grid */}
          <div ref={scrollContainerRef} className="flex-1 overflow-y-auto pt-4">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-5 px-1 pb-2">
              {filteredTemplates.map((template) => {
                const CategoryIcon = categoryIcons[template.category];
                const isCurrentlyApplying = isApplying && pendingTemplateId === template.id;

                return (
                  <button
                    key={template.id}
                    onClick={() => handleTemplateSelect(template.id)}
                    disabled={isApplying}
                    className={cn(
                      "group relative p-6 rounded-xl border border-border/60",
                      "hover:border-primary/60 hover:shadow-lg hover:shadow-primary/10",
                      "hover:bg-accent/30 hover:scale-[1.02]",
                      "transition-all duration-300 ease-out",
                      "backdrop-blur-sm bg-background/50",
                      "text-left",
                      isApplying && !isCurrentlyApplying && "opacity-50 cursor-not-allowed",
                      isCurrentlyApplying && "border-primary/80 shadow-lg shadow-primary/20 scale-[1.02]"
                    )}
                  >
                    {/* Category badge */}
                    <div className="absolute top-4 right-4">
                      <div className="p-2 rounded-lg bg-muted/80 backdrop-blur-sm border border-border/40">
                        <CategoryIcon className="h-4 w-4 text-muted-foreground" />
                      </div>
                    </div>

                    {/* Loading overlay */}
                    {isCurrentlyApplying && (
                      <div className="absolute inset-0 bg-background/80 backdrop-blur-sm rounded-xl flex items-center justify-center z-10">
                        <Loader2 className="h-8 w-8 animate-spin text-primary" />
                      </div>
                    )}

                    {/* Icon */}
                    <div className="text-5xl mb-4 transition-transform duration-200 group-hover:scale-110">
                      {template.icon}
                    </div>

                    {/* Template Info */}
                    <h3 className="font-semibold text-base mb-2 pr-10 group-hover:text-primary transition-colors duration-200">
                      {template.name}
                    </h3>
                    <p className="text-sm text-muted-foreground line-clamp-2 leading-relaxed">
                      {template.description}
                    </p>
                  </button>
                );
              })}
            </div>

            {filteredTemplates.length === 0 && (
              <div className="flex flex-col items-center justify-center py-16 text-muted-foreground">
                <div className="p-4 rounded-full bg-muted/50 mb-4">
                  <BookOpen className="h-12 w-12 opacity-50" />
                </div>
                <p className="text-base">No templates found in this category</p>
              </div>
            )}
          </div>
        </DialogContent>
      </Dialog>

      {/* Confirmation Dialog */}
      <AlertDialog open={showConfirmDialog} onOpenChange={setShowConfirmDialog}>
        <AlertDialogContent className="backdrop-blur-xl bg-background/95 border-border/50">
          <AlertDialogHeader>
            <AlertDialogTitle className="flex items-center gap-2">
              <div className="p-2 rounded-lg bg-destructive/10">
                <FileText className="h-5 w-5 text-destructive" />
              </div>
              Replace Existing Content?
            </AlertDialogTitle>
            <AlertDialogDescription className="text-base leading-relaxed">
              You have existing content in the editor. Applying this template will replace all current content. 
              <br />
              <span className="font-semibold text-destructive">This action cannot be undone.</span>
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel onClick={handleCancelReplace}>
              Cancel
