/**
 * Mina Rich Editor - Anthropic Provider
 *
 * Adapter for Anthropic's Messages API with streaming.
 * Parses `content_block_delta` SSE events to yield text chunks.
 *
 * Uses native `fetch()` and `ReadableStream` — no external dependencies.
 *
 * @packageDocumentation
 */

import type { AIProvider, AIStreamOptions } from './types';

/**
 * Configuration for the Anthropic provider.
 */
export interface AnthropicProviderOptions {
  /** Your Anthropic API key. Sent as `x-api-key` header. */
  apiKey: string;
  /** Model to use. @default `'claude-sonnet-4-20250514'` */
  model?: string;
  /** Base URL of the API. @default `'https://api.anthropic.com/v1'` */
  baseUrl?: string;
  /** Default sampling temperature. @default `0.7` */
  temperature?: number;
}

/**
 * Creates an {@link AIProvider} that talks to the Anthropic Messages API
 * using SSE streaming.
 *
 * @param options - Provider configuration.
 * @returns An `AIProvider` ready to be passed to the editor.
 *
 * @example
 * ```typescript
 * import { createAnthropicProvider } from 'mina-rich-editor';
 *
 * const provider = createAnthropicProvider({
 *   apiKey: process.env.NEXT_PUBLIC_ANTHROPIC_API_KEY!,
 *   model: 'claude-sonnet-4-20250514',
 * });
 * ```
 */
export function createAnthropicProvider(
  options: AnthropicProviderOptions,
): AIProvider {
  const {
    apiKey,
    model: defaultModel = 'claude-sonnet-4-20250514',
    baseUrl = 'https://api.anthropic.com/v1',
    temperature: defaultTemperature = 0.7,
  } = options;

  return {
    async *stream(
      prompt: string,
      streamOptions?: AIStreamOptions,
    ): AsyncIterable<string> {
      const model = streamOptions?.model ?? defaultModel;
      const temperature = streamOptions?.temperature ?? defaultTemperature;
      const maxTokens = streamOptions?.maxTokens ?? 4096;
      const systemPrompt = streamOptions?.systemPrompt;

      const body: Record<string, unknown> = {
        model,
        max_tokens: maxTokens,
        temperature,
        stream: true,
        messages: [{ role: 'user', content: prompt }],
      };
      if (systemPrompt) {
        body.system = systemPrompt;
      }

      const response = await fetch(`${baseUrl}/messages`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-api-key': apiKey,
          'anthropic-version': '2023-06-01',
          'anthropic-dangerous-direct-browser-access': 'true',
        },
        body: JSON.stringify(body),
      });

      if (!response.ok) {
        const errorText = await response.text().catch(() => 'Unknown error');
        throw new Error(
          `Anthropic API error (${response.status}): ${errorText}`,
        );
      }

      if (!response.body) {
        throw new Error('Anthropic API returned no response body');
      }

      const reader = response.body.getReader();
      const decoder = new TextDecoder();
      let buffer = '';

      try {
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          buffer += decoder.decode(value, { stream: true });
          const lines = buffer.split('\n');
          buffer = lines.pop() ?? '';

          for (const line of lines) {
            const trimmed = line.trim();
            if (!trimmed || !trimmed.startsWith('data: ')) continue;

            const data = trimmed.slice(6);

            try {
              const parsed = JSON.parse(data);

              // Anthropic streams `content_block_delta` events with text deltas
              if (
                parsed.type === 'content_block_delta' &&
                parsed.delta?.type === 'text_delta'
              ) {
                const text = parsed.delta.text;
                if (text) {
                  yield text;
                }
              }

              // Stop on message_stop
              if (parsed.type === 'message_stop') {
                return;
              }
            } catch {
              // Ignore malformed JSON lines
            }
          }
        }

        // Process remaining buffer
        if (buffer.trim()) {
          const trimmed = buffer.trim();
          if (trimmed.startsWith('data: ')) {
            try {
              const parsed = JSON.parse(trimmed.slice(6));
              if (
                parsed.type === 'content_block_delta' &&
                parsed.delta?.type === 'text_delta' &&
                parsed.delta.text
              ) {
                yield parsed.delta.text;
              }
            } catch {
              // Ignore
            }
          }
        }
      } finally {
        reader.releaseLock();
      }
    },
  };
}

"use client";

import type { AIProvider } from "./types";

/**
 * Demo AI provider that simulates streaming responses.
 * Used as fallback when no real API key is configured.
 */
export const demoAIProvider: AIProvider = {
  async *stream(prompt: string) {
    // Detect styled/formatting prompts
    const lowerPrompt = prompt.toLowerCase();
    const isStylePrompt =
      lowerPrompt.includes('bold') ||
      lowerPrompt.includes('emphasize') ||
      lowerPrompt.includes('key words') ||
      lowerPrompt.includes('key concepts') ||
      lowerPrompt.includes('backtick') ||
      lowerPrompt.includes('code');

    // If prompt contains "Text:\n" it's a selection replacement request
    const textMatch = prompt.match(/Text:\n([\s\S]+)$/);
    if (textMatch) {
      const selectedText = textMatch[1].trim();

      if (isStylePrompt) {
        // Return a styled version of the text with markdown formatting
        const styledResponse = addDemoFormatting(selectedText, lowerPrompt);
        for (const char of styledResponse) {
          await new Promise((r) => setTimeout(r, 15));
          yield char;
        }
        return;
      }

      // Plain text replacement — rephrase
      const rephrased = `Here is the rephrased version of the selected text, maintaining the original meaning while using different phrasing`;
      for (const char of rephrased) {
        await new Promise((r) => setTimeout(r, 15));
        yield char;
      }
      return;
    }

    // Default: block generation response (no preamble — clean markdown only)
    const response = `## AI Integration Demo

This is a demo of the AI streaming in Mina Rich Editor. In production, connect your own OpenAI, Anthropic, or Gemini API key.

### Key Features

- **Streaming support** — content appears token by token
- **Markdown parsing** — headings, lists, and code blocks are auto-detected
- **Provider agnostic** — implement the \`AIProvider\` interface for any LLM

\`\`\`typescript
import { createOpenAIProvider } from 'mina-rich-editor';

const provider = createOpenAIProvider({
  apiKey: process.env.OPENAI_API_KEY!,
  model: 'gpt-4',
});
\`\`\`

> Tip: Try asking for lists, headings, or code examples!`;

    for (const char of response) {
      await new Promise((r) => setTimeout(r, 20));
      yield char;
    }
  },
};

/** Add demo markdown formatting to text based on the prompt type. */
function addDemoFormatting(text: string, lowerPrompt: string): string {
  const words = text.split(' ');

  if (lowerPrompt.includes('backtick') || lowerPrompt.includes('code')) {
    // Wrap technical-looking words in backticks
    return words
      .map((w) =>
        /^[a-z][a-zA-Z]*[A-Z]/.test(w) || // camelCase
        w.includes('(') ||
        w.includes('.') ||
        w.includes('_')
          ? `\`${w}\``
          : w,
      )
      .join(' ');
  }

  if (lowerPrompt.includes('italic') || lowerPrompt.includes('emphasis')) {
    // Bold important words, italicize others
    return words
      .map((w, i) => {
        if (w.length > 6 && i % 3 === 0) return `**${w}**`;
        if (w.length > 4 && i % 4 === 1) return `*${w}*`;
        return w;
      })
      .join(' ');
  }

  // Default: bold key words
  return words
    .map((w, i) => (w.length > 5 && i % 3 === 0 ? `**${w}**` : w))
    .join(' ');
}

/**
 * Mina Rich Editor - Google Gemini Provider
 *
 * Adapter for Google's Gemini API using SSE streaming.
 * Uses native `fetch()` and `ReadableStream` — no external dependencies.
 *
 * @packageDocumentation
 */

import type { AIProvider, AIStreamOptions } from './types';

/**
 * Configuration for the Gemini provider.
 */
export interface GeminiProviderOptions {
  /** Your Gemini API key. */
  apiKey: string;
  /** Model to use. @default `'gemini-2.5-flash'` */
  model?: string;
  /** Default sampling temperature. @default `0.7` */
  temperature?: number;
}

/**
 * Creates an {@link AIProvider} that talks to Google's Gemini API
 * using SSE streaming.
 *
 * @param options - Provider configuration.
 * @returns An `AIProvider` ready to be passed to the editor.
 *
 * @example
 * ```typescript
 * import { createGeminiProvider } from 'mina-rich-editor';
 *
 * const provider = createGeminiProvider({
 *   apiKey: process.env.NEXT_PUBLIC_GEMINI_API_KEY!,
 *   model: 'gemini-2.5-flash',
 * });
 * ```
 */
export function createGeminiProvider(options: GeminiProviderOptions): AIProvider {
  const {
    apiKey,
    model: defaultModel = 'gemini-2.5-flash',
    temperature: defaultTemperature = 0.7,
  } = options;

  return {
    async *stream(
      prompt: string,
      streamOptions?: AIStreamOptions,
    ): AsyncIterable<string> {
      const model = streamOptions?.model ?? defaultModel;
      const temperature = streamOptions?.temperature ?? defaultTemperature;
      const maxTokens = streamOptions?.maxTokens;
      const systemPrompt = streamOptions?.systemPrompt;

      const contents: Array<{ role: string; parts: Array<{ text: string }> }> = [];

      if (systemPrompt) {
        contents.push({
          role: 'user',
          parts: [{ text: systemPrompt }],
        });
        contents.push({
          role: 'model',
          parts: [{ text: 'Understood. I will follow these instructions.' }],
        });
      }

      contents.push({
        role: 'user',
        parts: [{ text: prompt }],
      });

      const body: Record<string, unknown> = {
        contents,
        generationConfig: {
          temperature,
          ...(maxTokens !== undefined ? { maxOutputTokens: maxTokens } : {}),
        },
      };

      const url = `https://generativelanguage.googleapis.com/v1beta/models/${model}:streamGenerateContent?alt=sse&key=${apiKey}`;

      const response = await fetch(url, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(body),
      });

      if (!response.ok) {
        const errorText = await response.text().catch(() => 'Unknown error');
        throw new Error(
          `Gemini API error (${response.status}): ${errorText}`,
        );
      }

      if (!response.body) {
        throw new Error('Gemini API returned no response body');
      }

      const reader = response.body.getReader();
      const decoder = new TextDecoder();
      let buffer = '';

      try {
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          buffer += decoder.decode(value, { stream: true });
          const lines = buffer.split('\n');
          // Keep the last (potentially incomplete) line in the buffer
          buffer = lines.pop() ?? '';

          for (const line of lines) {
            const trimmed = line.trim();
            if (!trimmed || !trimmed.startsWith('data: ')) continue;

            const data = trimmed.slice(6); // Remove "data: " prefix
            if (data === '[DONE]') return;

            try {
              const parsed = JSON.parse(data);
              const text =
                parsed.candidates?.[0]?.content?.parts?.[0]?.text;
              if (text) {
                yield text;
              }
            } catch {
              // Ignore malformed JSON lines (partial SSE data)
            }
          }
        }

        // Process any remaining data in the buffer
        if (buffer.trim()) {
          const trimmed = buffer.trim();
          if (trimmed.startsWith('data: ') && trimmed.slice(6) !== '[DONE]') {
            try {
              const parsed = JSON.parse(trimmed.slice(6));
              const text =
                parsed.candidates?.[0]?.content?.parts?.[0]?.text;
              if (text) {
                yield text;
              }
            } catch {
              // Ignore
            }
          }
        }
      } finally {
        reader.releaseLock();
      }
    },
  };
}

/**
 * Mina Rich Editor - OpenAI-Compatible Provider
 *
 * Default adapter for any OpenAI-compatible chat completions endpoint.
 * Works with OpenAI, Azure OpenAI, Ollama, LM Studio, Together AI,
 * and any other service that implements the OpenAI SSE streaming format.
 *
 * Uses native `fetch()` and `ReadableStream` — no external dependencies.
 *
 * @packageDocumentation
 */

import type { AIProvider, AIStreamOptions } from './types';

/**
 * Configuration for the OpenAI-compatible provider.
 */
export interface OpenAIProviderOptions {
  /** Your API key. Sent as `Authorization: Bearer <key>`. */
  apiKey: string;
  /** Model to use. @default `'gpt-4'` */
  model?: string;
  /** Base URL of the API. @default `'https://api.openai.com/v1'` */
  baseUrl?: string;
  /** Default sampling temperature. @default `0.7` */
  temperature?: number;
}

/**
 * Creates an {@link AIProvider} that talks to any OpenAI-compatible
 * chat completions endpoint using SSE streaming.
 *
 * @param options - Provider configuration.
 * @returns An `AIProvider` ready to be passed to the editor.
 *
 * @example
 * ```typescript
 * import { createOpenAIProvider } from 'mina-rich-editor';
 *
 * const provider = createOpenAIProvider({
 *   apiKey: process.env.NEXT_PUBLIC_OPENAI_API_KEY!,
 *   model: 'gpt-4',
 * });
 * ```
 */
export function createOpenAIProvider(options: OpenAIProviderOptions): AIProvider {
  const {
    apiKey,
    model: defaultModel = 'gpt-4',
    baseUrl = 'https://api.openai.com/v1',
    temperature: defaultTemperature = 0.7,
  } = options;

  return {
    async *stream(
      prompt: string,
      streamOptions?: AIStreamOptions,
    ): AsyncIterable<string> {
      const model = streamOptions?.model ?? defaultModel;
      const temperature = streamOptions?.temperature ?? defaultTemperature;
      const maxTokens = streamOptions?.maxTokens;
      const systemPrompt = streamOptions?.systemPrompt;

      const messages: Array<{ role: string; content: string }> = [];
      if (systemPrompt) {
        messages.push({ role: 'system', content: systemPrompt });
      }
      messages.push({ role: 'user', content: prompt });

      const body: Record<string, unknown> = {
        model,
        messages,
        temperature,
        stream: true,
      };
      if (maxTokens !== undefined) {
        body.max_tokens = maxTokens;
      }

      const response = await fetch(`${baseUrl}/chat/completions`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${apiKey}`,
        },
        body: JSON.stringify(body),
      });

      if (!response.ok) {
        const errorText = await response.text().catch(() => 'Unknown error');
        throw new Error(
          `OpenAI API error (${response.status}): ${errorText}`,
        );
      }

      if (!response.body) {
        throw new Error('OpenAI API returned no response body');
      }

      const reader = response.body.getReader();
      const decoder = new TextDecoder();
      let buffer = '';

      try {
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          buffer += decoder.decode(value, { stream: true });
          const lines = buffer.split('\n');
          // Keep the last (potentially incomplete) line in the buffer
          buffer = lines.pop() ?? '';

          for (const line of lines) {
            const trimmed = line.trim();
            if (!trimmed || !trimmed.startsWith('data: ')) continue;

            const data = trimmed.slice(6); // Remove "data: " prefix
            if (data === '[DONE]') return;

            try {
              const parsed = JSON.parse(data);
              const content = parsed.choices?.[0]?.delta?.content;
              if (content) {
                yield content;
              }
            } catch {
              // Ignore malformed JSON lines (partial SSE data)
            }
          }
        }

        // Process any remaining data in the buffer
        if (buffer.trim()) {
          const trimmed = buffer.trim();
          if (trimmed.startsWith('data: ') && trimmed.slice(6) !== '[DONE]') {
            try {
              const parsed = JSON.parse(trimmed.slice(6));
              const content = parsed.choices?.[0]?.delta?.content;
              if (content) {
                yield content;
              }
            } catch {
              // Ignore
            }
          }
        }
      } finally {
        reader.releaseLock();
      }
    },
  };
}

/**
 * Mina Rich Editor - Stream-to-Blocks Converter
 *
 * Transforms a streaming `AsyncIterable<string>` from an AI provider into
 * live editor blocks. Tracks which lines have been processed so each
 * complete line is handled exactly once, while the partial (last) line
 * provides a live typing preview.
 *
 * @packageDocumentation
 */

import type { EditorAction } from '../reducer/actions';
import type { TextNode, NodeType, InlineText, NodeAttributes } from '../types';
import { generateId } from '../utils/id-generator';

// ─── Inline Markdown Parsing ─────────────────────────────────────────────────

/**
 * Strip orphaned markdown markers (e.g. standalone `**`, `~~`) that the LLM
 * left unclosed. Only removes markers that don't have a matching closing pair.
 */
function cleanOrphanedMarkers(text: string): string {
  // Count occurrences of each marker. Odd count means one is orphaned.
  const markers = ['**', '~~'] as const;
  let cleaned = text;
  for (const marker of markers) {
    // Split by the marker — if odd number of segments, there's an orphaned one
    const parts = cleaned.split(marker);
    if (parts.length % 2 === 0) {
      // Odd number of markers (even number of parts) — remove the last orphaned one
      const lastIdx = cleaned.lastIndexOf(marker);
      cleaned = cleaned.slice(0, lastIdx) + cleaned.slice(lastIdx + marker.length);
    }
  }
  return cleaned.trim();
}

/** Parse inline markdown formatting into InlineText children. */
export function parseInlineMarkdown(text: string): InlineText[] {
  if (!text) return [{ content: text }];

  // Clean up orphaned markers before parsing
  const cleaned = cleanOrphanedMarkers(text);
  if (!cleaned) return [{ content: '' }];

  const segments: InlineText[] = [];
  const inlineRe = /(\*\*(.+?)\*\*|\*(.+?)\*|`(.+?)`|~~(.+?)~~)/g;
  let lastIndex = 0;
  let match: RegExpExecArray | null;

  while ((match = inlineRe.exec(cleaned)) !== null) {
    if (match.index > lastIndex) {
      segments.push({ content: cleaned.slice(lastIndex, match.index) });
    }

    if (match[2] !== undefined) {
      segments.push({ content: match[2], bold: true });
    } else if (match[3] !== undefined) {
      segments.push({ content: match[3], italic: true });
    } else if (match[4] !== undefined) {
      segments.push({ content: match[4], code: true });
    } else if (match[5] !== undefined) {
      segments.push({ content: match[5], strikethrough: true });
    }

    lastIndex = match.index + match[0].length;
  }

  if (lastIndex < cleaned.length) {
    segments.push({ content: cleaned.slice(lastIndex) });
  }

  return segments.length > 0 ? segments : [{ content: cleaned }];
}

export function hasInlineFormatting(text: string): boolean {
  return /(\*\*.+?\*\*|\*[^*]+?\*|`.+?`|~~.+?~~)/.test(text);
}

// ─── Block Helpers ───────────────────────────────────────────────────────────

function parseLineType(raw: string): { type: NodeType; content: string; attributes?: NodeAttributes } {
  if (raw.startsWith('### ')) return { type: 'h3', content: raw.slice(4) };
  if (raw.startsWith('## ')) return { type: 'h2', content: raw.slice(3) };
  if (raw.startsWith('# ')) return { type: 'h1', content: raw.slice(2) };
  if (/^[-*+] /.test(raw)) return { type: 'li', content: raw.slice(2) };
  if (/^\d+\.\s/.test(raw)) return { type: 'li', content: raw.replace(/^\d+\.\s/, '') };
  if (raw.startsWith('> ')) return { type: 'blockquote', content: raw.slice(2) };
  if (/^---+$/.test(raw.trim()) || /^\*\*\*+$/.test(raw.trim())) return { type: 'hr', content: '' };

  const imgMatch = raw.match(/^!\[([^\]]*)\]\(([^)]+)\)$/);
  if (imgMatch) return { type: 'img', content: '', attributes: { src: imgMatch[2], alt: imgMatch[1] } };

  return { type: 'p', content: raw };
}

function createBlock(type: NodeType, content: string, attributes?: NodeAttributes): TextNode {
  return {
    id: generateId(type),
    type: type as TextNode['type'],
    content,
    ...(attributes && { attributes }),
  };
}

// ─── Preamble detection ─────────────────────────────────────────────────────

/** Common AI preamble patterns that should be stripped from the beginning of output. */
const PREAMBLE_PATTERNS = [
  /^here['']?s?\s/i,
  /^sure[!,.\s]/i,
  /^of course[!,.\s]/i,
  /^i['']?d be happy to/i,
  /^i['']?ll /i,
  /^let me /i,
  /^absolutely[!,.\s]/i,
  /^certainly[!,.\s]/i,
  /^great[!,.\s]/i,
];

function isPreambleLine(line: string): boolean {
  const trimmed = line.trim();
  if (!trimmed) return false;
  return PREAMBLE_PATTERNS.some((re) => re.test(trimmed));
}

// ─── Main ─────────────────────────────────────────────────────────────────────

/**
 * Consumes an AI text stream and dispatches editor actions to build
 * blocks in real-time with a live typing effect.
 */
export async function streamToBlocks(
  stream: AsyncIterable<string>,
  dispatch: (action: EditorAction) => void,
  targetId: string,
): Promise<void> {
  let fullText = '';

  // Ordered list of block IDs we've inserted, used to find the insertion point.
  const insertedBlockIds: string[] = [];
  // Wrap in object to avoid TS closure narrowing on `let` across functions.
  const s = { block: null as TextNode | null };
  // How many complete lines we've already converted into finalized blocks.
  let processedLineCount = 0;
  // Code fence state
  let inCodeBlock = false;
  let codeBlockContent = '';
  // Content from finalized complete lines only — prevents partial preview
  // from being double-counted when the partial line becomes complete.
  let committedContent = '';
  // Whether we've seen real content yet (for preamble stripping)
  let pastPreamble = false;
  // Whether s.block was created by partial-line preview (not yet confirmed by a complete line)
  let blockIsPreview = false;

  function lastInsertedId(): string {
    return insertedBlockIds.length > 0
      ? insertedBlockIds[insertedBlockIds.length - 1]
      : targetId;
  }

  /** Finalize the current block: apply inline formatting, mark as done. */
  function finalizeBlock(): void {
    if (!s.block) return;

    // Apply inline formatting on finalization
    if (s.block.type !== 'pre' && s.block.type !== 'img' && hasInlineFormatting(s.block.content ?? '')) {
      dispatch({
        type: 'UPDATE_NODE',
        payload: {
          id: s.block.id,
          updates: { children: parseInlineMarkdown(s.block.content ?? '') } as any,
        },
      });
    }

    insertedBlockIds.push(s.block.id);
    committedContent = '';
    s.block = null;
    blockIsPreview = false;
  }

  /** Insert a brand-new block after the last inserted one. */
  function insertBlock(type: NodeType, content: string, attributes?: NodeAttributes): void {
    finalizeBlock();

    const block = createBlock(type, content, attributes);
    s.block = block;
    committedContent = content;
    blockIsPreview = false;

    dispatch({
      type: 'INSERT_NODE',
      payload: { node: block, targetId: lastInsertedId(), position: 'after' },
    });
  }

  /** Update the live-preview content of the current block. */
  function updateContent(content: string): void {
    if (!s.block) return;
    s.block = { ...s.block, content };
    dispatch({
      type: 'UPDATE_CONTENT',
      payload: { id: s.block.id, content },
    });
  }

  /** Update the current block's type in-place (e.g. p → h2). */
  function updateType(type: NodeType, content: string): void {
    if (!s.block) return;
    s.block = { ...s.block, type: type as TextNode['type'], content };
    dispatch({
      type: 'UPDATE_NODE',
      payload: { id: s.block.id, updates: { type, content } as any },
    });
  }

  /** Discard a preview block that turned out to be something else (e.g. code fence). */
  function discardPreviewBlock(): void {
    if (!s.block || !blockIsPreview) return;
    dispatch({ type: 'DELETE_NODE', payload: { id: s.block.id } });
    s.block = null;
    blockIsPreview = false;
    committedContent = '';
  }

  // ── Stream loop ─────────────────────────────────────────────────────────

  for await (const chunk of stream) {
    fullText += chunk;

    const lines = fullText.split('\n');
    // Everything except the last element is a complete line.
    const completeLines = lines.slice(0, -1);
    const partialLine = lines[lines.length - 1];

    // ── Process only NEW complete lines ──────────────────────────────────
    for (let i = processedLineCount; i < completeLines.length; i++) {
      const line = completeLines[i];

      // Code fence toggle
      if (line.trim().startsWith('```')) {
        if (!inCodeBlock) {
          inCodeBlock = true;
          codeBlockContent = '';
          discardPreviewBlock();
        } else {
          // Closing fence — finalize code block
          inCodeBlock = false;
          if (s.block?.type === 'pre') {
            updateContent(codeBlockContent);
            finalizeBlock();
          } else {
            insertBlock('pre', codeBlockContent);
            finalizeBlock();
          }
          codeBlockContent = '';
        }
        continue;
      }

      if (inCodeBlock) {
        codeBlockContent += (codeBlockContent ? '\n' : '') + line;
        // Live update the code block
        if (s.block?.type === 'pre') {
          updateContent(codeBlockContent);
        } else {
          insertBlock('pre', codeBlockContent);
        }
        continue;
      }

      // Blank line → finalize current block (paragraph break)
      if (line.trim() === '') {
        finalizeBlock();
        continue;
      }

      // Strip preamble lines at the start of the response
      if (!pastPreamble) {
        if (isPreambleLine(line)) continue;
        pastPreamble = true;
      }

      // Regular content line
      const { type, content, attributes } = parseLineType(line);

      // Skip empty content (e.g. bare `- ` with no text, or standalone `**`)
      if (!content.trim() && type !== 'hr') continue;

      if (!s.block) {
        insertBlock(type, content, attributes);
      } else if (blockIsPreview) {
        // Block was created by partial-line preview — update in-place with final content
        if (type !== s.block.type) {
          updateType(type, content);
        } else {
          updateContent(content);
        }
        committedContent = content;
        blockIsPreview = false;
      } else if (s.block.type === type && type === 'p') {
        // Continue same paragraph — append using committed content
        // (not s.block.content which may include partial preview text)
        committedContent = committedContent + ' ' + content;
        updateContent(committedContent);
      } else {
        // Different type or non-paragraph same type — new block
        insertBlock(type, content, attributes);
      }
    }

    processedLineCount = completeLines.length;

    // ── Live-preview the partial line ────────────────────────────────────
    if (!partialLine) continue;

    if (inCodeBlock) {
      // Inside code fence — show partial code
      const preview = codeBlockContent + (codeBlockContent ? '\n' : '') + partialLine;
      if (s.block?.type === 'pre') {
        updateContent(preview);
      } else {
        insertBlock('pre', preview);
        blockIsPreview = true;
      }
      continue;
    }

    const { type, content, attributes } = parseLineType(partialLine);

    if (!s.block) {
      // No block yet — create one for the partial line
      insertBlock(type, content, attributes);
      blockIsPreview = true;
    } else {
      // Update existing block with partial content.
      // If the type changed (e.g. `#` paragraph → `## ` heading), update in-place.
      if (type !== s.block.type) {
        updateType(type, content);
      } else if (type === 'p' && committedContent) {
        // Paragraph continuation preview — use committed base to avoid duplication
        updateContent(committedContent + ' ' + content);
      } else {
        updateContent(content);
      }
    }
  }

  // ── Cleanup ─────────────────────────────────────────────────────────────

  // Close any unclosed code fence
  if (inCodeBlock && codeBlockContent) {
    if (s.block?.type === 'pre') {
      updateContent(codeBlockContent);
    } else {
      insertBlock('pre', codeBlockContent);
    }
  }

  finalizeBlock();
}

/**
 * Mina Rich Editor - AI Provider Types
 *
 * Defines the provider-agnostic interface for AI text generation.
 * Consumers implement {@link AIProvider} to plug in any LLM backend
 * (OpenAI, Anthropic, Ollama, custom proxy, etc.).
 *
 * @packageDocumentation
 */

/**
 * Options that can be passed per-request to control generation behaviour.
 */
export interface AIStreamOptions {
  /** Model identifier (e.g. `'gpt-4'`, `'claude-sonnet-4-20250514'`). */
  model?: string;
  /** Sampling temperature (0-2). Higher = more creative. */
  temperature?: number;
  /** Maximum tokens to generate. */
  maxTokens?: number;
  /** System-level prompt prepended to every request. */
  systemPrompt?: string;
}

/**
 * A provider that can stream text from an LLM.
 *
 * Implementations must return an `AsyncIterable<string>` that yields
 * text chunks as they arrive from the model.
 *
 * @example Custom provider
 * ```typescript
 * const myProvider: AIProvider = {
 *   async *stream(prompt) {
 *     const res = await fetch('/api/llm', {
 *       method: 'POST',
 *       body: JSON.stringify({ prompt }),
 *     });
 *     const reader = res.body!.getReader();
 *     const decoder = new TextDecoder();
 *     while (true) {
 *       const { done, value } = await reader.read();
 *       if (done) break;
 *       yield decoder.decode(value);
 *     }
 *   },
 * };
 * ```
 */
export interface AIProvider {
  /**
   * Stream text from the model for the given prompt.
   *
   * @param prompt - The user prompt to send to the model.
   * @param options - Optional per-request overrides.
   * @returns An async iterable of string chunks.
   */
  stream(prompt: string, options?: AIStreamOptions): AsyncIterable<string>;
}

/**
 * Configuration object passed to editor components to enable AI features.
 *
 * @example
 * ```tsx
 * <CompactEditor ai={{ provider: myProvider }} />
 * ```
 */
export interface AIConfig {
  /** The AI provider to use for generation. */
  provider: AIProvider;
  /** Default system prompt used when none is provided per-request. */
  defaultSystemPrompt?: string;
}

/**
 * Mina Rich Editor - Awareness / Presence Tracking
 *
 * Uses the Y.js Awareness protocol to share each user's cursor position
 * and presence state with all connected peers.
 *
 * All imports are dynamic so the base editor works without `yjs` or
 * `y-websocket` installed.
 *
 * @packageDocumentation
 */

import type { CollabUser } from './types';

// ─── Types ────────────────────────────────────────────────────────────────────

/** Shape of the awareness local state we publish. */
interface AwarenessLocalState {
  user: {
    name: string;
    color: string;
  };
  cursor?: {
    nodeId: string;
    offset: number;
  };
}

/**
 * Opaque handle returned by `createAwarenessManager`. Consumers interact
 * with awareness exclusively through this interface.
 */
export interface AwarenessManager {
  /**
   * Update the local user's cursor position.
   * Pass `null` to clear the cursor (e.g. when the editor loses focus).
   */
  updateCursor(cursor: { nodeId: string; offset: number } | null): void;

  /**
   * Subscribe to changes in the set of connected users (including cursor
   * movements). Returns an unsubscribe function.
   */
  onUsersChange(callback: (users: CollabUser[]) => void): () => void;

  /** Get the current snapshot of connected users. */
  getUsers(): CollabUser[];

  /** Tear down listeners. Called automatically by `useCollaboration`. */
  destroy(): void;
}

// ─── Factory ──────────────────────────────────────────────────────────────────

/**
 * Create an `AwarenessManager` bound to a Y.js Awareness instance.
 *
 * @param awareness - A `y-websocket` Awareness instance.
 * @param user      - The local user's display info.
 */
export function createAwarenessManager(
  awareness: any, // Awareness from y-websocket — typed as `any` to avoid hard dep
  user: { name: string; color: string }
): AwarenessManager {
  // Set initial local state
  awareness.setLocalStateField('user', {
    name: user.name,
    color: user.color,
  });

  const subscribers = new Set<(users: CollabUser[]) => void>();

  /** Build the `CollabUser[]` snapshot from awareness states. */
  function buildUsers(): CollabUser[] {
    const states: Map<number, AwarenessLocalState> = awareness.getStates();
    const users: CollabUser[] = [];

    states.forEach((state: AwarenessLocalState, clientId: number) => {
      if (!state.user) return;
      users.push({
        id: String(clientId),
        name: state.user.name,
        color: state.user.color,
        cursor: state.cursor ?? undefined,
      });
    });

    return users;
  }

  /** Handler bound to the awareness `change` event. */
  function handleChange() {
    const users = buildUsers();
    subscribers.forEach((cb) => cb(users));
  }

  awareness.on('change', handleChange);

  return {
    updateCursor(cursor) {
      awareness.setLocalStateField('cursor', cursor);
    },

    onUsersChange(callback) {
      subscribers.add(callback);
      // Immediately fire with current state so the subscriber is in sync.
      callback(buildUsers());
      return () => {
        subscribers.delete(callback);
      };
    },

    getUsers() {
      return buildUsers();
    },

    destroy() {
      awareness.off('change', handleChange);
      subscribers.clear();
    },
  };
}

/**
 * Mina Rich Editor - Collaboration Module
 *
 * Re-exports the public API surface for the collaboration system.
 *
 * @packageDocumentation
 */

export type { CollabOptions, CollabState, CollabUser } from './types';
export { REMOTE_ORIGIN } from './types';

export {
  applyOperationToYDoc,
  syncYDocToStore,
  initYDocFromContainer,
} from './y-binding';

export type { AwarenessManager } from './awareness';
export { createAwarenessManager } from './awareness';

/**
 * Mina Rich Editor - Collaboration Type Definitions
 *
 * Types for the Y.js-based real-time collaboration system.
 * All collaboration features are opt-in; the base editor works without
 * `yjs` or `y-websocket` installed.
 *
 * @packageDocumentation
 */

/**
 * Options for initializing real-time collaboration.
 *
 * @example
 * ```tsx
 * <CollaborationProvider
 *   roomId="doc-123"
 *   serverUrl="wss://collab.example.com"
 *   user={{ name: "Alice", color: "#e66" }}
 * >
 *   <CompactEditor />
 * </CollaborationProvider>
 * ```
 */
export interface CollabOptions {
  /** Unique identifier for the shared document / room. */
  roomId: string;

  /** WebSocket server URL (e.g. `wss://collab.example.com`). */
  serverUrl: string;

  /** The local user's display information. */
  user: {
    name: string;
    color: string;
  };
}

/**
 * Live state exposed by the collaboration system.
 */
export interface CollabState {
  /** Whether the WebSocket connection is currently active. */
  isConnected: boolean;

  /** List of users currently in the room (includes the local user). */
  connectedUsers: CollabUser[];

  /** The local Y.js client ID (as string), used to filter out own cursor. */
  localClientId: string | null;
}

/**
 * Representation of a single collaborating user.
 */
export interface CollabUser {
  /** Unique client ID assigned by the awareness protocol. */
  id: string;

  /** Display name. */
  name: string;

  /** Hex color used for cursor and selection highlighting. */
  color: string;

  /** Current cursor position (absent when the user has no active focus). */
  cursor?: {
    /** ID of the editor node the cursor sits in. */
    nodeId: string;
    /** Character offset within that node's text content. */
    offset: number;
  };
}

/**
 * Internal flag attached to dispatched actions so the Y.js binding can
 * distinguish locally-initiated changes from remote ones, preventing
 * infinite feedback loops.
 */
export const REMOTE_ORIGIN = '__mina_collab_remote__' as const;

/**
 * Mina Rich Editor - Y.js Binding
 *
 * Bridges Mina's operation-based state model and Y.js CRDTs.
 *
 * ## Data model inside the Y.Doc
 *
 * ```
 * yDoc.getMap('root')          // Y.Map  — mirrors ContainerNode
 *   .get('id')                 // string
 *   .get('type')               // 'container'
 *   .get('attributes')         // Y.Map (optional)
 *   .get('children')           // Y.Array<Y.Map>  — each child is a node
 * ```
 *
 * Every node (text, container, structural) is stored as a `Y.Map` with the
 * keys `id`, `type`, `attributes`, `content`, `children`, `lines`.
 * Only keys that carry a value are set, keeping the document lean.
 *
 * All `yjs` / `y-websocket` imports are **dynamic** so the base editor
 * bundle is never bloated when collaboration is unused.
 *
 * @packageDocumentation
 */

import type {
  ContainerNode,
  EditorNode,
  HistoryOperation,
  InlineText,
  BlockLine,
  NodeAttributes,
} from '../types';
import { REMOTE_ORIGIN } from './types';

// ─── Lazy Y.js loader ────────────────────────────────────────────────────────

/**
 * The Y.js module type. Typed as `any` to avoid hard-dependency on yjs
 * type declarations at compile time (yjs is an optional peer dep).
 */
type YModule = any;
let _Y: YModule | null = null;

/**
 * Lazily load the `yjs` module. Throws a clear message when the peer
 * dependency is not installed.
 */
async function getY(): Promise<YModule> {
  if (_Y) return _Y;
  try {
    _Y = await import('yjs' as string);
    return _Y;
  } catch {
    throw new Error(
      '[mina-editor] Collaboration requires "yjs" as a peer dependency. ' +
        'Install it with: npm install yjs y-websocket'
    );
  }
}

// Re-export the loader so other modules can get Y without duplicating logic.
export { getY };

// ─── Type aliases for readability ─────────────────────────────────────────────

/** Y.Doc instance (typed as `any` to avoid hard dep on yjs declarations). */
type YDoc = any;
/** Y.Map instance. */
type YMap = any;
/** Y.Array instance. */
type YArray = any;

// ─── EditorNode -> Y.Map ──────────────────────────────────────────────────────

/**
 * Convert an `InlineText` segment to a plain JS object suitable for
 * storing inside a Y.Array.
 */
function inlineTextToPlain(inline: InlineText): Record<string, unknown> {
  const obj: Record<string, unknown> = { content: inline.content };
  if (inline.id) obj.id = inline.id;
  if (inline.bold) obj.bold = true;
  if (inline.italic) obj.italic = true;
  if (inline.underline) obj.underline = true;
  if (inline.strikethrough) obj.strikethrough = true;
  if (inline.code) obj.code = true;
  if (inline.elementType) obj.elementType = inline.elementType;
  if (inline.href) obj.href = inline.href;
  if (inline.className) obj.className = inline.className;
  if (inline.styles) obj.styles = inline.styles;
  return obj;
}

/**
 * Serialise a `BlockLine` to a plain object.
 */
function blockLineToPlain(line: BlockLine): Record<string, unknown> {
  const obj: Record<string, unknown> = {};
  if (line.content !== undefined) obj.content = line.content;
  if (line.children) obj.children = line.children.map(inlineTextToPlain);
  return obj;
}

/**
 * Populate a Y.Map (that is already integrated into a Y.Doc) with node data.
 * Y.js requires types to be part of a document before reading — so we must
 * first insert child Y.Map/Y.Array into the parent, THEN set their values.
 */
function populateYMap(Y: YModule, yMap: YMap, node: EditorNode): void {
  yMap.set('id', node.id);
  yMap.set('type', node.type);

  if (node.attributes) {
    const yAttrs = new Y.Map() as YMap;
    yMap.set('attributes', yAttrs); // integrate first
    for (const [k, v] of Object.entries(node.attributes)) {
      if (v !== undefined) yAttrs.set(k, v);
    }
  }

  const isStructural = ['container', 'table', 'thead', 'tbody', 'tr'].includes(node.type as string);

  // Container / structural nodes have children
  if (isStructural && 'children' in node && Array.isArray((node as ContainerNode).children)) {
    const yChildren = new Y.Array() as YArray;
    yMap.set('children', yChildren); // integrate first
    for (const child of (node as ContainerNode).children) {
      const yChild = new Y.Map() as YMap;
      yChildren.push([yChild]); // integrate child into array
      populateYMap(Y, yChild, child); // now populate it
    }
  }

  // TextNode fields
  if ('content' in node && (node as any).content !== undefined) {
    yMap.set('content', (node as any).content);
  }
  if (!isStructural && 'children' in node && Array.isArray((node as any).children)) {
    // Inline children for text nodes
    yMap.set('inlineChildren', (node as any).children.map(inlineTextToPlain));
  }
  if ('lines' in node && (node as any).lines) {
    yMap.set('lines', (node as any).lines.map(blockLineToPlain));
  }
}

/**
 * Convert a `Y.Map` node back into a plain Mina `EditorNode`.
 */
function yMapToNode(yMap: YMap): EditorNode {
  const type = yMap.get('type') as string;
  const id = yMap.get('id') as string;

  const yAttrs = yMap.get('attributes') as YMap | undefined;
  const attributes: NodeAttributes | undefined = yAttrs
    ? Object.fromEntries(yAttrs.entries())
    : undefined;

  // Container / structural types
  if (type === 'container' || type === 'table' || type === 'thead' || type === 'tbody' || type === 'tr') {
    const yChildren = yMap.get('children') as YArray | undefined;
    const children: EditorNode[] = [];
    if (yChildren) {
      yChildren.forEach((child: YMap) => {
        children.push(yMapToNode(child));
      });
    }
    return { id, type: type as any, children, ...(attributes ? { attributes } : {}) } as EditorNode;
  }

  // Text node
  const node: Record<string, unknown> = { id, type };
  if (attributes) node.attributes = attributes;

  const content = yMap.get('content');
  if (content !== undefined) node.content = content;

  const inlineChildren = yMap.get('inlineChildren');
  if (inlineChildren) node.children = inlineChildren;

  const lines = yMap.get('lines');
  if (lines) node.lines = lines;

  return node as unknown as EditorNode;
}

// ─── Apply local HistoryOperation -> Y.Doc ────────────────────────────────────

/**
 * Apply a Mina `HistoryOperation` to the Y.Doc, translating it into Y.js
 * mutations. All mutations are wrapped in a single `yDoc.transact()` so
 * they arrive at remote peers as one atomic update.
 *
 * @param yDoc  - The shared Y.Doc instance.
 * @param op    - The operation produced by the local reducer.
 */
export async function applyOperationToYDoc(
  yDoc: YDoc,
  op: HistoryOperation
): Promise<void> {
  const Y = await getY();
  const yRoot = yDoc.getMap('root') as YMap;

  yDoc.transact(() => {
    applyOpRecursive(Y, yRoot, op);
  }, REMOTE_ORIGIN);
}

/**
 * Internal recursive helper that performs the actual Y.js mutations.
 */
function applyOpRecursive(
  Y: YModule,
  yRoot: YMap,
  op: HistoryOperation
): void {
  switch (op.type) {
    case 'update_node': {
      const target = findYMapById(yRoot, op.id);
      if (!target) return;

      const changes = op.changes as Record<string, unknown>;
      for (const [key, value] of Object.entries(changes)) {
        if (key === 'attributes' && typeof value === 'object' && value !== null) {
          let yAttrs = target.get('attributes') as YMap | undefined;
          if (!yAttrs) {
            yAttrs = new Y.Map() as YMap;
            target.set('attributes', yAttrs);
          }
          for (const [ak, av] of Object.entries(value as Record<string, unknown>)) {
            if (av === undefined) {
              yAttrs.delete(ak);
            } else {
              yAttrs.set(ak, av);
            }
          }
        } else if (key === 'children' && Array.isArray(value)) {
          // Could be container children or inline children
          const nodeType = target.get('type') as string;
          if (nodeType === 'container' || nodeType === 'table' || nodeType === 'thead' || nodeType === 'tbody' || nodeType === 'tr') {
            const yChildren = new Y.Array() as YArray;
            target.set('children', yChildren); // integrate first
            for (const child of value) {
              const yChild = new Y.Map() as YMap;
              yChildren.push([yChild]); // integrate child
              populateYMap(Y, yChild, child as EditorNode); // then populate
            }
          } else {
            // Inline children
            target.set('inlineChildren', value.map((c: InlineText) => inlineTextToPlain(c)));
          }
        } else if (key === 'lines' && Array.isArray(value)) {
          target.set('lines', value.map((l: BlockLine) => blockLineToPlain(l)));
        } else {
          target.set(key, value);
        }
      }
      break;
    }

    case 'delete_node': {
      deleteYMapById(yRoot, op.nodeId);
      break;
    }

    case 'insert_at_index': {
      const parent = findYMapById(yRoot, op.parentId);
      if (!parent) return;
      let yChildren = parent.get('children') as YArray | undefined;
      if (!yChildren) {
        yChildren = new Y.Array() as YArray;
        parent.set('children', yChildren);
      }
      const yNode = new Y.Map() as YMap;
      yChildren.insert(op.index, [yNode]); // integrate first
      populateYMap(Y, yNode, op.node);      // then populate
      break;
    }

    case 'replace_container': {
      // Clear existing keys from yRoot
      const keysToDelete: string[] = [];
      yRoot.forEach((_: unknown, key: string) => keysToDelete.push(key));
      for (const k of keysToDelete) yRoot.delete(k);
      // Populate yRoot directly from the container (yRoot is integrated)
      populateYMap(Y, yRoot, op.container);
      break;
    }

    case 'batch': {
      for (const subOp of op.operations) {
        applyOpRecursive(Y, yRoot, subOp);
      }
      break;
    }
  }
}

// ─── Y.Doc change -> Mina store ──────────────────────────────────────────────

/**
 * Reconstruct the full `ContainerNode` from the Y.Doc root and dispatch
 * a `REPLACE_CONTAINER` action into the Mina store.
 *
 * This is intentionally simple: Y.js guarantees convergence, so on every
 * remote update we rebuild the plain-JS tree from the authoritative Y.Doc.
 * The reducer's structural sharing ensures that only truly changed
 * sub-trees trigger React re-renders.
 *
 * @param dispatch - The Zustand store dispatch function.
 * @param yDoc     - The shared Y.Doc.
 */
export function syncYDocToStore(
  dispatch: (action: { type: string; payload?: unknown; _origin?: string }) => void,
  yDoc: YDoc
): void {
  const yRoot = yDoc.getMap('root') as YMap;
  if (!yRoot.get('id')) return; // Doc not yet initialised

  const container = yMapToNode(yRoot) as ContainerNode;
  dispatch({
    type: 'REPLACE_CONTAINER',
    payload: { container },
    _origin: REMOTE_ORIGIN,
  });
}

/**
 * Initialise the Y.Doc root map from a Mina `ContainerNode`.
 * Called once when the first client connects and the doc is empty.
 */
export async function initYDocFromContainer(
  yDoc: YDoc,
  container: ContainerNode
): Promise<void> {
  const Y = await getY();
  const yRoot = yDoc.getMap('root') as YMap;

  // Only initialise if the doc is empty
  if (yRoot.get('id')) return;

  yDoc.transact(() => {
    // Populate yRoot directly (it's already integrated in the doc)
    populateYMap(Y, yRoot, container);
  });
}

// ─── Y.Map tree traversal helpers ─────────────────────────────────────────────

/**
 * Find a `Y.Map` node by its `id` field, searching recursively through
 * the `children` Y.Array.
 */
function findYMapById(yMap: YMap, id: string): YMap | null {
  if (yMap.get('id') === id) return yMap;

  const yChildren = yMap.get('children');
  if (yChildren && typeof (yChildren as YArray).forEach === 'function') {
    let found: YMap | null = null;
    (yChildren as YArray).forEach((child: YMap) => {
      if (!found) {
        found = findYMapById(child, id);
      }
    });
    if (found) return found;
  }

  return null;
}

/**
 * Delete a node from the Y.Doc tree by its `id`.
 * Searches parent `children` arrays and splices the matching entry.
 */
function deleteYMapById(yMap: YMap, id: string): boolean {
  const yChildren = yMap.get('children');
  if (!yChildren || typeof (yChildren as YArray).forEach !== 'function') return false;

  const arr = yChildren as YArray;
  let idx = -1;
  arr.forEach((child: YMap, i: number) => {
    if (idx === -1 && child.get('id') === id) {
      idx = i;
    }
  });
  if (idx !== -1) {
    arr.delete(idx, 1);
    return true;
  }

  // Recurse
  let deleted = false;
  arr.forEach((child: YMap) => {
    if (!deleted) {
      deleted = deleteYMapById(child, id);
    }
  });
  return deleted;
}

