/**
 * CommandManager — Chainable command execution.
 *
 * Supports TipTap-style command chaining:
 *   editor.commands.toggleBold()
 *   editor.chain().toggleBold().toggleItalic().run()
 *   editor.can().toggleBold()
 */

import type { CommandContext, ExtensionContext } from './types';
import { ExtensionManager } from './ExtensionManager';

export class CommandManager {
  private extensionManager: ExtensionManager;
  private context: CommandContext;

  constructor(extensionManager: ExtensionManager, context: ExtensionContext) {
    this.extensionManager = extensionManager;
    // Build command context with all registered commands
    this.context = {
      ...context,
      commands: this.buildCommandProxy(),
    };
  }

  /** Direct command access: editor.commands.toggleBold() */
  get commands(): Record<string, (...args: any[]) => boolean> {
    return this.buildCommandProxy();
  }

  /** Start a command chain: editor.chain().toggleBold().toggleItalic().run() */
  chain(): CommandChain {
    return new CommandChain(this.extensionManager, this.context);
  }

  /** Check if commands can execute: editor.can().toggleBold() */
  can(): Record<string, (...args: any[]) => boolean> {
    return this.buildCanProxy();
  }

  private buildCommandProxy(): Record<string, (...args: any[]) => boolean> {
    const proxy: Record<string, (...args: any[]) => boolean> = {};
    for (const name of this.extensionManager.getRegisteredCommands()) {
      proxy[name] = (...args: any[]) => {
        return this.extensionManager.executeCommand(name, this.context, ...args);
      };
    }
    return proxy;
  }

  private buildCanProxy(): Record<string, (...args: any[]) => boolean> {
    // For "can" checks, we create a context with a no-op dispatch
    const dryContext: CommandContext = {
      ...this.context,
      dispatch: () => {}, // No-op — just check if command returns true
    };
    const proxy: Record<string, (...args: any[]) => boolean> = {};
    for (const name of this.extensionManager.getRegisteredCommands()) {
      proxy[name] = (...args: any[]) => {
        return this.extensionManager.executeCommand(name, dryContext, ...args);
      };
    }
    return proxy;
  }
}

export class CommandChain {
  /** Allow dynamic command names added by the Proxy at runtime. */
  [key: string]: ((...args: any[]) => CommandChain) | any;

  private queue: Array<() => boolean> = [];
  private extensionManager: ExtensionManager;
  private context: CommandContext;

  constructor(extensionManager: ExtensionManager, context: CommandContext) {
    this.extensionManager = extensionManager;
    this.context = context;

    // Create a Proxy so any method call adds to the queue.
    // IMPORTANT: capture `proxy` so we can return it from method calls to
    // keep the chain on the Proxy (not on the raw target).
    const proxy: CommandChain = new Proxy(this, {
      get(target, prop) {
        if (prop === 'run') return target.run.bind(target);
        if (typeof prop === 'string' && !(prop in target)) {
          // Dynamic command name — queue it and return the proxy for chaining
          return (...args: any[]) => {
            target.queue.push(() =>
              target.extensionManager.executeCommand(prop, target.context, ...args)
            );
            return proxy; // Return the Proxy so the next call is still intercepted
          };
        }
        return Reflect.get(target, prop);
      },
    });
    return proxy;
  }

  /** Execute all queued commands. Returns true if all succeeded. */
  run(): boolean {
    let allSucceeded = true;
    for (const cmd of this.queue) {
      if (!cmd()) allSucceeded = false;
    }
    this.queue = [];
    return allSucceeded;
  }
}

/**
 * Extension.create() — Factory for functional extensions.
 *
 * Functional extensions add behavior without defining new node or mark types.
 * Examples: History (undo/redo), Collaboration, AI content generation.
 *
 * @example
 * ```typescript
 * const MyExtension = Extension.create({
 *   name: 'my-extension',
 *   addCommands() {
 *     return {
 *       doSomething: () => ({ dispatch, state }) => {
 *         // ...
 *         return true;
 *       },
 *     };
 *   },
 *   addKeyboardShortcuts() {
 *     return { 'Mod-k': (ctx) => ctx.commands.doSomething() };
 *   },
 * });
 * ```
 */

import type { ExtensionConfig, ResolvedExtension } from './types';

export const Extension = {
  /**
   * Create a functional extension from a config object.
   * Returns a resolved extension instance ready for registration.
   */
  create(config: ExtensionConfig): ResolvedExtension {
    return {
      kind: 'extension',
      name: config.name,
      priority: config.priority ?? 100,
      config,
      options: config.addOptions?.() ?? {},
      storage: config.addStorage?.() ?? {},
    };
  },
};

/**
 * ExtensionManager — Central registry for all Mina extensions.
 *
 * Manages registration, resolution, and lookup for:
 *   - Node extensions (block types)
 *   - Mark extensions (inline formatting)
 *   - Functional extensions (behavior)
 *   - Commands, keyboard shortcuts, input rules, slash commands
 */

import type {
  AnyResolvedExtension,
  ResolvedExtension,
  ResolvedNodeExtension,
  ResolvedMarkExtension,
  CommandFunction,
  CommandContext,
  ShortcutHandler,
  InputRule,
  SlashCommand,
  ExtensionContext,
  BlockRenderProps,
} from './types';

export class ExtensionManager {
  /** All registered extensions, sorted by priority (highest first). */
  private extensions: AnyResolvedExtension[] = [];

  /** Node type → node extension lookup. */
  private nodeRegistry = new Map<string, ResolvedNodeExtension>();

  /** Mark name → mark extension lookup. */
  private markRegistry = new Map<string, ResolvedMarkExtension>();

  /** Command name → command function lookup. */
  private commandRegistry = new Map<string, CommandFunction>();

  /** Key string → shortcut handler lookup. */
  private shortcutRegistry = new Map<string, ShortcutHandler>();

  /** All registered input rules (checked in priority order). */
  private inputRules: InputRule[] = [];

  /** All registered slash commands. */
  private slashCommands: SlashCommand[] = [];

  /** Extension name → storage lookup. */
  private storageMap = new Map<string, Record<string, any>>();

  // ─── Registration ──────────────────────────────────────────────────────────

  /**
   * Register one or more extensions.
   * Extensions are sorted by priority and their hooks are indexed into registries.
   */
  register(...extensions: AnyResolvedExtension[]): void {
    for (const ext of extensions) {
      // Prevent duplicate registration
      if (this.extensions.some(e => e.name === ext.name)) {
        continue;
      }

      this.extensions.push(ext);
      this.storageMap.set(ext.name, ext.storage);

      // Index node types
      if (ext.kind === 'node') {
        for (const nodeType of ext.nodeTypes) {
          this.nodeRegistry.set(nodeType, ext);
        }
      }

      // Index mark names
      if (ext.kind === 'mark') {
        this.markRegistry.set(ext.config.markName, ext);
      }

      // Index commands
      const commands = ext.config.addCommands?.();
      if (commands) {
        for (const [name, fn] of Object.entries(commands)) {
          this.commandRegistry.set(name, fn);
        }
      }

      // Index keyboard shortcuts
      const shortcuts = ext.config.addKeyboardShortcuts?.();
      if (shortcuts) {
        for (const [key, handler] of Object.entries(shortcuts)) {
          this.shortcutRegistry.set(key, handler);
        }
      }

      // Index input rules
      const rules = ext.config.addInputRules?.();
      if (rules) {
        this.inputRules.push(...rules);
      }

      // Index slash commands
      if ('addSlashCommands' in ext.config) {
        const slashCmds = ext.config.addSlashCommands?.();
        if (slashCmds) {
          this.slashCommands.push(...slashCmds);
        }
      }
    }

    // Sort by priority (highest first)
    this.extensions.sort((a, b) => b.priority - a.priority);
  }

  // ─── Node lookups ──────────────────────────────────────────────────────────

  /** Get the node extension registered for a given node type. */
  getNodeExtension(nodeType: string): ResolvedNodeExtension | undefined {
    return this.nodeRegistry.get(nodeType);
  }

  /** Get the CSS class string for a node type (from the extension's addStyles). */
  getNodeStyles(nodeType: string): string | undefined {
    const ext = this.nodeRegistry.get(nodeType);
    return ext?.config.addStyles?.();
  }

  /** Get a custom React renderer for a node type. */
  getNodeRenderer(nodeType: string): ((props: BlockRenderProps) => React.ReactNode) | undefined {
    const ext = this.nodeRegistry.get(nodeType);
    return ext?.config.renderBlock;
  }

  /** Check if a node type is registered. */
  hasNodeType(nodeType: string): boolean {
    return this.nodeRegistry.has(nodeType);
  }

  /** Get all registered node type strings. */
  getRegisteredNodeTypes(): string[] {
    return Array.from(this.nodeRegistry.keys());
  }

  // ─── Mark lookups ──────────────────────────────────────────────────────────

  /** Get the mark extension registered for a given mark name. */
  getMarkExtension(markName: string): ResolvedMarkExtension | undefined {
    return this.markRegistry.get(markName);
  }

  /** Check if a mark name is registered. */
  hasMarkName(markName: string): boolean {
    return this.markRegistry.has(markName);
  }

  /** Get all registered mark names. */
  getRegisteredMarkNames(): string[] {
    return Array.from(this.markRegistry.keys());
  }

  // ─── Command lookups ───────────────────────────────────────────────────────

  /** Get a command function by name. */
  getCommand(name: string): CommandFunction | undefined {
    return this.commandRegistry.get(name);
  }

  /** Execute a command by name with the given context and arguments. */
  executeCommand(name: string, context: CommandContext, ...args: any[]): boolean {
    const command = this.commandRegistry.get(name);
    if (!command) return false;
    return command(...args)(context);
  }

  /** Get all registered command names. */
  getRegisteredCommands(): string[] {
    return Array.from(this.commandRegistry.keys());
  }

  // ─── Keyboard shortcut lookups ─────────────────────────────────────────────

  /** Get the handler for a keyboard shortcut string. */
  getShortcut(key: string): ShortcutHandler | undefined {
    return this.shortcutRegistry.get(key);
  }

  /** Get all registered keyboard shortcuts. */
  getRegisteredShortcuts(): Map<string, ShortcutHandler> {
    return new Map(this.shortcutRegistry);
  }

  // ─── Input rule matching ───────────────────────────────────────────────────

  /** Test all input rules against text. Returns the first match, or null. */
  matchInputRule(text: string, context: ExtensionContext): boolean {
    for (const rule of this.inputRules) {
      const match = text.match(rule.find);
      if (match) {
        const handled = rule.handler(match, context);
        if (handled) return true;
      }
    }
    return false;
  }

  /** Get all registered input rules. */
  getInputRules(): InputRule[] {
    return [...this.inputRules];
  }

  // ─── Slash commands ────────────────────────────────────────────────────────

  /** Get all registered slash commands for the command palette. */
  getSlashCommands(): SlashCommand[] {
    return [...this.slashCommands];
  }

  // ─── Storage ───────────────────────────────────────────────────────────────

  /** Get the storage object for an extension by name. */
  getStorage(extensionName: string): Record<string, any> | undefined {
    return this.storageMap.get(extensionName);
  }

  // ─── Lifecycle ─────────────────────────────────────────────────────────────

  /** Call onCreate on all extensions that define it. */
  onCreate(context: ExtensionContext): void {
    for (const ext of this.extensions) {
      ext.config.onCreate?.({ ...context, storage: ext.storage });
    }
  }

  /** Call onUpdate on all extensions that define it. */
  onUpdate(context: ExtensionContext): void {
    for (const ext of this.extensions) {
      ext.config.onUpdate?.({ ...context, storage: ext.storage });
    }
  }

  /** Call onSelectionUpdate on all extensions that define it. */
  onSelectionUpdate(context: ExtensionContext): void {
    for (const ext of this.extensions) {
      ext.config.onSelectionUpdate?.({ ...context, storage: ext.storage });
    }
  }

  /** Call onDestroy on all extensions that define it. */
  onDestroy(): void {
    for (const ext of this.extensions) {
      ext.config.onDestroy?.();
    }
  }

  // ─── Introspection ─────────────────────────────────────────────────────────

  /** Get all registered extensions. */
  getExtensions(): AnyResolvedExtension[] {
    return [...this.extensions];
  }

  /** Get an extension by name. */
  getExtension(name: string): AnyResolvedExtension | undefined {
    return this.extensions.find(e => e.name === name);
  }

  /** Get the total number of registered extensions. */
  get size(): number {
    return this.extensions.length;
  }
}

/**
 * Mark.create() — Factory for inline formatting extensions.
 *
 * Mark extensions define inline formatting (bold, italic, link, code, etc.)
 * and map to InlineText properties in Mina's document model.
 *
 * @example
 * ```typescript
 * const Bold = Mark.create({
 *   name: 'bold',
 *   markName: 'bold',
 *   inlineProperty: 'bold',
 *   parseHTML() {
 *     return [{ tag: 'strong' }, { tag: 'b' }, { style: 'font-weight=bold' }];
 *   },
 *   renderHTML() { return '<strong>'; },
 *   addKeyboardShortcuts() {
 *     return { 'Mod-b': (ctx) => ctx.commands.toggleBold() };
 *   },
 * });
 * ```
 */

import type { MarkExtensionConfig, ResolvedMarkExtension } from './types';

export const Mark = {
  /**
   * Create a mark extension from a config object.
   * Returns a resolved mark extension instance ready for registration.
   */
  create(config: MarkExtensionConfig): ResolvedMarkExtension {
    return {
      kind: 'mark',
      name: config.name,
      priority: config.priority ?? 100,
      config,
      options: config.addOptions?.() ?? {},
      storage: config.addStorage?.() ?? {},
    };
  },
};

/**
 * Node.create() — Factory for block-type extensions.
 *
 * Node extensions define new block types (headings, paragraphs, images, etc.)
 * and how they render, serialize, and parse from HTML.
 *
 * @example
 * ```typescript
 * const Heading = Node.create({
 *   name: 'heading',
 *   nodeType: ['h1', 'h2', 'h3', 'h4', 'h5', 'h6'],
 *   group: 'block',
 *   addStyles() { return 'text-4xl font-bold'; },
 *   addKeyboardShortcuts() {
 *     return { 'Mod-Alt-1': (ctx) => ctx.commands.setHeading({ level: 1 }) };
 *   },
 * });
 * ```
 */

import type { NodeExtensionConfig, ResolvedNodeExtension } from './types';

export const Node = {
  /**
   * Create a node extension from a config object.
   * Returns a resolved node extension instance ready for registration.
   */
  create(config: NodeExtensionConfig): ResolvedNodeExtension {
    const nodeTypes = Array.isArray(config.nodeType)
      ? config.nodeType
      : [config.nodeType];

    return {
      kind: 'node',
      name: config.name,
      priority: config.priority ?? 100,
      config,
      options: config.addOptions?.() ?? {},
      storage: config.addStorage?.() ?? {},
      nodeTypes,
    };
  },
};

/**
 * Mina Extension System
