 * const MyMark = Mark.create({
 *   name: 'highlight',
 *   markName: 'highlight',
 *   inlineProperty: 'className',
 *   renderHTML() { return '<mark>'; },
 * });
 *
 * const manager = new ExtensionManager();
 * manager.register(MyMark);
 * ```
 */

