  Strikethrough,
  InlineCode,
  Link,
];

/**
 * Mina Extension System — Type Definitions
 *
 * TipTap-inspired extension API built natively on Mina's architecture.
 * Supports three extension types:
 *   - Extension.create() → functional extensions (History, Collaboration, AI)
 *   - Node.create()      → block types (Heading, Paragraph, Image, Table)
 *   - Mark.create()      → inline formatting (Bold, Italic, Link, Code)
 */

import type { TextNode, EditorState, EditorNode, InlineText, ContainerNode } from '../types';
import type { EditorAction } from '../reducer/actions';

// ─── Context passed to extension hooks ───────────────────────────────────────

/** Context provided to extension commands and lifecycle hooks. */
export interface ExtensionContext {
  /** Current editor state (read-only snapshot). */
  state: EditorState;
  /** Dispatch an action to mutate editor state. */
  dispatch: (action: EditorAction) => void;
  /** Access the current document container. */
  getContainer: () => ContainerNode;
  /** Access extension storage. */
  storage: Record<string, any>;
}

/** Context provided to commands, extends base context with chainable helpers. */
export interface CommandContext extends ExtensionContext {
  /** The registered commands from all extensions. */
  commands: Record<string, (...args: any[]) => boolean>;
}

// ─── Command types ───────────────────────────────────────────────────────────

/** A command function that returns true if it was applied successfully. */
export type CommandFunction = (...args: any[]) => (context: CommandContext) => boolean;

// ─── Keyboard shortcut types ─────────────────────────────────────────────────

/** Handler for a keyboard shortcut. Return true to prevent default behavior. */
export type ShortcutHandler = (context: ExtensionContext) => boolean;

// ─── Input rule types ────────────────────────────────────────────────────────

/** An input rule that matches text patterns and applies transformations. */
export interface InputRule {
  /** Regex pattern to match against the current text. Use $ anchor for end-of-line. */
  find: RegExp;
  /** Handler called when pattern matches. Return true if handled. */
  handler: (match: RegExpMatchArray, context: ExtensionContext) => boolean;
}

// ─── HTML parse/render rules ─────────────────────────────────────────────────

/** Rule for parsing HTML elements into Mina nodes or marks. */
export interface ParseRule {
  /** CSS selector or tag name to match (e.g., 'strong', 'h1', 'img[src]'). */
  tag?: string;
  /** CSS style property to match (e.g., 'font-weight=bold'). */
  style?: string;
  /** Extract attributes from the DOM element. */
  getAttrs?: (element: HTMLElement) => Record<string, any> | null;
  /** Priority for conflicting rules (higher wins). */
  priority?: number;
}

/** Spec for a node/mark attribute with defaults and serialization. */
export interface AttributeSpec {
  /** Default value when not specified. */
  default?: any;
  /** Extract attribute from HTML during parsing. */
  parseHTML?: (element: HTMLElement) => any;
  /** Render attribute to HTML attributes. */
  renderHTML?: (value: any) => Record<string, string> | null;
}

// ─── Slash command (for CommandMenu integration) ─────────────────────────────

/** Describes a slash command entry in the command palette. */
export interface SlashCommand {
  /** Display label in the menu. */
  label: string;
  /** Optional description shown below the label. */
  description?: string;
  /** Keywords for search filtering. */
  keywords?: string[];
  /** Icon component (React element). */
  icon?: React.ReactNode;
  /** Command to execute when selected. */
  action: (context: ExtensionContext) => void;
  /** Group for organizing commands (e.g., 'text', 'media', 'advanced'). */
  group?: string;
}

// ─── Block rendering props ───────────────────────────────────────────────────

/** Props passed to custom block renderers. */
export interface BlockRenderProps {
  node: TextNode;
  isActive: boolean;
  isReadOnly: boolean;
  onUpdate: (content: string) => void;
}

// ─── Base extension config ───────────────────────────────────────────────────

/** Configuration object passed to Extension.create(). */
export interface ExtensionConfig {
  /** Unique name for this extension. */
  name: string;
  /** Load priority (higher loads first, default: 100). */
  priority?: number;

  // ── Configuration ──
  /** Define configurable options for this extension. */
  addOptions?: () => Record<string, any>;
  /** Define mutable storage for this extension. */
  addStorage?: () => Record<string, any>;

  // ── Commands ──
  /** Register commands that can be called via editor.commands.name(). */
  addCommands?: () => Record<string, CommandFunction>;

  // ── Keyboard shortcuts ──
  /** Map key combinations to handlers (e.g., 'Mod-b' → toggle bold). */
  addKeyboardShortcuts?: () => Record<string, ShortcutHandler>;

  // ── Input rules ──
  /** Pattern-based text transformations during typing. */
  addInputRules?: () => InputRule[];

  // ── Slash commands ──
  /** Register entries in the slash command palette. */
  addSlashCommands?: () => SlashCommand[];

  // ── Lifecycle hooks ──
  onCreate?: (context: ExtensionContext) => void;
  onUpdate?: (context: ExtensionContext) => void;
  onSelectionUpdate?: (context: ExtensionContext) => void;
  onDestroy?: () => void;
}

/** Configuration object passed to Node.create(). */
export interface NodeExtensionConfig extends ExtensionConfig {
  /** The node type string (e.g., 'h1', 'p', 'img'). Maps to EditorNode.type. */
  nodeType: string | string[];
  /** Node group for content rules. */
  group?: 'block' | 'inline' | 'structural';
  /** Whether the node can be dragged. */
  draggable?: boolean;

  // ── HTML round-trip ──
  /** How to recognize this node in pasted/imported HTML. */
  parseHTML?: () => ParseRule[];
  /** How to serialize this node to semantic HTML. */
  renderHTML?: (node: TextNode) => string;

  // ── React rendering ──
  /** Custom React component to render this block. */
  renderBlock?: (props: BlockRenderProps) => React.ReactNode;

  // ── Attributes ──
  /** Define custom attributes for this node type. */
  addAttributes?: () => Record<string, AttributeSpec>;

  // ── Styles ──
  /** CSS class string for this node type (replaces hardcoded getTypeClassName). */
  addStyles?: () => string;
}

/** Configuration object passed to Mark.create(). */
export interface MarkExtensionConfig extends ExtensionConfig {
  /** The mark name (e.g., 'bold', 'italic', 'link'). */
  markName: string;
  /** Which InlineText property this mark maps to (e.g., 'bold', 'href'). */
  inlineProperty: keyof InlineText;

  // ── HTML round-trip ──
  /** How to recognize this mark in pasted/imported HTML. */
  parseHTML?: () => ParseRule[];
  /** How to render this mark to HTML tag (e.g., returns '<strong>'). */
  renderHTML?: (attrs?: Record<string, any>) => string;

  // ── Attributes ──
  /** Define custom attributes for this mark. */
  addAttributes?: () => Record<string, AttributeSpec>;
}

// ─── Resolved extension instances ────────────────────────────────────────────

/** A resolved extension instance with type discriminator. */
export interface ResolvedExtension {
  kind: 'extension';
  name: string;
  priority: number;
  config: ExtensionConfig;
  options: Record<string, any>;
  storage: Record<string, any>;
}

/** A resolved node extension instance. */
export interface ResolvedNodeExtension {
  kind: 'node';
  name: string;
  priority: number;
  config: NodeExtensionConfig;
  options: Record<string, any>;
  storage: Record<string, any>;
  /** All node type strings this extension handles. */
  nodeTypes: string[];
}

/** A resolved mark extension instance. */
export interface ResolvedMarkExtension {
  kind: 'mark';
  name: string;
  priority: number;
  config: MarkExtensionConfig;
  options: Record<string, any>;
  storage: Record<string, any>;
}

/** Union of all resolved extension types. */
export type AnyResolvedExtension = ResolvedExtension | ResolvedNodeExtension | ResolvedMarkExtension;

/**
 * Block Drag Handler Functions
 * 
 * Functions for handling drag operations in Block components
 */

import React from "react";
import { TextNode } from "../../types";

/**
 * Create handle block drag start
 */
export function createHandleBlockDragStart(
  textNode: TextNode,
  onBlockDragStart?: (nodeId: string) => void
) {
  return (e: React.DragEvent) => {
    e.stopPropagation();
    e.dataTransfer.effectAllowed = "move";
    e.dataTransfer.setData("text/plain", textNode.id);
    e.dataTransfer.setData(
      "application/json",
      JSON.stringify({
        nodeId: textNode.id,
        type: textNode.type,
      })
    );
    if (onBlockDragStart) {
      onBlockDragStart(textNode.id);
    }
  };
}

/**
 * Create handle block drag end
 */
export function createHandleBlockDragEnd(
  onDragEnd?: () => void
) {
  return (e: React.DragEvent) => {
    e.stopPropagation();
    // Clear dragging state
    if (onDragEnd) {
      onDragEnd();
    }
  };
}

/**
 * Block Event Handler Functions
 * 
 * Functions for handling events in Block components
 */

import React from "react";
import { TextNode, ContainerNode, InlineText } from "../../types";
import { EditorAction, EditorActions } from "../../reducer/actions";
import { findParentById } from "../../utils/tree-operations";
import { generateId } from "../../utils/id-generator";

/** Parameters shared by all block-level event handler factory functions. */
export interface BlockEventHandlerParams {
  textNode: TextNode;
  readOnly: boolean;
  onInput: (element: HTMLElement) => void;
  onKeyDown: (e: React.KeyboardEvent<HTMLElement>) => void;
  onClick: () => void;
  onCreateNested?: (nodeId: string) => void;
  onChangeBlockType?: (nodeId: string, newType: string) => void;
  onInsertImage?: (nodeId: string) => void;
  onCreateList?: (nodeId: string, listType: string) => void;
  currentContainer: ContainerNode | (() => ContainerNode); // Can be value or getter for optimization
  dispatch: React.Dispatch<EditorAction>;
  localRef: React.RefObject<HTMLElement | null>;
  isComposingRef: React.MutableRefObject<boolean>;
  shouldPreserveSelectionRef: React.MutableRefObject<boolean>;
  showCommandMenu: boolean;
  setShowCommandMenu: (show: boolean) => void;
  setCommandMenuAnchor: (el: HTMLElement | null) => void;
}

/** Creates a factory that returns a compositionstart handler marking the IME composition as active. */
export function createHandleCompositionStart() {
  return (isComposingRef: React.MutableRefObject<boolean>) => {
    return () => {
      isComposingRef.current = true;
    };
  };
}

/** Creates a factory that returns a compositionend handler which clears the IME flag and flushes any pending content update. */
export function createHandleCompositionEnd() {
  return (
    isComposingRef: React.MutableRefObject<boolean>,
    onInput?: (element: HTMLElement) => void,
    localRef?: React.RefObject<HTMLElement | null>
  ) => {
    return () => {
      isComposingRef.current = false;

      // Flush any pending content update immediately after composition ends
      // so we don't wait for the next input event or debounce timer
      if (onInput && localRef?.current) {
        onInput(localRef.current);
      }
    };
  };
}

/** Creates an input handler that detects "/" to open the command menu and forwards content updates while guarding selection preservation. */
export function createHandleInput(params: Pick<BlockEventHandlerParams, 'textNode' | 'readOnly' | 'onInput' | 'onChangeBlockType' | 'showCommandMenu' | 'setShowCommandMenu' | 'setCommandMenuAnchor' | 'shouldPreserveSelectionRef' | 'dispatch'>) {
  return (e: React.FormEvent<HTMLDivElement>) => {
    const { textNode, readOnly, onInput, onChangeBlockType, showCommandMenu, setShowCommandMenu, setCommandMenuAnchor, shouldPreserveSelectionRef, dispatch } = params;
    const element = e.currentTarget;
    const text = element.textContent || "";

    // Check if the block is empty and user typed "/"
    if (text === "/" && !readOnly && onChangeBlockType) {
      setShowCommandMenu(true);
      setCommandMenuAnchor(element);
    } else if (showCommandMenu && text !== "/") {
      // Close menu if user continues typing
      setShowCommandMenu(false);
    }

    // Check for inline Markdown formatting patterns (only on plain text, not readOnly).
    // We check the DOM element's childElementCount rather than textNode.children
    // because during typing the textNode closure may be stale.
    const hasFormattedSpans = element.childElementCount > 0;
    if (!readOnly && !hasFormattedSpans) {
      const inlineFormatApplied = detectAndApplyInlineFormatting(text, element, textNode, dispatch);
      if (inlineFormatApplied) {
        // Don't set shouldPreserveSelectionRef — we WANT the Block's
        // useEffect to fire and update innerHTML with the formatted HTML.
        // Don't call onInput either — the dispatch already updated state.
        return;
      }
    }

    // Guard: prevent the useEffect from clobbering the DOM while the
    // debounced content dispatch triggers a second re-render.
    // The content debounce is 50ms, and React needs additional time to
    // process the state update and re-render. We use 120ms to safely
    // cover the full debounce + re-render window.
    shouldPreserveSelectionRef.current = true;

    // Call the parent onInput handler
    onInput(element);

    setTimeout(() => {
      shouldPreserveSelectionRef.current = false;
    }, 120);
  };
}

/**
 * Detects inline Markdown patterns in the full text content of a block and, if found,
 * dispatches an UPDATE_NODE action to replace the raw text with formatted inline children.
 *
 * Supported patterns (checked in priority order):
 *   **text**  → bold
 *   ~~text~~  → strikethrough
 *   `text`    → inline code
 *   *text*    → italic  (only single-star, not double)
 *
 * Returns true when a pattern was matched and the state was updated (caller should
 * skip the normal onInput path).  Returns false when no pattern matched.
 */
function detectAndApplyInlineFormatting(
  text: string,
  element: HTMLElement,
  textNode: TextNode,
  dispatch: React.Dispatch<EditorAction>
): boolean {
  // Helper: build the inline children array from the three segments and dispatch.
  function applyFormat(
    before: string,
    content: string,
    after: string,
    format: Partial<InlineText>
  ): boolean {
    const children: InlineText[] = [];
    if (before) children.push({ content: before });
    children.push({ content, ...format });
    if (after) children.push({ content: after });

    dispatch(EditorActions.updateNode(textNode.id, { children, content: undefined }));

    // Force the DOM to update: the shouldPreserveSelectionRef guard in
    // Block's useEffect would normally skip the innerHTML write during
    // typing. But we WANT the DOM to update here (to show formatted text
    // instead of raw markers). We schedule this after React re-renders.
    requestAnimationFrame(() => {
      // By the time rAF fires, React will have re-rendered with the new
      // textNode (which has children). The useEffect will have fired and
      // updated innerHTML IF shouldPreserveSelectionRef was false.
      // If it didn't update, force it now:
      element.focus();
      const sel = window.getSelection();
      if (sel) {
        const range = document.createRange();
        range.selectNodeContents(element);
        range.collapse(false);
        sel.removeAllRanges();
        sel.addRange(range);
      }
    });

    return true;
  }

  // 1. Bold: **text**  (must be checked before single-star italic)
  const boldMatch = text.match(/^([\s\S]*?)\*\*(.+?)\*\*([\s\S]*)$/);
  if (boldMatch) {
    return applyFormat(boldMatch[1], boldMatch[2], boldMatch[3], { bold: true });
  }

  // 2. Strikethrough: ~~text~~
  const strikeMatch = text.match(/^([\s\S]*?)~~(.+?)~~([\s\S]*)$/);
  if (strikeMatch) {
    return applyFormat(strikeMatch[1], strikeMatch[2], strikeMatch[3], { strikethrough: true });
  }

  // 3. Inline code: `text`  (single backtick, not triple)
  const codeMatch = text.match(/^([\s\S]*?)(?<!`)(`{1})(?!`)(.+?)(?<!`)\2(?!`)([\s\S]*)$/);
  if (codeMatch) {
    return applyFormat(codeMatch[1], codeMatch[3], codeMatch[4], { code: true });
  }

  // 4. Italic: *text*  — single star, NOT preceded/followed by another star
  //    Negative lookbehind/lookahead ensures we don't match inside **bold**.
  const italicMatch = text.match(/^([\s\S]*?)(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)([\s\S]*)$/);
  if (italicMatch) {
    return applyFormat(italicMatch[1], italicMatch[2], italicMatch[3], { italic: true });
  }

  return false;
}

/** Creates a keydown handler that manages command menu navigation, list item creation, and Shift+Enter nesting within a block. */
export function createHandleKeyDown(params: BlockEventHandlerParams) {
  return (e: React.KeyboardEvent<HTMLDivElement>) => {
    const {
      textNode,
      onKeyDown,
      onCreateNested,
      showCommandMenu,
      setShowCommandMenu,
      setCommandMenuAnchor,
      currentContainer,
      dispatch,
    } = params;

    // Close command menu on Escape
    if (e.key === "Escape" && showCommandMenu) {
      e.preventDefault();
      setShowCommandMenu(false);
      setCommandMenuAnchor(null);
      return;
    }

    // If command menu is open, let it handle the keyboard events
    if (
      showCommandMenu &&
      ["ArrowDown", "ArrowUp", "Enter"].includes(e.key)
    ) {
      // Don't prevent default - let CommandMenu handle it
      return;
    }

    // For list items (ol/li), handle Enter and Shift+Enter specially
    // For non-list items, Shift+Enter creates nested blocks
    const isListItem =
      textNode.type === "ol" ||
      textNode.type === "li";

    // Handle Shift+Enter for list items - add line break within item
    if (e.key === "Enter" && e.shiftKey && isListItem) {
      e.preventDefault();
      e.stopPropagation();

      // Pass to SimpleEditor to handle line break insertion
      onKeyDown(e);
      return;
    }

    // Handle Shift+Enter for non-list items - create nested block
    if (e.key === "Enter" && e.shiftKey && !isListItem && onCreateNested) {
      e.preventDefault();
      onCreateNested(textNode.id);
      return;
    }

    // Handle regular Enter for list items - create new list item at same level
    if (e.key === "Enter" && !e.shiftKey && isListItem) {
      e.preventDefault();
      e.stopPropagation();

      // Get current container (call it if it's a getter function)
      const container = typeof currentContainer === 'function' ? currentContainer() : currentContainer;

      // Find the parent container
      const parent = findParentById(container, textNode.id);

      if (parent) {
        // Create a new list item with the same type
        const newListItem: TextNode = {
          id: generateId('li'),
          type: textNode.type, // Keep the same type (ul/ol/li)
          content: "",
        };

        // Insert after the current list item
        dispatch({
          type: "INSERT_NODE",
          payload: {
            node: newListItem,
            targetId: textNode.id,
            position: "after",
          },
        });

        // Wait for the browser to paint the new list item before focusing it.
        requestAnimationFrame(() => {
          const newElement = document.querySelector(
            `[data-node-id="${newListItem.id}"]`
          ) as HTMLElement;
          if (newElement) {
            newElement.focus();
          }
        });
      }

      return;
    }

    // Pass to parent handler for other keys
    onKeyDown(e);
  };
}

/** Creates a click handler that prevents link navigation in edit mode and calls the parent onClick callback. */
export function createHandleClick(params: Pick<BlockEventHandlerParams, 'readOnly' | 'onClick'>) {
  return (e: React.MouseEvent<HTMLDivElement>) => {
    const { readOnly, onClick } = params;
    // Check if the click target is a link
    const target = e.target as HTMLElement;
    if (target.tagName === "A" && target.hasAttribute("href")) {
      // In read-only mode, let links work naturally
      if (readOnly) {
        return; // Let the browser handle the link
      } else {
        // In edit mode, prevent link navigation
        e.preventDefault();
      }
    }

    // Call the parent onClick handler
    onClick();
  };
}

/** Creates a handler that routes a command-menu selection to the appropriate block-type change, image, list, or table operation. */
export function createHandleCommandSelect(params: {
  textNode: TextNode;
  onChangeBlockType?: (nodeId: string, newType: string) => void;
  onInsertImage?: (nodeId: string) => void;
  onCreateList?: (nodeId: string, listType: string) => void;
  onCreateTable?: (nodeId: string) => void;
  localRef: React.RefObject<HTMLElement | null>;
  setShowCommandMenu: (show: boolean) => void;
  setCommandMenuAnchor: (el: HTMLElement | null) => void;
}) {
  return (commandValue: string) => {
    const {
      textNode,
      onChangeBlockType,
      onInsertImage,
      onCreateList,
      onCreateTable,
      localRef,
      setShowCommandMenu,
      setCommandMenuAnchor,
    } = params;

    if (!localRef.current) return;

    // Clear the "/" character
    localRef.current.textContent = "";

    // Close the menu immediately
    setShowCommandMenu(false);
    setCommandMenuAnchor(null);

    // Handle image insertion specially
    if (commandValue === "img" && onInsertImage) {
      onInsertImage(textNode.id);
      return;
    }

    // Handle list creation (both ordered and unordered) - create a container with multiple list items
    if ((commandValue === "ol" || commandValue === "ul") && onCreateList) {
      // Small delay to ensure menu is closed before creating the list
      setTimeout(() => {
        onCreateList(textNode.id, commandValue);
      }, 50);
      return;
    }

    // Handle table creation
    if (commandValue === "table" && onCreateTable) {
      // Small delay to ensure menu is closed before opening table dialog
      setTimeout(() => {
        onCreateTable(textNode.id);
      }, 50);
      return;
    }

    // For other block types (including 'li'), just change the type
    if (onChangeBlockType) {
      onChangeBlockType(textNode.id, commandValue);

      // Wait for the browser to paint the updated block before refocusing it.
      requestAnimationFrame(() => {
        localRef.current?.focus();
      });
    }
  };
}

/** Creates a handler that dispatches a background-color attribute update for the given text node. */
export function createHandleBackgroundColorChange(
  textNode: TextNode,
  dispatch: React.Dispatch<EditorAction>
) {
  return (color: string) => {
    dispatch({
      type: "UPDATE_ATTRIBUTES",
      payload: {
        id: textNode.id,
        attributes: {
          backgroundColor: color,
        },
        merge: true,
      },
    });
  };
}

/**
 * Block Renderer Utilities
 *
 * Helper functions for determining which component to render for each node type
 */

import { EditorNode, isContainerNode, ContainerNode } from "../../types";
import { ExtensionManager } from "../../extensions/ExtensionManager";

/**
 * Determine which HTML element to render based on node type
 */
export function getElementType(type: string): "li" | "ol" | "h1" | "h2" | "h3" | "h4" | "h5" | "h6" | "p" | "blockquote" | "pre" | "div" {
  switch (type) {
    case "li":
      return "li";
    case "ol":
      return "ol";
    case "h1":
      return "h1";
    case "h2":
      return "h2";
    case "h3":
      return "h3";
    case "h4":
      return "h4";
    case "h5":
      return "h5";
    case "h6":
      return "h6";
    case "p":
      return "p";
    case "blockquote":
      return "blockquote";
    case "code":
      return "pre";
    default:
      return "div";
  }
}

/**
 * Determine which HTML element to render based on node type, checking the
 * extension registry first and falling back to the hardcoded switch.
 *
 * Custom node extensions can override the element type by registering a
 * `renderBlock` function. For simple overrides without a custom renderer,
 * the fallback is "div" for unrecognized types.
 *
 * @param type - The node type string
 * @param extensionManager - Optional ExtensionManager from the store
 * @returns The HTML element tag name to render
 */
export function getElementTypeFromRegistry(
  type: string,
  extensionManager?: ExtensionManager
): "li" | "ol" | "h1" | "h2" | "h3" | "h4" | "h5" | "h6" | "p" | "blockquote" | "pre" | "div" {
  // For extension-registered custom node types not in the built-in switch,
  // we still fall through to the built-in switch. Custom elements that need
  // a different HTML tag should override via renderBlock in their extension.
  // The registry check here is a hook for future element-type overrides.
  if (extensionManager && extensionManager.hasNodeType(type)) {
    // Currently we defer to the hardcoded mapping for element types.
    // Extensions can set a custom renderBlock to bypass element-type entirely.
  }
  return getElementType(type);
}

/**
 * Check if node should render as a special component
 */
export function getNodeRenderType(node: EditorNode): 
  | "container" 
  | "table" 
  | "flex" 
  | "nested-container"
  | "br" 
  | "img" 
  | "video" 
  | "text" 
{
  if (node.type === "br") return "br";
  if (node.type === "img") return "img";
  if (node.type === "video") return "video";

  if (isContainerNode(node)) {
    const containerNode = node as ContainerNode;
    const firstChild = containerNode.children[0];
    const layoutType = containerNode.attributes?.layoutType as string | undefined;

    if (firstChild?.type === "table") return "table";
    if (layoutType === "flex") return "flex";

    return "nested-container";
  }

  return "text";
}

/**
 * Get container CSS classes
 */
export function getContainerClasses(
  isFlexContainer: boolean,
  isActive: boolean
): string {
  if (isFlexContainer) return "";

  return `border-l-2 border-border/50 pl-2 ml-6 transition-all ${
    isActive ? "border-primary" : "hover:border-border"
  }`;
}

/**
 * Block Styles Utilities
 * 
 * Functions for building className and style objects for blocks
 */

import { TextNode } from "../../types";
import { getTypeClassNameFromRegistry } from "./block-utils";
import { ExtensionManager } from "../../extensions/ExtensionManager";

interface BlockStyleParams {
  textNode: TextNode;
  className: string;
  readOnly: boolean;
  isActive: boolean;
  isListItem: boolean;
  isFirstBlock: boolean;
  notionBased: boolean;
  /** Optional ExtensionManager for registry-aware style lookup */
  extensionManager?: ExtensionManager;
}

/**
 * Build the complete className string for a block
 */
export function buildBlockClassName({
  textNode,
  className,
  readOnly,
  isActive,
  isListItem,
  isFirstBlock,
  notionBased,
  extensionManager,
}: BlockStyleParams): string {
  const parts = [
    // List item positioning
    isListItem ? "relative" : "",

    // Type-specific styles (h1, h2, p, etc.) — registry takes precedence over hardcoded
    getTypeClassNameFromRegistry(textNode.type, extensionManager),

    // Custom className from node attributes
    className,

    // Editor mode styles
    readOnly ? "" : "outline-none",

    // Spacing based on type
    getBlockSpacing(textNode.type, isListItem),

    // Notion-style first block spacing
    notionBased && isFirstBlock && textNode.type === 'h1' ? "mt-8 pb-12" : "",

    // Transitions
    "transition-all",

    // Active/hover states
    !readOnly && isActive ? "border-b bg-accent/5" : "",
    !readOnly ? "hover:bg-accent/5" : "",
    readOnly ? "cursor-default" : "",
  ];

  return parts.filter(Boolean).join(" ");
}

/**
 * Get spacing classes based on node type
 */
function getBlockSpacing(nodeType: string, isListItem: boolean): string {
  if (isListItem) {
    return "px-3 py-0.5 mb-0.5";
  }

  if (nodeType.startsWith('h')) {
    return "px-3 py-1";
  }

  return "px-3 py-1 mb-1";
}

/**
 * Build inline styles for a block
 */
export function buildBlockStyles(
  depth: number,
  isListItem: boolean,
  textColor: string,
  backgroundColor?: string
): React.CSSProperties {
  return {
    marginLeft: isListItem ? `${depth * 0.5 + 1.5}rem` : `${depth * 0.5}rem`,
    ...(textColor ? { color: textColor } : {}),
    ...(backgroundColor ? { backgroundColor } : {}),
  };
}

/**
 * Parse custom className to extract color and class
 */
export function parseCustomClassName(customClassName: string | number | boolean | Record<string, string> | undefined): {
  textColor: string;
  className: string;
} {
  const classNameStr = typeof customClassName === "string" ? customClassName : "";
  const isHexColor = classNameStr.startsWith("#");

  return {
    textColor: isHexColor ? classNameStr : "",
    className: isHexColor ? "" : classNameStr,
  };
}

/**
 * Block Utility Functions
 *
 * Helper functions for Block component rendering and selection management
 */

import { TextNode } from "../../types";
import { ExtensionManager } from "../../extensions/ExtensionManager";

/**
 * Helper function to escape HTML entities
 */
export function escapeHTML(text: string): string {
  const div = document.createElement("div");
  div.textContent = text;
  return div.innerHTML;
}

/**
 * Get CSS classes for each node type
 */
export function getTypeClassName(type: string): string {
  switch (type) {
    case "h1":
      return "text-4xl font-bold text-foreground leading-[1.2] mb-2";
    case "h2":
      return "text-3xl font-bold text-foreground leading-[1.2] mb-1.5";
    case "h3":
      return "text-2xl font-bold text-foreground leading-[1.2] mb-1";
    case "h4":
      return "text-xl font-semibold text-foreground leading-[1.3] mb-1";
    case "h5":
      return "text-lg font-semibold text-foreground leading-[1.4] mb-0.5";
    case "h6":
      return "text-base font-semibold text-foreground leading-[1.4] mb-0.5";
    case "p":
      return "text-base text-foreground leading-[1.6]";
    case "ol":
      return "text-base text-foreground leading-[1.6] list-decimal list-inside";
    case "li":
      return "text-base text-foreground leading-[1.6] list-disc list-inside";
    case "blockquote":
      return "text-base text-muted-foreground italic border-l-4 border-primary pl-6 py-1";
    case "code":
      return "font-mono text-sm bg-secondary text-secondary-foreground px-4 py-2 rounded-lg whitespace-pre-wrap break-words";
    default:
      return "text-base text-foreground leading-[1.6]";
  }
}

/**
 * Get CSS classes for a node type, checking the extension registry first.
 * Falls back to the hardcoded switch in getTypeClassName for backward compatibility.
 *
 * @param type - The node type string
 * @param extensionManager - Optional ExtensionManager from the store
 * @returns CSS class string for the node type
 */
export function getTypeClassNameFromRegistry(
  type: string,
  extensionManager?: ExtensionManager
): string {
  // Try extension registry first
  if (extensionManager) {
    const styles = extensionManager.getNodeStyles(type);
    if (styles !== undefined) return styles;
  }
  // Fall back to hardcoded switch
  return getTypeClassName(type);
}

/**
 * Build HTML content from children or lines
 */
export function buildHTML(textNode: TextNode, readOnly: boolean): string {
  // Check if node has inline children with formatting
  const hasChildren =
    Array.isArray(textNode.children) && textNode.children.length > 0;
  // Check if node has multiple lines
  const hasLines = Array.isArray(textNode.lines) && textNode.lines.length > 0;

  // For code blocks, we need to escape HTML entities
  const isCodeBlock = textNode.type === "code";

  // If node has multiple lines (e.g., ordered list with multiple items)
  if (hasLines) {
    return textNode
      .lines!.map((line, index) => {
        let lineContent = "";

        // If line has inline children with formatting
        if (line.children && line.children.length > 0) {
          lineContent = line.children
            .map((child) => {
              // Check if className is a hex color or Tailwind class
              const isHexColor =
                child.className && child.className.startsWith("#");
              const colorStyle = isHexColor ? child.className : "";
              const className = isHexColor ? "" : child.className;

              const classes = [
                child.bold ? "font-bold" : "",
                child.italic ? "italic" : "",
                child.underline ? "underline" : "",
                child.strikethrough ? "line-through" : "",
                child.code ? "font-mono bg-gray-100 dark:bg-gray-800 px-1 py-0.5 rounded" : "",
                className || "", // Include custom className (only if not hex color)
              ]
                .filter(Boolean)
                .join(" ");

              const styleAttr = colorStyle
                ? ` style="color: ${colorStyle};"`
                : "";
              const childContent = isCodeBlock
                ? escapeHTML(child.content || "")
                : child.content || "";

              // If it's a link
              if (child.href) {
                const linkClasses = ["hover:underline cursor-pointer", classes]
                  .filter(Boolean)
                  .join(" ");
                const italicSpacing = child.italic ? "inline" : "";
                const combinedClasses = [linkClasses, italicSpacing]
                  .filter(Boolean)
                  .join(" ");
                return `<a href="${child.href}" target="_blank" rel="noopener noreferrer" class="${combinedClasses}"${styleAttr}>${childContent}</a>`;
              }

              if (child.elementType) {
                const elementClasses = getTypeClassName(child.elementType);
                const italicSpacing = child.italic ? "inline" : "";
                const combinedClasses = [elementClasses, classes, italicSpacing]
                  .filter(Boolean)
                  .join(" ");
                return `<span class="${combinedClasses}"${styleAttr}>${childContent}</span>`;
              }

              if (classes || colorStyle) {
                const italicSpacing = child.italic ? "inline" : "";
                const combinedClasses = [classes, italicSpacing]
                  .filter(Boolean)
                  .join(" ");
                const classAttr = combinedClasses
                  ? ` class="${combinedClasses}"`
                  : "";
                return `<span${classAttr}${styleAttr}>${childContent}</span>`;
              }
              return childContent;
            })
            .join("");
        } else {
          lineContent = isCodeBlock
            ? escapeHTML(line.content || "")
            : line.content || "";
        }

        return lineContent;
      })
      .join("<br>");
  }

  // If node has inline children with formatting (single line)
  if (hasChildren) {
    return textNode
      .children!.map((child) => {
        // Build inline styles from the styles object
        let inlineStyles = "";
        if (child.styles) {
          inlineStyles = Object.entries(child.styles)
            .map(([key, value]) => {
              // Convert camelCase to kebab-case (fontSize -> font-size)
              const kebabKey = key.replace(/([A-Z])/g, "-$1").toLowerCase();
              return `${kebabKey}: ${value}`;
            })
            .join("; ");
        }

        const classes = [
          child.bold ? "font-bold" : "",
          child.italic ? "italic" : "",
          child.underline ? "underline" : "",
          child.strikethrough ? "line-through" : "",
          child.code ? "font-mono bg-gray-100 dark:bg-gray-800 px-1 py-0.5 rounded" : "",
          child.className || "",
        ]
          .filter(Boolean)
          .join(" ");

        const styleAttr = inlineStyles ? ` style="${inlineStyles}"` : "";
        const childContent = isCodeBlock
          ? escapeHTML(child.content || "")
          : child.content || "";

        // If it's a link
        if (child.href) {
          const linkClasses = ["underline cursor-pointer", classes]
            .filter(Boolean)
            .join(" ");
          const combinedClasses = [linkClasses].filter(Boolean).join(" ");
          return `<a href="${child.href}" target="_blank" rel="noopener noreferrer" class="${combinedClasses}"${styleAttr}>${childContent}</a>`;
        }

        // If child has an elementType, wrap in appropriate element
        if (child.elementType) {
          const elementClasses = getTypeClassName(child.elementType);
          // Add extra spacing for italic text to prevent overlapping
          const combinedClasses = [elementClasses, classes]
            .filter(Boolean)
            .join(" ");
          return `<span class="${combinedClasses}"${styleAttr}>${childContent}</span>`;
        }

        if (classes || inlineStyles) {
          // Add extra spacing for italic text to prevent overlapping
          const combinedClasses = [classes].filter(Boolean).join(" ");
          const classAttr = combinedClasses
            ? ` class="${combinedClasses}"`
            : "";
          return `<span${classAttr}${styleAttr}>${childContent}</span>`;
        }
        return childContent;
      })
      .join("");
  }

  // Simple content (single line, no formatting)
  const content = textNode.content || "";
  return isCodeBlock ? escapeHTML(content) : content;
}

/**
 * Save current selection position
 */
export function saveSelection(localRef: React.RefObject<HTMLElement | null>): {
  start: number;
  end: number;
  collapsed: boolean;
} | null {
  if (!localRef.current) return null;

  const selection = window.getSelection();
  if (!selection || selection.rangeCount === 0) return null;

  const range = selection.getRangeAt(0);
  if (!localRef.current.contains(range.commonAncestorContainer)) return null;

  // Create a simplified representation of the selection
  const preCaretRange = range.cloneRange();
  preCaretRange.selectNodeContents(localRef.current);
  preCaretRange.setEnd(range.startContainer, range.startOffset);

  return {
    start: preCaretRange.toString().length,
    end: preCaretRange.toString().length + range.toString().length,
    collapsed: range.collapsed,
  };
}

/**
 * Restore selection to saved position
 */
export function restoreSelection(
  localRef: React.RefObject<HTMLElement | null>,
  savedSelection: { start: number; end: number; collapsed: boolean } | null
): void {
  if (!savedSelection || !localRef.current) return;

  const selection = window.getSelection();
  if (!selection) return;

  let charIndex = 0;
  let startNode: Node | undefined = undefined;
  let startOffset = 0;
  let endNode: Node | undefined = undefined;
  let endOffset = 0;

  const walk = (node: Node): void => {
    if (startNode && endNode) return;

    if (node.nodeType === Node.TEXT_NODE) {
      const textLength = node.textContent?.length || 0;

      // Find start position
      if (!startNode && charIndex + textLength >= savedSelection.start) {
        startNode = node;
        startOffset = savedSelection.start - charIndex;
      }

      // Find end position
      if (!endNode && charIndex + textLength >= savedSelection.end) {
        endNode = node;
        endOffset = savedSelection.end - charIndex;
      }

      charIndex += textLength;
    } else {
      for (let i = 0; i < node.childNodes.length; i++) {
        walk(node.childNodes[i]);
        if (startNode && endNode) break;
      }
    }
  };

  walk(localRef.current);

  try {
    const range = document.createRange();

    if (startNode && endNode) {
      const start = startNode as Node;
      const end = endNode as Node;
      range.setStart(
        start,
        Math.min(startOffset, start.textContent?.length || 0)
      );

      if (savedSelection.collapsed) {
        range.collapse(true);
      } else {
        range.setEnd(end, Math.min(endOffset, end.textContent?.length || 0));
      }

      selection.removeAllRanges();
      selection.addRange(range);
    }
  } catch (e) {
    console.warn("Failed to restore selection:", e);
  }
}

/**
 * Block Handlers Index
 * 
 * Central export point for all block handler functions
