/**
 * Clipboard Event Handlers
 *
 * Functions for handling copy, cut, and paste events in the editor.
 * Supports pasting HTML (with formatting) and plain text.
 * Sanitizes all pasted HTML to prevent XSS.
 */

import { EditorActions, EditorAction } from '../reducer/actions';
import { ContainerNode, EditorNode } from '../types';
import { parseHtmlToNodes, parsePlainTextToNodes } from '../utils/html-to-nodes';
import { parseMarkdownToNodes } from '../utils/parse-markdown';

/** Parameters required by all clipboard handler factory functions. */
export interface ClipboardHandlerParams {
  getContainer: () => ContainerNode;
  getActiveNodeId: () => string | null;
  dispatch: React.Dispatch<EditorAction>;
}

// ============================================================================
// Markdown detection helpers
// ============================================================================

/**
 * Returns true if the text contains any Markdown patterns (block or inline).
 * Used for multi-line paste detection.
 */
function looksLikeMarkdown(text: string): boolean {
  return (
    /^#{1,6}\s/m.test(text) ||   // headings
    /^[-*]\s/m.test(text) ||      // unordered lists
    /^\d+\.\s/m.test(text) ||     // ordered lists
    /^>\s/m.test(text) ||         // blockquotes
    /^```/m.test(text) ||         // code fences
    /^---$/m.test(text) ||        // horizontal rules
    /\*\*.+\*\*/m.test(text) ||   // bold
    /\[.+\]\(.+\)/m.test(text)    // links
  );
}

/**
 * Returns true if the text starts with a block-level Markdown pattern.
 * Used for single-line paste detection — we intentionally exclude inline
 * markers like **bold** to avoid surprising conversions.
 */
function looksLikeMarkdownBlock(text: string): boolean {
  return (
    /^#{1,6}\s/.test(text) ||  // heading
    /^[-*]\s/.test(text) ||    // unordered list item
    /^\d+\.\s/.test(text) ||   // ordered list item
    /^>\s/.test(text) ||       // blockquote
    /^```/.test(text) ||       // code fence
    /^---$/.test(text)         // horizontal rule
  );
}

/**
 * Creates a copy handler.
 * Lets the browser handle the default copy behavior for selected text.
 * No override needed — contentEditable elements copy correctly by default.
 */
export function createHandleCopy(_params: ClipboardHandlerParams) {
  return (_e: React.ClipboardEvent<HTMLDivElement>) => {
    // The browser handles the default copy of selected DOM content natively.
  };
}

/**
 * Creates a paste handler.
 * Handles pasting HTML or plain text from external sources by converting
 * the clipboard content into EditorNodes and inserting them after the active node.
 *
 * Media file pastes (images/videos) are handled separately in Editor.tsx via
 * a document-level paste listener, so they are skipped here.
 */
export function createHandlePaste(params: ClipboardHandlerParams) {
  return (e: React.ClipboardEvent<HTMLDivElement>) => {
    if (!e.clipboardData) return;

    // If the clipboard contains media files, let the media paste handler in
    // Editor.tsx deal with it (it runs on the document-level paste listener).
    const items = e.clipboardData.items;
    for (let i = 0; i < items.length; i++) {
      const item = items[i];
      if (
        item.kind === 'file' &&
        (item.type.startsWith('image/') || item.type.startsWith('video/'))
      ) {
        // Media files — skip; the document-level handler takes care of them
        return;
      }
    }

    // Get plain text first to check if it's single-line
    const text = e.clipboardData.getData('text/plain');
    const html = e.clipboardData.getData('text/html');
    const isMultiLine = text.includes('\n');

    // Single-line text that matches a block-level Markdown pattern (e.g.
    // "# My Title", "- item", "> quote"): convert it to the appropriate block.
    // We deliberately exclude inline-only markers like **bold** here — those
    // are better inserted as-is at the cursor.
    if (!isMultiLine && looksLikeMarkdownBlock(text)) {
      const nodes = parseMarkdownToNodes(text);
      if (nodes.length > 0) {
        e.preventDefault();
        insertPastedNodes(params, nodes);
        return;
      }
    }

    // Single-line text with no Markdown block syntax: let the browser handle
    // it natively. The browser's default paste inserts text at the cursor
    // position within the focused contenteditable element — exactly what
    // the user expects for inline paste.
    if (!isMultiLine) {
      return; // Don't preventDefault — browser does the right thing
    }

    // Multi-line paste: parse into blocks and insert after active node
    if (html) {
      const nodes = parseHtmlToNodes(html);
      if (nodes.length > 0) {
        e.preventDefault();
        insertPastedNodes(params, nodes);
        return;
      }
    }

    if (text) {
      // If the plain text looks like Markdown, parse it with the Markdown
      // parser so headings, lists, blockquotes, etc. become proper blocks.
      if (looksLikeMarkdown(text)) {
        const nodes = parseMarkdownToNodes(text);
        if (nodes.length > 0) {
          e.preventDefault();
          insertPastedNodes(params, nodes);
          return;
        }
      }

      // Regular plain text (no Markdown) — split on newlines into paragraphs
      const nodes = parsePlainTextToNodes(text);
      if (nodes.length > 0) {
        e.preventDefault();
        insertPastedNodes(params, nodes);
      }
    }
  };
}

/**
 * Creates a cut handler.
 * Lets the browser handle the default cut of selected DOM content.
 * Deletion of the selected text inside a contentEditable element is done
 * automatically by the browser; block deletions are handled by the keyboard handler.
 */
export function createHandleCut(_params: ClipboardHandlerParams) {
  return (_e: React.ClipboardEvent<HTMLDivElement>) => {
    // Browser handles the cut of selected text in contentEditable natively.
  };
}

/**
 * Insert an array of parsed nodes after the currently active node.
 */
function insertPastedNodes(params: ClipboardHandlerParams, nodes: EditorNode[]) {
  const activeNodeId = params.getActiveNodeId();
  const container = params.getContainer();

  // Determine insertion target: active node, or last child of container
  const targetId =
    activeNodeId || container.children[container.children.length - 1]?.id;

  if (!targetId) return;

  if (nodes.length === 1) {
    params.dispatch(EditorActions.insertNode(nodes[0], targetId, 'after'));
  } else {
    // Build a batch of sequential inserts
    const actions: EditorAction[] = nodes.map((node, i) => {
      const insertAfter = i === 0 ? targetId : nodes[i - 1].id;
      return EditorActions.insertNode(node, insertAfter, 'after');
    });
    params.dispatch(EditorActions.batch(actions));
  }
}

/**
 * Drag and Drop Handler Functions
 *
 * Factory functions for handling drag and drop operations in the editor.
 * Drop logic is delegated to focused strategy functions in drop-strategies.ts.
 */

import { EditorActions } from '../reducer/actions';
import { ContainerNode, TextNode, isTextNode, isContainerNode } from '../types';
import { findNodeAnywhere } from '../utils/editor-helpers';
import {
  DropContext,
  DropPosition,
  handleFlexReorder,
  handleFlexMerge,
  handleFlexExtract,
  handleRootMove,
  handleFileDrop,
} from './drop-strategies';

/** Parameters shared by drag-and-drop handler factory functions. */
export interface DragDropHandlerParams {
  container: ContainerNode | (() => ContainerNode);
  dispatch: React.Dispatch<any>;
  toast: any;
  draggingNodeId: string | null;
  setDraggingNodeId: (id: string | null) => void;
  setDragOverNodeId: (id: string | null) => void;
  setDropPosition: (pos: "before" | "after" | "left" | "right" | null) => void;
  setIsUploading: (uploading: boolean) => void;
  onUploadImage?: (file: File) => Promise<string>;
}

/** Creates a dragstart handler that records the image node ID as the currently dragged node. */
export function createHandleImageDragStart(setDraggingNodeId: (id: string) => void) {
  return (nodeId: string) => {
    setDraggingNodeId(nodeId);
  };
}

/** Creates a dragstart handler that records the block node ID as the currently dragged node. */
export function createHandleBlockDragStart(setDraggingNodeId: (id: string) => void) {
  return (nodeId: string) => {
    setDraggingNodeId(nodeId);
  };
}

/** Creates a dragenter handler that prevents the default browser behavior to allow custom drop handling. */
export function createHandleDragEnter() {
  return (e: React.DragEvent, _nodeId: string) => {
    e.preventDefault();
    e.stopPropagation();
  };
}

/** Creates a dragover handler that calculates and sets the drop position (before/after/left/right) based on cursor location. */
export function createHandleDragOver(params: Omit<DragDropHandlerParams, 'toast' | 'setIsUploading' | 'onUploadImage'>) {
  return (e: React.DragEvent, nodeId: string) => {
    const { container: containerOrGetter, draggingNodeId, setDragOverNodeId, setDropPosition } = params;
    const container = typeof containerOrGetter === 'function' ? containerOrGetter() : containerOrGetter;
    e.preventDefault();
    e.stopPropagation();

    // Don't show drop indicator if we're hovering over the dragged element itself
    if (draggingNodeId === nodeId) {
      e.dataTransfer.dropEffect = "none";
      setDragOverNodeId(null);
      setDropPosition(null);
      return;
    }

    const targetResult = findNodeAnywhere(nodeId, container);
    const draggingResult = draggingNodeId
      ? findNodeAnywhere(draggingNodeId, container)
      : null;

    if (!targetResult) return;

    const targetNode = targetResult.node;
    const draggingNode = draggingResult?.node;
    const isTargetImage =
      isTextNode(targetNode) && (targetNode as TextNode).type === "img";
    const isDraggingImage =
      draggingNode &&
      isTextNode(draggingNode) &&
      (draggingNode as TextNode).type === "img";

    // Check if target and dragging nodes are in the same flex container
    const inSameFlexContainer =
      targetResult.parentId &&
      draggingResult?.parentId &&
      targetResult.parentId === draggingResult.parentId;

    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();

    // If both are images, check for horizontal (left/right) drop zones
    if (isTargetImage && isDraggingImage) {
      const edgeThreshold = rect.width * 0.3; // 30% from each edge

      // If in same flex container, allow reordering via horizontal drop
      if (inSameFlexContainer) {
        // Get the parent container to check positions
        const parent = draggingResult?.parentId
          ? (container.children.find(
              (c) => c.id === draggingResult.parentId
            ) as ContainerNode)
          : null;

        if (parent) {
          const dragIndex = parent.children.findIndex(
            (c) => c.id === draggingNodeId
          );
          const targetIndex = parent.children.findIndex((c) => c.id === nodeId);

          // Check if we're on the left edge
          if (e.clientX < rect.left + edgeThreshold) {
            // Prevent dropping to the left of the item immediately to our right
            if (targetIndex === dragIndex + 1) {
              e.dataTransfer.dropEffect = "none";
              setDragOverNodeId(null);
              setDropPosition(null);
              return;
            }
            setDragOverNodeId(nodeId);
            setDropPosition("left");
            e.dataTransfer.dropEffect = "move";
            return;
          }
          // Check if we're on the right edge
          else if (e.clientX > rect.right - edgeThreshold) {
            // Prevent dropping to the right of the item immediately to our left
            if (targetIndex === dragIndex - 1) {
              e.dataTransfer.dropEffect = "none";
              setDragOverNodeId(null);
              setDropPosition(null);
              return;
            }
            setDragOverNodeId(nodeId);
            setDropPosition("right");
            e.dataTransfer.dropEffect = "move";
            return;
          }
        }
        // If we're in the middle of an item in the same flex container, no drop
        e.dataTransfer.dropEffect = "none";
        setDragOverNodeId(null);
        setDropPosition(null);
        return;
      } else {
        // Not in same container - allow horizontal merge
        if (e.clientX < rect.left + edgeThreshold) {
          setDragOverNodeId(nodeId);
          setDropPosition("left");
          e.dataTransfer.dropEffect = "move";
          return;
        } else if (e.clientX > rect.right - edgeThreshold) {
          setDragOverNodeId(nodeId);
          setDropPosition("right");
          e.dataTransfer.dropEffect = "move";
          return;
        }
      }
    }

    // Default vertical drop logic
    const midPoint = rect.top + rect.height / 2;
    const position = e.clientY < midPoint ? "before" : "after";

    // If dragging an existing block, check if this would result in no movement
    if (draggingNodeId) {
      // Find the indices of the dragged node and target node
      const draggedIndex = container.children.findIndex(
        (n) => n.id === draggingNodeId
      );
      const targetIndex = container.children.findIndex((n) => n.id === nodeId);

      // Don't allow drops that would result in no movement
      if (
        (position === "after" && targetIndex === draggedIndex - 1) ||
        (position === "before" && targetIndex === draggedIndex + 1)
      ) {
        e.dataTransfer.dropEffect = "none";
        setDragOverNodeId(null);
        setDropPosition(null);
        return;
      }
    }

    // Allow drop - use "move" for existing blocks, "copy" for external files
    e.dataTransfer.dropEffect = draggingNodeId ? "move" : "copy";

    setDragOverNodeId(nodeId);
    setDropPosition(position);
  };
}

/** Creates a dragleave handler that clears the drop indicator when the pointer leaves the target element. */
export function createHandleDragLeave(setDragOverNodeId: (id: string | null) => void, setDropPosition: (pos: "before" | "after" | "left" | "right" | null) => void) {
  return (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();

    // Only clear if we're actually leaving the element (not entering a child)
    const relatedTarget = e.relatedTarget as HTMLElement;
    const currentTarget = e.currentTarget as HTMLElement;

    if (!currentTarget.contains(relatedTarget)) {
      setDragOverNodeId(null);
      setDropPosition(null);
    }
  };
}

/** Creates an async drop handler that delegates to the appropriate drop strategy. */
export function createHandleDrop(params: DragDropHandlerParams, dropPosition: "before" | "after" | "left" | "right" | null) {
  return async (e: React.DragEvent, nodeId: string) => {
    const {
      container: containerOrGetter,
      dispatch,
      toast,
      draggingNodeId,
      setDraggingNodeId,
      setDragOverNodeId,
      setDropPosition,
      setIsUploading,
      onUploadImage,
    } = params;
    const container = typeof containerOrGetter === 'function' ? containerOrGetter() : containerOrGetter;

    e.preventDefault();
    e.stopPropagation();

    const cleanup = () => {
      setDragOverNodeId(null);
      setDropPosition(null);
      setDraggingNodeId(null);
    };

    // If no dragging node, handle as file drop
    if (!draggingNodeId) {
      await handleFileDrop(e, nodeId, {
        dispatch, toast, setIsUploading, onUploadImage, dropPosition, cleanup,
      });
      return;
    }

    // Don't drop on itself
    if (draggingNodeId === nodeId) {
      cleanup();
      return;
    }

    const draggingResult = findNodeAnywhere(draggingNodeId, container);
    const targetResult = findNodeAnywhere(nodeId, container);

    if (!draggingResult || !targetResult) {
      cleanup();
      return;
    }

    const ctx: DropContext = {
      container, dispatch, draggingNodeId,
      draggingResult, targetNodeId: nodeId, targetResult,
      dropPosition: (dropPosition || "after") as DropPosition,
      cleanup,
    };

    const inSameFlexContainer =
      draggingResult.parentId &&
      targetResult.parentId &&
      draggingResult.parentId === targetResult.parentId;

    const isHorizontal = dropPosition === "left" || dropPosition === "right";

    if (isHorizontal) {
      if (inSameFlexContainer && draggingResult.parent && targetResult.parent) {
        handleFlexReorder(ctx);
      } else if (isTextNode(draggingResult.node) && isTextNode(targetResult.node)) {
        handleFlexMerge(ctx);
      } else {
        cleanup();
      }
    } else if (draggingResult.parentId && draggingResult.parent) {
      handleFlexExtract(ctx);
    } else {
      handleRootMove(ctx);
    }
  };
}

/**
 * Drop Strategy Functions
 *
 * Extracted from the monolithic createHandleDrop into focused, testable strategies.
 * Each strategy handles one specific drag-and-drop scenario.
 */

import { ContainerNode, TextNode, EditorNode, isTextNode, isContainerNode } from '../types';
import { EditorActions } from '../reducer/actions';
import { generateId } from '../utils/id-generator';
import { uploadImage } from '../utils/image-upload';

interface FindNodeResult {
  node: EditorNode;
  parent?: ContainerNode;
  parentId?: string;
}

export type DropPosition = "before" | "after" | "left" | "right";

export interface DropContext {
  container: ContainerNode;
  dispatch: (action: any) => void;
  draggingNodeId: string;
  draggingResult: FindNodeResult;
  targetNodeId: string;
  targetResult: FindNodeResult;
  dropPosition: DropPosition;
  cleanup: () => void;
}

/**
 * Strategy 1: Reorder children within the same flex container.
 * Handles left/right drops where both nodes share a flex parent.
 */
export function handleFlexReorder(ctx: DropContext): void {
  const { draggingNodeId, targetNodeId, dropPosition, dispatch, cleanup } = ctx;
  const parent = ctx.draggingResult.parent!;
  const newChildren = [...parent.children];

  const dragIndex = newChildren.findIndex((c) => c.id === draggingNodeId);
  const targetIndex = newChildren.findIndex((c) => c.id === targetNodeId);

  // Remove the dragged item from its current position
  const [draggedItem] = newChildren.splice(dragIndex, 1);

  // Calculate the new target index after removal
  const adjustedTargetIndex =
    dragIndex < targetIndex ? targetIndex - 1 : targetIndex;

  // Insert at the correct position based on drop side
  if (dropPosition === "left") {
    newChildren.splice(adjustedTargetIndex, 0, draggedItem);
  } else {
    newChildren.splice(adjustedTargetIndex + 1, 0, draggedItem);
  }

  dispatch(
    EditorActions.updateNode(parent.id, {
      children: newChildren as any,
    })
  );

  cleanup();
}

/**
 * Strategy 2: Merge separate images into a flex container.
 * Handles left/right drops between images not in the same flex parent,
 * including adding to an existing flex container or creating a new one.
 */
export function handleFlexMerge(ctx: DropContext): void {
  const {
    container, dispatch, draggingNodeId, draggingResult,
    targetNodeId, targetResult, dropPosition, cleanup,
  } = ctx;
  const draggingNode = draggingResult.node;
  const targetNode = targetResult.node;

  // If target is in a flex container, add dragged node to it
  if (
    targetResult.parentId &&
    targetResult.parent?.attributes?.layoutType === "flex"
  ) {
    const parent = targetResult.parent;
    const targetIndex = parent.children.findIndex((c) => c.id === targetNodeId);
    const newChildren = [...parent.children];

    if (dropPosition === "left") {
      newChildren.splice(targetIndex, 0, draggingNode as TextNode);
    } else {
      newChildren.splice(targetIndex + 1, 0, draggingNode as TextNode);
    }

    dispatch(
      EditorActions.batch([
        EditorActions.deleteNode(draggingNodeId),
        EditorActions.updateNode(parent.id, {
          children: newChildren as any,
        }),
      ])
    );

    cleanup();
    return;
  }

  // Neither is in a flex container -- create a new one

  // Find reference nodes at root level
  const targetRootIndex = container.children.findIndex(
    (n) =>
      n.id === targetNodeId ||
      (isContainerNode(n) &&
        (n as ContainerNode).children.some((c) => c.id === targetNodeId))
  );
  const draggingRootIndex = container.children.findIndex(
    (n) =>
      n.id === draggingNodeId ||
      (isContainerNode(n) &&
        (n as ContainerNode).children.some((c) => c.id === draggingNodeId))
  );

  // Find a stable reference node for insertion
  let referenceNodeId: string | null = null;
  let insertPosition: "before" | "after" = "after";

  const firstIndex = Math.min(targetRootIndex, draggingRootIndex);
  if (firstIndex > 0) {
    referenceNodeId = container.children[firstIndex - 1].id;
    insertPosition = "after";
  } else if (container.children.length > 2) {
    for (let i = 0; i < container.children.length; i++) {
      if (i !== targetRootIndex && i !== draggingRootIndex) {
        referenceNodeId = container.children[i].id;
        insertPosition = i < firstIndex ? "after" : "before";
        break;
      }
    }
  }

  // Create a flex container with both images
  const flexContainer: ContainerNode = {
    id: generateId("flex-container"),
    type: "container",
    children:
      dropPosition === "left"
        ? [draggingNode as TextNode, targetNode as TextNode]
        : [targetNode as TextNode, draggingNode as TextNode],
    attributes: {
      layoutType: "flex",
      gap: "4",
    },
  };

  const actions: any[] = [
    EditorActions.deleteNode(draggingNodeId),
    EditorActions.deleteNode(targetNodeId),
  ];

  if (referenceNodeId) {
    actions.push(
      EditorActions.insertNode(flexContainer, referenceNodeId, insertPosition)
    );
  } else {
    actions.push(
      EditorActions.replaceContainer({
        ...container,
        children: [flexContainer],
      })
    );
  }

  dispatch(EditorActions.batch(actions));
  cleanup();
}

/**
 * Strategy 3: Extract an image from a flex container and place it elsewhere.
 * Handles vertical drops where the source is inside a flex container.
 * Also handles unwrapping the flex container when only one child remains.
 */
export function handleFlexExtract(ctx: DropContext): void {
  const {
    container, dispatch, draggingNodeId, draggingResult,
    targetNodeId, dropPosition, cleanup,
  } = ctx;
  const draggingNode = draggingResult.node;
  const parent = draggingResult.parent!;
  const remainingChildren = parent.children.filter(
    (c) => c.id !== draggingNodeId
  );

  const insertPos =
    dropPosition === "before" || dropPosition === "after"
      ? dropPosition
      : "after";

  const actions: any[] = [];

  // If only one child remains, unwrap the container
  if (remainingChildren.length === 1) {
    const parentIndex = container.children.findIndex(
      (c) => c.id === parent.id
    );

    const isTargetTheFlexContainer = targetNodeId === parent.id;

    if (isTargetTheFlexContainer) {
      let referenceNodeId: string | null = null;
      let referencePosition: "before" | "after" = insertPos === "before" ? "before" : "after";

      if (parentIndex > 0) {
        referenceNodeId = container.children[parentIndex - 1].id;
        referencePosition = "after";
      } else if (parentIndex < container.children.length - 1) {
        referenceNodeId = container.children[parentIndex + 1].id;
        referencePosition = "before";
      }

      if (referenceNodeId) {
        actions.push(
          EditorActions.insertNode(
            remainingChildren[0],
            referenceNodeId,
            referencePosition
          )
        );
        actions.push(
          EditorActions.insertNode(
            draggingNode,
            remainingChildren[0].id,
            insertPos
          )
        );
        actions.push(EditorActions.deleteNode(parent.id));
      } else {
        actions.push(EditorActions.insertNode(remainingChildren[0], container.id, "append"));
        actions.push(EditorActions.insertNode(draggingNode, remainingChildren[0].id, insertPos));
        actions.push(EditorActions.deleteNode(parent.id));
      }
    } else {
      // Target is NOT the flex container
      const targetIndex = container.children.findIndex((c) => c.id === targetNodeId);
      const isTargetBeforeFlex = targetIndex === parentIndex - 1 && insertPos === "after";
      const isTargetAfterFlex = targetIndex === parentIndex + 1 && insertPos === "before";

      if (isTargetBeforeFlex || isTargetAfterFlex) {
        actions.push(EditorActions.insertNode(draggingNode, targetNodeId, insertPos));

        if (isTargetBeforeFlex) {
          actions.push(
            EditorActions.insertNode(remainingChildren[0], draggingNodeId, "after")
          );
        } else {
          actions.push(
            EditorActions.insertNode(remainingChildren[0], draggingNodeId, "before")
          );
        }

        actions.push(EditorActions.deleteNode(parent.id));
      } else {
        actions.push(EditorActions.insertNode(draggingNode, targetNodeId, insertPos));
        actions.push(EditorActions.deleteNode(draggingNodeId));

        if (parentIndex > 0) {
          const prevNode = container.children[parentIndex - 1];
          actions.push(
            EditorActions.insertNode(remainingChildren[0], prevNode.id, "after")
          );
        } else if (parentIndex === 0 && container.children.length > 1) {
          const nextNode = container.children[1];
          actions.push(
            EditorActions.insertNode(remainingChildren[0], nextNode.id, "before")
          );
        } else {
          actions.push(
            EditorActions.insertNode(remainingChildren[0], container.id, "append")
          );
        }

        actions.push(EditorActions.deleteNode(parent.id));
      }
    }
  } else {
    // Multiple children remain, just update the flex container
    actions.push(
      EditorActions.updateNode(parent.id, {
        children: remainingChildren as any,
      })
    );
    actions.push(EditorActions.insertNode(draggingNode, targetNodeId, insertPos));
  }

  actions.push(EditorActions.setActiveNode(draggingNodeId));
  dispatch(EditorActions.batch(actions));
  cleanup();
}

/**
 * Strategy 4: Move blocks at root level.
 * Always uses moveNode (never swapNodes) for predictable ordering.
 */
export function handleRootMove(ctx: DropContext): void {
  const {
    dispatch, draggingNodeId, draggingResult,
    targetNodeId, dropPosition, cleanup,
  } = ctx;
  const draggingNode = draggingResult.node;

  const insertPos =
    dropPosition === "before" || dropPosition === "after"
      ? dropPosition
      : "after";

  dispatch(
    EditorActions.batch([
      EditorActions.moveNode(draggingNodeId, targetNodeId, insertPos),
      EditorActions.setActiveNode(draggingNodeId),
    ])
  );

  cleanup();
}

export interface FileDropParams {
  dispatch: (action: any) => void;
  toast: any;
  setIsUploading: (uploading: boolean) => void;
  onUploadImage?: (file: File) => Promise<string>;
  dropPosition: DropPosition | null;
  cleanup: () => void;
}

/**
 * Strategy 5: Handle external file upload drops.
 * Processes dropped media files, uploads them, and inserts a node.
 * Toast is kept only for upload failure reporting.
 */
export async function handleFileDrop(
  e: React.DragEvent,
  nodeId: string,
  params: FileDropParams
): Promise<void> {
  const { dispatch, toast, setIsUploading, onUploadImage, dropPosition, cleanup } = params;

  // Try to get files from dataTransfer
  let files: File[] = [];

  if (e.dataTransfer.items) {
    const items = Array.from(e.dataTransfer.items);
    files = items
      .filter((item) => item.kind === "file")
      .map((item) => item.getAsFile())
      .filter((file): file is File => file !== null);
  } else {
    files = Array.from(e.dataTransfer.files);
  }

  // Find first image or video file
  const mediaFile = files.find(
    (file) => file.type.startsWith("image/") || file.type.startsWith("video/")
  );

  if (!mediaFile) {
    cleanup();
    return;
  }

  const isVideo = mediaFile.type.startsWith("video/");
  setIsUploading(true);

  try {
    let mediaUrl: string;

    if (onUploadImage) {
      mediaUrl = await onUploadImage(mediaFile);
    } else {
      const result = await uploadImage(mediaFile);
      if (!result.success || !result.url) {
        throw new Error(result.error || "Upload failed");
      }
      mediaUrl = result.url;
    }

    const mediaNode: TextNode = {
      id: generateId(isVideo ? "video" : "img"),
      type: isVideo ? "video" : "img",
      content: "",
      attributes: {
        src: mediaUrl,
        alt: mediaFile.name,
      },
    };

    const insertPos =
      dropPosition === "before" || dropPosition === "after"
        ? dropPosition
        : "after";

    dispatch(
      EditorActions.batch([
        EditorActions.insertNode(mediaNode, nodeId, insertPos),
        EditorActions.setActiveNode(mediaNode.id),
      ])
    );
  } catch (error) {
    toast({
      variant: "destructive",
      title: "Upload failed",
      description:
        error instanceof Error
          ? error.message
          : "Failed to upload file. Please try again.",
    });
  } finally {
    setIsUploading(false);
    cleanup();
  }
}

/**
 * File Upload Handler Functions
 * 
 * Functions for handling file uploads in the editor
 */

import { EditorActions } from '../reducer/actions';
import { ContainerNode, TextNode } from '../types';
import { uploadImage } from '../utils/image-upload';
import { generateId } from '../utils/id-generator';

export interface FileUploadHandlerParams {
  container: ContainerNode;
  dispatch: React.Dispatch<any>;
  state: any;
  toast: any;
  setIsUploading: (uploading: boolean) => void;
  fileInputRef: React.RefObject<HTMLInputElement | null>;
  multipleFileInputRef: React.RefObject<HTMLInputElement | null>;
  onUploadImage?: (file: File) => Promise<string>;
}

/**
 * Handle single file change (supports both images and videos)
 */
export function createHandleFileChange(params: FileUploadHandlerParams) {
  return async (e: React.ChangeEvent<HTMLInputElement>) => {
    const { container, dispatch, state, toast, setIsUploading, fileInputRef, onUploadImage } = params;
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);

    // Determine if file is image or video
    const isVideo = file.type.startsWith('video/');
    const isImage = file.type.startsWith('image/');

    if (!isImage && !isVideo) {
      toast({
        variant: "destructive",
        title: "Invalid file type",
        description: "Please upload an image or video file.",
      });
      setIsUploading(false);
      return;
    }

    try {
      // Use custom upload handler if provided, otherwise use default
      let fileUrl: string;

      if (onUploadImage) {
        fileUrl = await onUploadImage(file);
      } else {
        const result = await uploadImage(file);
        if (!result.success || !result.url) {
          throw new Error(result.error || "Upload failed");
        }
        fileUrl = result.url;
      }

      // Create new media node (image or video)
      const mediaNode: TextNode = {
        id: generateId(isVideo ? 'video' : 'img'),
        type: isVideo ? "video" : "img",
        content: "", // Optional caption
        attributes: {
          src: fileUrl,
          alt: file.name,
        },
      };

      // Insert media after current node or at end
      const targetId =
        state.activeNodeId ||
        container.children[container.children.length - 1]?.id;
      if (targetId) {
        dispatch(EditorActions.insertNode(mediaNode, targetId, "after"));
      } else {
        dispatch(EditorActions.insertNode(mediaNode, container.id, "append"));
      }

      toast({
        title: `${isVideo ? 'Video' : 'Image'} uploaded`,
        description: `Your ${isVideo ? 'video' : 'image'} has been added to the editor.`,
      });
    } catch (error) {
      toast({
        variant: "destructive",
        title: "Upload failed",
        description:
          error instanceof Error
            ? error.message
            : "An unexpected error occurred",
      });
    } finally {
      setIsUploading(false);
      // Reset file input
      if (fileInputRef.current) {
        fileInputRef.current.value = "";
      }
    }
  };
}

/**
 * Handle multiple files change (supports both images and videos)
 */
export function createHandleMultipleFilesChange(params: FileUploadHandlerParams) {
  return async (e: React.ChangeEvent<HTMLInputElement>) => {
    const { container, dispatch, state, toast, setIsUploading, multipleFileInputRef, onUploadImage } = params;
    const files = Array.from(e.target.files || []);
    if (files.length === 0) return;

    setIsUploading(true);

    try {
      // Filter to only images and videos
      const validFiles = files.filter(
        (file) => file.type.startsWith('image/') || file.type.startsWith('video/')
      );

      if (validFiles.length === 0) {
        toast({
          variant: "destructive",
          title: "Invalid file types",
          description: "Please upload only image or video files.",
        });
        setIsUploading(false);
        return;
      }

      // Upload all media files
      const uploadPromises = validFiles.map(async (file) => {
        if (onUploadImage) {
          return await onUploadImage(file);
        } else {
          const result = await uploadImage(file);
          if (!result.success || !result.url) {
            throw new Error(result.error || "Upload failed");
          }
          return result.url;
        }
      });

      const mediaUrls = await Promise.all(uploadPromises);

      // Create media nodes (images and videos)
      const mediaNodes: TextNode[] = mediaUrls.map((url, index) => {
        const file = validFiles[index];
        const isVideo = file.type.startsWith('video/');

        return {
          id: generateId(isVideo ? 'video' : 'img'),
          type: isVideo ? "video" : "img",
          content: "",
          attributes: {
            src: url,
            alt: file.name,
          },
        };
      });

      // Create flex container with media
      const flexContainer: ContainerNode = {
        id: generateId("flex-container"),
        type: "container",
        children: mediaNodes,
        attributes: {
          layoutType: "flex",
          gap: "4",
          flexWrap: "wrap", // Enable wrapping
        },
      };

      // Insert the flex container after current node or at end
      const targetId =
        state.activeNodeId ||
        container.children[container.children.length - 1]?.id;
      if (targetId) {
        dispatch(EditorActions.insertNode(flexContainer, targetId, "after"));
      } else {
        dispatch(
          EditorActions.insertNode(flexContainer, container.id, "append")
        );
      }

      // For flex containers, set the first child as active (containers themselves aren't focusable)
      if (mediaNodes.length > 0) {
        dispatch(EditorActions.setActiveNode(mediaNodes[0].id));
      }

      const videoCount = validFiles.filter((f) => f.type.startsWith('video/')).length;
      const imageCount = validFiles.filter((f) => f.type.startsWith('image/')).length;
      let description = "";
      if (videoCount > 0 && imageCount > 0) {
        description = `${imageCount} image(s) and ${videoCount} video(s) added in a flex layout.`;
      } else if (videoCount > 0) {
        description = `${videoCount} video(s) added in a flex layout.`;
      } else {
        description = `${imageCount} image(s) added in a flex layout.`;
      }

      toast({
        title: "Media uploaded",
        description,
      });
    } catch (error) {
      toast({
        variant: "destructive",
        title: "Upload failed",
        description:
          error instanceof Error
            ? error.message
            : "An unexpected error occurred",
      });
    } finally {
      setIsUploading(false);
      // Reset file input
      if (multipleFileInputRef.current) {
        multipleFileInputRef.current.value = "";
      }
    }
  };
}

