/**
 * Flex Container Drag-and-Drop Handlers
 *
 * Handles drag and drop operations for flex containers
 */

import { EditorActions } from '../reducer/actions';
import { ContainerNode, TextNode, isTextNode } from '../types';
import { findNodeAnywhere } from '../utils/editor-helpers';

export interface FlexContainerHandlerParams {
  container: ContainerNode;
  dispatch: React.Dispatch<any>;
  draggingNodeId: string | null;
  setDragOverFlexId: (id: string | null) => void;
  setFlexDropPosition: (pos: "left" | "right" | null) => void;
}

/**
 * Handle drag over on flex container edges
 */
export function createHandleFlexContainerDragOver(params: FlexContainerHandlerParams) {
  return (e: React.DragEvent, flexContainerId: string, position: "left" | "right" | null) => {
    const { container, draggingNodeId, setDragOverFlexId, setFlexDropPosition } = params;

    e.preventDefault();
    e.stopPropagation();

    // Only proceed if we have a dragging node from state
    if (!draggingNodeId) {
      return;
    }

    // Find the dragging node
    const draggingResult = findNodeAnywhere(draggingNodeId, container);

    if (!draggingResult || !isTextNode(draggingResult.node)) {
      // Not a valid node to drag
      setDragOverFlexId(null);
      setFlexDropPosition(null);
      return;
    }

    const draggingNode = draggingResult.node as TextNode;

    // Only allow image nodes
    if (draggingNode.type !== 'img') {
      setDragOverFlexId(null);
      setFlexDropPosition(null);
      return;
    }

    // Check if we're in the edge zones
    if (position) {
      setDragOverFlexId(flexContainerId);
      setFlexDropPosition(position);
      e.dataTransfer.dropEffect = "move";
    } else {
      setDragOverFlexId(null);
      setFlexDropPosition(null);
    }
  };
}

/**
 * Handle drag leave on flex container
 */
export function createHandleFlexContainerDragLeave(
  setDragOverFlexId: (id: string | null) => void,
  setFlexDropPosition: (pos: "left" | "right" | null) => void
) {
  return (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();

    setDragOverFlexId(null);
    setFlexDropPosition(null);
  };
}

/**
 * Handle drop on flex container edges
 */
export function createHandleFlexContainerDrop(params: FlexContainerHandlerParams) {
  return (e: React.DragEvent, flexContainerId: string, position: "left" | "right" | null) => {
    const {
      container,
      dispatch,
      draggingNodeId,
      setDragOverFlexId,
      setFlexDropPosition,
    } = params;

    e.preventDefault();
    e.stopPropagation();

    if (!position || !draggingNodeId) {
      setDragOverFlexId(null);
      setFlexDropPosition(null);
      return;
    }

    // Find the dragging node and the flex container
    const draggingResult = findNodeAnywhere(draggingNodeId, container);
    const flexResult = findNodeAnywhere(flexContainerId, container);

    if (!draggingResult || !flexResult) {
      setDragOverFlexId(null);
      setFlexDropPosition(null);
      return;
    }

    const draggingNode = draggingResult.node as TextNode;
    const flexContainer = flexResult.node as ContainerNode;

    // Only handle image nodes
    if (draggingNode.type !== 'img') {
      setDragOverFlexId(null);
      setFlexDropPosition(null);
      return;
    }

    // Check if the dragging node is already in this flex container
    const isInSameContainer = draggingResult.parentId === flexContainerId;

    if (isInSameContainer) {
      // Reordering within the same flex container
      const currentIndex = flexContainer.children.findIndex(c => c.id === draggingNodeId);
      const newChildren = [...flexContainer.children];

      // Remove from current position
      const [movedNode] = newChildren.splice(currentIndex, 1);

      // Insert at new position
      if (position === "left") {
        newChildren.unshift(movedNode);
      } else {
        newChildren.push(movedNode);
      }

      dispatch(EditorActions.updateNode(flexContainerId, {
        children: newChildren as any,
      }));
    } else {
      // Adding image from outside to the flex container
      const newChildren = [...flexContainer.children];

      if (position === "left") {
        newChildren.unshift(draggingNode);
      } else {
        newChildren.push(draggingNode);
      }

      dispatch(
        EditorActions.batch([
          EditorActions.deleteNode(draggingNodeId),
          EditorActions.updateNode(flexContainerId, {
            children: newChildren as any,
          }),
        ])
      );
    }

    setDragOverFlexId(null);
    setFlexDropPosition(null);
  };
}

/**
 * Image Selection Handler Functions
 * 
 * Functions for handling multi-image selection and flex container creation
 */

import { EditorActions } from '../reducer/actions';
import { ContainerNode, TextNode } from '../types';
import { findNodeAnywhere } from '../utils/editor-helpers';
import { generateId } from '../utils/id-generator';

/** Parameters shared by image selection handler factories. */
export interface ImageSelectionHandlerParams {
  container: ContainerNode | (() => ContainerNode);
  dispatch: React.Dispatch<any>;
  toast: any;
}

/** Creates a handler that groups two or more selected images into a flex container node. */
export function createHandleGroupSelectedImages(
  params: ImageSelectionHandlerParams,
  selectedImageIds: Set<string>,
  clearSelection: () => void
) {
  return () => {
    const { container: containerOrGetter, dispatch, toast } = params;
    const container = typeof containerOrGetter === 'function' ? containerOrGetter() : containerOrGetter;

    if (selectedImageIds.size < 2) {
      toast({
        variant: "destructive",
        title: "Not enough images",
        description: "Please select at least 2 images to group",
      });
      return;
    }

    // Find all selected image nodes
    const imageNodes: TextNode[] = [];
    const imageResults = [];

    for (const imageId of selectedImageIds) {
      const result = findNodeAnywhere(imageId, container);
      if (result && result.node.type === 'img') {
        imageNodes.push(result.node as TextNode);
        imageResults.push(result);
      }
    }

    if (imageNodes.length < 2) {
      toast({
        variant: "destructive",
        title: "Invalid selection",
        description: "Could not find all selected images",
      });
      return;
    }

    // Find the position to insert the new flex container
    // Use the position of the first selected image (topmost in the document)
    let referenceNodeId: string | null = null;
    let insertPosition: "before" | "after" = "after";

    // Find the first image in the root container
    for (const child of container.children) {
      if (selectedImageIds.has(child.id)) {
        // Found the first selected image at root level
        const index = container.children.indexOf(child);
        if (index > 0) {
          referenceNodeId = container.children[index - 1].id;
          insertPosition = "after";
        } else if (container.children.length > imageNodes.length) {
          // Find a non-selected node to use as reference
          const nextNonSelected = container.children.find(
            c => !selectedImageIds.has(c.id)
          );
          if (nextNonSelected) {
            referenceNodeId = nextNonSelected.id;
            insertPosition = "before";
          }
        }
        break;
      }
    }

    // Create a flex container with all selected images
    const flexContainer: ContainerNode = {
      id: generateId("flex-container"),
      type: "container",
      children: imageNodes,
      attributes: {
        layoutType: "flex",
        gap: "4",
        flexWrap: "wrap",
      },
    };

    // Batch: delete all selected images and insert flex container
    const actions: any[] = [];

    // Delete all selected images
    for (const imageId of selectedImageIds) {
      actions.push(EditorActions.deleteNode(imageId));
    }

    // Insert the flex container
    if (referenceNodeId) {
      actions.push(
        EditorActions.insertNode(flexContainer, referenceNodeId, insertPosition)
      );
    } else {
      // If no reference node, replace entire container
      actions.push(
        EditorActions.replaceContainer({
          ...container,
          children: [flexContainer],
        })
      );
    }

    dispatch(EditorActions.batch(actions));

    toast({
      title: "Images grouped!",
      description: `${imageNodes.length} images placed in a flex layout`,
    });

    clearSelection();
  };
}

/** Creates a handler that toggles an image's presence in the set of selected image IDs. */
export function createHandleToggleImageSelection(
  selectedImageIds: Set<string>,
  setSelectedImageIds: (ids: Set<string>) => void
) {
  return (imageId: string) => {
    const newSelection = new Set(selectedImageIds);
    if (newSelection.has(imageId)) {
      newSelection.delete(imageId);
    } else {
      newSelection.add(imageId);
    }
    setSelectedImageIds(newSelection);
  };
}

/** Creates a handler that clears all currently selected image IDs. */
export function createHandleClearImageSelection(
  setSelectedImageIds: (ids: Set<string>) => void
) {
  return () => {
    setSelectedImageIds(new Set());
  };
}

/** Checks whether all currently selected images share the same flex container parent, returning the parent ID if so. */
export function checkImagesInSameFlex(
  params: ImageSelectionHandlerParams,
  selectedImageIds: Set<string>
): { inSameFlex: boolean; flexParentId: string | null } {
  const { container: containerOrGetter } = params;
  const container = typeof containerOrGetter === 'function' ? containerOrGetter() : containerOrGetter;

  if (selectedImageIds.size < 2) {
    return { inSameFlex: false, flexParentId: null };
  }

  const imageResults = [];
  for (const imageId of selectedImageIds) {
    const result = findNodeAnywhere(imageId, container);
    if (result && result.node.type === 'img') {
      imageResults.push(result);
    }
  }

  // Check if all images have the same parent that is a flex container
  const firstParentId = imageResults[0]?.parentId;
  const firstParent = imageResults[0]?.parent;

  if (!firstParentId || !firstParent || firstParent.attributes?.layoutType !== 'flex') {
    return { inSameFlex: false, flexParentId: null };
  }

  // Check all images have the same flex parent
  const allSameParent = imageResults.every(
    r => r.parentId === firstParentId && r.parent?.attributes?.layoutType === 'flex'
  );

  return {
    inSameFlex: allSameParent,
    flexParentId: allSameParent ? firstParentId : null,
  };
}

/** Creates a handler that reverses the order of selected images within their shared flex container. */
export function createHandleReverseImagesInFlex(
  params: ImageSelectionHandlerParams,
  selectedImageIds: Set<string>,
  flexParentId: string
) {
  return () => {
    const { container: containerOrGetter, dispatch, toast } = params;
    const container = typeof containerOrGetter === 'function' ? containerOrGetter() : containerOrGetter;

    // Find the flex container
    const flexResult = findNodeAnywhere(flexParentId, container);
    if (!flexResult || flexResult.node.type !== 'container') {
      return;
    }

    const flexContainer = flexResult.node as ContainerNode;
    const children = [...flexContainer.children];

    // Separate selected and non-selected images
    const selectedIndices: number[] = [];
    const selectedNodes: TextNode[] = [];

    children.forEach((child, index) => {
      if (selectedImageIds.has(child.id)) {
        selectedIndices.push(index);
        selectedNodes.push(child as TextNode);
      }
    });

    // Reverse only the selected images
    selectedNodes.reverse();

    // Put them back in their positions
    selectedIndices.forEach((originalIndex, i) => {
      children[originalIndex] = selectedNodes[i];
    });

    // Update the flex container
    dispatch(
      EditorActions.updateNode(flexParentId, {
        children: children as any,
      })
    );

    toast({
      title: "Images reversed!",
      description: `Order of ${selectedImageIds.size} images reversed`,
    });
  };
}

/** Creates a handler that removes the selected images from their flex container and places them as standalone root-level nodes. */
export function createHandleExtractFromFlex(
  params: ImageSelectionHandlerParams,
  selectedImageIds: Set<string>,
  flexParentId: string,
  clearSelection: () => void
) {
  return () => {
    const { container: containerOrGetter, dispatch, toast } = params;
    const container = typeof containerOrGetter === 'function' ? containerOrGetter() : containerOrGetter;

    // Find the flex container
    const flexResult = findNodeAnywhere(flexParentId, container);
    if (!flexResult || flexResult.node.type !== 'container') {
      return;
    }

    const flexContainer = flexResult.node as ContainerNode;
    const imagesToExtract: TextNode[] = [];
    const remainingChildren = flexContainer.children.filter((child) => {
      if (selectedImageIds.has(child.id)) {
        imagesToExtract.push(child as TextNode);
        return false;
      }
      return true;
    });

    const actions: any[] = [];

    // If only one or no children remain, unwrap the flex container
    if (remainingChildren.length <= 1) {
      // Find the flex container's position in root
      const flexIndex = container.children.findIndex(c => c.id === flexParentId);

      if (flexIndex > 0) {
        const prevNode = container.children[flexIndex - 1];

        // Insert remaining child if exists
        if (remainingChildren.length === 1) {
          actions.push(
            EditorActions.insertNode(remainingChildren[0], prevNode.id, 'after')
          );
        }

        // Insert extracted images
        let lastNodeId = remainingChildren.length === 1 ? remainingChildren[0].id : prevNode.id;
        imagesToExtract.forEach(image => {
          actions.push(EditorActions.insertNode(image, lastNodeId, 'after'));
          lastNodeId = image.id;
        });

        // Delete the flex container
        actions.push(EditorActions.deleteNode(flexParentId));
      } else {
        // First position - just delete flex and add all children
        actions.push(EditorActions.deleteNode(flexParentId));

        if (remainingChildren.length === 1) {
          actions.push(
            EditorActions.insertNode(
              remainingChildren[0],
              container.children[1]?.id || container.id,
              container.children[1]?.id ? 'before' : 'append'
            )
          );
        }

        imagesToExtract.forEach(image => {
          actions.push(
            EditorActions.insertNode(
              image,
              container.children[1]?.id || container.id,
              container.children[1]?.id ? 'before' : 'append'
            )
          );
        });
      }
    } else {
      // Update flex container with remaining children
      actions.push(
        EditorActions.updateNode(flexParentId, {
          children: remainingChildren as any,
        })
      );

      // Insert extracted images after the flex container
      let lastNodeId = flexParentId;
      imagesToExtract.forEach(image => {
        actions.push(EditorActions.insertNode(image, lastNodeId, 'after'));
        lastNodeId = image.id;
      });
    }

    dispatch(EditorActions.batch(actions));

    toast({
      title: "Images extracted!",
      description: `${imagesToExtract.length} images removed from flex container`,
    });

    clearSelection();
  };
}

/**
 * Editor Handlers Index
 * 
 * Central export point for all editor handler functions
 */

// Selection handlers
export * from './selection-handlers';

// Keyboard handlers
export * from './keyboard-handlers';

// Drag and drop handlers
export * from './drag-drop-handlers';

// File upload handlers
export * from './file-upload-handlers';

// Node operation handlers
export * from './node-operation-handlers';

/**
 * Keyboard Event Handlers
 *
 * Functions for handling keyboard events in the editor
 */

import { EditorActions } from "../reducer/actions";
import {
  ContainerNode,
  TextNode,
  getNodeTextContent,
  hasInlineChildren,
  isTextNode,
} from "../types";
import { findNodeInTree, parseDOMToInlineChildren } from "../utils/editor-helpers";
import { generateId } from "../utils/id-generator";

/** Parameters shared by all keyboard handler factory functions. */
export interface KeyboardHandlerParams {
  container: ContainerNode | (() => ContainerNode);
  dispatch: React.Dispatch<any>;
  nodeRefs: React.MutableRefObject<Map<string, HTMLElement>>;
  lastEnterTime: React.MutableRefObject<number>;
  onToggleImageSelection?: (nodeId: string) => void;
  isComposingRef?: React.MutableRefObject<boolean>;
}

/** Creates a debounced content-change handler that parses the DOM and dispatches the appropriate update action. */
export function createHandleContentChange(
  params: KeyboardHandlerParams,
  contentUpdateTimers: React.MutableRefObject<Map<string, NodeJS.Timeout>>,
  isComposingRef?: React.MutableRefObject<boolean>
) {
  return (nodeId: string, element: HTMLElement) => {
    const { container: containerOrGetter, dispatch } = params;
    const container = typeof containerOrGetter === 'function' ? containerOrGetter() : containerOrGetter;
    const result = findNodeInTree(nodeId, container);
    if (!result || !isTextNode(result.node)) return;
    const node = result.node as TextNode;

    const newContent = element.textContent || "";

    // Get the current text content (from plain content or inline children)
    const currentContent = getNodeTextContent(node);

    // Only update if content actually changed
    if (newContent !== currentContent) {
      // Clear any existing timer for this node
      const existingTimer = contentUpdateTimers.current.get(nodeId);
      if (existingTimer) {
        clearTimeout(existingTimer);
      }

      // Debounce: batch rapid keystrokes into one state update (50ms window)
      const timer = setTimeout(() => {
        // IME reschedule: don't dispatch during active composition (e.g. CJK input).
        // The compositionend handler will call onInput to flush once composition ends.
        if (isComposingRef?.current) {
          const rescheduleTimer = setTimeout(() => {
            contentUpdateTimers.current.delete(nodeId);
          }, 50);
          contentUpdateTimers.current.set(nodeId, rescheduleTimer);
          return;
        }

        // Auto-detect ordered list pattern: "1. ", "2. ", etc. (only with space)
      const orderedListMatch = newContent.match(/^(\d+)\.\s(.+)$/);
      // Auto-detect unordered list pattern: "- " or "* "
      const unorderedListMatch = newContent.match(/^[-*]\s(.+)$/);

      if (orderedListMatch && node.type === "p") {
        // Convert to ordered list item and remove only the number prefix
        const [_match, _number, content] = orderedListMatch;

        dispatch(
          EditorActions.updateNode(node.id, {
            type: "ol",
            content: content,
          })
        );
        contentUpdateTimers.current.delete(nodeId);
        return;
      } else if (unorderedListMatch && node.type === "p") {
        // Convert to unordered list item and remove the bullet prefix
        const [_, content] = unorderedListMatch;

        dispatch(
          EditorActions.updateNode(node.id, {
            type: "li",
            content: content,
          })
        );
        contentUpdateTimers.current.delete(nodeId);
        return;
      } else if (node.type === "p" && /^(#{1,6})\s(.+)$/.test(newContent)) {
        // Auto-detect heading pattern: "# text", "## text", ..., "###### text"
        const headingMatch = newContent.match(/^(#{1,6})\s(.+)$/)!;
        const level = headingMatch[1].length;
        const content = headingMatch[2];
        const headingType = `h${level}` as TextNode["type"];

        dispatch(
          EditorActions.updateNode(node.id, {
            type: headingType,
            content: content,
          })
        );
        contentUpdateTimers.current.delete(nodeId);
        return;
      } else if (node.type === "p" && /^>\s(.+)$/.test(newContent)) {
        // Auto-detect blockquote: "> text"
        const blockquoteMatch = newContent.match(/^>\s(.+)$/)!;

        dispatch(
          EditorActions.updateNode(node.id, {
            type: "blockquote",
            content: blockquoteMatch[1],
          })
        );
        contentUpdateTimers.current.delete(nodeId);
        return;
      } else if (node.type === "p" && /^(-{3,}|\*{3,}|_{3,})$/.test(newContent)) {
        // Auto-detect horizontal rule: "---", "***", or "___"
        dispatch(
          EditorActions.updateNode(node.id, {
            type: "hr",
            content: "",
          })
        );
        contentUpdateTimers.current.delete(nodeId);
        return;
      } else if (node.type === "p" && newContent === "```") {
        // Auto-detect code block: "```"
        dispatch(
          EditorActions.updateNode(node.id, {
            type: "code",
            content: "",
          })
        );
        contentUpdateTimers.current.delete(nodeId);
        return;
      } else if (
        node.type === "li" &&
        (node.lines || newContent.includes("\n"))
      ) {
        // List items with line breaks should always use lines structure
        const textLines = newContent
          .split("\n")
          .filter((line) => line.trim() !== "");

        if (textLines.length > 1) {
          // Multiple lines - use lines structure
          const updatedLines = textLines.map((lineText) => {
            // Remove number prefix if present (e.g., "1. text" -> "text")
            const cleanedText = lineText.replace(/^\d+\.\s*/, "");
            return { content: cleanedText };
          });

          dispatch(
            EditorActions.updateNode(node.id, {
              lines: updatedLines,
              content: undefined, // Clear simple content
              children: undefined, // Clear children
            })
          );
        } else {
          // Single line - use simple content
          dispatch(EditorActions.updateContent(node.id, newContent));
        }
      } else if (!hasInlineChildren(node)) {
        // Simple content node - just update the text
        dispatch(EditorActions.updateContent(node.id, newContent));
      } else {
        // Node has inline children with formatting - parse DOM to preserve formatting
        const parsedChildren = parseDOMToInlineChildren(element);

        dispatch(
          EditorActions.updateNode(node.id, {
            children: parsedChildren,
          })
        );
      }

      // Clean up the timer reference
      contentUpdateTimers.current.delete(nodeId);
    }, 50); // Small 50ms debounce - fast enough to avoid content loss

    // Store the timer reference
    contentUpdateTimers.current.set(nodeId, timer);
    }
  };
}

/** Creates a click handler that toggles image selection when Ctrl/Cmd is held during a click. */
export function createHandleClickWithModifier(params: KeyboardHandlerParams) {
  return (e: React.MouseEvent, nodeId: string) => {
    const { container: containerOrGetter, onToggleImageSelection } = params;
    const container = typeof containerOrGetter === 'function' ? containerOrGetter() : containerOrGetter;

    // Check if Ctrl (Windows/Linux) or Cmd (Mac) is pressed
    const isCtrlOrCmd = e.ctrlKey || e.metaKey;

    if (isCtrlOrCmd && onToggleImageSelection) {
      // Find the node to check if it's an image
      const result = findNodeInTree(nodeId, container);
      if (result && isTextNode(result.node)) {
        const node = result.node as TextNode;

        // Only toggle selection for image nodes
        if (node.type === 'img') {
          e.preventDefault();
          e.stopPropagation();
          onToggleImageSelection(nodeId);
        }
      }
    }
  };
}

/** Creates a keydown handler that manages Enter (block splitting), Backspace (block deletion), and list item logic. */
export function createHandleKeyDown(params: KeyboardHandlerParams) {
  return (e: React.KeyboardEvent<HTMLElement>, nodeId: string) => {
    const { container: containerOrGetter, dispatch, nodeRefs, lastEnterTime } = params;
    const container = typeof containerOrGetter === 'function' ? containerOrGetter() : containerOrGetter;
    // CRITICAL: Get the actual node ID from the DOM element's data attribute
    // This ensures we get the correct ID for nested list items, not the container's ID
    const actualNodeId =
      (e.currentTarget as HTMLElement).getAttribute("data-node-id") || nodeId;

    if (e.key === "Enter") {
      const result = findNodeInTree(actualNodeId, container);
      if (!result || !isTextNode(result.node)) {
        return;
      }
      const node = result.node as TextNode;

      // Shift+Enter: Add a line break within the same block
      if (e.shiftKey) {
        e.preventDefault();
        const selection = window.getSelection();
        if (selection && selection.rangeCount > 0) {
          const range = selection.getRangeAt(0);
          range.deleteContents();
          const br = document.createElement("br");
          range.insertNode(br);
          range.setStartAfter(br);
          range.collapse(true);
          selection.removeAllRanges();
          selection.addRange(range);
        }

        return;
      }

      e.preventDefault();

      const currentTime = Date.now();
      lastEnterTime.current = currentTime;

      // Get cursor position
      const selection = window.getSelection();
      const element = nodeRefs.current.get(actualNodeId);

      if (!element || !selection) return;

      // Calculate cursor position in text
      let cursorPosition = 0;
      if (selection.rangeCount > 0) {
        const range = selection.getRangeAt(0);
        const preSelectionRange = range.cloneRange();
        preSelectionRange.selectNodeContents(element);
        preSelectionRange.setEnd(range.startContainer, range.startOffset);
        cursorPosition = preSelectionRange.toString().length;
      }

      // Get the full text content
      const fullText = getNodeTextContent(node);

      // Check if this is a list item (li or ol)
      if (node.type === "li" || node.type === "ol") {
        // Split content at cursor position
        const beforeCursor = fullText.substring(0, cursorPosition);
        const afterCursor = fullText.substring(cursorPosition);

        // If the current item is empty (no text before or after cursor), exit the list
        if (!beforeCursor.trim() && !afterCursor.trim()) {
          // Convert to paragraph and exit list
          const newNode: TextNode = {
            id: generateId("p"),
            type: "p",
            content: "",
            attributes: {},
          };

          dispatch(EditorActions.batch([
            EditorActions.deleteNode(actualNodeId),
            EditorActions.insertNode(newNode, actualNodeId, "after"),
            EditorActions.setActiveNode(newNode.id),
          ]));

          // Wait for the browser to paint the new DOM node before focusing it.
          requestAnimationFrame(() => {
            const newElement = nodeRefs.current.get(newNode.id);
            if (newElement) {
              newElement.focus();
            }
          });

          return;
        }

        // Create new list item with content after cursor, same type as current
        const newNode: TextNode = {
          id: generateId(node.type),
          type: node.type,
          content: afterCursor,
          attributes: {},
        };

        // Batch all dispatches to avoid intermediate re-renders
        dispatch(EditorActions.batch([
          EditorActions.updateNode(actualNodeId, {
            content: beforeCursor,
            children: undefined, // Clear inline formatting when splitting
            lines: undefined, // Clear multiline structure
          }),
          EditorActions.insertNode(newNode, actualNodeId, "after"),
          EditorActions.setActiveNode(newNode.id),
        ]));

        lastEnterTime.current = currentTime;

        // Wait for the browser to paint the new list item before focusing it.
        requestAnimationFrame(() => {
          const newElement = nodeRefs.current.get(newNode.id);
          if (newElement) {
            newElement.focus();
            // For list items, place cursor after the bullet/number marker
            // For other blocks, place at the start
            if (node.type === "li" || node.type === "ol") {
              // Place cursor at the very start of the text content, which will be after the marker
              const range = document.createRange();
              const sel = window.getSelection();
              // Use setStart on the element itself to position after the list marker
              range.selectNodeContents(newElement);
              range.collapse(true);
              sel?.removeAllRanges();
              sel?.addRange(range);
            } else {
              const range = document.createRange();
              const sel = window.getSelection();
              if (newElement.childNodes.length > 0) {
                const firstNode = newElement.childNodes[0];
                range.setStart(firstNode, 0);
                range.collapse(true);
                sel?.removeAllRanges();
                sel?.addRange(range);
              }
            }
          }
        });

        return;
      }

      // Regular paragraph/heading - create normal block
      {
        // Split content at cursor position
        const beforeCursor = fullText.substring(0, cursorPosition);
        const afterCursor = fullText.substring(cursorPosition);

        // Track the new paragraph ID so the rAF focus callback can use it
        let newParagraphId = "";

        // Check if node has inline children (formatted content)
        const nodeHasInlineChildren = hasInlineChildren(node);

        if (nodeHasInlineChildren && node.children) {
          // Split inline children at cursor position
          let currentPos = 0;
          const beforeChildren: typeof node.children = [];
          const afterChildren: typeof node.children = [];
          let splitDone = false;

          for (const child of node.children) {
            const childLength = (child.content || "").length;
            const childStart = currentPos;
            const childEnd = currentPos + childLength;

            if (splitDone) {
              // Everything after the split goes to the new node
              afterChildren.push({ ...child });
            } else if (cursorPosition <= childStart) {
              // Cursor is before this child - entire child goes to new node
              afterChildren.push({ ...child });
              splitDone = true;
            } else if (cursorPosition >= childEnd) {
              // Cursor is after this child - entire child stays in current node
              beforeChildren.push({ ...child });
            } else {
              // Cursor is in the middle of this child - need to split it
              const offsetInChild = cursorPosition - childStart;

              // Part before cursor stays in current node
              if (offsetInChild > 0) {
                beforeChildren.push({
                  ...child,
                  content: child.content!.substring(0, offsetInChild),
                });
              }

              // Part after cursor goes to new node
              if (offsetInChild < childLength) {
                afterChildren.push({
                  ...child,
                  content: child.content!.substring(offsetInChild),
                });
              }

              splitDone = true;
            }

            currentPos = childEnd;
          }

          // Create new node with children after cursor (always create a paragraph on Enter)
          const newNode: TextNode = {
            id: generateId("p"),
            type: "p",
            content: afterChildren.length === 0 ? afterCursor : node.content,
            children: afterChildren.length > 0 ? afterChildren : undefined,
            attributes: {},
          };

          // Batch all three dispatches into one to avoid intermediate re-renders
          // that could clobber DOM content during the split.
          dispatch(EditorActions.batch([
            EditorActions.updateNode(actualNodeId, {
              children: beforeChildren.length > 0 ? beforeChildren : undefined,
              content:
                beforeChildren.length === 0 ? beforeCursor : node.content,
            }),
            EditorActions.insertNode(newNode, actualNodeId, "after"),
            EditorActions.setActiveNode(newNode.id),
          ]));
          newParagraphId = newNode.id;
        } else {
          // Simple case: no inline children, just plain text
          // Create new node with content after cursor (always create a paragraph on Enter)
          const newNode: TextNode = {
            id: generateId("p"),
            type: "p",
            content: afterCursor,
            attributes: {},
          };

          // Batch all three dispatches into one to avoid intermediate re-renders
          dispatch(EditorActions.batch([
            EditorActions.updateNode(actualNodeId, {
              content: beforeCursor,
            }),
            EditorActions.insertNode(newNode, actualNodeId, "after"),
            EditorActions.setActiveNode(newNode.id),
          ]));
          newParagraphId = newNode.id;
        }

        lastEnterTime.current = currentTime;

        // Wait for the browser to paint the new paragraph before focusing it.
        requestAnimationFrame(() => {
          const newElement = nodeRefs.current.get(newParagraphId);
          if (newElement) {
            newElement.focus();
            // Place cursor at the start of the new node
            const range = document.createRange();
            const sel = window.getSelection();
            if (newElement.childNodes.length > 0) {
              const firstNode = newElement.childNodes[0];
              range.setStart(firstNode, 0);
              range.collapse(true);
              sel?.removeAllRanges();
              sel?.addRange(range);
            }
          }
        });
      }
    } else if (e.key === "Backspace" || e.key === "Delete") {
      const result = findNodeInTree(actualNodeId, container);
      if (!result || !isTextNode(result.node)) return;

      const node = result.node as TextNode;
      const { siblings } = result;

      const selection = window.getSelection();
      const cursorAtStart =
        selection && selection.anchorOffset === 0 && selection.isCollapsed;

      // Get the actual DOM element to check real text content
      const element = nodeRefs.current.get(actualNodeId);
      const domTextContent = element?.textContent || "";

      // Get the full text content (handles both simple content and inline children)
      const fullTextContent = getNodeTextContent(node);
      // For list items, check if the DOM content is empty (what the user actually sees)
      // For other nodes, check both state and DOM
      const isListItemType = node.type === "li" || node.type === "ol";
      const isNodeEmpty = isListItemType 
        ? (!domTextContent || domTextContent.trim() === "")
        : ((!fullTextContent || fullTextContent.trim() === "") && 
           (!domTextContent || domTextContent.trim() === ""));

      // If cursor is at the start and node is empty or BR, delete the node
      if ((cursorAtStart && isNodeEmpty) || node.type === "br") {
        e.preventDefault();

        const currentIndex = siblings.findIndex((n) => n.id === actualNodeId);

        // Don't delete if it's the only node in the container
        if (siblings.length === 1) {
          // Just clear the content instead
          if (hasInlineChildren(node)) {
            dispatch(EditorActions.updateNode(node.id, { children: [] }));
          } else if (node.content) {
            dispatch(EditorActions.updateContent(node.id, ""));
          }
          return;
        }

        // Count non-image blocks
        const nonImageBlocks = siblings.filter((n) => {
          if (!isTextNode(n)) return true; // Container nodes are not images
          return (n as TextNode).type !== "img";
        });

        // Don't delete if this is the last non-image block
        if (nonImageBlocks.length === 1 && node.type !== "img") {
          // Just clear the content instead
          if (hasInlineChildren(node)) {
            dispatch(EditorActions.updateNode(node.id, { children: [] }));
          } else if (node.content) {
            dispatch(EditorActions.updateContent(node.id, ""));
          }
          return;
        }

        // Delete the current node
        dispatch(EditorActions.deleteNode(actualNodeId));

        // Focus the previous node if it exists, otherwise the next one
        const prevNode = siblings[currentIndex - 1];
        const nextNode = siblings[currentIndex + 1];
        const nodeToFocus = prevNode || nextNode;

        if (nodeToFocus) {
          dispatch(EditorActions.setActiveNode(nodeToFocus.id));

          // Wait for the browser to paint after the deleted node is removed, then focus.
          requestAnimationFrame(() => {
            const elementToFocus = nodeRefs.current.get(nodeToFocus.id);
            if (elementToFocus) {
              elementToFocus.focus();
              const range = document.createRange();
              const sel = window.getSelection();

              // Find the last text node to place cursor at the end
              const lastChild = elementToFocus.childNodes[elementToFocus.childNodes.length - 1];
              if (lastChild) {
                if (lastChild.nodeType === Node.TEXT_NODE) {
                  // Place at end of text node
                  range.setStart(lastChild, lastChild.textContent?.length || 0);
                } else {
                  // Place after the last child element
                  range.setStartAfter(lastChild);
                }
                range.collapse(true);
                sel?.removeAllRanges();
                sel?.addRange(range);
              } else if (elementToFocus.childNodes.length === 0) {
                // Empty element, place cursor inside it
                range.selectNodeContents(elementToFocus);
                range.collapse(false);
                sel?.removeAllRanges();
                sel?.addRange(range);
              }
            }
          });
        }
      }
    }
  };
}

/**
 * Node Operation Handler Functions
 *
 * Functions for handling node operations (add, delete, create nested, etc.)
 */

import { EditorActions } from "../reducer/actions";
import {
  ContainerNode,
  StructuralNode,
  TextNode,
  EditorNode,
  isContainerNode,
  isTextNode,
} from "../types";
import { findNodeInTree } from "../utils/editor-helpers";
import { generateId } from "../utils/id-generator";
import { serializeToHtml } from "../utils/serialize-to-html";

/** Parameters shared by node operation handler factories. */
export interface NodeOperationHandlerParams {
  container: ContainerNode | (() => ContainerNode);
  dispatch: React.Dispatch<any>;
  toast: any;
  nodeRefs: React.MutableRefObject<Map<string, HTMLElement>>;
  editorContentRef: React.RefObject<HTMLDivElement | null>;
}

/** Creates a click handler that sets the clicked text node as the active node, ignoring container nodes. */
export function createHandleNodeClick(
  params: Pick<NodeOperationHandlerParams, "container" | "dispatch">
) {
  return (nodeId: string) => {
    const { container: containerOrGetter, dispatch } = params;
    const container = typeof containerOrGetter === 'function' ? containerOrGetter() : containerOrGetter;
    // Don't set container nodes as active - they're not focusable
    // Only text nodes and image nodes can be focused
    const result = findNodeInTree(nodeId, container);
    if (result && isContainerNode(result.node)) {
      // For container nodes, don't set as active
      // The child blocks will handle their own clicks
      return;
    }
    dispatch(EditorActions.setActiveNode(nodeId));
  };
}

/** Creates a handler that deletes a node and automatically unwraps its parent flex container if only one child remains. */
export function createHandleDeleteNode(
  params: Pick<NodeOperationHandlerParams, "container" | "dispatch" | "toast">
) {
  return (nodeId: string) => {
    const { container: containerOrGetter, dispatch, toast } = params;
    const container = typeof containerOrGetter === 'function' ? containerOrGetter() : containerOrGetter;

    // Find the node being deleted to determine its type
    const findNode = (nodes: EditorNode[]): EditorNode | null => {
      for (const node of nodes) {
        if (node.id === nodeId) return node;
        if (isContainerNode(node)) {
          const found = findNode((node as ContainerNode).children);
          if (found) return found;
        }
      }
      return null;
    };

    const nodeToDelete = findNode(container.children);

    // Determine the type of content being deleted
    let contentType = "Block";
    let contentDescription = "The block has been deleted.";

    if (nodeToDelete) {
      if (isContainerNode(nodeToDelete)) {
        const firstChild = (nodeToDelete as ContainerNode).children[0];
        if (firstChild?.type === "table") {
          contentType = "Table removed";
          contentDescription = "The table has been deleted.";
        }
      } else if (nodeToDelete.type === "img") {
        contentType = "Image removed";
        contentDescription = "The image has been deleted.";
      } else if (nodeToDelete.type === "video") {
        contentType = "Video removed";
        contentDescription = "The video has been deleted.";
      }
    }

    // Check if the node is inside a flex container
    const parentContainer = container.children.find(
      (child) =>
        isContainerNode(child) &&
        (child as ContainerNode).children.some((c) => c.id === nodeId)
    );

    if (parentContainer) {
      const containerNode = parentContainer as ContainerNode;
      const remainingChildren = containerNode.children.filter(
        (c) => c.id !== nodeId
      );

      // If only one child left, unwrap it from the container
      if (remainingChildren.length === 1) {
        // Batch: delete container and insert remaining child (single history entry)
        const containerIndex = container.children.findIndex(
          (c) => c.id === parentContainer.id
        );
        const actions: any[] = [EditorActions.deleteNode(parentContainer.id)];

        if (containerIndex > 0) {
          const prevNode = container.children[containerIndex - 1];
          actions.push(
            EditorActions.insertNode(remainingChildren[0], prevNode.id, "after")
          );
        } else if (containerIndex === 0 && container.children.length > 1) {
          const nextNode = container.children[1];
          actions.push(
            EditorActions.insertNode(
              remainingChildren[0],
              nextNode.id,
              "before"
            )
          );
        }

        dispatch(EditorActions.batch(actions));
      } else if (remainingChildren.length === 0) {
        // No children left, delete the container
        dispatch(EditorActions.deleteNode(parentContainer.id));
      } else {
        // Multiple children remain, just remove this one
        dispatch(EditorActions.deleteNode(nodeId));
      }
    } else {
      dispatch(EditorActions.deleteNode(nodeId));
    }

    toast({
      title: contentType,
      description: contentDescription,
    });
  };
}

/** Creates a handler that inserts a new empty paragraph before or after the given target node and focuses it. */
export function createHandleAddBlock(
  params: Pick<NodeOperationHandlerParams, "dispatch" | "nodeRefs">
) {
  return (targetId: string, position: "before" | "after" = "after") => {
    const { dispatch, nodeRefs } = params;
    // Create new paragraph node
    const newNode: TextNode = {
      id: generateId("p"),
      type: "p",
      content: "",
      attributes: {},
    };

    dispatch(EditorActions.insertNode(newNode, targetId, position));
    dispatch(EditorActions.setActiveNode(newNode.id));

    // Wait for the browser to paint the new paragraph before focusing it.
    requestAnimationFrame(() => {
      const newElement = nodeRefs.current.get(newNode.id);
      if (newElement) {
        newElement.focus();
      }
    });
  };
}

/** Creates a handler that wraps the current root-level node in a new container and appends a new empty paragraph beside it. */
export function createHandleCreateNested(
  params: Pick<NodeOperationHandlerParams, "container" | "dispatch" | "toast">
) {
  return (nodeId: string) => {
    const { container: containerOrGetter, dispatch, toast } = params;
    const container = typeof containerOrGetter === 'function' ? containerOrGetter() : containerOrGetter;
    const result = findNodeInTree(nodeId, container);
    if (!result) return;

    const { node, parentId } = result;

    // If the node is inside a nested container (not root), we need to handle it differently
    // We only allow 1 level of nesting, so if we're already nested, add to the parent container
    const isAlreadyNested = parentId !== container.id;

    if (isAlreadyNested) {
      // We're inside a nested container, so just add a new paragraph to the parent container
      const newParagraph: TextNode = {
        id: generateId("p"),
        type: "p",
        content: "",
        attributes: {},
      };

      // Insert after the current node within the parent container
      dispatch(EditorActions.insertNode(newParagraph, nodeId, "after"));
      dispatch(EditorActions.setActiveNode(newParagraph.id));

      // Focus is handled by the useEffect watching state.activeNodeId
      return;
    }

    // Node is at root level, create a nested container
    if (!isTextNode(node)) return;
    const textNode = node as TextNode;

    // Create the new paragraph that will be focused
    const newParagraphId = generateId("p");
    const newParagraph: TextNode = {
      id: newParagraphId,
      type: "p",
      content: "",
      attributes: {},
    };

    // Create a nested container with the current node inside it
    const nestedContainer: ContainerNode = {
      id: generateId("container"),
      type: "container",
      children: [
        // Copy the current node
        { ...textNode },
        // Add a new empty paragraph inside the nested container
        newParagraph,
      ],
      attributes: {},
    };

    // Delete the original node
    dispatch(EditorActions.deleteNode(nodeId));

    // Insert the nested container in its place
    // Since we deleted the node, we insert after the previous node or prepend to container
    const nodeIndex = container.children.findIndex((n) => n.id === nodeId);
    if (nodeIndex > 0) {
      const previousNode = container.children[nodeIndex - 1];
      dispatch(
        EditorActions.insertNode(nestedContainer, previousNode.id, "after")
      );
    } else {
      dispatch(
        EditorActions.insertNode(nestedContainer, container.id, "prepend")
      );
    }

    // Set the new paragraph as active
    dispatch(EditorActions.setActiveNode(newParagraphId));

    toast({
      title: "Nested block created",
      description:
        "Press Shift+Enter again to add more blocks in this container",
    });

    // Focus is handled by the useEffect watching state.activeNodeId
  };
}

/** Creates a handler that changes a node's block type and clears its content, typically called from the command menu. */
export function createHandleChangeBlockType(
  params: Pick<NodeOperationHandlerParams, "dispatch" | "nodeRefs">
) {
  return (nodeId: string, newType: string) => {
    const { dispatch, nodeRefs } = params;
    // When changing block type from command menu, clear the content (removes the "/" character)
    dispatch(
      EditorActions.updateNode(nodeId, {
        type: newType as any,
        content: "",
      })
    );

    // Wait for the browser to paint the type-changed block before focusing it.
    requestAnimationFrame(() => {
      const element = nodeRefs.current.get(nodeId);
      if (element) {
        element.focus();
      }
    });
  };
}

/** Creates a handler that deletes the current empty block and opens the file input to trigger an image upload. */
export function createHandleInsertImageFromCommand(
  params: Pick<NodeOperationHandlerParams, "dispatch" | "nodeRefs">,
  fileInputRef: React.RefObject<HTMLInputElement | null>
) {
  return (nodeId: string) => {
    const { dispatch } = params;
    // Delete the current empty block
    dispatch(EditorActions.deleteNode(nodeId));

    // Wait for the delete dispatch to flush before triggering the file input.
    requestAnimationFrame(() => {
      fileInputRef.current?.click();
    });
  };
}

/** Creates a handler that appends a new list item of the specified type to the end of the editor container. */
export function createHandleCreateList(params: NodeOperationHandlerParams) {
  return (listType: "ul" | "ol" | "li") => {
    const { container: containerOrGetter, dispatch, toast, editorContentRef } = params;
    const container = typeof containerOrGetter === 'function' ? containerOrGetter() : containerOrGetter;

    // For 'ul' and 'ol', we create 'ol' type items (numbered)
    // For 'li', we create 'li' type items (bulleted)
    const itemType = listType === "ul" ? "li" : listType === "ol" ? "ol" : "li";

    // Create a simple list item
    const listItem: TextNode = {
      id: generateId(itemType),
      type: itemType as any,
      content: "",
      attributes: {},
    };

    // Insert the list item at the end
    const lastNode = container.children[container.children.length - 1];
    if (lastNode) {
      dispatch(EditorActions.insertNode(listItem, lastNode.id, "after"));
    } else {
      // If no nodes exist, replace the container
      dispatch(
        EditorActions.replaceContainer({
          ...container,
          children: [listItem],
        })
      );
    }

    const listTypeLabel = listType === "ol" ? "numbered" : "bulleted";
    toast({
      title: "List Item Added",
      description: `Added a new ${listTypeLabel} list item`,
    });

    // Smooth scroll to the newly created list item
    setTimeout(() => {
      const editorContent = editorContentRef.current;
      if (editorContent) {
        const lastChild = editorContent.querySelector(
          "[data-editor-content]"
        )?.lastElementChild;
        if (lastChild) {
          lastChild.scrollIntoView({
            behavior: "smooth",
            block: "end",
            inline: "nearest",
          });
        }
      }
    }, 150);
  };
}

/** Creates a handler that converts the current block into a list item of the given type when triggered from the command menu. */
export function createHandleCreateListFromCommand(
  params: Pick<NodeOperationHandlerParams, "dispatch" | "toast" | "nodeRefs">
) {
  return (nodeId: string, listType: string) => {
    const { dispatch, toast, nodeRefs } = params;

    // Convert the current block to a list item
    // listType can be 'li' (bulleted) or 'ol' (numbered)
    dispatch(EditorActions.updateNode(nodeId, {
      type: listType as any,
      content: "", // Clear content when converting
    }));

    const listTypeLabel = listType === "ol" ? "numbered" : "bulleted";
    toast({
      title: "List Item Created",
      description: `Converted to ${listTypeLabel} list item`,
    });

    // Wait for the browser to paint the converted list item before focusing it.
    requestAnimationFrame(() => {
      const element = nodeRefs.current.get(nodeId);
      if (element) {
        element.focus();
        dispatch(EditorActions.setActiveNode(nodeId));
      }
    });
  };
}

/** Creates a handler that inserts a new paragraph with a default placeholder link at the end of the container. */
export function createHandleCreateLink(params: NodeOperationHandlerParams) {
  return () => {
    const { container: containerOrGetter, dispatch, toast, editorContentRef } = params;
    const container = typeof containerOrGetter === 'function' ? containerOrGetter() : containerOrGetter;

    // Create a paragraph with a link
    const linkNode: TextNode = {
      id: generateId("p"),
      type: "p",
      children: [
        {
          content: "www.text.com",
          href: "https://www.text.com",
        },
      ],
      attributes: {},
    };

    // Insert the link node at the end
    const lastNode = container.children[container.children.length - 1];
    if (lastNode) {
      dispatch(EditorActions.insertNode(linkNode, lastNode.id, "after"));
    } else {
      // If no nodes exist, replace the container
      dispatch(
        EditorActions.replaceContainer({
          ...container,
          children: [linkNode],
        })
      );
    }

    toast({
      title: "Link Created",
      description: "Added a new link element",
    });

    // Smooth scroll to the newly created link
    setTimeout(() => {
      const editorContent = editorContentRef.current;
      if (editorContent) {
        const lastChild = editorContent.querySelector(
          "[data-editor-content]"
        )?.lastElementChild;
        if (lastChild) {
          lastChild.scrollIntoView({
            behavior: "smooth",
            block: "end",
            inline: "nearest",
          });
        }
      }
    }, 150);
  };
}

/** Creates a handler that builds and inserts a fully structured table node with the specified row and column count. */
export function createHandleCreateTable(
  params: NodeOperationHandlerParams,
  activeNodeId?: string
) {
  return (rows: number, cols: number) => {
    const { container: containerOrGetter, dispatch, toast, editorContentRef } = params;
    const container = typeof containerOrGetter === 'function' ? containerOrGetter() : containerOrGetter;

    // Create header cells
    const headerCells: TextNode[] = Array.from({ length: cols }, (_, i) => ({
      id: generateId("th"),
      type: "th",
      content: `Column ${i + 1}`,
      attributes: {},
    }));

    // Create header row
    const headerRow: StructuralNode = {
      id: generateId("tr-header"),
      type: "tr",
      children: headerCells,
      attributes: {},
    };

    // Create thead
    const thead: StructuralNode = {
      id: generateId("thead"),
      type: "thead",
      children: [headerRow],
      attributes: {},
    };

    // Create body rows
    const bodyRows: StructuralNode[] = Array.from({ length: rows }, () => {
      const cells: TextNode[] = Array.from({ length: cols }, () => ({
        id: generateId("td"),
        type: "td",
        content: "",
        attributes: {},
      }));

      return {
        id: generateId("tr"),
        type: "tr",
        children: cells,
        attributes: {},
      };
    });

    // Create tbody
    const tbody: StructuralNode = {
      id: generateId("tbody"),
      type: "tbody",
      children: bodyRows,
      attributes: {},
    };

    // Create table
    const table: StructuralNode = {
      id: generateId("table"),
      type: "table",
      children: [thead, tbody],
      attributes: {},
    };

    // Wrap table in a container for consistent handling
    const tableWrapper: ContainerNode = {
      id: generateId("table-wrapper"),
      type: "container",
      children: [table],
      attributes: {},
    };

    // Determine where to insert the table
    let targetNode = null;
    let targetPosition: "after" | "before" = "after";

    if (activeNodeId) {
      // If we have an active node (from command menu), insert after it
      targetNode = container.children.find((n) => n.id === activeNodeId);
      targetPosition = "after";
    }

    if (!targetNode) {
      // Fallback: insert at the end
      targetNode = container.children[container.children.length - 1];
      targetPosition = "after";
    }

    if (targetNode) {
      dispatch(EditorActions.insertNode(tableWrapper, targetNode.id, targetPosition));
    } else {
      // If no nodes exist, replace the container
      dispatch(
        EditorActions.replaceContainer({
          ...container,
          children: [tableWrapper],
        })
      );
    }

    toast({
      title: "Table Created",
      description: `Added a ${rows}×${cols} table`,
    });

    // Smooth scroll to the newly created table
    setTimeout(() => {
      const editorContent = editorContentRef.current;
      if (editorContent) {
        const tableElement = editorContent.querySelector(
          `[data-node-id="${tableWrapper.id}"]`
        );
        if (tableElement) {
          tableElement.scrollIntoView({
            behavior: "smooth",
            block: "center",
            inline: "nearest",
          });
        }
      }
    }, 150);
  };
}

/** Creates an async handler that serializes the editor container to HTML and copies it to the clipboard. */
export function createHandleCopyHtml(
  params: Pick<NodeOperationHandlerParams, "toast">,
  enhanceSpaces: boolean,
  setCopiedHtml: (copied: boolean) => void
) {
  return async (container: ContainerNode) => {
    const { toast } = params;
    let html = serializeToHtml(container);

    // Wrap with spacing classes if enhance spaces is enabled
    if (enhanceSpaces) {
      html = `<div class="[&>*]:my-3 [&_*]:my-5">\n${html}\n</div>`;
    }

    try {
      await navigator.clipboard.writeText(html);
      setCopiedHtml(true);
      toast({
        title: "HTML copied!",
        description: "HTML code has been copied to clipboard.",
      });
      setTimeout(() => setCopiedHtml(false), 2000);
    } catch (error) {
      toast({
        variant: "destructive",
        title: "Copy failed",
        description: "Failed to copy HTML to clipboard.",
      });
    }
  };
}

/** Creates an async handler that serializes the container's children to pretty-printed JSON and copies it to the clipboard. */
export function createHandleCopyJson(
  params: Pick<NodeOperationHandlerParams, "toast">,
  setCopiedJson: (copied: boolean) => void
) {
  return async (container: ContainerNode) => {
    const { toast } = params;
    const json = JSON.stringify(container.children, null, 2);
    try {
      await navigator.clipboard.writeText(json);
      setCopiedJson(true);
      toast({
        title: "JSON copied!",
        description: "JSON data has been copied to clipboard.",
      });
      setTimeout(() => setCopiedJson(false), 2000);
    } catch (error) {
      toast({
        variant: "destructive",
        title: "Copy failed",
        description: "Failed to copy JSON to clipboard.",
      });
    }
  };
}

/**
 * Selection Handler Functions
 *
 * Functions for handling text selection and formatting in the editor
 */

import { EditorActions } from "../reducer/actions";
import { ContainerNode, SelectionInfo, TextNode, isTextNode } from "../types";
import {
  detectFormatsInRange,
  restoreSelection,
} from "../utils/editor-helpers";
import { findNodeById } from "../utils/tree-operations";

/** Parameters shared by all selection handler factory functions. */
export interface SelectionHandlerParams {
  container: ContainerNode | (() => ContainerNode);
  state: any;
  dispatch: React.Dispatch<any>;
  selectionManager: any;
  nodeRefs: React.MutableRefObject<Map<string, HTMLElement>>;
}

/** Creates a selection-change handler that detects the active node, measures the selection range, and dispatches format state updates with a debounce. */
export function createHandleSelectionChange(
  params: SelectionHandlerParams,
  selectionDispatchTimerRef: React.MutableRefObject<NodeJS.Timeout | null>
) {
  return () => {
    const { container: containerOrGetter, state, dispatch, selectionManager, nodeRefs } = params;
    const container = typeof containerOrGetter === 'function' ? containerOrGetter() : containerOrGetter;
    const selection = window.getSelection();
    const hasText =
      selection !== null &&
      !selection.isCollapsed &&
      selection.toString().length > 0;

    // Also track collapsed cursor (even when no text selected)
    const hasCursor = selection !== null && selection.isCollapsed;

    if ((hasText || hasCursor) && selection) {
      // NEW APPROACH: Find the actual node by traversing the DOM upwards from the selection
      const range = selection.getRangeAt(0);
      let currentElement: HTMLElement | null = null;

      // Start from the selection's common ancestor
      let node: Node | null = range.commonAncestorContainer;

      // Walk up the DOM to find the closest element with data-node-id
      while (node) {
        if (node.nodeType === Node.ELEMENT_NODE) {
          const element = node as HTMLElement;
          const nodeId = element.getAttribute("data-node-id");
          const nodeType = element.getAttribute("data-node-type");

          // We found a text node (not a container)
          if (nodeId && nodeType && nodeType !== "container") {
            currentElement = element;
            break;
          }
        }
        node = node.parentNode;
      }

      if (!currentElement) {
        // Fallback to old behavior if we can't find via DOM
        const freshCurrentNode = state.activeNodeId
          ? (findNodeById(container, state.activeNodeId) as
              | TextNode
              | undefined)
          : (container.children[0] as TextNode | undefined);

        if (freshCurrentNode) {
          currentElement = nodeRefs.current.get(freshCurrentNode.id) || null;
        }
      }

      if (currentElement) {
        const actualNodeId = currentElement.getAttribute("data-node-id");

        if (actualNodeId) {
          // Find the actual node in the tree (including nested nodes)
          const actualNode = findNodeById(container, actualNodeId) as
            | TextNode
            | undefined;

          if (actualNode && isTextNode(actualNode)) {
            const preSelectionRange = range.cloneRange();
            preSelectionRange.selectNodeContents(currentElement);
            preSelectionRange.setEnd(range.startContainer, range.startOffset);
            let start = preSelectionRange.toString().length;
            let end = start + range.toString().length;

            // Detect active formats in the selected range
            const detected = detectFormatsInRange(actualNode, start, end);

            const selectionInfo: SelectionInfo = {
              text: selection.toString(),
              start,
              end,
              nodeId: actualNode.id,
              formats: {
                bold: detected.bold,
                italic: detected.italic,
                underline: detected.underline,
                strikethrough: detected.strikethrough,
                code: detected.code,
              },
              elementType: detected.elementType,
              href: detected.href,
              className: detected.className,
              styles: detected.styles,
            };

            // Check if selection actually changed
            const currentSel = selectionManager.getSelection();
            const changed =
              !currentSel ||
              currentSel.start !== start ||
              currentSel.end !== end ||
              currentSel.nodeId !== actualNode.id ||
              currentSel.formats.bold !== detected.bold ||
              currentSel.formats.italic !== detected.italic ||
              currentSel.formats.underline !== detected.underline ||
              currentSel.elementType !== detected.elementType;

            if (changed) {
              // Update ref immediately (fast, no re-renders)
              selectionManager.setSelection(selectionInfo);

              // Debounce state dispatch to avoid excessive re-renders
              if (selectionDispatchTimerRef.current) {
                clearTimeout(selectionDispatchTimerRef.current);
              }

              // Debounce: batch rapid selection-change events into one toolbar re-render.
              selectionDispatchTimerRef.current = setTimeout(() => {
                dispatch(EditorActions.setCurrentSelection(selectionInfo));
              }, 150);
            }
            return; // Exit early on success
          }
        }
      }
    }

    // Clear selection if no valid selection found
    const currentSel = selectionManager.getSelection();
    if (currentSel !== null) {
      // Clear ref immediately
      selectionManager.setSelection(null);

      // Clear state with debounce
      if (selectionDispatchTimerRef.current) {
        clearTimeout(selectionDispatchTimerRef.current);
      }

      // Debounce: avoid clearing the toolbar selection on every transient pointer event.
      selectionDispatchTimerRef.current = setTimeout(() => {
        dispatch(EditorActions.setCurrentSelection(null));
      }, 150);
    }
  };
}

/** Creates a format-toggle handler that dispatches the given format to the reducer and restores the selection afterwards. */
export function createHandleFormat(params: SelectionHandlerParams) {
  return (format: "bold" | "italic" | "underline" | "strikethrough" | "code") => {
    const { dispatch, selectionManager, nodeRefs } = params;

    // Get fresh selection from ref (more up-to-date than state)
    const refSelection = selectionManager.getSelection();
    if (!refSelection) {
      return;
    }

    // Save selection for restoration
    const { start, end, nodeId } = refSelection;

    // Dispatch toggle format action - reducer handles everything!
    dispatch(EditorActions.toggleFormat(format));

    // Restore selection after the browser has painted the formatted DOM.
    requestAnimationFrame(() => {
      const element = nodeRefs.current.get(nodeId);
      if (element) {
        restoreSelection(element, start, end);
      }
    });
  };
}

/** Creates a handler that applies a CSS color value as an inline style to the current selection. */
export function createHandleApplyColor(
  params: SelectionHandlerParams,
  toast: any,
  setSelectedColor: (color: string) => void
) {
  return (color: string) => {
    const { dispatch, selectionManager, nodeRefs } = params;
    // Get fresh selection from ref
    const refSelection = selectionManager.getSelection();
    if (!refSelection) return;

    const { nodeId, start, end } = refSelection;

    // Apply color as inline style
    dispatch(EditorActions.applyInlineStyle("color", color));

    setSelectedColor(color);

    toast({
      title: "Color Applied",
      description: `Applied color: ${color}`,
    });

    // Restore selection after the browser has painted the color-styled DOM.
    requestAnimationFrame(() => {
      const element = nodeRefs.current.get(nodeId);
      if (element) {
        restoreSelection(element, start, end);
      }
    });
  };
}

/** Creates a handler that applies a font-size inline style value to the current text selection. */
export function createHandleApplyFontSize(
  params: SelectionHandlerParams,
  toast: any
) {
  return (fontSize: string) => {
    const { dispatch, selectionManager, nodeRefs } = params;
    // Get fresh selection from ref
    const refSelection = selectionManager.getSelection();
    if (!refSelection) return;

    const { nodeId, start, end } = refSelection;

    // Apply font size as inline style
    dispatch(EditorActions.applyInlineStyle("fontSize", fontSize));

    toast({
      title: "Font Size Applied",
      description: `Applied font size: ${fontSize}`,
    });

    // Restore selection after the browser has painted the font-size-styled DOM.
    requestAnimationFrame(() => {
      const element = nodeRefs.current.get(nodeId);
      if (element) {
        restoreSelection(element, start, end);
      }
    });
  };
}

/** Creates a handler that changes the block or inline element type of the currently selected text. */
export function createHandleTypeChange(
  params: SelectionHandlerParams,
  handleSelectionChange: () => void
) {
  return (type: TextNode["type"]) => {
    const { dispatch, selectionManager, nodeRefs } = params;

    // Check if there's a selection (use ref for freshest data)
    const refSelection = selectionManager.getSelection();
    if (!refSelection) return;

    // Save selection info before dispatch
    const { start, end, nodeId } = refSelection;

    // Block-level types should change the entire block, not inline formatting
    if (type === "ol" || type === "li" || type === "code") {
      dispatch(EditorActions.updateNode(nodeId, { type: type }));

      // Restore selection after the browser has painted the converted list node.
      requestAnimationFrame(() => {
        const element = nodeRefs.current.get(nodeId);
        if (element) {
          restoreSelection(element, start, end);
          handleSelectionChange();
        }
      });
      return;
    }

    // Apply as inline element type to selected text (or at cursor position)
    const elementType = type as
      | "p"
      | "h1"
      | "h2"
      | "h3"
      | "h4"
      | "h5"
      | "h6"
      | "blockquote";

    dispatch(EditorActions.applyInlineElementType(elementType));

    // Restore selection after the browser has painted the type-changed inline node.
    requestAnimationFrame(() => {
      const element = nodeRefs.current.get(nodeId);
      if (element) {
        restoreSelection(element, start, end);
        // Manually trigger selection change detection to update the UI
        handleSelectionChange();
      }
    });
  };
}

import * as React from "react"

const MOBILE_BREAKPOINT = 768

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(undefined)

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`)
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    }
    mql.addEventListener("change", onChange)
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    return () => mql.removeEventListener("change", onChange)
  }, [])

  return !!isMobile
}

/**
 * Toast Hook
 * 
 * Simple wrapper around sonner toast notifications
 */

import { toast as sonnerToast } from 'sonner';

export interface ToastProps {
  title?: string;
  description?: string;
  variant?: 'default' | 'destructive';
}

export function useToast() {
  const toast = ({ title, description, variant }: ToastProps) => {
    if (variant === 'destructive') {
      sonnerToast.error(title, {
        description,
      });
    } else {
      sonnerToast.success(title, {
        description,
      });
    }
  };

  return { toast };
}

import { useCallback, useState } from "react";
import { TextNode } from "..";
import {
  createHandleCompositionStart,
  createHandleCompositionEnd,
  createHandleInput,
  createHandleKeyDown,
  createHandleClick,
  createHandleCommandSelect,
  createHandleBackgroundColorChange,
  createHandleBlockDragStart,
  createHandleBlockDragEnd,
} from "../handlers/block";
import { useContainerGetter } from "../store/editor-store";

export interface UseBlockHandlersParams {
  textNode: TextNode;
  readOnly: boolean;
  isActive: boolean;
  dispatch: (action: any) => void;
  localRef: React.RefObject<HTMLElement | null>;
  isComposingRef: React.MutableRefObject<boolean>;
  shouldPreserveSelectionRef: React.MutableRefObject<boolean>;
  onInput: (element: HTMLElement) => void;
  onKeyDown: (e: React.KeyboardEvent<HTMLElement>) => void;
  onClick: () => void;
  onCreateNested?: (nodeId: string) => void;
  onChangeBlockType?: (nodeId: string, newType: string) => void;
  onInsertImage?: (nodeId: string) => void;
  onCreateList?: (nodeId: string, listType: string) => void;
  onCreateTable?: (nodeId: string) => void;
  onBlockDragStart?: (nodeId: string) => void;
  onSetDragOverNodeId?: (nodeId: string | null) => void;
  onSetDropPosition?: (position: "before" | "after" | "left" | "right" | null) => void;
  onSetDraggingNodeId?: (nodeId: string | null) => void;
  onUploadCoverImage?: (file: File) => Promise<string>;
}

/**
 * useBlockHandlers
 *
 * Encapsulates all useCallback declarations for Block event handling,
 * keeping Block.tsx focused on structure and rendering.
 */
export function useBlockHandlers({
  textNode,
  readOnly,
  dispatch,
  localRef,
  isComposingRef,
  shouldPreserveSelectionRef,
  onInput,
  onKeyDown,
  onClick,
  onCreateNested,
  onChangeBlockType,
  onInsertImage,
  onCreateList,
  onCreateTable,
  onBlockDragStart,
  onSetDragOverNodeId,
  onSetDropPosition,
  onSetDraggingNodeId,
}: UseBlockHandlersParams) {
  const [showCommandMenu, setShowCommandMenu] = useState(false);
  const [commandMenuAnchor, setCommandMenuAnchor] = useState<HTMLElement | null>(null);

  // Stable getter for the current container (avoids re-renders)
  const getContainer = useContainerGetter();

  const handleCompositionStart = useCallback(
    createHandleCompositionStart()(isComposingRef),
    []
  );

  const handleCompositionEnd = useCallback(
    createHandleCompositionEnd()(isComposingRef, onInput, localRef),
    [onInput]
  );

  const handleInput = useCallback(
    createHandleInput({
      textNode,
      readOnly,
      onInput,
      onChangeBlockType,
      showCommandMenu,
      setShowCommandMenu,
      setCommandMenuAnchor,
      shouldPreserveSelectionRef,
      dispatch,
    }),
    [textNode, readOnly, onInput, onChangeBlockType, showCommandMenu, dispatch]
  );

  const handleKeyDown = useCallback(
    createHandleKeyDown({
      textNode,
      readOnly,
      onInput,
      onKeyDown,
      onClick,
      onCreateNested,
      onChangeBlockType,
      onInsertImage,
      onCreateList,
      currentContainer: getContainer,
      dispatch,
      localRef,
      isComposingRef,
      shouldPreserveSelectionRef,
      showCommandMenu,
      setShowCommandMenu,
      setCommandMenuAnchor,
    }),
    [
      textNode,
      readOnly,
      onKeyDown,
      onCreateNested,
      showCommandMenu,
      dispatch,
    ]
  );

  const handleClick = useCallback(createHandleClick({ readOnly, onClick }), [
    readOnly,
    onClick,
  ]);

  const handleCommandSelect = useCallback(
    createHandleCommandSelect({
      textNode,
      onChangeBlockType,
      onInsertImage,
      onCreateList,
      onCreateTable,
      localRef,
      setShowCommandMenu,
      setCommandMenuAnchor,
    }),
    [textNode, onChangeBlockType, onInsertImage, onCreateList, onCreateTable]
  );

  const handleBackgroundColorChange = useCallback(
    createHandleBackgroundColorChange(textNode, dispatch),
    [textNode, dispatch]
  );

  const handleBlockDragStartFn = useCallback(
    createHandleBlockDragStart(textNode, onBlockDragStart),
    [textNode, onBlockDragStart]
  );

  const handleBlockDragEndFn = useCallback(
    createHandleBlockDragEnd(() => {
      if (onSetDragOverNodeId && onSetDropPosition && onSetDraggingNodeId) {
        onSetDragOverNodeId(null);
        onSetDropPosition(null);
        onSetDraggingNodeId(null);
      }
    }),
    [onSetDragOverNodeId, onSetDropPosition, onSetDraggingNodeId]
  );

  return {
    showCommandMenu,
    setShowCommandMenu,
    commandMenuAnchor,
    setCommandMenuAnchor,
    handleCompositionStart,
    handleCompositionEnd,
    handleInput,
    handleKeyDown,
    handleClick,
    handleCommandSelect,
    handleBackgroundColorChange,
    handleBlockDragStartFn,
    handleBlockDragEndFn,
  };
}

/**
 * Mina Rich Editor - useCollaboration Hook
 *
 * React hook that wires up Y.js real-time collaboration for a Mina editor
 * instance. Handles:
 *
 * 1. Creating a `Y.Doc` and connecting via `y-websocket`.
 * 2. Initialising the Y.Doc from the current editor state (first client).
 * 3. Forwarding local operations to Y.js (local -> remote).
 * 4. Applying remote Y.js changes back into the Zustand store (remote -> local).
 * 5. Cursor / presence tracking via the Awareness protocol.
 *
 * @packageDocumentation
 */

import { useEffect, useRef, useState } from 'react';
import type { CollabOptions, CollabState } from '../collaboration/types';
import { REMOTE_ORIGIN } from '../collaboration/types';
import {
  getY,
  applyOperationToYDoc,
  syncYDocToStore,
  initYDocFromContainer,
} from '../collaboration/y-binding';
import { createAwarenessManager, type AwarenessManager } from '../collaboration/awareness';
import { useEditorStoreInstance } from '../store/editor-store';

// ─── Dynamic import for y-websocket ──────────────────────────────────────────

async function loadYWebsocket(): Promise<any> {
  try {
    return await import('y-websocket' as string);
  } catch {
    throw new Error(
      '[mina-editor] Collaboration requires "y-websocket" as a peer dependency. ' +
        'Install it with: npm install y-websocket'
    );
  }
}

// ─── Hook ─────────────────────────────────────────────────────────────────────

export function useCollaboration(options: CollabOptions): CollabState {
  const { roomId, serverUrl, user } = options;
  const store = useEditorStoreInstance();

  const [isConnected, setIsConnected] = useState(false);
  const [connectedUsers, setConnectedUsers] = useState<import('../collaboration/types').CollabUser[]>([]);
  const [localClientId, setLocalClientId] = useState<string | null>(null);

  const yDocRef = useRef<any>(null);
  const providerRef = useRef<any>(null);
  const awarenessRef = useRef<AwarenessManager | null>(null);
  const unsubStoreRef = useRef<(() => void) | null>(null);
  const isRemoteUpdate = useRef(false);

  useEffect(() => {
    let cancelled = false;
    let cleanupProvider: (() => void) | null = null;
    let cleanupCursor: (() => void) | null = null;

    (async () => {
      // Use the SAME getY() as y-binding to guarantee a single yjs instance
      const Y = await getY();
      const { WebsocketProvider } = await loadYWebsocket();

      if (cancelled) return;

      // 1. Create Y.Doc
      const yDoc = new Y.Doc();
      yDocRef.current = yDoc;
      setLocalClientId(String(yDoc.clientID));
      console.log('[yjs] Created Y.Doc, clientID:', yDoc.clientID);

      // 2. Set up Y.Doc observer BEFORE connecting so we catch the initial sync
      const yRoot = yDoc.getMap('root');
      const handleYChange = (_events: any[], transaction: any) => {
        console.log('[yjs] observeDeep fired, origin:', transaction.origin, 'REMOTE_ORIGIN:', REMOTE_ORIGIN, 'match:', transaction.origin === REMOTE_ORIGIN);
        if (transaction.origin === REMOTE_ORIGIN) return;

        console.log('[yjs] Syncing Y.Doc → store');
        isRemoteUpdate.current = true;
        syncYDocToStore((action: any) => store.getState().dispatch(action), yDoc);
        isRemoteUpdate.current = false;
      };
      yRoot.observeDeep(handleYChange);

      // 3. Connect to server
      console.log('[yjs] Connecting to', serverUrl, 'room:', roomId);
      const provider = new WebsocketProvider(serverUrl, roomId, yDoc);
      providerRef.current = provider;

      // 4. Connection state
      provider.on('status', ({ status }: { status: string }) => {
        console.log('[yjs] Connection status:', status);
        if (!cancelled) setIsConnected(status === 'connected');
      });

      // 5. Awareness / presence
      const awareness = createAwarenessManager(provider.awareness, user);
      awarenessRef.current = awareness;
      awareness.onUsersChange((users: import('../collaboration/types').CollabUser[]) => {
        if (!cancelled) setConnectedUsers(users);
      });

      // 6. Init Y.Doc — wait for sync event from y-websocket.
      //    y-websocket emits 'sync' (not 'synced') with (isSynced: boolean).
      let initDone = false;
      const tryInit = async (source: string) => {
        if (initDone || cancelled) return;
        initDone = true;
        const yr = yDoc.getMap('root');
        const hasId = yr.get('id');
        console.log('[yjs] tryInit from:', source, 'yRoot has id:', hasId);
        if (!hasId) {
          const currentContainer = store.getState().current;
          console.log('[yjs] Initializing Y.Doc from editor state, container id:', currentContainer.id);
          await initYDocFromContainer(yDoc, currentContainer);
          console.log('[yjs] Y.Doc initialized, yRoot id now:', yr.get('id'));
        } else {
          console.log('[yjs] Y.Doc already has content from server, syncing to store');
          isRemoteUpdate.current = true;
          syncYDocToStore((action: any) => store.getState().dispatch(action), yDoc);
          isRemoteUpdate.current = false;
        }
      };

      // Listen for the sync event (fires when initial server state is received)
      provider.on('sync', (isSynced: boolean) => {
        console.log('[yjs] sync event, isSynced:', isSynced);
        if (isSynced) tryInit('sync-event');
      });

      // If already synced by the time we get here
      if (provider.synced) {
        console.log('[yjs] Provider already synced on setup');
        tryInit('already-synced');
      }

      // Safety fallback
      const initTimeout = setTimeout(() => {
        console.log('[yjs] Init timeout fallback fired');
        tryInit('timeout');
      }, 1000);

      // 7. Observe local store changes -> push into Y.Doc
      let prevContainer = store.getState().current;
      const unsubStore = store.subscribe((state: any) => {
        if (isRemoteUpdate.current) {
          prevContainer = state.current;
          return;
        }

        if (state.current !== prevContainer) {
          console.log('[yjs] Store changed, pushing to Y.Doc. Container id:', state.current.id, 'children:', state.current.children?.length);
          const op = {
            type: 'replace_container' as const,
            container: state.current,
          };
          applyOperationToYDoc(yDoc, op).then(() => {
            console.log('[yjs] Y.Doc updated successfully. yRoot id:', yRoot.get('id'), 'children:', yRoot.get('children')?.length);
          }).catch((err: any) => {
            console.error('[yjs] Failed to sync to Y.Doc:', err);
          });
          prevContainer = state.current;
        }
      });
      unsubStoreRef.current = unsubStore;

      // 8. Track cursor position via selectionchange
      const getCursorPosition = (): { nodeId: string; offset: number } | null => {
        const sel = window.getSelection();
        if (!sel || sel.rangeCount === 0) return null;
        const range = sel.getRangeAt(0);
        let node: Node | null = range.startContainer;
        while (node && !(node instanceof HTMLElement && node.dataset.nodeId)) {
          node = node.parentElement;
        }
        if (!node || !(node instanceof HTMLElement)) return null;
        return { nodeId: node.dataset.nodeId!, offset: range.startOffset };
      };

      let cursorThrottle: ReturnType<typeof setTimeout> | null = null;
      const handleSelectionChange = () => {
        if (cursorThrottle) return;
        cursorThrottle = setTimeout(() => {
          cursorThrottle = null;
          const cursor = getCursorPosition();
          awareness.updateCursor(cursor);
        }, 50);
      };
      document.addEventListener('selectionchange', handleSelectionChange);

      cleanupCursor = () => {
        document.removeEventListener('selectionchange', handleSelectionChange);
        if (cursorThrottle) clearTimeout(cursorThrottle);
      };

      cleanupProvider = () => {
        clearTimeout(initTimeout);
        yRoot.unobserveDeep(handleYChange);
        awareness.destroy();
        provider.destroy();
        yDoc.destroy();
      };
    })();

    return () => {
      cancelled = true;
      unsubStoreRef.current?.();
      unsubStoreRef.current = null;
      cleanupCursor?.();
      cleanupProvider?.();
      yDocRef.current = null;
      providerRef.current = null;
      awarenessRef.current = null;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [roomId, serverUrl, store]);

  return { isConnected, connectedUsers, localClientId };
}

/**
 * Mina Rich Editor - useEditorAI Hook
 *
 * React hook that integrates AI content generation into the editor.
 * Manages streaming state, cancellation via AbortController, and
 * dispatches blocks into the editor tree via the store.
 *
 * @packageDocumentation
 */

'use client';

import { useState, useRef, useCallback } from 'react';
import type { AIProvider, AIStreamOptions } from '../ai/types';
import type { SelectionInfo, InlineText } from '../types';
import { streamToBlocks, parseInlineMarkdown } from '../ai/stream-to-blocks';
import { useEditorDispatch, useActiveNodeId } from '../store/editor-store';

/**
 * Configuration for {@link useEditorAI}.
 */
export interface UseEditorAIOptions {
  /** The AI provider to use for text generation. */
  provider: AIProvider;
  /** Default system prompt prepended to every generation request. */
  defaultSystemPrompt?: string;
}

/**
 * Return type of {@link useEditorAI}.
 */
export interface UseEditorAIReturn {
  /**
   * Generate AI content and stream it into the editor after the
   * currently active block (or a specified target block).
   */
  generateContent: (
    prompt: string,
    options?: AIStreamOptions,
    targetNodeId?: string,
  ) => Promise<void>;

  /**
   * Stream AI content for replacing selected text.
   * Returns the final replacement text and parsed InlineText[] children.
   * When `styled: true`, AI returns markdown-formatted text parsed into rich InlineText[].
   */
  replaceSelectionWithAI: (
    instruction: string,
    selection: SelectionInfo,
    options?: AIStreamOptions & { styled?: boolean },
  ) => Promise<{ text: string; children: InlineText[] }>;

  /** Whether a generation is currently in progress. */
  isGenerating: boolean;

  /** Live preview of streaming text (for selection replacement). */
  streamingPreview: string;

  /** Live preview of rich InlineText[] (for styled selection replacement). */
  streamingPreviewChildren: InlineText[];

  /** Reset the streaming preview. */
  resetPreview: () => void;

  /** Abort the current generation (no-op if not generating). */
  abort: () => void;
}

/**
 * Hook that provides AI content generation capabilities to the editor.
 */
export function useEditorAI(options: UseEditorAIOptions): UseEditorAIReturn {
  const { provider, defaultSystemPrompt } = options;

  const dispatch = useEditorDispatch();
  const activeNodeId = useActiveNodeId();
  const [isGenerating, setIsGenerating] = useState(false);
  const [streamingPreview, setStreamingPreview] = useState('');
  const [streamingPreviewChildren, setStreamingPreviewChildren] = useState<InlineText[]>([]);
  const abortControllerRef = useRef<AbortController | null>(null);

  const resetPreview = useCallback(() => {
    setStreamingPreview('');
    setStreamingPreviewChildren([]);
  }, []);

  const abort = useCallback(() => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }
    setIsGenerating(false);
  }, []);

  const generateContent = useCallback(
    async (
      prompt: string,
      streamOptions?: AIStreamOptions,
      targetNodeId?: string,
    ) => {
      const targetId = targetNodeId ?? activeNodeId;
      if (!targetId) {
        console.warn(
          '[useEditorAI] No target node ID. Focus a block or pass targetNodeId.',
        );
        return;
      }

      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }

      const controller = new AbortController();
      abortControllerRef.current = controller;
      setIsGenerating(true);

      try {
        const fallbackSystemPrompt =
          'You are a content generator inside a rich text editor. Output ONLY clean markdown content. Rules:\n' +
          '- NO preamble (no "Here\'s...", "Sure!", "I\'d be happy to...")\n' +
          '- NO trailing summary or sign-off\n' +
          '- Start directly with the content\n' +
          '- Use proper markdown: # headings, - lists, ```code blocks```, **bold**, *italic*\n' +
          '- Each code block must use triple backtick fences on their own lines';

        const mergedOptions: AIStreamOptions = {
          ...streamOptions,
          systemPrompt:
            streamOptions?.systemPrompt ?? defaultSystemPrompt ?? fallbackSystemPrompt,
        };

        const rawStream = provider.stream(prompt, mergedOptions);

        async function* abortableStream(): AsyncIterable<string> {
          for await (const chunk of rawStream) {
            if (controller.signal.aborted) return;
            yield chunk;
          }
        }

        await streamToBlocks(abortableStream(), dispatch, targetId);
      } catch (error) {
        if (error instanceof DOMException && error.name === 'AbortError') {
          return;
        }
        console.error('[useEditorAI] Generation failed:', error);
        throw error;
      } finally {
        if (abortControllerRef.current === controller) {
          abortControllerRef.current = null;
        }
        setIsGenerating(false);
      }
    },
    [provider, defaultSystemPrompt, dispatch, activeNodeId],
  );

  const replaceSelectionWithAI = useCallback(
    async (
      instruction: string,
      selection: SelectionInfo,
      streamOptions?: AIStreamOptions & { styled?: boolean },
    ): Promise<{ text: string; children: InlineText[] }> => {
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }

      const controller = new AbortController();
      abortControllerRef.current = controller;
      setIsGenerating(true);
      setStreamingPreview('');
      setStreamingPreviewChildren([]);

      const isStyled = streamOptions?.styled ?? false;

      try {
        const systemPrompt = isStyled
          ? 'You are a text editing assistant. Return ONLY the rewritten text. Use markdown: **bold**, *italic*, ~~strikethrough~~, `code` where appropriate. No explanations, no quotes.'
          : 'You are a text editing assistant. Return ONLY the rewritten text. No explanations, no markdown formatting, no quotes, no prefixes like "Here\'s...". Just the rewritten text itself.';

        const fullPrompt = `${instruction}\n\nText:\n${selection.text}`;

        const mergedOptions: AIStreamOptions = {
          ...streamOptions,
          systemPrompt:
            streamOptions?.systemPrompt ?? systemPrompt,
        };

        const rawStream = provider.stream(fullPrompt, mergedOptions);
        let accumulated = '';

        for await (const chunk of rawStream) {
          if (controller.signal.aborted) break;
          accumulated += chunk;
          setStreamingPreview(accumulated);
          if (isStyled) {
            setStreamingPreviewChildren(parseInlineMarkdown(accumulated));
          }
        }

        // Collapse newlines to spaces for inline replacement
        const finalText = accumulated.replace(/\n+/g, ' ').trim();
        setStreamingPreview(finalText);

        const children = isStyled
          ? parseInlineMarkdown(finalText)
          : [{ content: finalText }];
        setStreamingPreviewChildren(children);

        return { text: finalText, children };
      } catch (error) {
        if (error instanceof DOMException && error.name === 'AbortError') {
          return { text: '', children: [] };
        }
        console.error('[useEditorAI] Selection replacement failed:', error);
        throw error;
      } finally {
        if (abortControllerRef.current === controller) {
          abortControllerRef.current = null;
        }
        setIsGenerating(false);
      }
    },
    [provider],
  );

  return {
    generateContent,
    replaceSelectionWithAI,
    isGenerating,
    streamingPreview,
    streamingPreviewChildren,
    resetPreview,
    abort,
  };
}

/**
 * useEditorAPI — Programmatic CMS Integration API
 *
 * Gives CMS consumers a clean way to get/set editor content in any format
 * (JSON, HTML, Markdown, plain text) without coupling to internal store shape.
 *
 * All getter functions are non-reactive: they read from `store.getState()`
 * at call time and will never cause a component re-render.
 *
 * @example
 * ```tsx
 * function SaveButton() {
 *   const api = useEditorAPI();
 *
 *   const handleSave = () => {
 *     fetch('/api/save', {
 *       method: 'POST',
 *       body: JSON.stringify({ html: api.getHTML(), json: api.getJSON() }),
 *     });
 *   };
 *
 *   return <button onClick={handleSave}>Save</button>;
 * }
 * ```
 */

import { useRef } from 'react';
import { ContainerNode, EditorNode, TextNode, isTextNode } from '../types';
import { serializeToSemanticHtml } from '../utils/serialize-semantic-html';
import { useEditorStoreInstance } from '../store/editor-store';

// ---------------------------------------------------------------------------
// Markdown serializer — loaded once via require so a missing file in a
// consumer's environment never breaks the module at load time.
// ---------------------------------------------------------------------------

let _serializeToMarkdown: ((container: ContainerNode) => string) | null = null;

try {
  // eslint-disable-next-line @typescript-eslint/no-var-requires
  const mod = require('../lib/utils/serialize-markdown');
  if (mod && typeof mod.serializeToMarkdown === 'function') {
    _serializeToMarkdown = mod.serializeToMarkdown;
  }
} catch {
  // Module not available — getMarkdown() will return '' and warn the caller.
}

// ---------------------------------------------------------------------------
// Plain-text walker
// ---------------------------------------------------------------------------

/**
 * Recursively walks all nodes in a tree and concatenates text content,
 * separating blocks with newlines.
 */
function extractPlainText(node: EditorNode): string {
  if (isTextNode(node)) {
    const textNode = node as TextNode;

    // Multi-line nodes (e.g. ordered lists)
    if (textNode.lines && textNode.lines.length > 0) {
      return textNode.lines
        .map((line) => {
          if (line.children && line.children.length > 0) {
            return line.children.map((c) => c.content).join('');
          }
          return line.content ?? '';
        })
        .join('\n');
    }

    // Inline-children (rich text, single line)
    if (textNode.children && textNode.children.length > 0) {
      return textNode.children.map((c) => c.content).join('');
    }

    // Simple content
    return textNode.content ?? '';
  }

  // Container / structural node — recurse
  if ('children' in node && Array.isArray((node as ContainerNode).children)) {
    return (node as ContainerNode).children
      .map(extractPlainText)
      .filter(Boolean)
      .join('\n');
  }

  return '';
}

// ---------------------------------------------------------------------------
// Public interface
// ---------------------------------------------------------------------------

export interface EditorAPI {
  /** Returns the document as JSON (the native block model). */
  getJSON: () => ContainerNode;

  /** Returns the document as clean semantic HTML (no Tailwind classes). */
  getHTML: () => string;

  /**
   * Returns the document as Markdown.
   * Logs a warning and returns '' if the Markdown serializer is unavailable.
   */
  getMarkdown: () => string;

  /** Replaces the entire editor content with the provided container. */
  setContent: (content: ContainerNode) => void;

  /**
   * Returns true if the document has been modified from its initial state
   * (any edits have been pushed onto the undo history stack).
   */
  isDirty: () => boolean;

  /** Returns the number of top-level blocks in the document. */
  getBlockCount: () => number;

  /** Returns all text content concatenated as plain text. */
  getPlainText: () => string;
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

/**
 * Hook that provides programmatic access to editor content in all formats.
 *
 * Must be called inside an `<EditorProvider>` tree.
 *
 * Design notes:
 * - Uses `store.getState()` (via `useEditorStoreInstance`) for all reads so
 *   that NO reactive subscription is created — the hook itself never causes
 *   a re-render.
 * - The returned `EditorAPI` object is stable across renders (held in a ref).
 */
export function useEditorAPI(): EditorAPI {
  // Grab the raw Zustand store instance from context. This does NOT subscribe
  // to state — it only gives us access to getState() and dispatch().
  const store = useEditorStoreInstance();

  // Keep a stable API object so callers can destructure once.
  const apiRef = useRef<EditorAPI | null>(null);

  if (!apiRef.current) {
    apiRef.current = {
      getJSON(): ContainerNode {
        const state = store.getState();
        return state.current;
      },

      getHTML(): string {
        const state = store.getState();
        const container = state.current;
        return serializeToSemanticHtml(container);
      },

      getMarkdown(): string {
        if (!_serializeToMarkdown) {
          console.warn(
            '[useEditorAPI] getMarkdown(): Markdown serializer is not available. ' +
              'Ensure `src/lib/utils/serialize-markdown.ts` exports `serializeToMarkdown`.'
          );
          return '';
        }
        const state = store.getState();
        const container = state.current;
        return _serializeToMarkdown(container);
      },

      setContent(content: ContainerNode): void {
        store.getState().dispatch({
          type: 'REPLACE_CONTAINER',
          payload: { container: content },
        });
      },

      isDirty(): boolean {
        return store.getState().undoStack.length > 0;
      },

      getBlockCount(): number {
        const state = store.getState();
        const container = state.current;
        return container.children.length;
      },

      getPlainText(): string {
        const state = store.getState();
        const container = state.current;
        return extractPlainText(container);
      },
    };
  }

  return apiRef.current;
}

/**
 * useEditorClipboard
 *
 * Provides stable copy, paste, and cut event handlers wired to the editor's
 * dispatch and container state.
 */

import React, { useCallback, useMemo } from "react";
import {
  createHandleCopy,
  createHandlePaste,
  createHandleCut,
} from "../handlers/clipboard-handlers";
import type { ContainerNode } from "../types";
import type { EditorAction } from "../reducer/actions";

interface UseEditorClipboardParams {
  dispatch: React.Dispatch<EditorAction>;
  getContainer: () => ContainerNode;
  getActiveNodeId: () => string | null;
}

export function useEditorClipboard({
  dispatch,
  getContainer,
  getActiveNodeId,
}: UseEditorClipboardParams) {
  const clipboardParams = useMemo(
    () => ({
      getContainer,
      getActiveNodeId,
      dispatch,
    }),
    [getContainer, getActiveNodeId, dispatch]
  );

  const handleCopy = useCallback(createHandleCopy(clipboardParams), [
    clipboardParams,
  ]);

  const handlePaste = useCallback(createHandlePaste(clipboardParams), [
    clipboardParams,
  ]);

  const handleCut = useCallback(createHandleCut(clipboardParams), [
    clipboardParams,
  ]);

  return { handleCopy, handlePaste, handleCut };
}

"use client";

import React, { createContext, useContext } from "react";

/**
 * EditorContext
 *
 * Holds all stable editor-wide values that every Block needs.
 * This eliminates the 30+ prop drilling from Editor → Block,
 * and allows the Block memo comparator to only care about 4 props.
 *
 * Stable values (callbacks that never change identity): put in the context.
 * Dynamic per-block values (nodeId, isActive, depth, isFirstBlock): keep as props.
 */
export interface EditorContextValue {
  // Mode
  readOnly: boolean;
  notionBased: boolean;

  // Media upload
  onUploadImage?: (file: File) => Promise<string>;
  onUploadVideo?: (file: File) => Promise<string>;

  // Block operations — each takes nodeId as first arg so Block wraps with its own id
  onInput: (nodeId: string, element: HTMLElement) => void;
  onKeyDown: (e: React.KeyboardEvent<HTMLElement>, nodeId: string) => void;
  onNodeClick: (nodeId: string) => void;
  onDeleteNode: (nodeId: string) => void;
  onCreateNested: (nodeId: string) => void;
  onChangeBlockType: (nodeId: string, newType: string) => void;
  onInsertImage: (nodeId: string) => void;
  onCreateList: (nodeId: string, listType: string) => void;
  onCreateTable: (nodeId: string) => void;

  // Image selection
  selectedImageIds: Set<string>;
  onToggleImageSelection: (nodeId: string) => void;
  onClickWithModifier: (e: React.MouseEvent, nodeId: string) => void;

  // Drag-drop
  onBlockDragStart: (nodeId: string) => void;
  onImageDragStart: (nodeId: string) => void;
  onSetDragOverNodeId: (nodeId: string | null) => void;
  onSetDropPosition: (
    position: "before" | "after" | "left" | "right" | null
  ) => void;
  draggingNodeId: string | null;
  onSetDraggingNodeId: (nodeId: string | null) => void;
  onFlexContainerDragOver: (
    e: React.DragEvent,
    flexId: string,
    position: "left" | "right" | null
  ) => void;
  onFlexContainerDragLeave: (e: React.DragEvent) => void;
  onFlexContainerDrop: (
    e: React.DragEvent,
    flexId: string,
    position: "left" | "right" | null
  ) => void;
  dragOverFlexId: string | null;
  flexDropPosition: "left" | "right" | null;

  // Node ref registration (replaces the nodeRef prop callback)
  registerNodeRef: (nodeId: string, el: HTMLElement | null) => void;

  // Cover image (for first block drag handle)
  hasCoverImage: boolean;
  onUploadCoverImage?: (file: File) => Promise<string>;

  // AI integration
  onAISelect?: (nodeId: string) => void;
}

const EditorContext = createContext<EditorContextValue | null>(null);

/**
 * EditorContextProvider
 *
 * Wrap the editor content with this provider. Pass a memoized `value` object
 * (built with useMemo in Editor.tsx) so that context consumers only re-render
 * when the specific fields they read actually change.
 */
export function EditorContextProvider({
  value,
  children,
}: {
  value: EditorContextValue;
  children: React.ReactNode;
}) {
  return (
    <EditorContext.Provider value={value}>{children}</EditorContext.Provider>
  );
}

/**
 * useEditorContext
 *
 * Reads the editor-wide context. Throws if used outside an EditorContextProvider
 * so bugs surface immediately during development.
 */
export function useEditorContext(): EditorContextValue {
  const ctx = useContext(EditorContext);
  if (!ctx) {
    throw new Error(
      "useEditorContext must be used inside <EditorContextProvider>. " +
        "Make sure Block is rendered within the Editor component tree."
    );
  }
  return ctx;
}

/**
 * useEditorDragDrop
 *
 * Encapsulates all drag-and-drop state and handlers for the editor,
 * including both block-level drag-drop and flex-container drag-drop.
 *
 * Uses refs for draggingNodeId and dropPosition so that useCallback
 * dependencies stay stable and handlers always read current values.
 */

import { useState, useCallback, useRef } from "react";
import { ContainerNode } from "..";
import {
  createHandleImageDragStart,
  createHandleBlockDragStart,
  createHandleDragEnter,
  createHandleDragOver,
  createHandleDragLeave,
  createHandleDrop,
} from "../handlers/drag-drop-handlers";
import {
  createHandleFlexContainerDragOver,
  createHandleFlexContainerDragLeave,
  createHandleFlexContainerDrop,
} from "../handlers/flex-container-handlers";

interface UseEditorDragDropParams {
  dispatch: (action: any) => void;
  getContainer: () => ContainerNode;
  toast: any;
  onUploadImage?: (file: File) => Promise<string>;
}

export function useEditorDragDrop({
  dispatch,
  getContainer,
  toast,
  onUploadImage,
}: UseEditorDragDropParams) {
  const [dragOverNodeId, setDragOverNodeId] = useState<string | null>(null);
  const [dropPosition, setDropPosition] = useState<
    "before" | "after" | "left" | "right" | null
  >(null);
  const [draggingNodeId, setDraggingNodeId] = useState<string | null>(null);
  const [dragOverFlexId, setDragOverFlexId] = useState<string | null>(null);
  const [flexDropPosition, setFlexDropPosition] = useState<
    "left" | "right" | null
  >(null);

  // Refs for stable callback access to current values
  const draggingNodeIdRef = useRef(draggingNodeId);
  draggingNodeIdRef.current = draggingNodeId;

  const dropPositionRef = useRef(dropPosition);
  dropPositionRef.current = dropPosition;

  const handleImageDragStart = useCallback(
    createHandleImageDragStart(setDraggingNodeId),
    []
  );

  const handleBlockDragStart = useCallback(
    createHandleBlockDragStart(setDraggingNodeId),
    []
  );

  const handleDragEnter = useCallback(createHandleDragEnter(), []);

  const handleDragOver = useCallback(
    (e: React.DragEvent, nodeId: string) => {
      const handler = createHandleDragOver({
        container: getContainer,
        dispatch,
        draggingNodeId: draggingNodeIdRef.current,
        setDraggingNodeId,
        setDragOverNodeId,
        setDropPosition,
      });
      return handler(e, nodeId);
    },
    [dispatch, getContainer]
  );

  const handleDragLeave = useCallback(
    createHandleDragLeave(setDragOverNodeId, setDropPosition),
    []
  );

  const handleDrop = useCallback(
    (e: React.DragEvent, nodeId: string) => {
      const handler = createHandleDrop(
        {
          container: getContainer,
          dispatch,
          toast,
          draggingNodeId: draggingNodeIdRef.current,
          setDraggingNodeId,
          setDragOverNodeId,
          setDropPosition,
          setIsUploading: () => {},
          onUploadImage,
        },
        dropPositionRef.current
      );
      return handler(e, nodeId);
    },
    [dispatch, getContainer, toast, onUploadImage]
  );

  const handleFlexContainerDragOver = useCallback(
    (e: React.DragEvent, flexContainerId: string, position: "left" | "right" | null) => {
      const handler = createHandleFlexContainerDragOver({
        container: getContainer(),
        dispatch,
        draggingNodeId: draggingNodeIdRef.current,
        setDragOverFlexId,
        setFlexDropPosition,
      });
      return handler(e, flexContainerId, position);
    },
    [dispatch, getContainer]
  );

  const handleFlexContainerDragLeave = useCallback(
    createHandleFlexContainerDragLeave(setDragOverFlexId, setFlexDropPosition),
    []
  );

  const handleFlexContainerDrop = useCallback(
    (e: React.DragEvent, flexContainerId: string, position: "left" | "right" | null) => {
      const handler = createHandleFlexContainerDrop({
        container: getContainer(),
        dispatch,
        draggingNodeId: draggingNodeIdRef.current,
        setDragOverFlexId,
        setFlexDropPosition,
      });
      return handler(e, flexContainerId, position);
    },
    [dispatch, getContainer]
  );

  return {
    // State
    dragOverNodeId,
    setDragOverNodeId,
    dropPosition,
    setDropPosition,
    draggingNodeId,
    setDraggingNodeId,
    dragOverFlexId,
    flexDropPosition,
    // Block drag-drop handlers
    handleImageDragStart,
    handleBlockDragStart,
    handleDragEnter,
    handleDragOver,
    handleDragLeave,
    handleDrop,
    // Flex container drag-drop handlers
    handleFlexContainerDragOver,
    handleFlexContainerDragLeave,
    handleFlexContainerDrop,
  };
}

/**
 * useEditorFileUpload
 *
 * Encapsulates all file upload state, refs, and handlers for the editor.
 * Covers single image, multiple images, video, and free-image uploads.
 */

import { useState, useRef, useCallback } from "react";
import { ContainerNode } from "..";
import {
  createHandleFileChange,
  createHandleMultipleFilesChange,
  createHandleImageUploadClick,
  createHandleMultipleImagesUploadClick,
  createHandleFreeImageFileChange,
  createHandleFreeImageUploadClick,
} from "../handlers/file-upload-handlers";

interface UseEditorFileUploadParams {
  dispatch: (action: any) => void;
  getContainer: () => ContainerNode;
  getActiveNodeId: () => string | null;
  toast: any;
  onUploadImage?: (file: File) => Promise<string>;
}

export function useEditorFileUpload({
  dispatch,
  getContainer,
  getActiveNodeId,
  toast,
  onUploadImage,
}: UseEditorFileUploadParams) {
  const [isUploading, setIsUploading] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const multipleFileInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);
  const freeImageInputRef = useRef<HTMLInputElement>(null);

  // Build params objects using getters so handlers always see fresh values
  const makeUploadParams = (
    inputRef: React.RefObject<HTMLInputElement | null>,
    multiRef: React.RefObject<HTMLInputElement | null>
  ) => ({
    get container() {
      return getContainer();
    },
    dispatch,
    get state() {
      return {
        activeNodeId: getActiveNodeId(),
        current: getContainer(),
        undoStack: [],
        redoStack: [],
      } as any;
    },
    toast,
    setIsUploading,
    fileInputRef: inputRef,
    multipleFileInputRef: multiRef,
    onUploadImage,
  });

  const handleFileChange = useCallback(
    createHandleFileChange(makeUploadParams(fileInputRef, multipleFileInputRef)),
    [dispatch, getContainer, getActiveNodeId, toast, onUploadImage]
  );

  const handleMultipleFilesChange = useCallback(
    createHandleMultipleFilesChange(
      makeUploadParams(fileInputRef, multipleFileInputRef)
    ),
    [dispatch, getContainer, getActiveNodeId, toast, onUploadImage]
  );

  const handleImageUploadClick = useCallback(
    createHandleImageUploadClick(fileInputRef),
    []
  );

  const handleMultipleImagesUploadClick = useCallback(
    createHandleMultipleImagesUploadClick(multipleFileInputRef),
    []
  );

  const handleVideoUploadClick = useCallback(
    createHandleImageUploadClick(videoInputRef),
    []
  );

  const handleVideoFileChange = useCallback(
    createHandleFileChange(makeUploadParams(videoInputRef, videoInputRef)),
    [dispatch, getContainer, getActiveNodeId, toast, onUploadImage]
  );

  const handleFreeImageFileChange = useCallback(
    createHandleFreeImageFileChange(
      makeUploadParams(freeImageInputRef, freeImageInputRef)
    ),
    [dispatch, getContainer, getActiveNodeId, toast, onUploadImage]
  );

  const handleFreeImageUploadClick = useCallback(
    createHandleFreeImageUploadClick(freeImageInputRef),
    []
  );

  return {
    // State
    isUploading,
    setIsUploading,
    // Refs
    fileInputRef,
    multipleFileInputRef,
    videoInputRef,
    freeImageInputRef,
    // Handlers
    handleFileChange,
    handleMultipleFilesChange,
    handleImageUploadClick,
    handleMultipleImagesUploadClick,
    handleVideoUploadClick,
    handleVideoFileChange,
    handleFreeImageFileChange,
    handleFreeImageUploadClick,
  };
}

/**
 * useEditorKeyboardShortcuts
 *
 * Registers global keyboard shortcuts for the editor:
 *   - Ctrl/Cmd+A  : Select all content in current block
 *   - Ctrl/Cmd+B/I/U/Shift+S/E : Inline formatting
 *   - Ctrl/Cmd+Z  : Undo
 *   - Ctrl/Cmd+Y / Ctrl/Cmd+Shift+Z : Redo
 *   - ArrowUp/Down : Navigate between blocks
 */

import { useEffect } from "react";
import { EditorActions, ContainerNode } from "..";
import { findNodeInTree } from "../utils/editor-helpers";

interface UseEditorKeyboardShortcutsParams {
  readOnly: boolean;
  dispatch: (action: any) => void;
  getContainer: () => ContainerNode;
  getActiveNodeId: () => string | null;
  getCanUndo: () => boolean;
  getCanRedo: () => boolean;
  nodeRefs: React.MutableRefObject<Map<string, HTMLElement>>;
  handleFormat: (format: "bold" | "italic" | "underline" | "strikethrough" | "code") => void;
}

export function useEditorKeyboardShortcuts({
  dispatch,
  getContainer,
  getActiveNodeId,
  getCanUndo,
  getCanRedo,
  nodeRefs,
  handleFormat,
}: UseEditorKeyboardShortcutsParams) {
  useEffect(() => {
    const handleGlobalKeyDown = (e: KeyboardEvent) => {
      const isCtrlOrCmd = e.ctrlKey || e.metaKey;

      const activeElement = document.activeElement;
      const isInEditor = Array.from(nodeRefs.current.values()).some(
        (el) => el === activeElement || el.contains(activeElement)
      );

      // Ctrl+A / Cmd+A - Select all content in current block only
      if (isCtrlOrCmd && e.key === "a" && isInEditor) {
        e.preventDefault();

        const selection = window.getSelection();
        if (!selection) return;

        const currentBlock = activeElement as HTMLElement;
        if (currentBlock && currentBlock.isContentEditable) {
          const range = document.createRange();
          range.selectNodeContents(currentBlock);
          selection.removeAllRanges();
          selection.addRange(range);
        }
      }

      // Ctrl+B / Cmd+B - Toggle Bold
      if (isCtrlOrCmd && e.key === "b" && isInEditor) {
        e.preventDefault();
        const selection = window.getSelection();
        if (selection && !selection.isCollapsed) {
          handleFormat("bold");
        }
      }

      // Ctrl+I / Cmd+I - Toggle Italic
      if (isCtrlOrCmd && e.key === "i" && isInEditor) {
        e.preventDefault();
        const selection = window.getSelection();
        if (selection && !selection.isCollapsed) {
          handleFormat("italic");
        }
      }

      // Ctrl+U / Cmd+U - Toggle Underline
      if (isCtrlOrCmd && e.key === "u" && isInEditor) {
        e.preventDefault();
        const selection = window.getSelection();
        if (selection && !selection.isCollapsed) {
          handleFormat("underline");
        }
      }

      // Ctrl+Shift+S / Cmd+Shift+S - Toggle Strikethrough
      if (isCtrlOrCmd && e.shiftKey && e.key === "S" && isInEditor) {
        e.preventDefault();
        const selection = window.getSelection();
        if (selection && !selection.isCollapsed) {
          handleFormat("strikethrough");
        }
      }

      // Ctrl+E / Cmd+E - Toggle Code
      if (isCtrlOrCmd && e.key === "e" && isInEditor) {
        e.preventDefault();
        const selection = window.getSelection();
        if (selection && !selection.isCollapsed) {
          handleFormat("code");
        }
      }

      // Ctrl+Z / Cmd+Z - Undo
      if (isCtrlOrCmd && e.key === "z" && !e.shiftKey) {
        if (
          !isInEditor &&
          (activeElement?.tagName === "INPUT" ||
            activeElement?.tagName === "TEXTAREA")
        ) {
          return;
        }
        e.preventDefault();
        if (getCanUndo()) {
          dispatch(EditorActions.undo());
        }
      }

      // Ctrl+Y / Cmd+Y or Ctrl+Shift+Z - Redo
      if (
        (isCtrlOrCmd && e.key === "y") ||
        (isCtrlOrCmd && e.shiftKey && e.key === "Z")
      ) {
        if (
          !isInEditor &&
          (activeElement?.tagName === "INPUT" ||
            activeElement?.tagName === "TEXTAREA")
        ) {
          return;
        }
        e.preventDefault();
        if (getCanRedo()) {
          dispatch(EditorActions.redo());
        }
      }

      // Arrow Up/Down - Navigate between blocks
      const activeNodeId = getActiveNodeId();
      if (
        (e.key === "ArrowUp" || e.key === "ArrowDown") &&
        isInEditor &&
        activeNodeId
      ) {
        const currentElement = activeElement as HTMLElement;
        const currentNodeId =
          currentElement?.getAttribute("data-node-id") || activeNodeId;

        // Find the current node and its siblings
        const result = findNodeInTree(currentNodeId, getContainer());
        if (!result) return;

        const { siblings } = result;
        const currentIndex = siblings.findIndex((n) => n.id === currentNodeId);
        if (currentIndex === -1) return;

        // ArrowUp: Navigate to previous block
        if (e.key === "ArrowUp" && currentIndex > 0) {
          e.preventDefault();
          const prevNode = siblings[currentIndex - 1];
          dispatch(EditorActions.setActiveNode(prevNode.id));

          // Focus and place cursor at the end of the previous node
          requestAnimationFrame(() => {
            const prevElement = nodeRefs.current.get(prevNode.id);
            if (prevElement) {
              prevElement.focus();
              const range = document.createRange();
              const sel = window.getSelection();

              // Place cursor at the end
              const lastChild =
                prevElement.childNodes[prevElement.childNodes.length - 1];
              if (lastChild?.nodeType === Node.TEXT_NODE) {
                range.setStart(lastChild, lastChild.textContent?.length || 0);
              } else if (lastChild) {
                range.setStartAfter(lastChild);
              } else {
                range.selectNodeContents(prevElement);
              }
              range.collapse(true);
              sel?.removeAllRanges();
              sel?.addRange(range);
            }
          });
        }

        // ArrowDown: Navigate to next block
        if (e.key === "ArrowDown" && currentIndex < siblings.length - 1) {
          e.preventDefault();
          const nextNode = siblings[currentIndex + 1];
          dispatch(EditorActions.setActiveNode(nextNode.id));

          // Focus and place cursor at the end of the next node
          requestAnimationFrame(() => {
            const nextElement = nodeRefs.current.get(nextNode.id);
            if (nextElement) {
              nextElement.focus();
              const range = document.createRange();
              const sel = window.getSelection();

              // Place cursor at the end
              const lastChild =
                nextElement.childNodes[nextElement.childNodes.length - 1];
              if (lastChild?.nodeType === Node.TEXT_NODE) {
                range.setStart(lastChild, lastChild.textContent?.length || 0);
              } else if (lastChild) {
                range.setStartAfter(lastChild);
              } else {
                range.selectNodeContents(nextElement);
              }
              range.collapse(true);
              sel?.removeAllRanges();
              sel?.addRange(range);
            }
          });
        }
      }
    };

    document.addEventListener("keydown", handleGlobalKeyDown);
    return () => {
      document.removeEventListener("keydown", handleGlobalKeyDown);
    };
    // Use stable getter functions so the effect captures the latest values
    // without needing to re-register on every render
  }, [
    dispatch,
    getContainer,
    getActiveNodeId,
    getCanUndo,
    getCanRedo,
    nodeRefs,
    handleFormat,
  ]);
}

/**
 * useEditorSelection
 *
 * Encapsulates all selection-related formatting handlers and the debounced
 * selection-change listener for the editor.
 *
 * Stable design: handler functions are created once via useRef and never
 * recreated. They read all live values through a mutable ref so no closures
 * ever go stale.
 */

import React, { useState, useCallback, useRef } from "react";
import {
  createHandleSelectionChange,
  createHandleFormat,
  createHandleApplyColor,
  createHandleApplyFontSize,
  createHandleTypeChange,
} from "../handlers/selection-handlers";
import type { ContainerNode } from "../types";
import type { SelectionHandlerParams } from "../handlers/selection-handlers";

interface UseEditorSelectionParams {
  dispatch: React.Dispatch<any>;
  selectionManager: any;
  activeNodeId: string | null;
  getContainer: () => ContainerNode;
  toast: any;
  undoStackLength: number;
  currentSelection: any;
  nodeRefs: React.MutableRefObject<Map<string, HTMLElement>>;
}

export function useEditorSelection({
  dispatch,
  selectionManager,
  activeNodeId,
  getContainer,
  toast,
  undoStackLength,
  currentSelection,
  nodeRefs,
}: UseEditorSelectionParams) {
  const [selectedColor, setSelectedColor] = useState<string>("");

  // A single mutable ref that always holds the latest prop values.
  // All handler closures read from this ref, so they never go stale.
  const latestRef = useRef({
    dispatch,
    selectionManager,
    activeNodeId,
    getContainer,
    toast,
    undoStackLength,
    currentSelection,
    nodeRefs,
    setSelectedColor,
  });
  // Keep the ref up-to-date every render (cheap write, no re-render triggered)
  latestRef.current.dispatch = dispatch;
  latestRef.current.selectionManager = selectionManager;
  latestRef.current.activeNodeId = activeNodeId;
  latestRef.current.getContainer = getContainer;
  latestRef.current.toast = toast;
  latestRef.current.undoStackLength = undoStackLength;
  latestRef.current.currentSelection = currentSelection;
  latestRef.current.nodeRefs = nodeRefs;
  latestRef.current.setSelectedColor = setSelectedColor;

  const selectionDispatchTimerRef = useRef<NodeJS.Timeout | null>(null);

  // Build a stable SelectionHandlerParams proxy that always forwards to
  // the latest values via latestRef. This object is created once and its
  // identity never changes, so handlers that close over it are always fresh.
  const stableParams = useRef<SelectionHandlerParams>(null as any);
  if (!stableParams.current) {
    stableParams.current = {
      get container() {
        return latestRef.current.getContainer;
      },
      get state() {
        return {
          activeNodeId: latestRef.current.activeNodeId,
          current: latestRef.current.getContainer(),
          undoStack: [],
          redoStack: [],
          currentSelection: latestRef.current.currentSelection,
        } as any;
      },
      get dispatch() {
        return latestRef.current.dispatch;
      },
      get selectionManager() {
        return latestRef.current.selectionManager;
      },
      get nodeRefs() {
        return latestRef.current.nodeRefs;
      },
    };
  }

  // Build stable toast/setSelectedColor wrappers for color/fontSize handlers
  const stableToast = useCallback((...args: any[]) => {
    return (latestRef.current.toast as any)(...args);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);
  const stableSetSelectedColor = useCallback((color: string) => {
    latestRef.current.setSelectedColor(color);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // ── Create all handlers once (truly stable, empty deps) ───────────────────

  const handleSelectionChange = useCallback(
    createHandleSelectionChange(stableParams.current, selectionDispatchTimerRef),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    []
  );

  const handleFormat = useCallback(
    createHandleFormat(stableParams.current),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    []
  );

  const handleApplyColor = useCallback(
    createHandleApplyColor(stableParams.current, stableToast, stableSetSelectedColor),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    []
  );

  const handleApplyFontSize = useCallback(
    createHandleApplyFontSize(stableParams.current, stableToast),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    []
  );

  // handleTypeChange depends on handleSelectionChange but since that is
  // now stable ([] deps), handleTypeChange is also stable.
  const handleTypeChange = useCallback(
    createHandleTypeChange(stableParams.current, handleSelectionChange),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    []
  );

  return {
    selectedColor,
    handleSelectionChange,
    handleFormat,
    handleApplyColor,
    handleApplyFontSize,
    handleTypeChange,
  };
}

/**
 * useImageResize Hook
 *
 * Reusable hook that encapsulates image resize logic using the PointerEvent API.
 * Uses refs for intermediate values during drag to avoid re-renders per pixel,
 * and only commits state + dispatch on pointerup.
 */

"use client";

import { useRef, useState, useCallback, RefObject } from "react";

export interface UseImageResizeOptions {
  nodeId: string;
  initialWidth: number;
  unit: "percent" | "px";
  minWidth: number; // 20 for %, 200 for px
  maxWidth: number; // 100 for %, 800 for px
  containerRef: RefObject<HTMLElement | null>;
  dispatch: (action: any) => void;
  getNodeAttributes: () => Record<string, any>;
  aspectRatio?: number | null;
}

export interface UseImageResizeReturn {
  /** Current committed width value */
  currentWidth: number;
  /** Whether a resize drag is in progress */
  isResizing: boolean;
  /** Which handle side is being dragged */
  resizeSide: "left" | "right" | null;
  /** Dimension label string during resize, e.g. "640 x 480" */
  dimensionLabel: string | null;
  /** Attach to a resize handle's onPointerDown */
  handlePointerDown: (
    e: React.PointerEvent,
    side: "left" | "right"
  ) => void;
  /** Attach to a resize handle's onPointerMove */
  handlePointerMove: (e: React.PointerEvent) => void;
  /** Attach to a resize handle's onPointerUp */
  handlePointerUp: (e: React.PointerEvent) => void;
  /** Set width to a preset percentage (25, 50, 75, 100) */
  setWidthPreset: (preset: 25 | 50 | 75 | 100) => void;
  /** Keyboard handler for Shift+Arrow resizing */
  onKeyDown: (e: React.KeyboardEvent) => void;
  /** Update currentWidth when node attributes change externally */
  setCurrentWidth: (width: number) => void;
}

export function useImageResize({
  nodeId,
  initialWidth,
  unit,
  minWidth,
  maxWidth,
  containerRef,
  dispatch,
  getNodeAttributes,
  aspectRatio,
}: UseImageResizeOptions): UseImageResizeReturn {
  const [currentWidth, setCurrentWidth] = useState(initialWidth);
  const [isResizing, setIsResizing] = useState(false);
  const [resizeSide, setResizeSide] = useState<"left" | "right" | null>(null);
  const [dimensionLabel, setDimensionLabel] = useState<string | null>(null);

  // Refs for intermediate drag values — no re-renders per pixel
  const startXRef = useRef(0);
  const startWidthRef = useRef(initialWidth);
  const liveWidthRef = useRef(initialWidth);
  const rafRef = useRef<number | null>(null);
  const resizeSideRef = useRef<"left" | "right" | null>(null);

  const clamp = useCallback(
    (value: number) => Math.max(minWidth, Math.min(maxWidth, value)),
    [minWidth, maxWidth]
  );

  const computeDimensionLabel = useCallback(
    (width: number): string => {
      if (unit === "percent") {
        if (aspectRatio && containerRef.current) {
          const containerW = containerRef.current.offsetWidth;
          const pxWidth = Math.round((width / 100) * containerW);
          const pxHeight = Math.round(pxWidth / aspectRatio);
          return `${pxWidth} x ${pxHeight}`;
        }
        return `${Math.round(width)}%`;
      }
      // px mode
      if (aspectRatio) {
        const pxHeight = Math.round(width / aspectRatio);
        return `${Math.round(width)} x ${pxHeight}`;
      }
      return `${Math.round(width)}px`;
    },
    [unit, aspectRatio, containerRef]
  );

  const commitWidth = useCallback(
    (width: number) => {
      const attrs = getNodeAttributes();
      const existingStyles =
        attrs?.styles && typeof attrs.styles === "object" && !Array.isArray(attrs.styles)
          ? (attrs.styles as Record<string, string>)
          : {};

      const widthStr = unit === "percent" ? `${width.toFixed(2)}%` : `${Math.round(width)}px`;

      const newStyles = {
        ...existingStyles,
        width: widthStr,
      };

      dispatch({
        type: "UPDATE_ATTRIBUTES",
        payload: {
          id: nodeId,
          attributes: {
            ...attrs,
            styles: newStyles,
          },
          merge: false,
        },
      });
    },
    [nodeId, unit, dispatch, getNodeAttributes]
  );

  const handlePointerDown = useCallback(
    (e: React.PointerEvent, side: "left" | "right") => {
      e.preventDefault();
      e.stopPropagation();

      // Capture pointer so all subsequent events route to this element
      (e.target as HTMLElement).setPointerCapture(e.pointerId);

      startXRef.current = e.clientX;
      startWidthRef.current = currentWidth;
      liveWidthRef.current = currentWidth;
      resizeSideRef.current = side;

      setIsResizing(true);
      setResizeSide(side);
      setDimensionLabel(computeDimensionLabel(currentWidth));
    },
    [currentWidth, computeDimensionLabel]
  );

  const handlePointerMove = useCallback(
    (e: React.PointerEvent) => {
      if (!isResizing) return;

      // Cancel any pending rAF to avoid stacking
      if (rafRef.current !== null) {
        cancelAnimationFrame(rafRef.current);
      }

      const clientX = e.clientX;

      rafRef.current = requestAnimationFrame(() => {
        const deltaX = clientX - startXRef.current;
        const side = resizeSideRef.current;

        let newWidth: number;

        if (unit === "percent") {
          if (!containerRef.current) return;
          const containerWidth = containerRef.current.offsetWidth;
          const adjustedDelta = side === "left" ? -deltaX : deltaX;
          const deltaPercent = (adjustedDelta / containerWidth) * 100;
          newWidth = clamp(startWidthRef.current + deltaPercent);
        } else {
          // px mode
          const adjustedDelta = side === "left" ? -deltaX : deltaX;
          newWidth = clamp(startWidthRef.current + adjustedDelta);
        }

        liveWidthRef.current = newWidth;
        setCurrentWidth(newWidth);
        setDimensionLabel(computeDimensionLabel(newWidth));

        rafRef.current = null;
      });
    },
    [isResizing, unit, containerRef, clamp, computeDimensionLabel]
  );

  const handlePointerUp = useCallback(
    (e: React.PointerEvent) => {
      if (!isResizing) return;

      (e.target as HTMLElement).releasePointerCapture(e.pointerId);

      // Cancel any pending rAF
      if (rafRef.current !== null) {
        cancelAnimationFrame(rafRef.current);
        rafRef.current = null;
      }

      const finalWidth = liveWidthRef.current;
      setCurrentWidth(finalWidth);
      setIsResizing(false);
      setResizeSide(null);
      setDimensionLabel(null);

      commitWidth(finalWidth);
    },
    [isResizing, commitWidth]
  );

  const setWidthPreset = useCallback(
    (preset: 25 | 50 | 75 | 100) => {
      const newWidth = unit === "percent" ? preset : clamp((preset / 100) * maxWidth);
      setCurrentWidth(newWidth);
      commitWidth(newWidth);
    },
    [unit, maxWidth, clamp, commitWidth]
  );

  const onKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (!e.shiftKey) return;
      if (e.key !== "ArrowLeft" && e.key !== "ArrowRight") return;

      e.preventDefault();

      const step = unit === "percent" ? 5 : 20;
      const direction = e.key === "ArrowLeft" ? -1 : 1;
      const newWidth = clamp(currentWidth + direction * step);

      setCurrentWidth(newWidth);
      commitWidth(newWidth);
    },
    [currentWidth, unit, clamp, commitWidth]
  );

  return {
    currentWidth,
    isResizing,
    resizeSide,
    dimensionLabel,
    handlePointerDown,
    handlePointerMove,
    handlePointerUp,
    setWidthPreset,
    onKeyDown,
    setCurrentWidth,
  };
}

/**
 * useImageSelection
 *
 * Manages multi-image selection state and the operations that act on the selection
 * (group into flex, reverse order, extract from flex, clear).
 */

import React, { useState, useCallback, useMemo } from "react";
import {
  createHandleToggleImageSelection,
  createHandleClearImageSelection,
  createHandleGroupSelectedImages,
  checkImagesInSameFlex,
  createHandleReverseImagesInFlex,
  createHandleExtractFromFlex,
} from "../handlers/image-selection-handlers";
import type { ContainerNode } from "../types";

interface UseImageSelectionParams {
  dispatch: React.Dispatch<any>;
  toast: any;
  getContainer: () => ContainerNode;
}

export function useImageSelection({
  dispatch,
  toast,
  getContainer,
}: UseImageSelectionParams) {
  const [selectedImageIds, setSelectedImageIds] = useState<Set<string>>(
    new Set()
  );

  const handleToggleImageSelection = useCallback(
    createHandleToggleImageSelection(selectedImageIds, setSelectedImageIds),
    [selectedImageIds]
  );

  const handleClearImageSelection = useCallback(
    createHandleClearImageSelection(setSelectedImageIds),
    []
  );

  const handleGroupSelectedImages = useCallback(
    createHandleGroupSelectedImages(
      { container: getContainer, dispatch, toast },
      selectedImageIds,
      handleClearImageSelection
    ),
    [dispatch, toast, selectedImageIds, handleClearImageSelection]
  );

  const flexInfo = useMemo(() => {
    if (selectedImageIds.size < 2) {
      return { inSameFlex: false, flexParentId: null };
    }
    return checkImagesInSameFlex(
      { container: getContainer, dispatch, toast },
      selectedImageIds
    );
  }, [selectedImageIds, dispatch, toast, getContainer]);

  const handleReverseImagesInFlex = useCallback(
    createHandleReverseImagesInFlex(
      { container: getContainer, dispatch, toast },
      selectedImageIds,
      flexInfo.flexParentId || ""
    ),
    [dispatch, toast, selectedImageIds, flexInfo.flexParentId]
  );

  const handleExtractFromFlex = useCallback(
    createHandleExtractFromFlex(
      { container: getContainer, dispatch, toast },
      selectedImageIds,
      flexInfo.flexParentId || "",
      handleClearImageSelection
    ),
    [dispatch, toast, selectedImageIds, flexInfo.flexParentId, handleClearImageSelection]
  );

  return {
    selectedImageIds,
    handleToggleImageSelection,
    handleClearImageSelection,
    handleGroupSelectedImages,
    flexInfo,
    handleReverseImagesInFlex,
    handleExtractFromFlex,
  };
}

/**
 * useMediaPaste
 *
 * Attaches a document-level paste listener that intercepts image and video
 * file pastes from the clipboard and uploads them into the editor as nodes.
 */

import { useEffect } from "react";
import { EditorActions } from "..";
import type { ContainerNode, TextNode } from "../types";

interface UseMediaPasteParams {
  readOnly: boolean;
  dispatch: React.Dispatch<any>;
  toast: any;
  onUploadImage?: (file: File) => Promise<string>;
  setIsUploading: (uploading: boolean) => void;
  getContainer: () => ContainerNode;
  getActiveNodeId: () => string | null;
  nodeRefs: React.MutableRefObject<Map<string, HTMLElement>>;
}

export function useMediaPaste({
  readOnly,
  dispatch,
  toast,
  onUploadImage,
  setIsUploading,
  getContainer,
  getActiveNodeId,
  nodeRefs,
}: UseMediaPasteParams) {
  useEffect(() => {
    const handlePaste = async (e: ClipboardEvent) => {
      const activeElement = document.activeElement;
      const isInEditor = Array.from(nodeRefs.current.values()).some(
        (el) => el === activeElement || el.contains(activeElement)
      );

      if (!isInEditor || readOnly) return;

      const items = e.clipboardData?.items;
      if (!items) return;

      const mediaFiles: File[] = [];
      for (let i = 0; i < items.length; i++) {
        const item = items[i];
        if (
          item.kind === "file" &&
          (item.type.startsWith("image/") || item.type.startsWith("video/"))
        ) {
          const file = item.getAsFile();
          if (file) {
            mediaFiles.push(file);
          }
        }
      }

      if (mediaFiles.length === 0) return;

      e.preventDefault();

      setIsUploading(true);

      try {
        const uploadPromises = mediaFiles.map(async (file) => {
          if (onUploadImage) {
            return await onUploadImage(file);
          } else {
            const { uploadImage } = await import("../utils/image-upload");
            const result = await uploadImage(file);
            if (!result.success || !result.url) {
              throw new Error(result.error || "Upload failed");
            }
            return result.url;
          }
        });

        const mediaUrls = await Promise.all(uploadPromises);

        const timestamp = Date.now();
        const mediaNodes: TextNode[] = mediaUrls.map((url, index) => {
          const file = mediaFiles[index];
          const isVideo = file.type.startsWith("video/");

          return {
            id: `${isVideo ? "video" : "img"}-${timestamp}-${index}`,
            type: isVideo ? "video" : "img",
            content: "",
            attributes: {
              src: url,
              alt: file.name,
            },
          } as TextNode;
        });

        const container = getContainer();
        const targetId =
          getActiveNodeId() ||
          container.children[container.children.length - 1]?.id;

        if (mediaFiles.length === 1) {
          if (targetId) {
            dispatch(
              EditorActions.insertNode(mediaNodes[0], targetId, "after")
            );
          }
        } else {
          const flexContainer: ContainerNode = {
            id: `flex-container-${timestamp}`,
            type: "container",
            children: mediaNodes,
            attributes: {
              layoutType: "flex",
              gap: "4",
              flexWrap: "wrap",
            },
          };

          if (targetId) {
            dispatch(
              EditorActions.insertNode(flexContainer, targetId, "after")
            );
          }
        }

        const videoCount = mediaFiles.filter((f) =>
          f.type.startsWith("video/")
        ).length;
        const imageCount = mediaFiles.filter((f) =>
          f.type.startsWith("image/")
        ).length;
        let description = "";
        if (videoCount > 0 && imageCount > 0) {
          description = `${imageCount} image(s) and ${videoCount} video(s) pasted successfully.`;
        } else if (videoCount > 0) {
          description = `${videoCount} video(s) pasted successfully.`;
        } else {
          description = `${imageCount} image(s) pasted successfully.`;
        }

        toast({
          title: "Media pasted",
          description,
        });
      } catch (error) {
        toast({
          variant: "destructive",
          title: "Paste failed",
          description:
            error instanceof Error
              ? error.message
              : "An unexpected error occurred",
        });
      } finally {
        setIsUploading(false);
      }
    };

    document.addEventListener("paste", handlePaste);
    return () => {
      document.removeEventListener("paste", handlePaste);
    };
  }, [
    readOnly,
    dispatch,
    toast,
    onUploadImage,
    setIsUploading,
    getContainer,
    getActiveNodeId,
    nodeRefs,
  ]);
}

/**
 * useTableOperations
 *
 * Manages the table dialog state and handles table creation and markdown table import.
 */

import React, { useState, useCallback } from "react";
import { EditorActions } from "..";
import { createHandleCreateTable } from "../handlers/node-operation-handlers";
import type { ContainerNode } from "../types";

interface UseTableOperationsParams {
  dispatch: React.Dispatch<any>;
  toast: any;
  getContainer: () => ContainerNode;
  editorContentRef: React.RefObject<HTMLDivElement | null>;
}

export function useTableOperations({
  dispatch,
  toast,
  getContainer,
  editorContentRef,
}: UseTableOperationsParams) {
  const [tableDialogOpen, setTableDialogOpen] = useState(false);
  const [tableInsertionTargetId, setTableInsertionTargetId] = useState<
    string | undefined
  >(undefined);

  const nodeOperationParams = {
    container: getContainer,
    dispatch,
    toast,
    nodeRefs: { current: new Map<string, HTMLElement>() },
    editorContentRef,
  };

  const handleCreateTableFromCommand = useCallback(
    (nodeId: string) => {
      setTableInsertionTargetId(nodeId);
      dispatch(EditorActions.setActiveNode(nodeId));
      setTableDialogOpen(true);
    },
    [dispatch]
  );

  const handleImportMarkdownTable = useCallback(
    (table: any) => {
      const currentContainer = getContainer();
      const timestamp = Date.now();

      const tableWrapper: ContainerNode = {
        id: `table-wrapper-${timestamp}`,
        type: "container",
        children: [table],
        attributes: {},
      };

      let targetNode = null;
      let targetPosition: "after" | "before" = "after";

      if (tableInsertionTargetId) {
        targetNode = currentContainer.children.find(
          (n) => n.id === tableInsertionTargetId
        );
        targetPosition = "after";
      }

      if (!targetNode) {
        targetNode =
          currentContainer.children[currentContainer.children.length - 1];
        targetPosition = "after";
      }

      if (targetNode) {
        dispatch(
          EditorActions.insertNode(tableWrapper, targetNode.id, targetPosition)
        );
      } else {
        dispatch(
          EditorActions.replaceContainer({
            ...currentContainer,
            children: [tableWrapper],
          })
        );
      }

      toast({
        title: "Table Imported",
        description: "Markdown table has been imported successfully",
      });

      setTimeout(() => {
        const editorContent = editorContentRef.current;
        if (editorContent) {
          const tableElement = editorContent.querySelector(
            `[data-node-id="${tableWrapper.id}"]`
          );
          if (tableElement) {
            tableElement.scrollIntoView({
              behavior: "smooth",
              block: "center",
              inline: "nearest",
            });
          }
        }
      }, 150);
    },
    [dispatch, toast, tableInsertionTargetId, getContainer, editorContentRef]
  );

  const handleCreateTable = useCallback(
    createHandleCreateTable(nodeOperationParams, tableInsertionTargetId),
    [dispatch, toast, tableInsertionTargetId]
  );

  return {
    tableDialogOpen,
    setTableDialogOpen,
    tableInsertionTargetId,
    setTableInsertionTargetId,
    handleCreateTableFromCommand,
    handleImportMarkdownTable,
    handleCreateTable,
  };
}

/**
 * Mina Rich Editor
 * 
 * A flexible, TypeScript-first rich text editor library built with React.
 * Features a JSON-based document model, immutable state management,
 * and extensible plugin architecture.
 * 
 * @packageDocumentation
 * 
 * @example Basic Usage
 * ```tsx
 * import { EditorProvider, useEditor, EditorActions } from 'mina-rich-editor';
 * 
 * function App() {
 *   return (
 *     <EditorProvider>
 *       <MyEditor />
 *     </EditorProvider>
 *   );
 * }
 * 
 * function MyEditor() {
 *   const [state, dispatch] = useEditor();
 *   
 *   const addParagraph = () => {
 *     dispatch(EditorActions.insertNode(
 *       { id: 'p-new', type: 'p', content: 'Hello!' },
 *       state.container.id,
 *       'append'
 *     ));
 *   };
 *   
 *   return <button onClick={addParagraph}>Add Paragraph</button>;
 * }
 * ```
 */

