export * from './format-ops';
export * from './history-ops';
export * from './ui-ops';

/**
 * Mina Rich Editor - Node CRUD Operations
 *
 * Standalone handler functions for node-level reducer cases.
 * Each function takes `(state: EditorState, payload)` and returns `EditorState`.
 * All operations build inverted forward/backward operations for undo/redo.
 *
 * @packageDocumentation
 */

import {
  EditorState,
  ContainerNode,
  EditorNode,
  isTextNode,
  TextNode,
} from '../../types';
import {
  updateNodeById,
  deleteNodeById,
  insertNode,
  moveNode,
  cloneNode,
  findNodeById,
} from '../../utils/tree-operations';
import { generateId } from '../../utils/id-generator';
import { addToHistory, getCurrentContainer, findParentAndIndex } from './shared';

import type {
  UpdateNodeAction,
  UpdateAttributesAction,
  UpdateContentAction,
  DeleteNodeAction,
  InsertNodeAction,
  MoveNodeAction,
  SwapNodesAction,
  DuplicateNodeAction,
} from '../actions';

// ---------------------------------------------------------------------------
// UPDATE_NODE
// ---------------------------------------------------------------------------

export function handleUpdateNode(
  state: EditorState,
  payload: UpdateNodeAction['payload']
): EditorState {
  const { id, updates } = payload;
  const currentContainer = getCurrentContainer(state);
  const oldNode = findNodeById(currentContainer, id);

  const newContainer = updateNodeById(
    currentContainer,
    id,
    () => updates
  ) as ContainerNode;

  // Build backward operation: restore the old values for the changed keys
  const oldPartial: Partial<EditorNode> = {};
  if (oldNode) {
    for (const key of Object.keys(updates)) {
      (oldPartial as any)[key] = (oldNode as any)[key];
    }
  }

  return addToHistory(
    {
      ...state,
      metadata: {
        ...state.metadata,
        updatedAt: new Date().toISOString(),
      },
    },
    newContainer,
    {
      forward: { type: 'update_node', id, changes: updates },
      backward: { type: 'update_node', id, changes: oldPartial },
    }
  );
}

// ---------------------------------------------------------------------------
// UPDATE_ATTRIBUTES
// ---------------------------------------------------------------------------

export function handleUpdateAttributes(
  state: EditorState,
  payload: UpdateAttributesAction['payload']
): EditorState {
  const { id, attributes, merge = true } = payload;
  const currentContainer = getCurrentContainer(state);
  const oldNode = findNodeById(currentContainer, id);
  const oldAttributes = oldNode?.attributes;

  const newContainer = updateNodeById(currentContainer, id, (node) => ({
    attributes: merge ? { ...node.attributes, ...attributes } : attributes,
  })) as ContainerNode;

  const newAttributes = merge
    ? { ...oldAttributes, ...attributes }
    : attributes;

  return addToHistory(
    {
      ...state,
      metadata: {
        ...state.metadata,
        updatedAt: new Date().toISOString(),
      },
    },
    newContainer,
    {
      forward: { type: 'update_node', id, changes: { attributes: newAttributes } },
      backward: { type: 'update_node', id, changes: { attributes: oldAttributes } },
    }
  );
}

// ---------------------------------------------------------------------------
// UPDATE_CONTENT
// ---------------------------------------------------------------------------

export function handleUpdateContent(
  state: EditorState,
  payload: UpdateContentAction['payload']
): EditorState {
  const { id, content } = payload;
  const currentContainer = getCurrentContainer(state);
  const oldNode = findNodeById(currentContainer, id);

  const newContainer = updateNodeById(currentContainer, id, (node) => {
    if (isTextNode(node)) {
      return { content };
    }
    return {};
  }) as ContainerNode;

  // Capture old content and children for backward
  const oldContent = isTextNode(oldNode as EditorNode) ? (oldNode as TextNode).content : undefined;
  const oldChildren = isTextNode(oldNode as EditorNode) ? (oldNode as TextNode).children : undefined;

  return addToHistory(
    {
      ...state,
      metadata: {
        ...state.metadata,
        updatedAt: new Date().toISOString(),
      },
    },
    newContainer,
    {
      forward: { type: 'update_node', id, changes: { content } },
      backward: { type: 'update_node', id, changes: { content: oldContent, children: oldChildren } as Partial<EditorNode> },
    }
  );
}

// ---------------------------------------------------------------------------
// DELETE_NODE
// ---------------------------------------------------------------------------

export function handleDeleteNode(
  state: EditorState,
  payload: DeleteNodeAction['payload']
): EditorState {
  const { id } = payload;
  const currentContainer = getCurrentContainer(state);
  const oldNode = findNodeById(currentContainer, id);
  const posInfo = findParentAndIndex(currentContainer, id);

  const result = deleteNodeById(currentContainer, id);

  // If the root container was deleted, prevent it
  if (result === null) {
    return state;
  }

  // If after deletion there are no children left, create a default empty paragraph
  const resultContainer = result as ContainerNode;
  if (resultContainer.children.length === 0) {
    const defaultNode: TextNode = {
      id: generateId('p'),
      type: 'p',
      content: '',
      attributes: {},
    };
    resultContainer.children = [defaultNode];

    // Backward: replace with old container (complex case with empty fallback)
    return addToHistory(
      {
        ...state,
        activeNodeId: defaultNode.id,
        metadata: {
          ...state.metadata,
          updatedAt: new Date().toISOString(),
        },
      },
      resultContainer,
      {
        forward: { type: 'replace_container', container: resultContainer },
        backward: { type: 'replace_container', container: currentContainer },
      }
    );
  }

  // If the deleted node was the active one, move focus to the nearest sibling
  let newActiveNodeId = state.activeNodeId;
  if (state.activeNodeId === id) {
    const deletedIndex = posInfo?.index ?? 0;
    const children = resultContainer.children;
    const targetIndex = Math.min(deletedIndex, children.length - 1);
    newActiveNodeId = children[targetIndex].id;
  }

  return addToHistory(
    {
      ...state,
      activeNodeId: newActiveNodeId,
      metadata: {
        ...state.metadata,
        updatedAt: new Date().toISOString(),
      },
    },
    resultContainer,
    oldNode && posInfo
      ? {
          forward: { type: 'delete_node', nodeId: id },
          backward: { type: 'insert_at_index', node: oldNode, parentId: posInfo.parentId, index: posInfo.index },
        }
      : {
          forward: { type: 'replace_container', container: resultContainer },
          backward: { type: 'replace_container', container: currentContainer },
        }
  );
}

// ---------------------------------------------------------------------------
// INSERT_NODE
// ---------------------------------------------------------------------------

export function handleInsertNode(
  state: EditorState,
  payload: InsertNodeAction['payload']
): EditorState {
  const { node, targetId, position } = payload;
  const currentContainer = getCurrentContainer(state);
  const newContainer = insertNode(
    currentContainer,
    targetId,
    node,
    position
  ) as ContainerNode;

  return addToHistory(
    {
      ...state,
      activeNodeId: node.id,
      metadata: {
        ...state.metadata,
        updatedAt: new Date().toISOString(),
      },
    },
    newContainer,
    {
      forward: { type: 'replace_container', container: newContainer },
      backward: { type: 'delete_node', nodeId: node.id },
    }
  );
}

// ---------------------------------------------------------------------------
// MOVE_NODE
// ---------------------------------------------------------------------------

export function handleMoveNode(
  state: EditorState,
  payload: MoveNodeAction['payload']
): EditorState {
  const { nodeId, targetId, position } = payload;
  const currentContainer = getCurrentContainer(state);
  const newContainer = moveNode(
    currentContainer,
    nodeId,
    targetId,
    position
  ) as ContainerNode;

  // Move is complex to invert — use replace_container for safety
  return addToHistory(
    {
      ...state,
      metadata: {
        ...state.metadata,
        updatedAt: new Date().toISOString(),
      },
    },
    newContainer,
    {
      forward: { type: 'replace_container', container: newContainer },
      backward: { type: 'replace_container', container: currentContainer },
    }
  );
}

// ---------------------------------------------------------------------------
// SWAP_NODES
// ---------------------------------------------------------------------------

export function handleSwapNodes(
  state: EditorState,
  payload: SwapNodesAction['payload']
): EditorState {
  const { nodeId1, nodeId2 } = payload;
  const currentContainer = getCurrentContainer(state);

  // Find indices of both nodes
  const index1 = currentContainer.children.findIndex((n) => n.id === nodeId1);
  const index2 = currentContainer.children.findIndex((n) => n.id === nodeId2);

  // If either node not found, return current state
  if (index1 === -1 || index2 === -1) {
    return state;
  }

  // Clone container and swap positions
  const newChildren = [...currentContainer.children];
  [newChildren[index1], newChildren[index2]] = [
    newChildren[index2],
    newChildren[index1],
  ];

  const newContainer: ContainerNode = {
    ...currentContainer,
    children: newChildren,
  };

  // Swap is its own inverse
  return addToHistory(
    {
      ...state,
      metadata: {
        ...state.metadata,
        updatedAt: new Date().toISOString(),
      },
    },
    newContainer,
    {
      forward: { type: 'replace_container', container: newContainer },
      backward: { type: 'replace_container', container: currentContainer },
    }
  );
}

// ---------------------------------------------------------------------------
// DUPLICATE_NODE
// ---------------------------------------------------------------------------

export function handleDuplicateNode(
  state: EditorState,
  payload: DuplicateNodeAction['payload']
): EditorState {
  const { id, newId } = payload;
  const currentContainer = getCurrentContainer(state);

  // Clone the node with a new ID
  const nodeToClone = updateNodeById(currentContainer, id, (node) => node);
  const clonedNode = cloneNode(nodeToClone, newId);

  // Insert the cloned node after the original
  const newContainer = insertNode(
    currentContainer,
    id,
    clonedNode,
    'after'
  ) as ContainerNode;

  return addToHistory(
    {
      ...state,
      metadata: {
        ...state.metadata,
        updatedAt: new Date().toISOString(),
      },
    },
    newContainer,
    {
      forward: { type: 'replace_container', container: newContainer },
      backward: { type: 'delete_node', nodeId: clonedNode.id },
    }
  );
}

/**
 * Mina Rich Editor - Shared Reducer Utilities
 *
 * Shared helpers used across multiple operation modules.
 * Includes the operation-based history system.
 *
 * @packageDocumentation
 */

import {
  EditorState,
  ContainerNode,
  EditorNode,
  HistoryOperation,
  HistoryEntry,
  isContainerNode,
  isStructuralNode,
} from '../../types';
import {
  updateNodeById,
  deleteNodeById,
} from '../../utils/tree-operations';

/**
 * Maximum number of undo entries to keep.
 */
export const MAX_UNDO_SIZE = 50;

// ─── Container access ─────────────────────────────────────────────────────────

/**
 * Returns the current container from state.
 * Single source of truth — all operation handlers should use this.
 */
export function getCurrentContainer(state: EditorState): ContainerNode {
  return state.current;
}

// ─── Apply operations ─────────────────────────────────────────────────────────

/**
 * Insert a node into a parent container at a specific index.
 * Used during undo of delete operations.
 */
function insertNodeAtIndex(
  container: ContainerNode,
  parentId: string,
  node: EditorNode,
  index: number
): ContainerNode {
  if (container.id === parentId) {
    const children = [...container.children];
    children.splice(index, 0, node);
    return { ...container, children };
  }

  const newChildren = container.children.map((child) => {
    if (isContainerNode(child) || isStructuralNode(child)) {
      const result = insertNodeAtIndex(child as ContainerNode, parentId, node, index);
      if (result !== child) return result;
    }
    return child;
  });

  const changed = newChildren.some((c, i) => c !== container.children[i]);
  if (changed) {
    return { ...container, children: newChildren };
  }
  return container;
}

/**
 * Apply a HistoryOperation to a container, returning the new container.
 * Used by undo/redo to transform the current state.
 */
export function applyOperation(
  container: ContainerNode,
  op: HistoryOperation
): ContainerNode {
  switch (op.type) {
    case 'update_node':
      return updateNodeById(container, op.id, () => op.changes) as ContainerNode;

    case 'delete_node': {
      const result = deleteNodeById(container, op.nodeId);
      return (result as ContainerNode) ?? container;
    }

    case 'insert_at_index':
      return insertNodeAtIndex(container, op.parentId, op.node, op.index);

    case 'replace_container':
      return op.container;

    case 'batch':
      return op.operations.reduce(
        (c, subOp) => applyOperation(c, subOp),
        container
      );
  }
}

// ─── Find parent & index ──────────────────────────────────────────────────────

/**
 * Find the parent ID and child index of a node within the tree.
 * Returns null if the node is not found.
 */
export function findParentAndIndex(
  container: EditorNode,
  nodeId: string
): { parentId: string; index: number } | null {
  if (!isContainerNode(container) && !isStructuralNode(container)) {
    return null;
  }

  const parent = container as ContainerNode;
  const directIndex = parent.children.findIndex((c) => c.id === nodeId);
  if (directIndex !== -1) {
    return { parentId: parent.id, index: directIndex };
  }

  for (const child of parent.children) {
    if (isContainerNode(child) || isStructuralNode(child)) {
      const result = findParentAndIndex(child, nodeId);
      if (result) return result;
    }
  }

  return null;
}

// ─── History helpers ──────────────────────────────────────────────────────────

/**
 * Add a new container state to history with forward/backward operations.
 * Clears the redo stack (standard undo behavior).
 * Caps the undo stack at MAX_UNDO_SIZE entries.
 */
export function addToHistory(
  state: EditorState,
  newContainer: ContainerNode,
  operation?: { forward: HistoryOperation; backward: HistoryOperation }
): EditorState {
  const entry: HistoryEntry = operation
    ? {
        forward: operation.forward,
        backward: operation.backward,
        timestamp: Date.now(),
      }
    : {
        // Fallback: store full container snapshots as replace_container ops
        forward: { type: 'replace_container', container: newContainer },
        backward: { type: 'replace_container', container: state.current },
        timestamp: Date.now(),
      };

  let newUndoStack = [...state.undoStack, entry];

  // Cap undo stack size
  if (newUndoStack.length > MAX_UNDO_SIZE) {
    newUndoStack = newUndoStack.slice(newUndoStack.length - MAX_UNDO_SIZE);
  }

  return {
    ...state,
    current: newContainer,
    undoStack: newUndoStack,
    redoStack: [], // Clear redo on new action
  };
}

/**
 * Return a copy of state with the updatedAt timestamp set to now.
 */
export function withTimestamp(state: EditorState): EditorState {
  return {
    ...state,
    metadata: { ...state.metadata, updatedAt: new Date().toISOString() },
  };
}

/**
 * Mina Rich Editor - UI Operations
 *
 * Handles selection, active node, block selection, and cover image state.
 *
 * @packageDocumentation
 */

import { EditorState, SelectionInfo, CoverImage, TextNode } from '../../types';
import { addToHistory, getCurrentContainer, withTimestamp } from './shared';
import { generateId } from '../../utils/id-generator';

/**
 * Set the currently active/focused node (SET_ACTIVE_NODE).
 */
export function handleSetActiveNode(
  state: EditorState,
  payload: { nodeId: string | null }
): EditorState {
  return {
    ...state,
    activeNodeId: payload.nodeId,
  };
}

/**
 * Update the has-selection flag (SET_SELECTION).
 */
export function handleSetSelection(
  state: EditorState,
  payload: { hasSelection: boolean }
): EditorState {
  return {
    ...state,
    hasSelection: payload.hasSelection,
  };
}

/**
 * Bump the selection key to force re-renders (INCREMENT_SELECTION_KEY).
 */
export function handleIncrementSelectionKey(state: EditorState): EditorState {
  return {
    ...state,
    selectionKey: state.selectionKey + 1,
  };
}

/**
 * Set the current selection info (SET_CURRENT_SELECTION).
 */
export function handleSetCurrentSelection(
  state: EditorState,
  payload: { selection: SelectionInfo | null }
): EditorState {
  return {
    ...state,
    currentSelection: payload.selection,
    hasSelection: payload.selection !== null,
  };
}

/**
 * Mark all top-level blocks as selected (SELECT_ALL_BLOCKS).
 */
export function handleSelectAllBlocks(state: EditorState): EditorState {
  const currentContainer = getCurrentContainer(state);
  const allBlockIds = new Set(currentContainer.children.map((child) => child.id));
  return {
    ...state,
    selectedBlocks: allBlockIds,
  };
}

/**
 * Clear all block selections (CLEAR_BLOCK_SELECTION).
 */
export function handleClearBlockSelection(state: EditorState): EditorState {
  return {
    ...state,
    selectedBlocks: new Set(),
  };
}

/**
 * Delete all currently selected blocks (DELETE_SELECTED_BLOCKS).
 * If all blocks are removed a new empty paragraph is created as a fallback.
 */
export function handleDeleteSelectedBlocks(state: EditorState): EditorState {
  if (state.selectedBlocks.size === 0) {
    return state;
  }

  const currentContainer = getCurrentContainer(state);
  const newChildren = currentContainer.children.filter(
    (child) => !state.selectedBlocks.has(child.id)
  );

  // If all blocks were deleted, create a new empty paragraph
  if (newChildren.length === 0) {
    const newNode: TextNode = {
      id: generateId('p'),
      type: 'p',
      content: '',
      attributes: {},
    };
    newChildren.push(newNode);
  }

  return addToHistory(
    {
      ...state,
      selectedBlocks: new Set(),
      activeNodeId: newChildren[0]?.id || null,
      metadata: {
        ...state.metadata,
        updatedAt: new Date().toISOString(),
      },
    },
    {
      ...currentContainer,
      children: newChildren,
    }
  );
}

/**
 * Set or update the cover image (SET_COVER_IMAGE).
 */
export function handleSetCoverImage(
  state: EditorState,
  payload: { coverImage: CoverImage }
): EditorState {
  return withTimestamp({
    ...state,
    coverImage: payload.coverImage,
  });
}

/**
 * Remove the cover image (REMOVE_COVER_IMAGE).
 */
export function handleRemoveCoverImage(state: EditorState): EditorState {
  return withTimestamp({
    ...state,
    coverImage: null,
  });
}

/**
 * Update the vertical position of the cover image (UPDATE_COVER_IMAGE_POSITION).
 */
export function handleUpdateCoverImagePosition(
  state: EditorState,
  payload: { position: number }
): EditorState {
  if (!state.coverImage) {
    return state;
  }
  return withTimestamp({
    ...state,
    coverImage: {
      ...state.coverImage,
      position: payload.position,
    },
  });
}

/**
 * Shared utility for splitting inline children at selection boundaries
 * and applying a transform to the overlapping segments.
 *
 * Used by TOGGLE_FORMAT, APPLY_CUSTOM_CLASS, APPLY_INLINE_STYLE,
 * APPLY_LINK, REMOVE_LINK, and APPLY_INLINE_ELEMENT_TYPE.
 */

import { InlineText } from "../types";

// Apply a transform function to inline children within a selection range
export function applyToSelectionRange(
  children: InlineText[],
  start: number,
  end: number,
  transform: (child: InlineText) => InlineText
): InlineText[] {
  const result: InlineText[] = [];
  let currentPos = 0;

  for (const child of children) {
    const childLength = (child.content || "").length;
    const childStart = currentPos;
    const childEnd = currentPos + childLength;

    if (childEnd <= start || childStart >= end) {
      // No overlap - keep as is
      result.push({ ...child });
    } else {
      // There's overlap - split this child
      const overlapStart = Math.max(childStart, start);
      const overlapEnd = Math.min(childEnd, end);

      // Before overlap
      if (childStart < overlapStart) {
        result.push({
          ...child,
          content: child.content!.substring(0, overlapStart - childStart),
        });
      }

      // Overlapping part - apply the transform
      result.push(
        transform({
          ...child,
          content: child.content!.substring(
            overlapStart - childStart,
            overlapEnd - childStart
          ),
        })
      );

      // After overlap
      if (childEnd > overlapEnd) {
        result.push({
          ...child,
          content: child.content!.substring(overlapEnd - childStart),
        });
      }
    }

    currentPos = childEnd;
  }

  return result;
}

// Get inline children from a node, handling plain content and empty content fallback
export function getInlineChildren(
  nodeChildren: InlineText[] | undefined,
  hasInline: boolean,
  nodeContent: string | undefined,
  selectionText: string | undefined
): InlineText[] {
  if (hasInline && nodeChildren) {
    return nodeChildren;
  }
  if (nodeContent) {
    return [{ content: nodeContent }];
  }
  if (selectionText) {
    return [{ content: selectionText }];
  }
  return [{ content: "" }];
}

/**
 * Zustand Store for Mina Rich Editor
 *
 * Instance-based factory with React context for supporting multiple editor
 * instances on the same page. Each EditorProvider creates its own isolated
 * store instance.
 *
 * Optimized for performance with selective subscriptions.
 * Blocks subscribe only to their specific data, not the entire history.
 */

import React from "react";
import { create, useStore } from "zustand";
import { subscribeWithSelector } from "zustand/middleware";
import { useShallow } from "zustand/react/shallow";
import {
  EditorState,
  ContainerNode,
  SelectionInfo,
  EditorNode,
} from "../types";
import { editorReducer, createInitialState } from "../reducer/editor-reducer";
import { EditorAction } from "../reducer/actions";
import { buildNodeMap } from "../utils/tree-operations";
import { ExtensionManager } from "../extensions/ExtensionManager";
import { StarterKit } from "../extensions/starter-kit";
import type { AnyResolvedExtension } from "../extensions/types";

// Store interface
interface EditorStore extends EditorState {
  // Extension registry — populated with StarterKit by default.
  extensionManager: ExtensionManager;

  // Derived cache: flat map of nodeId → EditorNode for O(1) lookups.
  // Rebuilt after every dispatch. NOT part of EditorState.
  nodeMap: Map<string, EditorNode>;

  // Actions
  dispatch: (action: EditorAction) => void;

  // Optimized selectors that don't cause re-renders
  getNode: (nodeId: string) => EditorNode | undefined;
  getContainer: () => ContainerNode;
  isNodeActive: (nodeId: string) => boolean;
  getActiveNodeId: () => string | null;
  getContainerChildrenIds: () => string[];

  // Selection management (optimized to avoid re-renders)
  selectionManager: {
    getSelection: () => SelectionInfo | null;
    setSelection: (selection: SelectionInfo | null) => void;
    subscribe: (
      callback: (selection: SelectionInfo | null) => void
    ) => () => void;
  };

  // Internal selection state (not reactive)
  _selection: SelectionInfo | null;
  _selectionSubscribers: Set<(selection: SelectionInfo | null) => void>;
}

// Helper function to find node by ID in tree
function findNodeById(
  container: ContainerNode,
  nodeId: string
): EditorNode | undefined {
  if (container.id === nodeId) return container;

  for (const child of container.children) {
    if (child.id === nodeId) return child;

    if ("children" in child && Array.isArray(child.children)) {
      const found = findNodeById(child as ContainerNode, nodeId);
      if (found) return found;
    }
  }

  return undefined;
}

// ─── Factory ─────────────────────────────────────────────────────────────────

/**
 * Create a new isolated editor store instance.
 * Each EditorProvider calls this once and holds the returned store in a ref.
 */
export function createEditorStore(
  initialContainer?: ContainerNode,
  initialState?: EditorState,
  extensions?: AnyResolvedExtension[]
) {
  // Create extension manager — use provided extensions or fall back to StarterKit
  const extensionManager = new ExtensionManager();
  extensionManager.register(...(extensions ?? StarterKit));

  return create<EditorStore>()(
    subscribeWithSelector((set, get) => {
      // Initialize selection subscribers
      const selectionSubscribers = new Set<
        (selection: SelectionInfo | null) => void
      >();

      const baseState =
        initialState ??
        (initialContainer
          ? createInitialState(initialContainer)
          : createInitialState());

      return {
        // Initialize with provided or default state
        ...baseState,

        // Extension registry
        extensionManager,

        // Derived node map for O(1) lookups — rebuilt after every dispatch.
        nodeMap: buildNodeMap(baseState.current),

        // Selection state (non-reactive)
        _selection: null,
        _selectionSubscribers: selectionSubscribers,

        // Main dispatch function
        dispatch: (action: EditorAction) => {
          const currentState = get();
          const newState = editorReducer(currentState, action);
          // Only update EditorState fields - preserve store methods (dispatch, getNode, etc.)
          // Rebuild nodeMap for O(1) lookups in useBlockNode.
          set({
            version: newState.version,
            current: newState.current,
            undoStack: newState.undoStack,
            redoStack: newState.redoStack,
            activeNodeId: newState.activeNodeId,
            hasSelection: newState.hasSelection,
            selectionKey: newState.selectionKey,
            currentSelection: newState.currentSelection,
            selectedBlocks: newState.selectedBlocks,
            coverImage: newState.coverImage,
            metadata: newState.metadata,
            nodeMap: buildNodeMap(newState.current),
          });
        },

        // Optimized selectors (these don't cause subscriptions)
        getNode: (nodeId: string) => {
          return findNodeById(get().current, nodeId);
        },

        getContainer: () => {
          return get().current;
        },

        isNodeActive: (nodeId: string) => {
          return get().activeNodeId === nodeId;
        },

        getActiveNodeId: () => {
          return get().activeNodeId;
        },

        getContainerChildrenIds: () => {
          return get().current.children.map((child) => child.id);
        },

        // Selection manager (optimized to avoid re-renders)
        selectionManager: {
          getSelection: () => get()._selection,

          setSelection: (selection: SelectionInfo | null) => {
            // Update internal selection without triggering re-renders
            set({ _selection: selection });

            // Notify subscribers (e.g., toolbar) but don't trigger full re-render
            const subscribers = get()._selectionSubscribers;
            subscribers.forEach((callback) => callback(selection));
          },

          subscribe: (
            callback: (selection: SelectionInfo | null) => void
          ) => {
            const subscribers = get()._selectionSubscribers;
            subscribers.add(callback);
            return () => {
              subscribers.delete(callback);
            };
          },
        },
      };
    })
  );
}

// ─── React context ────────────────────────────────────────────────────────────

const EditorStoreContext = React.createContext<ReturnType<
  typeof createEditorStore
> | null>(null);

/**
 * Access the store instance from context.
 * Throws if used outside an EditorProvider.
 */
function useEditorStoreContext() {
  const store = React.useContext(EditorStoreContext);
  if (!store) {
    throw new Error(
      "useEditorStore must be used within an <EditorProvider>. " +
        "Wrap your editor in <EditorProvider> to fix this."
    );
  }
  return store;
}

// ─── Public hook (backward-compatible) ───────────────────────────────────────

/**
 * Returns the raw Zustand store instance from the nearest EditorProvider.
 * Use this when you need to call `store.subscribe(...)` or `store.getState()`
 * directly (e.g. to set up side-effect subscriptions without causing re-renders).
 *
 * Throws if used outside an EditorProvider.
 */
export function useEditorStoreInstance() {
  return useEditorStoreContext();
}

/**
 * Low-level hook that returns the Zustand store bound to the nearest
 * EditorProvider. Accepts an optional selector, matching the Zustand API.
 *
 * Prefer the specialized hooks (useEditorState, useEditorDispatch, …) over
 * calling this directly.
 */
export function useEditorStore<T>(
  selector: (state: EditorStore) => T
): T;
export function useEditorStore(): EditorStore;
export function useEditorStore<T>(
  selector?: (state: EditorStore) => T
): T | EditorStore {
  const store = useEditorStoreContext();
  // When no selector is provided return the full state (matches old API)
  return useStore(store, selector ?? ((s) => s as unknown as T)) as
    | T
    | EditorStore;
}

// ─── Specialized hooks ────────────────────────────────────────────────────────

/**
 * Hook for blocks to subscribe only to their specific node data.
 * Prevents re-renders when other nodes change.
 *
 * OPTIMIZATION: Uses subscribeWithSelector to ONLY subscribe to this specific node.
 * The selector function extracts just this node, and Zustand only notifies us
 * when the RETURN VALUE changes (using Object.is for reference equality).
 *
 * How it works:
 * 1. Selector extracts ONLY this specific node from state
 * 2. Zustand tracks the selector's return value
 * 3. On state change, Zustand re-runs selector and compares old vs new return value
 * 4. Only triggers re-render if the node reference actually changed
 * 5. Combined with structural sharing in reducer, unchanged nodes keep same reference
 *
 * Result:
 * - Type in block A → only block A's node reference changes → only block A re-renders ✅
 * - All other blocks keep same reference → selector returns same value → no re-render ✅
 */
export function useBlockNode(nodeId: string) {
  const store = useEditorStoreContext();
  return useStore(store, (state) => state.nodeMap.get(nodeId));
}

/**
 * Hook to check if a specific node is active.
 * Only re-renders when the active status of THIS node changes.
 */
export function useIsNodeActive(nodeId: string): boolean {
  const store = useEditorStoreContext();
  return useStore(store, (state) => state.activeNodeId === nodeId);
}

/**
 * Hook to get the current active node ID.
 * Only re-renders when the active node ID changes.
 */
export function useActiveNodeId(): string | null {
  const store = useEditorStoreContext();
  return useStore(store, (state) => state.activeNodeId);
}

/**
 * Hook to get the current container's children IDs.
 * Only re-renders when the children array changes.
 * Uses useShallow to prevent unnecessary re-renders from array recreation.
 */
export function useContainerChildrenIds(): string[] {
  const store = useEditorStoreContext();
  return useStore(
    store,
    useShallow((state) => {
      return state.current.children.map((child) => child.id);
    })
  );
}

/**
 * Hook to get the current container.
 * Use sparingly - prefer more specific hooks when possible.
 */
export function useContainer(): ContainerNode {
  const store = useEditorStoreContext();
  return useStore(store, (state) => state.current);
}

/**
 * Hook to get a stable getter for the current container.
 * Returns store.getState()-based getter - safe for callbacks/effects.
 */
export function useContainerGetter(): () => ContainerNode {
  const store = useEditorStoreContext();
  return React.useCallback(
    () => store.getState().current,
    [store]
  );
}

/**
 * Hook to access the ExtensionManager from the nearest EditorProvider.
 * Stable reference — never causes re-renders.
 */
export function useExtensionManager(): ExtensionManager {
  const store = useEditorStoreContext();
  return useStore(store, (state) => state.extensionManager);
}

/**
 * Hook to get the dispatch function.
 * Dispatch is a stable reference - never causes re-renders.
 */
export function useEditorDispatch() {
  const store = useEditorStoreContext();
  return useStore(store, (state) => state.dispatch);
}

/**
 * Hook to get the full editor state.
 * Use only when you need the complete state (like for toolbars).
 */
export function useEditorState(): EditorState {
  const store = useEditorStoreContext();
  return useStore(
    store,
    useShallow((state) => ({
      current: state.current,
      undoStack: state.undoStack,
      redoStack: state.redoStack,
      activeNodeId: state.activeNodeId,
      currentSelection: state.currentSelection,
      version: state.version,
      coverImage: state.coverImage,
      hasSelection: state.currentSelection !== null,
      selectionKey: state.selectionKey,
      selectedBlocks: state.selectedBlocks,
    }))
  );
}

/**
 * Hook for selection management (optimized to avoid re-renders).
 * selectionManager is a stable object created once per store.
 */
export function useSelectionManager() {
  const store = useEditorStoreContext();
  return useStore(store, (state) => state.selectionManager);
}

/**
 * Hook to subscribe to selection changes (for toolbar/UI updates).
 * Only components that need to react to selection changes should use this.
 */
export function useSelection(): SelectionInfo | null {
  const selectionManager = useSelectionManager();
  const [selection, setSelection] = React.useState<SelectionInfo | null>(
    selectionManager.getSelection()
  );

  React.useEffect(() => {
    const unsubscribe = selectionManager.subscribe(setSelection);
    return unsubscribe;
  }, [selectionManager]);

  return selection;
}

// ─── Provider ─────────────────────────────────────────────────────────────────

/** Props accepted by the EditorProvider component. */
export interface EditorProviderProps {
  children: React.ReactNode;
  initialContainer?: ContainerNode;
  initialState?: EditorState;
  /** Custom extensions (defaults to StarterKit if not provided). */
  extensions?: AnyResolvedExtension[];
  onChange?: (state: EditorState) => void;
}

/** React context provider that creates and exposes an isolated editor store instance to all child components. */
export function EditorProvider({
  children,
  initialContainer,
  initialState,
  extensions,
  onChange,
}: EditorProviderProps) {
  // Create the store exactly once per provider mount.
  // Use lazy-init useState (NOT useRef) because React Strict Mode unmounts
  // and remounts components, which resets refs but not state. With useState,
  // the store survives Strict Mode double-render and keeps the same IDs
  // that were generated during the first initialization.
  const [store] = React.useState(() =>
    createEditorStore(initialContainer, initialState, extensions)
  );

  // If initialState/initialContainer change AFTER mount, sync the store.
  const prevContainerRef = React.useRef(initialContainer);
  const prevStateRef = React.useRef(initialState);
  React.useEffect(() => {
    // Skip on first mount — the store already has the initial data
    if (
      prevContainerRef.current === initialContainer &&
      prevStateRef.current === initialState
    ) {
      return;
    }
    prevContainerRef.current = initialContainer;
    prevStateRef.current = initialState;

    if (initialState) {
      store.setState(initialState);
    } else if (initialContainer) {
      const newState = createInitialState(initialContainer);
      store.setState(newState);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [initialContainer, initialState]);

  // Subscribe to state changes for onChange callback
  React.useEffect(() => {
    if (!onChange) return;

    return store.subscribe((state) => {
      const editorState: EditorState = {
        current: state.current,
        undoStack: state.undoStack,
        redoStack: state.redoStack,
        activeNodeId: state.activeNodeId,
        currentSelection: state.currentSelection,
        version: state.version,
        coverImage: state.coverImage,
        hasSelection: state.currentSelection !== null,
        selectionKey: state.version
          ? parseInt(state.version.split(".").join(""))
          : 0,
        selectedBlocks: new Set<string>(),
      };
      onChange(editorState);
    });
  }, [onChange, store]);

  return React.createElement(
    EditorStoreContext.Provider,
    { value: store },
    children
  );
}

/**
 * Mina Rich Editor — CSS Custom Property Theming Layer
 *
 * These variables let consumers customize every visual aspect of the editor
 * without touching Tailwind or forking the library.
 *
 * USAGE
 * -----
 * Import this file once in your app:
 *
 *   import '@mina-editor/core/styles';
 *
 * Then override any variable in your own CSS:
 *
 *   .mina-editor {
 *     --mina-font-body: 'Inter', sans-serif;
 *     --mina-color-primary: #7c3aed;
 *     --mina-blockquote-border-color: #7c3aed;
 *   }
 *
 * All overrides are scoped to `.mina-editor`, so they never leak outside the
 * editor boundary.
 *
 * COMPATIBILITY
 * -------------
 * The existing Tailwind classes on Block.tsx and other components continue to
 * work unchanged. These variables are an additive layer on top — consumers who
 * have Tailwind configured see both systems working in harmony; those without
 * Tailwind can rely on these variables for their own CSS overrides.
 */

/* ============================================================================
   shadcn CSS variable fallbacks (zero specificity via :where)
   Provides sensible defaults when the editor is used outside a shadcn project.
   In a standard shadcn app, the host's :root / globals.css takes precedence.
   ============================================================================ */

:where(.mina-editor) {
  --background: #ffffff;
  --foreground: #1a1a1a;
  --card: #ffffff;
  --card-foreground: #1a1a1a;
  --popover: #ffffff;
  --popover-foreground: #1a1a1a;
  --primary: #1a1a1a;
  --primary-foreground: #ffffff;
  --secondary: #f8f8f6;
  --secondary-foreground: #1a1a1a;
  --muted: #f8f8f6;
  --muted-foreground: #3a3a3a;
  --accent: #f8f8f6;
  --accent-foreground: #1a1a1a;
  --destructive: #dc2626;
  --border: rgba(0, 0, 0, 0.08);
  --input: rgba(0, 0, 0, 0.08);
  --ring: rgba(0, 0, 0, 0.12);
  --radius: 0.625rem;
}

:where(.dark .mina-editor, .mina-editor[data-theme='dark']) {
  --background: #0a0a0a;
  --foreground: #e5e5e5;
  --card: #141414;
  --card-foreground: #e5e5e5;
  --popover: #141414;
  --popover-foreground: #e5e5e5;
  --primary: #e5e5e5;
  --primary-foreground: #0a0a0a;
  --secondary: #1a1a1a;
  --secondary-foreground: #e5e5e5;
  --muted: #1a1a1a;
  --muted-foreground: #999999;
  --accent: #1a1a1a;
  --accent-foreground: #e5e5e5;
  --destructive: #dc2626;
  --border: rgba(255, 255, 255, 0.08);
  --input: rgba(255, 255, 255, 0.1);
  --ring: rgba(255, 255, 255, 0.12);
}

/* ============================================================================
   Light mode defaults (scoped to .mina-editor)
   ============================================================================ */

.mina-editor {
  /* ── Typography ──────────────────────────────────────────────────────────── */
  --mina-font-body: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI',
    sans-serif;
  --mina-font-heading: inherit;
  --mina-font-mono: ui-monospace, 'Cascadia Code', 'Source Code Pro', Menlo,
    Consolas, monospace;

  /* ── Font sizes ──────────────────────────────────────────────────────────── */
  --mina-text-sm: 0.875rem;
  --mina-text-base: 1rem;
  --mina-text-lg: 1.125rem;
  --mina-text-xl: 1.25rem;
  --mina-text-2xl: 1.5rem;
  --mina-text-3xl: 1.875rem;
  --mina-text-4xl: 2.25rem;

  /* ── Line heights ────────────────────────────────────────────────────────── */
  --mina-leading-tight: 1.2;
  --mina-leading-snug: 1.3;
  --mina-leading-normal: 1.4;
  --mina-leading-relaxed: 1.6;

  /* ── Spacing ─────────────────────────────────────────────────────────────── */
  --mina-block-padding-x: 0.75rem;
  --mina-block-padding-y: 0.375rem;
  --mina-block-margin-bottom: 0.5rem;
  --mina-indent-size: 0.5rem;

  /* ── Colors ──────────────────────────────────────────────────────────────── */

  /* Text — use `inherit` by default so the editor picks up the parent theme */
  --mina-color-text: inherit;
  --mina-color-heading: inherit;
  --mina-color-muted: #6b7280;
  --mina-color-border: #e5e7eb;
  --mina-color-bg: transparent;
  --mina-color-bg-hover: rgba(0, 0, 0, 0.03);
  --mina-color-bg-active: rgba(0, 0, 0, 0.05);
  --mina-color-bg-code: rgba(0, 0, 0, 0.05);
  --mina-color-primary: #2563eb;

  /* ── Blockquote ──────────────────────────────────────────────────────────── */
  --mina-blockquote-border-width: 4px;
  --mina-blockquote-border-color: var(--mina-color-primary);
  --mina-blockquote-padding-left: 1.5rem;
  --mina-blockquote-font-style: italic;

  /* ── Code blocks ─────────────────────────────────────────────────────────── */
  --mina-code-bg: var(--mina-color-bg-code);
  --mina-code-padding: 1rem;
  --mina-code-border-radius: 0.5rem;
  --mina-code-font-size: var(--mina-text-sm);

  /* ── Inline code ─────────────────────────────────────────────────────────── */
  --mina-inline-code-bg: rgba(0, 0, 0, 0.06);
  --mina-inline-code-padding-x: 0.25rem;
  --mina-inline-code-padding-y: 0.125rem;
  --mina-inline-code-border-radius: 0.25rem;

  /* ── Toolbar ─────────────────────────────────────────────────────────────── */
  --mina-toolbar-bg: var(--mina-color-bg);
  --mina-toolbar-border-color: var(--mina-color-border);
  --mina-toolbar-button-size: 1.75rem;
  --mina-toolbar-icon-size: 1rem;

  /* ── Drag handle ─────────────────────────────────────────────────────────── */
  --mina-drag-handle-color: #9ca3af;
  --mina-drag-handle-color-hover: #6b7280;

  /* ── Selection / active block ────────────────────────────────────────────── */
  --mina-block-active-border-color: var(--mina-color-primary);
  --mina-block-active-bg: var(--mina-color-bg-active);

  /* ── Drop indicators (drag-and-drop) ─────────────────────────────────────── */
  --mina-drop-indicator-color: var(--mina-color-primary);
  --mina-drop-indicator-opacity: 0.3;

  /* ── Border radius ───────────────────────────────────────────────────────── */
  --mina-radius-sm: 0.25rem;
  --mina-radius-md: 0.375rem;
  --mina-radius-lg: 0.5rem;
}

/* ============================================================================
   Focus indicators (WCAG 2.1 AA — Success Criterion 2.4.7)
   Ensures every interactive element inside the editor has a visible focus ring.
   Contenteditable blocks are excluded because they have their own active-state
   visual cue (border + background tint).
   ============================================================================ */

.mina-editor *:focus-visible {
  outline: 2px solid var(--mina-color-primary);
  outline-offset: 2px;
}

.mina-editor [contenteditable]:focus-visible {
  outline: none; /* contenteditable blocks use border-b + bg-accent/5 as the visual cue */
}

/* ============================================================================
   Reduced motion (WCAG 2.1 AA — Success Criterion 2.3.3 / 1.4.3)
   Respects the operating-system preference for reduced motion.
   ============================================================================ */

@media (prefers-reduced-motion: reduce) {
  .mina-editor,
  .mina-editor * {
    animation-duration: 0.01ms !important;
    transition-duration: 0.01ms !important;
  }
}

/* ============================================================================
   Dark mode overrides
   Triggered by a `.dark` ancestor class (e.g. next-themes) OR by
   `data-theme="dark"` directly on the editor wrapper.
   ============================================================================ */

/* ============================================================================
   Scoped editor rules — contenteditable, selection, lists
   These MUST live under .mina-editor so they never leak to the host app.
   ============================================================================ */

/* Placeholder styling — Notion-like */
.mina-editor [contenteditable]:empty:before {
  content: attr(placeholder);
  color: var(--mina-color-muted);
  opacity: 0.4;
  pointer-events: none;
}

/* Command menu placeholder */
.mina-editor [contenteditable][data-show-command-placeholder="true"]:empty:before {
  content: "Type / for commands...";
  color: var(--mina-color-muted);
  opacity: 0.5;
  pointer-events: none;
}

/* Focus styles */
.mina-editor [contenteditable]:focus {
  outline: none;
}

/* Selection styles */
.mina-editor ::selection {
  background-color: #dbeafe;
  color: #1e40af;
}

/* List styling — natural HTML lists */
.mina-editor ul[data-list-type="ul"] {
  list-style-type: disc;
  padding-left: 1.5rem;
}

.mina-editor ol[data-list-type="ol"] {
  list-style-type: decimal;
  padding-left: 1.5rem;
}

/* List item placeholder fixes */
.mina-editor li[contenteditable]::marker {
  margin-right: 0.5rem;
}

.mina-editor li[contenteditable]:empty:before {
  display: inline-block;
  padding-left: 0.25rem;
}

.mina-editor li[contenteditable][data-show-command-placeholder="true"]:empty:before {
  display: inline-block;
  padding-left: 0.25rem;
}

/* ============================================================================
   Dark mode overrides
   Triggered by a `.dark` ancestor class (e.g. next-themes) OR by
   `data-theme="dark"` directly on the editor wrapper.
   ============================================================================ */

.dark .mina-editor,
.mina-editor[data-theme='dark'] {
  --mina-color-muted: var(--warm-400, #8a7060);
  --mina-color-border: var(--border-default, rgba(200,180,160,0.12));
  --mina-color-bg-hover: rgba(200, 180, 160, 0.05);
  --mina-color-bg-active: rgba(200, 180, 160, 0.08);
  --mina-color-bg-code: rgba(200, 180, 160, 0.08);
  --mina-inline-code-bg: rgba(200, 180, 160, 0.08);
  --mina-drag-handle-color: var(--warm-500, #6b5545);
  --mina-drag-handle-color-hover: var(--warm-400, #8a7060);
}

/* Dark selection override */
.dark .mina-editor ::selection,
.mina-editor[data-theme='dark'] ::selection {
  background-color: rgba(200, 180, 160, 0.25);
  color: var(--warm-50, #f8f7f5);
}

