/**
 * Mina Rich Editor - Document Templates
 *
 * @packageDocumentation
 */

import { EditorNode, TextNode } from "./types";
import { generateId } from "./utils/id-generator";

/**
 * Template metadata for organizing and displaying templates
 */
export interface TemplateMetadata {
  id: string;
  name: string;
  description: string;
  category: "productivity" | "creative" | "business" | "personal";
  icon: string;
  thumbnail?: string;
}

/**
 * Complete template with metadata and content
 */
export interface Template {
  metadata: TemplateMetadata;
  content: EditorNode[];
  coverImage?: {
    url: string;
    alt: string;
    position: number;
  };
}

/**
 * Generate unique IDs for template nodes
 */
function id(templateId: string, suffix: string): string {
  return generateId(`${templateId}-${suffix}`);
}

// ========================================
// BLANK TEMPLATE
// ========================================

export function createBlankTemplate(): Template {
  const tid = "blank";
  return {
    metadata: {
      id: tid,
      name: "Blank Document",
      description: "Start with a clean slate",
      category: "productivity",
      icon: "📄",
    },
    content: [
      {
        id: id(tid, "1"),
        type: "p",
        content: "Start writing...",
        attributes: {},
      } as TextNode,
    ],
  };
}

// ========================================
// TEMPLATE REGISTRY
// ========================================

export const TEMPLATES: Record<string, () => Template> = {
  blank: createBlankTemplate,
};

/**
 * Get all template metadata for displaying in a template chooser
 */
export function getAllTemplateMetadata(): TemplateMetadata[] {
  return Object.values(TEMPLATES).map((createTemplate) => createTemplate().metadata);
}

/**
 * Get a template by ID
 */
export function getTemplateById(id: string): Template | null {
  const createTemplate = TEMPLATES[id];
  return createTemplate ? createTemplate() : null;
}

/**
 * Get templates by category
 */
export function getTemplatesByCategory(
  category: TemplateMetadata["category"]
): TemplateMetadata[] {
  return getAllTemplateMetadata().filter((t) => t.category === category);
}

/**
 * Mina Rich Editor - Core Type Definitions
 * 
 * A flexible, type-safe document model for building rich text editors.
 * Supports nested containers, various node types, and dynamic attributes.
 * 
 * @packageDocumentation
 */

/**
 * Text direction for the editor.
 */
export type TextDirection = 'ltr' | 'rtl' | 'auto';

/**
 * Built-in node types — kept as a union for autocomplete and type safety.
 */
export type BuiltInNodeType =
  | 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6'
  | 'p' | 'blockquote' | 'ol' | 'li' | 'code' | 'pre'
  | 'img' | 'video' | 'audio' | 'a' | 'span' | 'div'
  | 'hr' | 'br'
  | 'table' | 'thead' | 'tbody' | 'tr' | 'th' | 'td'
  | 'container' | 'text';

/**
 * Supported node types. Includes built-in types plus any string for custom extensions.
 * The `(string & {})` trick preserves autocomplete for built-in types.
 */
export type NodeType = BuiltInNodeType | (string & {});

/**
 * Dynamic attributes that can be attached to any node.
 * Allows for custom styling, classes, data attributes, etc.
 * 
 * Special formatting attributes:
 * - bold: boolean - makes text bold
 * - italic: boolean - makes text italic
 * - underline: boolean - makes text underlined
 * - strikethrough: boolean - makes text strikethrough
 * - code: boolean - makes text inline code
 * - styles: Record<string, string> - inline CSS styles (e.g., { width: '50%' })
 * 
 * @example
 * ```typescript
 * const attributes: NodeAttributes = {
 *   bold: true,
 *   italic: true,
 *   className: 'text-blue-500',
 *   href: 'https://example.com',
 *   styles: { width: '75%' },
 * };
 * ```
 */
export interface NodeAttributes {
  bold?: boolean;
  italic?: boolean;
  underline?: boolean;
  strikethrough?: boolean;
  code?: boolean;
  styles?: Record<string, string>;
  [key: string]: string | number | boolean | Record<string, string> | undefined;
}

/**
 * Base interface for all editor nodes.
 * Every node must have an id, type, and attributes.
 */
export interface BaseNode {
  /** Unique identifier for the node (used for updates, deletion, etc.) */
  id: string;

  /** The type of node (h1, p, img, container, etc.) */
  type: NodeType;

  /** Dynamic attributes (className, style, href, src, etc.) */
  attributes?: NodeAttributes;
}

/**
 * Inline text segment with its own formatting
 */
export interface InlineText {
  content: string;
  id?: string;
  bold?: boolean;
  italic?: boolean;
  underline?: boolean;
  strikethrough?: boolean;
  code?: boolean;
  // Inline element type (for text that should render as p, h1, h2, etc. within a paragraph)
  // Note: 'code' is not included here - use the 'code' boolean property for inline code formatting
  elementType?: 'p' | 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6' | 'li' | 'blockquote';
  // Link URL (makes the text a clickable link)
  href?: string;
  // Custom Tailwind CSS classes
  className?: string;
  // Inline CSS styles (e.g., { fontSize: '24px', color: '#ff0000' })
  styles?: Record<string, string>;
}

/**
 * A single line of content within a block.
 * Can contain either plain text or inline formatted children.
 */
export interface BlockLine {
  /** Plain text content (if no formatting) */
  content?: string;
  /** Inline children with formatting */
  children?: InlineText[];
}

/**
 * Text content node - represents actual content/text.
 * Can be simple text, have inline children with formatting, OR have multiple lines.
 * 
 * @example Simple text (no formatting):
 * ```typescript
 * const textNode: TextNode = {
 *   id: 'p-1',
 *   type: 'p',
 *   content: 'Hello, world!',
 * };
 * ```
 * 
 * @example Block with inline children (rich formatting):
 * ```typescript
 * const paragraph: TextNode = {
 *   id: 'p-1',
 *   type: 'p',
 *   children: [
 *     { content: 'Hello ', bold: false },
 *     { content: 'world', bold: true },
 *     { content: '!', bold: false }
 *   ]
 * };
 * ```
 * 
 * @example Block with multiple lines (e.g., ordered list):
 * ```typescript
 * const listItem: TextNode = {
 *   id: 'li-1',
 *   type: 'li',
 *   lines: [
 *     { content: 'First item' },
 *     { content: 'Second item' },
 *     { content: 'Third item' }
 *   ]
 * };
 * ```
 */
export interface TextNode extends BaseNode {
  type: Exclude<NodeType, 'container'>;

  /** The actual text content (used when no inline formatting and single line) */
  content?: string;

  /** Inline children with individual formatting (used for rich text, single line) */
  children?: InlineText[];

  /** Multiple lines of content (used for multi-line blocks like ordered lists) */
  lines?: BlockLine[];
}

/**
 * Container node - can have children nodes (nested structure).
 * Allows building complex document trees.
 * 
 * @example
 * ```typescript
 * const container: ContainerNode = {
 *   id: 'root',
 *   type: 'container',
 *   children: [
 *     { id: 'h1-1', type: 'h1', content: 'Title' },
 *     { id: 'p-1', type: 'p', content: 'Paragraph' },
 *     {
 *       id: 'nested',
 *       type: 'container',
 *       children: [...]
 *     }
 *   ]
 * };
 * ```
 */
export interface ContainerNode extends BaseNode {
  type: 'container';

  /** Child nodes (can be TextNode or ContainerNode) */
  children: EditorNode[];
}

/**
 * Structural node - similar to container but for specific structures like tables
 * Can have children nodes for table elements (thead, tbody, tr)
 */
export interface StructuralNode extends BaseNode {
  type: 'table' | 'thead' | 'tbody' | 'tr';

  /** Child nodes */
  children: EditorNode[];
}

/**
 * Union type representing any node in the editor.
 */
export type EditorNode = TextNode | ContainerNode | StructuralNode;

/**
 * Information about the current text selection
 */
export interface SelectionInfo {
  /** The selected text */
  text: string;

  /** Start position in the text content */
  start: number;

  /** End position in the text content */
  end: number;

  /** ID of the node containing the selection */
  nodeId: string;

  /** Active formatting styles on the selection */
  formats: {
    bold: boolean;
    italic: boolean;
    underline: boolean;
    strikethrough: boolean;
    code: boolean;
  };

  /** Active element type on the selection (if all selected text has the same type) */
  elementType?: 'p' | 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6' | 'code' | 'blockquote' | 'li' | 'ol' | null;

  /** Active link href on the selection (if all selected text has the same href) */
  href?: string | null;

  /** Active custom class on the selection (if all selected text has the same class) */
  className?: string | null;

  /** Active inline styles on the selection (if all selected text has the same styles) */
  styles?: Record<string, string> | null;
}

/**
 * Cover image configuration for the document
 */
export interface CoverImage {
  /** URL of the cover image */
  url: string;

  /** Alt text for accessibility */
  alt?: string;

  /** Vertical position (0-100) for image positioning */
  position?: number;
}

// ─── History / Operation Types ────────────────────────────────────────────────

/**
 * A single atomic operation that can be applied to a ContainerNode tree.
 * Used for both undo (backward) and redo (forward) operations.
 */
export type HistoryOperation =
  | { type: 'update_node'; id: string; changes: Partial<EditorNode> }
  | { type: 'delete_node'; nodeId: string }
  | { type: 'insert_at_index'; node: EditorNode; parentId: string; index: number }
  | { type: 'replace_container'; container: ContainerNode }
  | { type: 'batch'; operations: HistoryOperation[] };

/**
 * A single entry in the undo/redo stack.
 * Contains both the forward (redo) and backward (undo) operations,
 * plus the resulting container state for fast access.
 */
export interface HistoryEntry {
  forward: HistoryOperation;
  backward: HistoryOperation;
  timestamp: number;
}

// ─── Editor State ─────────────────────────────────────────────────────────────

/**
 * The root document state for the editor.
 * Uses operation-based undo/redo instead of full snapshot history.
 */
export interface EditorState {
  /** Schema version for future migrations */
  version: string;

  /** The current document tree */
  current: ContainerNode;

  /** Stack of operations for undo (most recent at end) */
  undoStack: HistoryEntry[];

  /** Stack of operations for redo (most recent at end) */
  redoStack: HistoryEntry[];

  /** Currently active/focused node ID */
  activeNodeId: string | null;

  /** Whether there is an active text selection */
  hasSelection: boolean;

  /** Selection key to trigger re-renders when selection changes */
  selectionKey: number;

  /** Current selection information (null if no selection) */
  currentSelection: SelectionInfo | null;

  /** Set of block IDs that are currently selected (for multi-block operations like Ctrl+A) */
  selectedBlocks: Set<string>;

  /** Cover image for the document (like Notion) */
  coverImage: CoverImage | null;

  /** Optional metadata (created date, last modified, author, etc.) */
  metadata?: {
    createdAt?: string;
    updatedAt?: string;
    [key: string]: any;
  };
}

/**
 * Type guard to check if a node is a ContainerNode.
 * 
 * @param node - The node to check
 * @returns True if node is a ContainerNode
 * 
 * @example
 * ```typescript
 * if (isContainerNode(node)) {
 *   console.log(node.children.length);
 * }
 * ```
 */
export function isContainerNode(node: EditorNode | undefined | null): node is ContainerNode {
  if (!node) return false;
  return node.type === 'container';
}

/**
 * Type guard to check if a node is a StructuralNode (table, thead, tbody, tr).
 * 
 * @param node - The node to check
 * @returns True if node is a StructuralNode
 */
export function isStructuralNode(node: EditorNode | undefined | null): node is StructuralNode {
  if (!node) return false;
  return node.type === 'table' || node.type === 'thead' || node.type === 'tbody' || node.type === 'tr';
}

/**
 * Type guard to check if a node is a TextNode.
 * 
 * @param node - The node to check
 * @returns True if node is a TextNode
 * 
 * @example
 * ```typescript
 * if (isTextNode(node)) {
 *   console.log(node.content);
 * }
 * ```
 */
export function isTextNode(node: EditorNode | undefined | null): node is TextNode {
  if (!node) return false;
  return node.type !== 'container' && !isStructuralNode(node);
}

/**
 * Type guard to check if a node has inline children (rich text).
 * 
 * @param node - The node to check
 * @returns True if node has inline children
 * 
 * @example
 * ```typescript
 * if (hasInlineChildren(node)) {
 *   console.log(node.children); // Array of inline text segments
 * }
 * ```
 */
export function hasInlineChildren(node: EditorNode): node is TextNode & { children: InlineText[] } {
  return isTextNode(node) && Array.isArray((node as TextNode).children) && (node as TextNode).children!.length > 0;
}

/**
 * Get the text content of a node (whether simple or with inline children).
 * 
 * @param node - The node to extract text from
 * @returns The full text content
 * 
 * @example
 * ```typescript
 * const text = getNodeTextContent(node); // "Hello world!"
 * ```
 */
export function getNodeTextContent(node: TextNode): string {
  // If node has multiple lines, join them with newlines
  if (node.lines && node.lines.length > 0) {
    return node.lines
      .map(line => {
        if (line.children && line.children.length > 0) {
          return line.children.map(child => child.content).join('');
        }
        return line.content || '';
      })
      .join('\n');
  }

  // If node has inline children (single line with formatting)
  if (hasInlineChildren(node)) {
    return node.children!.map(child => child.content).join('');
  }

  // Simple content (single line, no formatting)
  return node.content || '';
}

/**
 * Class Replacement Utilities
 * 
 * Smart logic for replacing Tailwind classes in the same category
 */

import { tailwindClasses } from "../tailwind-classes";

/**
 * Get the category of a Tailwind class
 * @param className - The class to categorize
 * @returns The category name or null if not found
 */
export function getClassCategory(className: string): string | null {
  for (const group of tailwindClasses) {
    if (group.classes.includes(className)) {
      return group.category;
    }
  }
  return null;
}

/**
 * Get all classes from a specific category
 * @param category - The category name
 * @returns Array of class names in that category
 */
export function getClassesInCategory(category: string): string[] {
  const group = tailwindClasses.find(g => g.category === category);
  return group ? group.classes : [];
}

/**
 * Check if two classes are in the same category
 * @param class1 - First class name
 * @param class2 - Second class name
 * @returns true if both classes are in the same category
 */
export function areSameCategory(class1: string, class2: string): boolean {
  const cat1 = getClassCategory(class1);
  const cat2 = getClassCategory(class2);
  return cat1 !== null && cat1 === cat2;
}

/**
 * Replace classes in the same category with a new class
 * @param currentClasses - Space-separated string of current classes
 * @param newClass - The new class to add
 * @returns Updated space-separated string of classes
 */
export function replaceClassInCategory(
  currentClasses: string,
  newClass: string
): string {
  if (!currentClasses) return newClass;

  const classes = currentClasses.split(' ').filter(Boolean);
  const newCategory = getClassCategory(newClass);

  if (!newCategory) {
    // If new class is not in our known categories, just add it
    return [...classes, newClass].join(' ');
  }

  const categoryClasses = getClassesInCategory(newCategory);

  // Remove all classes from the same category
  const filtered = classes.filter(cls => !categoryClasses.includes(cls));

  // Add the new class
  return [...filtered, newClass].join(' ');
}

/**
 * Get a summary of what will be replaced
 * @param currentClasses - Space-separated string of current classes
 * @param newClass - The new class to add
 * @returns Object with replacement info
 */
export function getReplacementInfo(
  currentClasses: string,
  newClass: string
): {
  willReplace: boolean;
  replacedClasses: string[];
  newClasses: string;
  category: string | null;
} {
  const classes = currentClasses.split(' ').filter(Boolean);
  const newCategory = getClassCategory(newClass);

  if (!newCategory) {
    return {
      willReplace: false,
      replacedClasses: [],
      newClasses: replaceClassInCategory(currentClasses, newClass),
      category: null,
    };
  }

  const categoryClasses = getClassesInCategory(newCategory);
  const replacedClasses = classes.filter(cls => categoryClasses.includes(cls));

  return {
    willReplace: replacedClasses.length > 0,
    replacedClasses,
    newClasses: replaceClassInCategory(currentClasses, newClass),
    category: newCategory,
  };
}

/**
 * Get current classes from a selection's className attribute
 * @param className - The className string (might be null/undefined)
 * @returns Array of class names
 */
export function getCurrentClasses(className: string | null | undefined): string[] {
  if (!className) return [];
  return className.split(' ').filter(Boolean);
}

/**
 * Merge new class with existing classes, replacing same-category classes
 * @param existingClassName - Current className string
 * @param newClass - New class to apply
 * @returns Updated className string
 */
export function mergeClasses(
  existingClassName: string | null | undefined,
  newClass: string
): string {
  const current = existingClassName || '';
  return replaceClassInCategory(current, newClass);
}

/**
 * DOM Reconciler Utility
 *
 * Patches only changed DOM nodes instead of replacing innerHTML entirely,
 * preserving cursor position during content edits.
 *
 * Key principle: When the contentEditable element is focused and the user is
 * actively typing, the DOM is the source of truth and we should NOT overwrite
 * it from state. We only sync from state when:
 * - The element is not focused (user is not actively editing it)
 * - An external action occurred (undo/redo, formatting, etc.) — signaled by
 *   the caller passing `forceUpdate = true`
 */

/**
 * Reconcile the innerHTML of a contentEditable element with a desired HTML string.
 *
 * @param element       The contentEditable HTMLElement to update.
 * @param getNewHTML    A function that returns the desired HTML string (called lazily).
 * @param forceUpdate   When true, always update even if the element is focused.
 *                      Use this for undo/redo, formatting changes, etc.
 * @returns `true` if the DOM was actually updated, `false` if skipped or identical.
 */
export function reconcileContent(
  element: HTMLElement,
  getNewHTML: () => string,
  forceUpdate: boolean = false
): boolean {
  const isFocused = document.activeElement === element;

  // When the element is focused and we are not forcing an update, the user is
  // actively editing — the DOM is the source of truth, so skip the sync.
  if (isFocused && !forceUpdate) {
    return false;
  }

  const newHTML = getNewHTML();
  const currentHTML = element.innerHTML;

  // Skip update if content already matches
  if (currentHTML === newHTML) {
    return false;
  }

  // If the element is focused (forced update path), save and restore cursor position
  if (isFocused) {
    const charOffset = getCharacterOffset(element);

    element.innerHTML = newHTML;

    if (charOffset >= 0) {
      try {
        restoreCursorByOffset(element, charOffset);
      } catch {
        // Silently fail — cursor position is nice-to-have, not critical
      }
    }
  } else {
    // Element is not focused — safe to set innerHTML directly
    element.innerHTML = newHTML;
  }

  return true;
}

/**
 * Get the character offset of the current cursor (anchor) within `container`.
 * Returns -1 if there is no relevant selection.
 */
export function getCharacterOffset(container: Node): number {
  const selection = window.getSelection();
  if (!selection || selection.rangeCount === 0) return -1;

  const anchor = selection.anchorNode;
  if (!anchor || !container.contains(anchor)) return -1;

  return countCharacters(container, anchor, selection.anchorOffset);
}

/**
 * Walk text nodes under `container` counting characters until `targetNode` is
 * reached. Returns the total character offset at `targetNode[targetOffset]`.
 */
function countCharacters(
  container: Node,
  targetNode: Node,
  targetOffset: number
): number {
  let charCount = 0;
  const walker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT);
  let node: Text | null;
  while ((node = walker.nextNode() as Text | null)) {
    if (node === targetNode) {
      return charCount + targetOffset;
    }
    charCount += node.textContent?.length ?? 0;
  }
  // targetNode was not found as a text node — return the accumulated count
  return charCount + targetOffset;
}

/**
 * Restore the cursor to the given character offset within `container`.
 */
export function restoreCursorByOffset(container: Node, targetOffset: number): void {
  const walker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT);
  let charCount = 0;
  let node: Text | null;
  while ((node = walker.nextNode() as Text | null)) {
    const nodeLength = node.textContent?.length ?? 0;
    if (charCount + nodeLength >= targetOffset) {
      const selection = window.getSelection();
      if (selection) {
        const range = document.createRange();
        range.setStart(node, targetOffset - charCount);
        range.collapse(true);
        selection.removeAllRanges();
        selection.addRange(range);
      }
      return;
    }
    charCount += nodeLength;
  }

  // If offset is past end of content, place cursor at end
  const selection = window.getSelection();
  if (selection) {
    const range = document.createRange();
    range.selectNodeContents(container);
    range.collapse(false);
    selection.removeAllRanges();
    selection.addRange(range);
  }
}

/**
 * Drag Auto-Scroll Utility
 * 
 * Provides automatic scrolling functionality when dragging elements near viewport edges
 * This allows users to drag items to areas outside the current visible viewport
 */

import React from "react";

/**
 * Auto-scroll configuration
 */
export interface AutoScrollConfig {
  /** Distance from edge (in pixels) that triggers auto-scroll */
  scrollZone?: number;
  /** Scroll speed in pixels per frame */
  scrollSpeed?: number;
  /** Whether to enable horizontal scrolling */
  enableHorizontal?: boolean;
  /** Whether to enable vertical scrolling */
  enableVertical?: boolean;
}

const DEFAULT_CONFIG: Required<AutoScrollConfig> = {
  scrollZone: 80,
  scrollSpeed: 10,
  enableHorizontal: false,
  enableVertical: true,
};

/**
 * Setup auto-scroll for drag operations
 * Returns a cleanup function to remove event listeners
 */
export function setupDragAutoScroll(
  containerRef: React.RefObject<HTMLElement | null>,
  config: AutoScrollConfig = {}
): () => void {
  const finalConfig = { ...DEFAULT_CONFIG, ...config };
  let rafId: number | null = null;
  let isDragging = false;
  let lastMouseX = 0;
  let lastMouseY = 0;

  /**
   * Auto-scroll logic
   */
  const autoScroll = () => {
    if (!isDragging || !containerRef.current) {
      rafId = null;
      return;
    }

    const container = containerRef.current;
    const rect = container.getBoundingClientRect();
    const { scrollZone, scrollSpeed, enableVertical, enableHorizontal } = finalConfig;

    let scrollX = 0;
    let scrollY = 0;

    // Check vertical scrolling
    if (enableVertical) {
      // Scroll down when near bottom
      if (lastMouseY > rect.bottom - scrollZone) {
        const distance = lastMouseY - (rect.bottom - scrollZone);
        const intensity = Math.min(distance / scrollZone, 1);
        scrollY = scrollSpeed * intensity;
      }
      // Scroll up when near top
      else if (lastMouseY < rect.top + scrollZone) {
        const distance = (rect.top + scrollZone) - lastMouseY;
        const intensity = Math.min(distance / scrollZone, 1);
        scrollY = -scrollSpeed * intensity;
      }
    }

    // Check horizontal scrolling
    if (enableHorizontal) {
      // Scroll right when near right edge
      if (lastMouseX > rect.right - scrollZone) {
        const distance = lastMouseX - (rect.right - scrollZone);
        const intensity = Math.min(distance / scrollZone, 1);
        scrollX = scrollSpeed * intensity;
      }
      // Scroll left when near left edge
      else if (lastMouseX < rect.left + scrollZone) {
        const distance = (rect.left + scrollZone) - lastMouseX;
        const intensity = Math.min(distance / scrollZone, 1);
        scrollX = -scrollSpeed * intensity;
      }
    }

    // Perform scroll
    if (scrollX !== 0 || scrollY !== 0) {
      // Try to find the scrollable parent (could be window or a container)
      const scrollableParent = findScrollableParent(container);

      if (scrollableParent === window) {
        window.scrollBy(scrollX, scrollY);
      } else if (scrollableParent instanceof HTMLElement) {
        scrollableParent.scrollLeft += scrollX;
        scrollableParent.scrollTop += scrollY;
      }
    }

    // Continue animation loop
    rafId = requestAnimationFrame(autoScroll);
  };

  /**
   * Find the scrollable parent element
   */
  const findScrollableParent = (element: HTMLElement): HTMLElement | Window => {
    let parent = element.parentElement;

    while (parent) {
      const style = window.getComputedStyle(parent);
      const isScrollable =
        (style.overflowY === 'auto' || style.overflowY === 'scroll' ||
         style.overflowX === 'auto' || style.overflowX === 'scroll') &&
        (parent.scrollHeight > parent.clientHeight || parent.scrollWidth > parent.clientWidth);

      if (isScrollable) {
        return parent;
      }

      parent = parent.parentElement;
    }

    // Default to window if no scrollable parent found
    return window;
  };

  /**
   * Track mouse movement during drag
   */
  const handleDragOver = (e: DragEvent) => {
    lastMouseX = e.clientX;
    lastMouseY = e.clientY;

    // Start auto-scroll loop if not already running
    if (!rafId && isDragging) {
      rafId = requestAnimationFrame(autoScroll);
    }
  };

  /**
   * Start tracking drag
   */
  const handleDragStart = () => {
    isDragging = true;
  };

  /**
   * Stop tracking drag
   */
  const handleDragEnd = () => {
    isDragging = false;
    if (rafId) {
      cancelAnimationFrame(rafId);
      rafId = null;
    }
  };

  // Attach event listeners
  document.addEventListener('dragstart', handleDragStart);
  document.addEventListener('dragover', handleDragOver);
  document.addEventListener('dragend', handleDragEnd);
  document.addEventListener('drop', handleDragEnd);

  // Return cleanup function
  return () => {
    isDragging = false;
    if (rafId) {
      cancelAnimationFrame(rafId);
      rafId = null;
    }
    document.removeEventListener('dragstart', handleDragStart);
    document.removeEventListener('dragover', handleDragOver);
    document.removeEventListener('dragend', handleDragEnd);
    document.removeEventListener('drop', handleDragEnd);
  };
}

/**
 * React hook for drag auto-scroll
 */
export function useDragAutoScroll(
  containerRef: React.RefObject<HTMLElement | null>,
  config?: AutoScrollConfig
) {
  const configRef = React.useRef(config);

  React.useEffect(() => {
    configRef.current = config;
  }, [config]);

  React.useEffect(() => {
    const cleanup = setupDragAutoScroll(containerRef, configRef.current);
    return cleanup;
  }, [containerRef]);
}

// For non-React usage
export default setupDragAutoScroll;

/**
 * Editor Helper Functions
 *
 * Utility functions used by the SimpleEditor component
 */

import {
  TextNode,
  EditorNode,
  ContainerNode,
  isContainerNode,
} from "../types";

/** Parses a contentEditable DOM element back into the inline children structure, preserving all formatting. */
export function parseDOMToInlineChildren(
  element: HTMLElement
): TextNode["children"] {
  const children: TextNode["children"] = [];

  const walkNode = (
    node: Node,
    inheritedFormats: {
      bold?: boolean;
      italic?: boolean;
      underline?: boolean;
      strikethrough?: boolean;
      code?: boolean;
      className?: string;
      elementType?:
        | "p"
        | "h1"
        | "h2"
        | "h3"
        | "h4"
        | "h5"
        | "h6"
        | "li"
        | "blockquote";
      styles?: Record<string, string>;
      href?: string;
    } = {}
  ) => {
    if (node.nodeType === Node.TEXT_NODE) {
      // Direct text node - use inherited formatting
      const content = node.textContent || "";

      const hasAnyFormatting =
        inheritedFormats.bold ||
        inheritedFormats.italic ||
        inheritedFormats.underline ||
        inheritedFormats.strikethrough ||
        inheritedFormats.code ||
        inheritedFormats.className ||
        inheritedFormats.elementType ||
        inheritedFormats.styles ||
        inheritedFormats.href;

      // Always add content if it exists OR if it's empty but has formatting
      // This prevents structure changes when user deletes the last character
      if (content || hasAnyFormatting) {
        if (hasAnyFormatting) {
          children.push({
            content,
            bold: inheritedFormats.bold || undefined,
            italic: inheritedFormats.italic || undefined,
            underline: inheritedFormats.underline || undefined,
            strikethrough: inheritedFormats.strikethrough || undefined,
            code: inheritedFormats.code || undefined,
            className: inheritedFormats.className || undefined,
            elementType: inheritedFormats.elementType,
            styles: inheritedFormats.styles,
            href: inheritedFormats.href || undefined,
          });
        } else {
          children.push({ content });
        }
      }
    } else if (node.nodeType === Node.ELEMENT_NODE) {
      const el = node as HTMLElement;

      // ── PRIMARY PATH: read formatting from data-* attributes ──────────────
      // These are written by buildHTML and are the single source of truth.
      const hasDataAttrs =
        el.dataset.bold !== undefined ||
        el.dataset.italic !== undefined ||
        el.dataset.underline !== undefined ||
        el.dataset.strikethrough !== undefined ||
        el.dataset.code !== undefined ||
        el.dataset.href !== undefined ||
        el.dataset.elementType !== undefined ||
        el.dataset.className !== undefined ||
        el.dataset.styles !== undefined;

      let bold: boolean | undefined;
      let italic: boolean | undefined;
      let underline: boolean | undefined;
      let strikethrough: boolean | undefined;
      let code: boolean | undefined;
      let hrefFromData: string | undefined;
      let elementTypeFromData:
        | "p" | "h1" | "h2" | "h3" | "h4" | "h5" | "h6" | "blockquote"
        | undefined;
      let classNameFromData: string | undefined;
      let inlineStyles: Record<string, string> | undefined;

      if (hasDataAttrs) {
        // Reliable path: data attributes were set by buildHTML
        bold = el.dataset.bold === "true" || undefined;
        italic = el.dataset.italic === "true" || undefined;
        underline = el.dataset.underline === "true" || undefined;
        strikethrough = el.dataset.strikethrough === "true" || undefined;
        code = el.dataset.code === "true" || undefined;
        hrefFromData = el.dataset.href || undefined;
        const rawElementType = el.dataset.elementType;
        if (rawElementType) {
          const validElementTypes = ["p", "h1", "h2", "h3", "h4", "h5", "h6", "blockquote"] as const;
          if ((validElementTypes as readonly string[]).includes(rawElementType)) {
            elementTypeFromData = rawElementType as typeof elementTypeFromData;
          }
        }
        classNameFromData = el.dataset.className || undefined;
        if (el.dataset.styles) {
          try {
            inlineStyles = JSON.parse(el.dataset.styles);
          } catch {
            inlineStyles = undefined;
          }
        }
      } else {
        // ── FALLBACK PATH: CSS class-based detection (backward compatibility) ─
        const classList = Array.from(el.classList);

        bold = classList.includes("font-bold") || undefined;
        italic = classList.includes("italic") || undefined;
        underline = classList.includes("underline") || undefined;
        strikethrough = classList.includes("line-through") || undefined;
        code = classList.includes("font-mono") || undefined;

        // Extract inline styles from the element
        if (el.style && el.style.length > 0) {
          inlineStyles = {};
          for (let i = 0; i < el.style.length; i++) {
            const property = el.style[i];
            const value = el.style.getPropertyValue(property);
            if (value) {
              // Convert kebab-case to camelCase (font-size -> fontSize)
              const camelCaseProperty = property.replace(/-([a-z])/g, (g) => g[1].toUpperCase());
              inlineStyles[camelCaseProperty] = value;
            }
          }
          if (Object.keys(inlineStyles).length === 0) {
            inlineStyles = undefined;
          }
        }

        // Detect element type from classes
        if (classList.some((c) => c.includes("text-4xl"))) {
          elementTypeFromData = "h1";
        } else if (classList.some((c) => c.includes("text-3xl"))) {
          elementTypeFromData = "h2";
        } else if (classList.some((c) => c.includes("text-2xl"))) {
          elementTypeFromData = "h3";
        } else if (classList.some((c) => c.includes("text-xl"))) {
          elementTypeFromData = "h4";
        } else if (
          classList.some((c) => c.includes("text-lg")) &&
          classList.includes("font-semibold")
        ) {
          elementTypeFromData = "h5";
        } else if (
          classList.some((c) => c.includes("text-base")) &&
          classList.includes("font-semibold")
        ) {
          elementTypeFromData = "h6";
        } else if (classList.includes("border-l-4")) {
          elementTypeFromData = "blockquote";
        } else if (
          classList.some((c) => c.includes("text-base")) &&
          classList.some((c) => c.includes("leading-relaxed"))
        ) {
          elementTypeFromData = "p";
        }

        // Extract custom classes (filter out known formatting classes and extra spacing classes)
        const knownClasses = [
          "font-bold",
          "italic",
          "underline",
          "line-through",
          "font-mono",
          "bg-foreground/10",
          "px-1",
          "py-0.5",
          "rounded",
          "text-sm",
          "text-5xl",
          "text-4xl",
          "text-3xl",
          "text-2xl",
          "text-xl",
          "text-lg",
          "font-semibold",
          "border-l-4",
          "pl-4",
          "text-primary",
          "hover:underline",
          "cursor-pointer",
          "inline-block",
          "inline",
        ];
        const customClasses = classList.filter((c) => !knownClasses.includes(c));
        classNameFromData =
          customClasses.length > 0 ? customClasses.join(" ") : undefined;
      }

      // Resolve href: prefer data-href, then <a> tag's href attribute
      const resolvedHref =
        hrefFromData ||
        (el.tagName === "A" ? el.getAttribute("href") || undefined : undefined) ||
        inheritedFormats.href;

      // Merge inline styles with inherited styles
      const mergedStyles =
        inlineStyles || inheritedFormats.styles
          ? { ...inheritedFormats.styles, ...inlineStyles }
          : undefined;

      // Merge with inherited formatting
      const currentFormats = {
        bold: bold || inheritedFormats.bold,
        italic: italic || inheritedFormats.italic,
        underline: underline || inheritedFormats.underline,
        strikethrough: strikethrough || inheritedFormats.strikethrough,
        code: code || inheritedFormats.code,
        className: classNameFromData || inheritedFormats.className,
        elementType: elementTypeFromData || inheritedFormats.elementType,
        styles: mergedStyles,
        href: resolvedHref,
      };

      // If it's a span or anchor element with formatting, walk its children with inherited formats
      if (el.tagName === "SPAN" || el.tagName === "A") {
        // Check if the element is empty (no child nodes)
        if (node.childNodes.length === 0) {
          // Empty element with formatting - preserve it
          const hasAnyFormatting =
            currentFormats.bold ||
            currentFormats.italic ||
            currentFormats.underline ||
            currentFormats.strikethrough ||
            currentFormats.code ||
            currentFormats.className ||
            currentFormats.elementType ||
            currentFormats.styles ||
            currentFormats.href;

          if (hasAnyFormatting) {
            children.push({
              content: "",
              bold: currentFormats.bold || undefined,
              italic: currentFormats.italic || undefined,
              underline: currentFormats.underline || undefined,
              strikethrough: currentFormats.strikethrough || undefined,
              code: currentFormats.code || undefined,
              className: currentFormats.className || undefined,
              elementType: currentFormats.elementType,
              styles: currentFormats.styles,
              href: currentFormats.href || undefined,
            });
          }
        } else {
          // Element has children, walk them with current inherited formats
          for (let i = 0; i < node.childNodes.length; i++) {
            walkNode(node.childNodes[i], currentFormats);
          }
        }
      } else {
        // For other elements (like the main div), just walk children
        for (let i = 0; i < node.childNodes.length; i++) {
          walkNode(node.childNodes[i], inheritedFormats);
        }
      }
    }
  };

  for (let i = 0; i < element.childNodes.length; i++) {
    walkNode(element.childNodes[i]);
  }

  // Filter out empty content ONLY if it has no formatting
  // Keep empty spans with formatting so user can continue typing in them
  return children.filter((child) => {
    // If content exists and is not empty, always keep it
    if (child.content && child.content.length > 0) {
      return true;
    }

    // If content is empty, only keep it if it has any formatting attributes
    // This prevents the structure from changing when user deletes the last character
    const hasFormatting =
      child.bold ||
      child.italic ||
      child.underline ||
      child.strikethrough ||
      child.code ||
      child.className ||
      child.elementType ||
      child.href ||
      child.styles;

    return hasFormatting;
  });
}

/** Detects which inline formats (bold, italic, etc.) are active across a given character range within a node. */
export function detectFormatsInRange(
  node: TextNode,
  start: number,
  end: number
): {
  bold: boolean;
  italic: boolean;
  underline: boolean;
  strikethrough: boolean;
  code: boolean;
  elementType?:
    | "h1"
    | "h2"
    | "h3"
    | "h4"
    | "h5"
    | "h6"
    | "li"
    | "blockquote"
    | null;
  href?: string | null;
  className?: string | null;
  styles?: Record<string, string> | null;
} {
  const formats = {
    bold: false,
    italic: false,
    underline: false,
    strikethrough: false,
    code: false,
    elementType: null as any,
    href: null as string | null,
    className: null as string | null,
    styles: null as Record<string, string> | null,
  };

  // If node has no children, check node-level attributes
  if (!node.children || node.children.length === 0) {
    // For nodes without inline children, use the node's type as elementType if it's a heading
    // Note: 'code' is excluded from element types - it's only a block-level type, not inline
    const nodeElementType = [
      "h1",
      "h2",
      "h3",
      "h4",
      "h5",
      "h6",
      "blockquote",
      "li",
    ].includes(node.type)
      ? (node.type as
          | "h1"
          | "h2"
          | "h3"
          | "h4"
          | "h5"
          | "h6"
          | "li"
          | "blockquote")
      : null;

    return {
      bold: node.attributes?.bold === true,
      italic: node.attributes?.italic === true,
      underline: node.attributes?.underline === true,
      strikethrough: node.attributes?.strikethrough === true,
      code: node.attributes?.code === true,
      elementType: nodeElementType,
      href: null,
      className: null,
      styles: null,
    };
  }

  // Node has children array - analyze the range
  let currentPos = 0;
  let allBold = true;
  let allItalic = true;
  let allUnderline = true;
  let allStrikethrough = true;
  let allCode = true;
  let charsInRange = 0;
  let firstElementType: typeof formats.elementType = undefined;
  let allSameElementType = true;
  let firstHref: string | undefined = undefined;
  let allSameHref = true;
  let firstClassName: string | undefined = undefined;
  let allSameClassName = true;
  let firstStyles: Record<string, string> | undefined = undefined;
  let allSameStyles = true;

  for (const child of node.children) {
    const childLength = (child.content || "").length;
    const childStart = currentPos;
    const childEnd = currentPos + childLength;

    // Check if this child overlaps with the selection
    const overlaps = childStart < end && childEnd > start;

    if (overlaps) {
      charsInRange += Math.min(childEnd, end) - Math.max(childStart, start);

      if (!child.bold) allBold = false;
      if (!child.italic) allItalic = false;
      if (!child.underline) allUnderline = false;
      if (!child.strikethrough) allStrikethrough = false;
      if (!child.code) allCode = false;

      // Check element type
      const childElementType = child.elementType || null;
      if (firstElementType === undefined) {
        firstElementType = childElementType;
      } else if (firstElementType !== childElementType) {
        allSameElementType = false;
      }

      // Check href
      const childHref = child.href || null;
      if (firstHref === undefined) {
        firstHref = childHref || undefined;
      } else if (firstHref !== childHref) {
        allSameHref = false;
      }

      // Check className
      const childClassName = child.className || null;
      if (firstClassName === undefined) {
        firstClassName = childClassName || undefined;
      } else if (firstClassName !== childClassName) {
        allSameClassName = false;
      }

      // Check styles
      const childStyles = child.styles || null;
      if (firstStyles === undefined) {
        firstStyles = childStyles || undefined;
      } else if (JSON.stringify(firstStyles) !== JSON.stringify(childStyles)) {
        allSameStyles = false;
      }
    }

    currentPos = childEnd;
  }

  // A format is "active" if ALL selected text has that format
  const detectedFormats = {
    bold: charsInRange > 0 && allBold,
    italic: charsInRange > 0 && allItalic,
    underline: charsInRange > 0 && allUnderline,
    strikethrough: charsInRange > 0 && allStrikethrough,
    code: charsInRange > 0 && allCode,
    elementType: allSameElementType ? firstElementType : null,
    href: allSameHref ? firstHref || null : null,
    className: allSameClassName ? firstClassName || null : null,
    styles: allSameStyles ? firstStyles || null : null,
  };

  return detectedFormats;
}

/** Finds a node by ID anywhere in the tree, returning the node along with its parent ID and siblings. */
export function findNodeInTree(
  searchId: string,
  container: ContainerNode
): {
  node: EditorNode;
  parentId: string | null;
  siblings: EditorNode[];
} | null {
  // Check direct children
  for (let i = 0; i < container.children.length; i++) {
    const child = container.children[i];
    if (child.id === searchId) {
      return {
        node: child,
        parentId: container.id,
        siblings: container.children,
      };
    }
    // If child is a container, search recursively
    if (isContainerNode(child)) {
      const found = findNodeInTree(searchId, child as ContainerNode);
      if (found) return found;
    }
  }
  return null;
}

/** Searches both the root level and inside containers for a node by ID, returning the node with optional parent info. */
export function findNodeAnywhere(
  id: string,
  container: ContainerNode
): {
  node: EditorNode;
  parentId?: string;
  parent?: ContainerNode;
} | null {
  // Check root level
  const rootNode = container.children.find((n) => n.id === id);
  if (rootNode) return { node: rootNode };

  // Check inside containers
  for (const child of container.children) {
    if (isContainerNode(child)) {
      const containerNode = child as ContainerNode;
      const foundInContainer = containerNode.children.find((c) => c.id === id);
      if (foundInContainer)
        return {
          node: foundInContainer,
          parentId: child.id,
          parent: containerNode,
        };
    }
  }
  return null;
}

/** Restores a collapsed or range text selection to the given character offsets within an element. */
export function restoreSelection(
  element: HTMLElement,
  start: number,
  end: number
) {
  const range = document.createRange();
  const sel = window.getSelection();

  let currentPos = 0;
  let startNode: Node | null = null;
  let startOffset = 0;
  let endNode: Node | null = null;
  let endOffset = 0;
  let found = false;

  const walk = (node: Node) => {
    if (found) return;

    if (node.nodeType === Node.TEXT_NODE) {
      const textLength = node.textContent?.length || 0;

      if (!startNode && currentPos + textLength >= start) {
        startNode = node;
        startOffset = start - currentPos;
      }

      if (!endNode && currentPos + textLength >= end) {
        endNode = node;
        endOffset = end - currentPos;
        found = true;
      }

      currentPos += textLength;
    } else if (node.nodeType === Node.ELEMENT_NODE) {
      for (let i = 0; i < node.childNodes.length; i++) {
        walk(node.childNodes[i]);
        if (found) break;
      }
    }
  };

  walk(element);

  if (startNode && endNode && sel) {
    try {
      const startLength = (startNode as Text).textContent?.length || 0;
      const endLength = (endNode as Text).textContent?.length || 0;
      range.setStart(startNode, Math.min(startOffset, startLength));
      range.setEnd(endNode, Math.min(endOffset, endLength));
      sel.removeAllRanges();
      sel.addRange(range);
    } catch (e) {
      console.warn("Failed to restore selection:", e);
    }
  }
}

/**
 * HTML to Nodes Parser
 *
 * Converts pasted HTML content into EditorNode tree.
 * Used by clipboard paste handlers to support rich-text paste.
 */

import { EditorNode, InlineText, StructuralNode, TextNode } from '../types';
import { generateId } from './id-generator';

/**
 * Parse pasted HTML into an EditorNode array.
 * Sanitizes the HTML before parsing to prevent XSS.
 */
export function parseHtmlToNodes(html: string): EditorNode[] {
  const temp = document.createElement('div');
  temp.innerHTML = sanitizeHtml(html);

  const nodes: EditorNode[] = [];

  for (const child of Array.from(temp.childNodes)) {
    const result = parseElement(child);
    if (result === null) continue;
    // List parsing returns an array; all other parsers return a single node.
    if (Array.isArray(result)) {
      nodes.push(...result);
    } else {
      nodes.push(result);
    }
  }

  // If no block-level elements found, wrap plain text in a paragraph
  if (nodes.length === 0) {
    const text = temp.textContent || '';
    if (text.trim()) {
      nodes.push({
        id: generateId('p'),
        type: 'p',
        content: text,
      });
    }
  }

  return nodes;
}

// Return type is EditorNode | EditorNode[] | null because list parsing
// produces multiple nodes from a single <ul>/<ol> element.
type ParseResult = EditorNode | EditorNode[] | null;

function parseElement(node: Node): ParseResult {
  if (node.nodeType === Node.TEXT_NODE) {
    const text = node.textContent || '';
    if (!text.trim()) return null;
    return { id: generateId('p'), type: 'p', content: text };
  }

  if (node.nodeType !== Node.ELEMENT_NODE) return null;
  const el = node as HTMLElement;
  const tag = el.tagName.toLowerCase();

  switch (tag) {
    case 'h1':
    case 'h2':
    case 'h3':
    case 'h4':
    case 'h5':
    case 'h6': {
      const inlineChildren = parseInlineChildren(el);
      return {
        id: generateId(tag),
        type: tag as 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6',
        content: inlineChildren ? undefined : (el.textContent || ''),
        children: inlineChildren,
      };
    }
    case 'p':
    case 'div': {
      const inlineChildren = parseInlineChildren(el);
      return {
        id: generateId('p'),
        type: 'p',
        content: inlineChildren ? undefined : (el.textContent || ''),
        children: inlineChildren,
      };
    }
    case 'blockquote':
      return {
        id: generateId('blockquote'),
        type: 'blockquote',
        content: el.textContent || '',
      };
    case 'pre':
    case 'code':
      return {
        id: generateId('code'),
        type: 'code',
        content: el.textContent || '',
      };
    case 'ul':
      return parseList(el, 'li');
    case 'ol':
      return parseList(el, 'ol');
    case 'li':
      return { id: generateId('li'), type: 'li', content: el.textContent || '' };
    case 'hr':
      return { id: generateId('hr'), type: 'hr', content: '' };
    case 'img':
      return parseImg(el);
    case 'video':
      return parseMedia(el, 'video');
    case 'audio':
      return parseMedia(el, 'audio');
    case 'figure':
      return parseFigure(el);
    case 'table':
      return parseTable(el);
    case 'br':
      // Skip bare <br> tags
      return null;
    default:
      // For unknown elements, try to extract text content
      if (el.textContent?.trim()) {
        const inlineChildren = parseInlineChildren(el);
        return {
          id: generateId('p'),
          type: 'p',
          content: inlineChildren ? undefined : (el.textContent || ''),
          children: inlineChildren,
        };
      }
      return null;
  }
}

// ---------------------------------------------------------------------------
// List parsing — Bug 1 fix
// ---------------------------------------------------------------------------

/**
 * Parse a <ul> or <ol> element into an array of TextNodes.
 * Previously only the first <li> was returned; now ALL items are returned.
 *
 * @param el   - The list element
 * @param type - 'li' for <ul>, 'ol' for <ol>
 */
function parseList(el: HTMLElement, type: 'li' | 'ol'): EditorNode[] {
  const items = Array.from(el.querySelectorAll(':scope > li'));
  if (items.length === 0) return [];

  return items.map((item) => {
    const li = item as HTMLElement;
    const inlineChildren = parseInlineChildren(li);
    const node: TextNode = {
      id: generateId(type),
      type,
      content: inlineChildren ? undefined : (li.textContent || ''),
      children: inlineChildren,
    };
    return node;
  });
}

// ---------------------------------------------------------------------------
// Table parsing — Bug 2 fix
// ---------------------------------------------------------------------------

function parseTable(el: HTMLElement): StructuralNode {
  const tableNode: StructuralNode = {
    id: generateId('table'),
    type: 'table',
    children: [],
  };

  // Process <thead> and <tbody> children directly under <table>
  for (const child of Array.from(el.children)) {
    const childTag = child.tagName.toLowerCase();

    if (childTag === 'thead') {
      const theadNode: StructuralNode = {
        id: generateId('thead'),
        type: 'thead',
        children: parseTableRows(child as HTMLElement, 'th'),
      };
      tableNode.children.push(theadNode);
    } else if (childTag === 'tbody') {
      const tbodyNode: StructuralNode = {
        id: generateId('tbody'),
        type: 'tbody',
        children: parseTableRows(child as HTMLElement, 'td'),
      };
      tableNode.children.push(tbodyNode);
    } else if (childTag === 'tr') {
      // <tr> directly inside <table> (no thead/tbody wrapper)
      const rows = parseTableRows(el, 'td');
      tableNode.children.push(...rows);
      break;
    }
  }

  return tableNode;
}

function parseTableRows(section: HTMLElement, _defaultCellTag: 'th' | 'td'): StructuralNode[] {
  return Array.from(section.querySelectorAll(':scope > tr')).map((rowEl) => {
    const row = rowEl as HTMLElement;
    const cells: EditorNode[] = Array.from(
      row.querySelectorAll(':scope > th, :scope > td')
    ).map((cellEl) => {
      const cell = cellEl as HTMLElement;
      const cellTag = cell.tagName.toLowerCase() as 'th' | 'td';
      const inlineChildren = parseInlineChildren(cell);
      const textNode: TextNode = {
        id: generateId(cellTag),
        type: cellTag,
        content: inlineChildren ? undefined : (cell.textContent || ''),
        children: inlineChildren,
      };
      return textNode;
    });

    const rowNode: StructuralNode = {
      id: generateId('tr'),
      type: 'tr',
      children: cells,
    };
    return rowNode;
  });
}

// ---------------------------------------------------------------------------
// Image parsing — Bug 4 fix (alt text)
// ---------------------------------------------------------------------------

function parseImg(el: HTMLElement): TextNode {
  return {
    id: generateId('img'),
    type: 'img',
    attributes: {
      src: el.getAttribute('src') || '',
      alt: el.getAttribute('alt') || undefined,
    },
  };
}

// ---------------------------------------------------------------------------
// Video / Audio parsing — Bug 3 fix
// ---------------------------------------------------------------------------

function parseMedia(el: HTMLElement, mediaType: 'video' | 'audio'): TextNode {
  // src can live on the element itself or on a nested <source> child
  const src =
    el.getAttribute('src') ||
    (el.querySelector('source')?.getAttribute('src') ?? '');

  return {
    id: generateId(mediaType),
    type: mediaType,
    attributes: { src },
  };
}

/**
 * Handle <figure> wrappers around media or images.
 * Returns the inner media/image node, or a paragraph if no media found.
 */
function parseFigure(el: HTMLElement): ParseResult {
  const video = el.querySelector('video');
  if (video) return parseMedia(video, 'video');

  const audio = el.querySelector('audio');
  if (audio) return parseMedia(audio, 'audio');

  const img = el.querySelector('img');
  if (img) return parseImg(img);

  // Fallback: treat figure text content as a paragraph
  const text = el.textContent?.trim();
  if (text) {
    return { id: generateId('p'), type: 'p', content: text };
  }
  return null;
}

// ---------------------------------------------------------------------------
// Inline children / inline styles — Bug 5 fix
// ---------------------------------------------------------------------------

function parseInlineChildren(el: HTMLElement): InlineText[] | undefined {
  // If element has only a single text node child, no inline children needed
  if (el.childNodes.length === 1 && el.childNodes[0].nodeType === Node.TEXT_NODE) {
    return undefined;
  }

  // If the element has no child elements (only text), no inline children needed
  const hasChildElements = Array.from(el.childNodes).some(
    (n) => n.nodeType === Node.ELEMENT_NODE
  );
  if (!hasChildElements) {
    return undefined;
  }

  const children: InlineText[] = [];

  for (const child of Array.from(el.childNodes)) {
    if (child.nodeType === Node.TEXT_NODE) {
      const text = child.textContent || '';
      if (text) children.push({ content: text });
    } else if (child.nodeType === Node.ELEMENT_NODE) {
      const childEl = child as HTMLElement;
      const tag = childEl.tagName.toLowerCase();
      const text = childEl.textContent || '';
      if (!text) continue;

      const inline: InlineText = { content: text };

      // Detect formatting from HTML tags
      if (tag === 'strong' || tag === 'b') inline.bold = true;
      if (tag === 'em' || tag === 'i') inline.italic = true;
      if (tag === 'u') inline.underline = true;
      if (tag === 's' || tag === 'del' || tag === 'strike') inline.strikethrough = true;
      if (tag === 'code') inline.code = true;
      if (tag === 'a') inline.href = childEl.getAttribute('href') || undefined;

      // Bug 5: also apply inline style attribute formatting
      applyInlineStyles(childEl, inline);

      children.push(inline);
    }
  }

  return children.length > 0 ? children : undefined;
}

/**
 * Parse a CSS `style` attribute string and apply recognised properties to an
 * InlineText object.
 *
 * Recognised mappings:
 *   font-weight: bold | 700 | 800 | 900  → bold: true
 *   font-style: italic                    → italic: true
 *   text-decoration: underline            → underline: true
 *   text-decoration: line-through         → strikethrough: true
 *   color: <value>                        → styles.color
 *   font-size: <value>                    → styles.fontSize
 */
function applyInlineStyles(el: HTMLElement, inline: InlineText): void {
  const style = el.getAttribute('style');
  if (!style) return;

  // Parse each declaration
  const declarations = style.split(';').map((s) => s.trim()).filter(Boolean);

  const extraStyles: Record<string, string> = {};

  for (const decl of declarations) {
    const colonIdx = decl.indexOf(':');
    if (colonIdx === -1) continue;

    const prop = decl.slice(0, colonIdx).trim().toLowerCase();
    const value = decl.slice(colonIdx + 1).trim().toLowerCase();

    switch (prop) {
      case 'font-weight':
        if (value === 'bold' || value === 'bolder' || parseInt(value, 10) >= 700) {
          inline.bold = true;
        }
        break;
      case 'font-style':
        if (value === 'italic' || value === 'oblique') {
          inline.italic = true;
        }
        break;
      case 'text-decoration':
      case 'text-decoration-line': {
        // value may be compound e.g. "underline line-through"
        if (value.includes('underline')) inline.underline = true;
        if (value.includes('line-through')) inline.strikethrough = true;
        break;
      }
      case 'color':
        // Preserve original casing for colour values
        extraStyles['color'] = decl.slice(colonIdx + 1).trim();
        break;
      case 'font-size':
        extraStyles['fontSize'] = decl.slice(colonIdx + 1).trim();
        break;
      default:
        break;
    }
  }

  if (Object.keys(extraStyles).length > 0) {
    inline.styles = { ...(inline.styles ?? {}), ...extraStyles };
  }
}

// ---------------------------------------------------------------------------
// Plain text parser
// ---------------------------------------------------------------------------

/**
 * Parse pasted plain text into an EditorNode array.
 * Each non-empty line becomes a paragraph node.
 */
export function parsePlainTextToNodes(text: string): EditorNode[] {
  return text
    .split('\n')
    .filter((line) => line.trim())
    .map((line) => ({
      id: generateId('p'),
      type: 'p' as const,
      content: line,
    }));
}

// ---------------------------------------------------------------------------
// HTML sanitizer
// ---------------------------------------------------------------------------

/**
 * Remove dangerous HTML elements and event handler attributes to prevent XSS.
 */
function sanitizeHtml(html: string): string {
  const temp = document.createElement('div');
  temp.innerHTML = html;

  // Remove dangerous elements
  const dangerous = temp.querySelectorAll(
    'script, iframe, object, embed, form, style, link, meta'
  );
  dangerous.forEach((el) => el.remove());

  // Remove event handler attributes (on*)
  const allElements = temp.querySelectorAll('*');
  allElements.forEach((el) => {
    Array.from(el.attributes).forEach((attr) => {
      if (attr.name.startsWith('on')) el.removeAttribute(attr.name);
    });
  });

  return temp.innerHTML;
}

let counter = 0;

/** Generates a unique, deterministic node ID with an optional prefix using a monotonic counter. */
export function generateId(prefix: string = 'node'): string {
  return `${prefix}-${++counter}`;
}

/** Resets the internal ID counter to zero, useful for deterministic output in tests. */
export function resetIdCounter(): void {
  counter = 0;
}

