/**
 * Inline Formatting Utilities
 * 
 * Functions for splitting text nodes and applying inline formatting
 */

import { TextNode, InlineText, hasInlineChildren, getNodeTextContent } from '../types';
import { generateId } from './id-generator';

/** Splits a plain-text string at the given selection offsets, returning the before, selected, and after segments. */
export function splitTextAtSelection(
  content: string,
  startOffset: number,
  endOffset: number
): { before: string; selected: string; after: string } {
  return {
    before: content.substring(0, startOffset),
    selected: content.substring(startOffset, endOffset),
    after: content.substring(endOffset),
  };
}

/** Converts a plain-content TextNode into the inline-children format, leaving already-converted nodes unchanged. */
export function convertToInlineFormat(node: TextNode): TextNode {
  if (hasInlineChildren(node)) {
    return node; // Already in inline format
  }

  const content = node.content || '';

  return {
    ...node,
    content: undefined, // Remove content property
    children: [
      {
        id: generateId('text'),
        content: content,
      },
    ],
  };
}

/** Applies a Tailwind className to the selected character range within a node, splitting inline segments as needed. */
export function applyFormatting(
  node: TextNode,
  startOffset: number,
  endOffset: number,
  className: string
): TextNode {
  // Convert to inline format if needed
  const inlineNode = convertToInlineFormat(node);
  const fullText = getNodeTextContent(inlineNode);

  // Split the text
  const { before, selected, after } = splitTextAtSelection(fullText, startOffset, endOffset);

  // Build new children array
  const newChildren: InlineText[] = [];

  // Add "before" text if it exists
  if (before) {
    newChildren.push({
      id: generateId('text'),
      content: before,
    });
  }

  // Add formatted selection
  if (selected) {
    newChildren.push({
      id: generateId('span'),
      content: selected,
      className: className,
    });
  }

  // Add "after" text if it exists
  if (after) {
    newChildren.push({
      id: generateId('text'),
      content: after,
    });
  }

  return {
    ...inlineNode,
    children: newChildren,
  };
}

/** Merges adjacent inline text segments that share identical formatting properties to reduce tree size. */
export function mergeAdjacentTextNodes(children: InlineText[]): InlineText[] {
  if (children.length <= 1) return children;

  const merged: InlineText[] = [];
  let current = { ...children[0] };

  for (let i = 1; i < children.length; i++) {
    const next = children[i];

    // Check if formatting properties match
    if (
      current.bold === next.bold &&
      current.italic === next.italic &&
      current.underline === next.underline &&
      current.strikethrough === next.strikethrough &&
      current.code === next.code &&
      current.className === next.className &&
      current.href === next.href &&
      current.elementType === next.elementType &&
      JSON.stringify(current.styles) === JSON.stringify(next.styles)
    ) {
      // Merge them
      current = {
        ...current,
        content: (current.content || '') + (next.content || ''),
      };
    } else {
      merged.push(current);
      current = { ...next };
    }
  }

  merged.push(current);
  return merged;
}

/** Removes a specific className from inline children that overlap the given character range. */
export function removeFormatting(
  node: TextNode,
  _startOffset: number,
  _endOffset: number,
  _className: string
): TextNode {
  if (!hasInlineChildren(node)) {
    return node; // Nothing to remove
  }

  // This is more complex - we need to traverse inline children
  // and split spans that intersect with the selection
  // For now, simplified implementation

  return node;
}

/** Returns the array of class names applied to the inline segment at the given cursor offset within a node. */
export function getFormattingAtPosition(node: TextNode, offset: number): string[] {
  if (!hasInlineChildren(node)) {
    return node.attributes?.className ? [String(node.attributes.className)] : [];
  }

  let currentOffset = 0;
  for (const child of node.children!) {
    const childLength = (child.content || '').length;
    if (offset >= currentOffset && offset <= currentOffset + childLength) {
      return child.className ? [child.className] : [];
    }
    currentOffset += childLength;
  }

  return [];
}

/**
 * Markdown Table Parser
 * 
 * Converts markdown table syntax to editor table structure
 */

import { StructuralNode, TextNode } from "../types";
import { generateId } from "./id-generator";

/**
 * Parse markdown table string into table structure
 * 
 * @example
 * ```
 * | Header 1 | Header 2 |
 * |----------|----------|
 * | Cell 1   | Cell 2   |
 * ```
 */
export function parseMarkdownTable(markdown: string): {
  success: boolean;
  table?: StructuralNode;
  error?: string;
} {
  try {
    // Split into lines and remove empty lines
    const lines = markdown
      .trim()
      .split('\n')
      .map(line => line.trim())
      .filter(line => line.length > 0);

    if (lines.length < 2) {
      return {
        success: false,
        error: "Table must have at least a header row and separator row",
      };
    }

    // Parse header row
    const headerLine = lines[0];
    if (!headerLine.startsWith('|') || !headerLine.endsWith('|')) {
      return {
        success: false,
        error: "Table rows must start and end with |",
      };
    }

    const headerCells = headerLine
      .split('|')
      .slice(1, -1) // Remove first and last empty strings
      .map(cell => cell.trim());

    if (headerCells.length === 0) {
      return {
        success: false,
        error: "Header row must have at least one column",
      };
    }

    // Check separator row
    const separatorLine = lines[1];
    if (!separatorLine.includes('---') && !separatorLine.includes('-')) {
      return {
        success: false,
        error: "Second row must be a separator (e.g., |---|---|)",
      };
    }

    // Parse body rows
    const bodyLines = lines.slice(2);
    const numCols = headerCells.length;

    // Validate all rows have same number of columns
    for (let i = 0; i < bodyLines.length; i++) {
      const cells = bodyLines[i]
        .split('|')
        .slice(1, -1)
        .map(cell => cell.trim());

      if (cells.length !== numCols) {
        return {
          success: false,
          error: `Row ${i + 3} has ${cells.length} columns, expected ${numCols}`,
        };
      }
    }

    // Create header cells
    const headerCellNodes: TextNode[] = headerCells.map((content) => ({
      id: generateId("th"),
      type: "th",
      content: content || "",
      attributes: {},
    }));

    // Create header row
    const headerRow: StructuralNode = {
      id: generateId("tr-header"),
      type: "tr",
      children: headerCellNodes,
      attributes: {},
    };

    // Create thead
    const thead: StructuralNode = {
      id: generateId("thead"),
      type: "thead",
      children: [headerRow],
      attributes: {},
    };

    // Create body rows
    const bodyRows: StructuralNode[] = bodyLines.map((line) => {
      const cells = line
        .split('|')
        .slice(1, -1)
        .map(cell => cell.trim());

      const cellNodes: TextNode[] = cells.map((content) => ({
        id: generateId("td"),
        type: "td",
        content: content || "",
        attributes: {},
      }));

      return {
        id: generateId("tr"),
        type: "tr",
        children: cellNodes,
        attributes: {},
      };
    });

    // Create tbody
    const tbody: StructuralNode = {
      id: generateId("tbody"),
      type: "tbody",
      children: bodyRows,
      attributes: {},
    };

    // Create table
    const table: StructuralNode = {
      id: generateId("table"),
      type: "table",
      children: [thead, tbody],
      attributes: {},
    };

    return {
      success: true,
      table,
    };
  } catch (error) {
    return {
      success: false,
      error: error instanceof Error ? error.message : "Failed to parse markdown table",
    };
  }
}

/**
 * Validate if string looks like a markdown table
 */
export function isMarkdownTable(text: string): boolean {
  const lines = text.trim().split('\n').filter(line => line.trim().length > 0);

  if (lines.length < 2) return false;

  // Check if first line has pipes
  if (!lines[0].includes('|')) return false;

  // Check if second line is separator
  const secondLine = lines[1];
  return secondLine.includes('---') || (secondLine.includes('-') && secondLine.includes('|'));
}

/**
 * Parse Markdown to Editor Nodes
 *
 * Converts a Markdown string into an array of EditorNode blocks.
 * Uses a simple line-by-line parser — no external dependencies.
 * Handles headings, paragraphs, lists, blockquotes, code blocks,
 * horizontal rules, images, tables, and inline formatting.
 */

import { EditorNode, InlineText, StructuralNode, TextNode } from '../types';
import { generateId } from './id-generator';
import { parseMarkdownTable, isMarkdownTable } from './markdown-table-parser';

// ============================================================================
// Public API
// ============================================================================

/**
 * Parses a Markdown string into an array of EditorNode blocks.
 *
 * @param markdown - The Markdown string to parse
 * @returns An array of EditorNode blocks representing the document
 *
 * @example
 * ```typescript
 * const nodes = parseMarkdownToNodes('# Hello\n\nWorld');
 * // [{ type: 'h1', content: 'Hello' }, { type: 'p', content: 'World' }]
 * ```
 */
export function parseMarkdownToNodes(markdown: string): EditorNode[] {
  const lines = markdown.split('\n');
  const nodes: EditorNode[] = [];
  let i = 0;

  while (i < lines.length) {
    const line = lines[i];

    // ── Empty lines ─────────────────────────────────────────────────────────
    if (line.trim() === '') {
      i++;
      continue;
    }

    // ── Fenced code block ───────────────────────────────────────────────────
    if (line.trimStart().startsWith('```')) {
      const result = parseFencedCodeBlock(lines, i);
      nodes.push(result.node);
      i = result.nextIndex;
      continue;
    }

    // ── Table detection ─────────────────────────────────────────────────────
    // Collect all consecutive pipe lines to form a potential table
    if (line.trim().startsWith('|')) {
      const result = parseTableBlock(lines, i);
      if (result.node) {
        nodes.push(result.node);
        i = result.nextIndex;
        continue;
      }
    }

    // ── Heading ─────────────────────────────────────────────────────────────
    const headingMatch = line.match(/^(#{1,6})\s+(.+)$/);
    if (headingMatch) {
      const level = headingMatch[1].length as 1 | 2 | 3 | 4 | 5 | 6;
      const type = `h${level}` as TextNode['type'];
      const content = headingMatch[2].trim();
      nodes.push(makeTextNode(type, content));
      i++;
      continue;
    }

    // ── Horizontal rule ─────────────────────────────────────────────────────
    if (/^(-{3,}|\*{3,}|_{3,})\s*$/.test(line.trim())) {
      nodes.push({ id: generateId('hr'), type: 'hr' } as TextNode);
      i++;
      continue;
    }

    // ── Blockquote ──────────────────────────────────────────────────────────
    const bqMatch = line.match(/^>\s?(.*)$/);
    if (bqMatch) {
      const content = bqMatch[1];
      nodes.push(makeTextNode('blockquote', content));
      i++;
      continue;
    }

    // ── Unordered list item ─────────────────────────────────────────────────
    const ulMatch = line.match(/^[-*+]\s+(.+)$/);
    if (ulMatch) {
      nodes.push(makeTextNode('li', ulMatch[1]));
      i++;
      continue;
    }

    // ── Ordered list item ───────────────────────────────────────────────────
    const olMatch = line.match(/^\d+\.\s+(.+)$/);
    if (olMatch) {
      nodes.push(makeTextNode('ol', olMatch[1]));
      i++;
      continue;
    }

    // ── Image ────────────────────────────────────────────────────────────────
    const imgMatch = line.match(/^!\[([^\]]*)\]\(([^)]+)\)\s*$/);
    if (imgMatch) {
      const alt = imgMatch[1];
      const src = imgMatch[2];
      const node: TextNode = {
        id: generateId('img'),
        type: 'img',
        content: '',
        attributes: { src, alt },
      };
      nodes.push(node);
      i++;
      continue;
    }

    // ── Paragraph (everything else) ─────────────────────────────────────────
    nodes.push(makeTextNode('p', line));
    i++;
  }

  return nodes;
}

// ============================================================================
// Inline formatting parser
// ============================================================================

/**
 * Parses inline Markdown formatting markers in a content string.
 * Returns `children` array when formatting is found, or plain `content` string.
 *
 * Supported markers:
 * - `***text***` → bold + italic
 * - `**text**`  → bold
 * - `*text*`    → italic
 * - `` `text` `` → inline code
 * - `~~text~~`  → strikethrough
 * - `[text](url)` → link
 * - `<u>text</u>` → underline
 */
function parseInlineFormatting(
  text: string
): { content: string } | { children: InlineText[] } {
  // Quick check: if no formatting markers are present, return plain content
  const hasMarkers =
    text.includes('**') ||
    text.includes('*') ||
    text.includes('`') ||
    text.includes('~~') ||
    text.includes('[') ||
    text.includes('<u>');

  if (!hasMarkers) {
    return { content: text };
  }

  const segments = tokenizeInline(text);
  if (segments.length === 0) {
    return { content: text };
  }

  // If there's exactly one segment and it has no formatting flags, keep plain
  if (
    segments.length === 1 &&
    !segments[0].bold &&
    !segments[0].italic &&
    !segments[0].code &&
    !segments[0].strikethrough &&
    !segments[0].href &&
    !segments[0].underline
  ) {
    return { content: segments[0].content };
  }

  return { children: segments };
}

/**
 * Tokenizes inline markdown text into an array of InlineText segments.
 * Uses a simple regex-based approach with ordered pattern matching.
 */
function tokenizeInline(text: string): InlineText[] {
  const segments: InlineText[] = [];
  let remaining = text;

  while (remaining.length > 0) {
    // Try to match any inline pattern at the current position

    // ── Bold + Italic: ***text*** ─────────────────────────────────────────
    const boldItalicMatch = remaining.match(/^\*{3}([^*]+)\*{3}/);
    if (boldItalicMatch) {
      segments.push({ content: boldItalicMatch[1], bold: true, italic: true });
      remaining = remaining.slice(boldItalicMatch[0].length);
      continue;
    }

    // ── Bold: **text** ─────────────────────────────────────────────────────
    const boldMatch = remaining.match(/^\*{2}([^*]+)\*{2}/);
    if (boldMatch) {
      segments.push({ content: boldMatch[1], bold: true });
      remaining = remaining.slice(boldMatch[0].length);
      continue;
    }

    // ── Italic: *text* ─────────────────────────────────────────────────────
    const italicMatch = remaining.match(/^\*([^*]+)\*/);
    if (italicMatch) {
      segments.push({ content: italicMatch[1], italic: true });
      remaining = remaining.slice(italicMatch[0].length);
      continue;
    }

    // ── Inline code: `text` ────────────────────────────────────────────────
    const codeMatch = remaining.match(/^`([^`]+)`/);
    if (codeMatch) {
      segments.push({ content: codeMatch[1], code: true });
      remaining = remaining.slice(codeMatch[0].length);
      continue;
    }

    // ── Strikethrough: ~~text~~ ────────────────────────────────────────────
    const strikeMatch = remaining.match(/^~~([^~]+)~~/);
    if (strikeMatch) {
      segments.push({ content: strikeMatch[1], strikethrough: true });
      remaining = remaining.slice(strikeMatch[0].length);
      continue;
    }

    // ── Link: [text](url) ──────────────────────────────────────────────────
    const linkMatch = remaining.match(/^\[([^\]]+)\]\(([^)]+)\)/);
    if (linkMatch) {
      segments.push({ content: linkMatch[1], href: linkMatch[2] });
      remaining = remaining.slice(linkMatch[0].length);
      continue;
    }

    // ── Underline: <u>text</u> ─────────────────────────────────────────────
    const underlineMatch = remaining.match(/^<u>([^<]*)<\/u>/);
    if (underlineMatch) {
      segments.push({ content: underlineMatch[1], underline: true });
      remaining = remaining.slice(underlineMatch[0].length);
      continue;
    }

    // ── Plain text: consume up to the next possible marker ────────────────
    // Find the position of the next potential formatting character
    const nextMarker = findNextMarkerPosition(remaining);

    if (nextMarker === 0) {
      // Current char is a marker char but didn't match any pattern
      // Consume one character as plain text
      const lastSeg = segments[segments.length - 1];
      if (lastSeg && !lastSeg.bold && !lastSeg.italic && !lastSeg.code && !lastSeg.strikethrough && !lastSeg.href && !lastSeg.underline) {
        lastSeg.content += remaining[0];
      } else {
        segments.push({ content: remaining[0] });
      }
      remaining = remaining.slice(1);
    } else {
      const plainText = remaining.slice(0, nextMarker);
      const lastSeg = segments[segments.length - 1];
      if (lastSeg && !lastSeg.bold && !lastSeg.italic && !lastSeg.code && !lastSeg.strikethrough && !lastSeg.href && !lastSeg.underline) {
        lastSeg.content += plainText;
      } else {
        segments.push({ content: plainText });
      }
      remaining = remaining.slice(nextMarker);
    }
  }

  return segments.filter(seg => seg.content.length > 0);
}

/**
 * Finds the position of the next potential inline formatting marker.
 * Returns the length of `text` if no markers are found (consume all).
 */
function findNextMarkerPosition(text: string): number {
  for (let i = 0; i < text.length; i++) {
    const ch = text[i];
    if (ch === '*' || ch === '`' || ch === '~' || ch === '[' || ch === '<') {
      return i;
    }
  }
  return text.length;
}

// ============================================================================
// Node factory helpers
// ============================================================================

/**
 * Creates a TextNode with parsed inline formatting.
 * Uses `children` array when formatting markers are found, otherwise plain `content`.
 */
function makeTextNode(type: TextNode['type'], rawContent: string): TextNode {
  const parsed = parseInlineFormatting(rawContent);

  if ('children' in parsed) {
    return {
      id: generateId(type),
      type,
      children: parsed.children,
    };
  }

  return {
    id: generateId(type),
    type,
    content: parsed.content,
  };
}

// ============================================================================
// Fenced code block parser
// ============================================================================

function parseFencedCodeBlock(
  lines: string[],
  startIndex: number
): { node: EditorNode; nextIndex: number } {
  const openingLine = lines[startIndex];
  const langMatch = openingLine.match(/^```(\w*)$/);
  const lang = langMatch ? langMatch[1] : '';
  const codeLines: string[] = [];
  let i = startIndex + 1;

  while (i < lines.length) {
    if (lines[i].trimStart() === '```') {
      i++; // consume closing fence
      break;
    }
    codeLines.push(lines[i]);
    i++;
  }

  const node: TextNode = {
    id: generateId('code'),
    type: 'code',
    content: codeLines.join('\n'),
    attributes: lang ? { language: lang } : {},
  };

  return { node, nextIndex: i };
}

// ============================================================================
// Table block parser
// ============================================================================

function parseTableBlock(
  lines: string[],
  startIndex: number
): { node: EditorNode | null; nextIndex: number } {
  // Collect consecutive pipe-table lines
  let i = startIndex;
  const tableLines: string[] = [];

  while (i < lines.length && lines[i].trim().startsWith('|')) {
    tableLines.push(lines[i]);
    i++;
  }

  const tableText = tableLines.join('\n');

  if (!isMarkdownTable(tableText)) {
    return { node: null, nextIndex: startIndex };
  }

  const result = parseMarkdownTable(tableText);

  if (!result.success || !result.table) {
    // Fall through to paragraph parsing
    return { node: null, nextIndex: startIndex };
  }

  return { node: result.table as StructuralNode, nextIndex: i };
}

/**
 * Serialize Editor State to Markdown
 *
 * Converts the editor's block model to standard Markdown text.
 * Handles all block types, inline formatting, lists, tables, images, and more.
 */

import {
  ContainerNode,
  StructuralNode,
  TextNode,
  EditorNode,
  InlineText,
  isTextNode,
  isContainerNode,
  isStructuralNode,
  hasInlineChildren,
} from '../types';

// ============================================================================
// Public API
// ============================================================================

/**
 * Serializes a ContainerNode tree to standard Markdown.
 *
 * @param container - The root container node from editor state
 * @returns A Markdown string representing the document
 *
 * @example
 * ```typescript
 * const md = serializeToMarkdown(state.container);
 * // # Title
 * //
 * // **Bold** normal text
 * ```
 */
export function serializeToMarkdown(container: ContainerNode): string {
  const lines = serializeChildrenToLines(container.children, 0);
  return lines.join('\n');
}

// ============================================================================
// Inline formatting
// ============================================================================

/**
 * Escapes Markdown special characters in plain text content.
 * Only escapes characters when they appear in plain text, not in formatting.
 */
function escapeMdChars(text: string): string {
  // Escape special Markdown characters in plain text content
  return text
    .replace(/\\/g, '\\\\')
    .replace(/\*/g, '\\*')
    .replace(/_/g, '\\_')
    .replace(/`/g, '\\`')
    .replace(/\[/g, '\\[')
    .replace(/\]/g, '\\]')
    .replace(/^(#+\s)/gm, '\\$1')
    .replace(/^(>\s)/gm, '\\$1');
}

/**
 * Serializes a single InlineText segment to a Markdown string.
 * Applies bold, italic, code, strikethrough, link, underline markers.
 */
function serializeInlineSegment(segment: InlineText): string {
  const text = segment.content || '';
  if (!text) return '';

  // For plain text (no formatting), escape special chars
  const hasFormatting =
    segment.bold ||
    segment.italic ||
    segment.code ||
    segment.strikethrough ||
    segment.href ||
    segment.underline;

  let result = hasFormatting ? text : escapeMdChars(text);

  // Apply formatting markers inside-out (code innermost)
  if (segment.code) {
    result = `\`${result}\``;
  }

  if (segment.strikethrough) {
    result = `~~${result}~~`;
  }

  if (segment.underline) {
    // No standard Markdown — use HTML fallback
    result = `<u>${result}</u>`;
  }

  // bold+italic combined → ***text***
  if (segment.bold && segment.italic) {
    result = `***${result}***`;
  } else if (segment.bold) {
    result = `**${result}**`;
  } else if (segment.italic) {
    result = `*${result}*`;
  }

  // Link wraps around all other formatting
  if (segment.href) {
    result = `[${result}](${segment.href})`;
  }

  // Colors/font sizes are skipped — Markdown doesn't support these

  return result;
}

/**
 * Returns the inline Markdown content for a TextNode, handling:
 * - `content`  → plain string (escaped)
 * - `children` → array of InlineText segments with formatting
 * - `lines`    → multiple BlockLines joined with newline
 */
function serializeTextNodeContent(node: TextNode): string {
  // Multi-line content (e.g. list items with multiple lines)
  if (node.lines && node.lines.length > 0) {
    return node.lines
      .map(line => {
        if (line.children && line.children.length > 0) {
          return line.children.map(seg => serializeInlineSegment(seg)).join('');
        }
        return escapeMdChars(line.content || '');
      })
      .join('\n');
  }

  // Inline children (rich formatting)
  if (hasInlineChildren(node)) {
    return node.children!.map(seg => serializeInlineSegment(seg)).join('');
  }

  // Plain text
  return escapeMdChars(node.content || '');
}

// ============================================================================
// Block serialization
// ============================================================================

const HEADING_PREFIXES: Record<string, string> = {
  h1: '#',
  h2: '##',
  h3: '###',
  h4: '####',
  h5: '#####',
  h6: '######',
};

/**
 * Serializes a single TextNode to an array of Markdown line strings.
 * Returns empty array for nodes with no content.
 */
function serializeTextNodeToLines(node: TextNode, _indent: number): string[] {
  const { type, attributes } = node;

  // ── HR ────────────────────────────────────────────────────────────────────
  if (type === 'hr') {
    return ['---', ''];
  }

  // ── BR ────────────────────────────────────────────────────────────────────
  if (type === 'br') {
    return [''];
  }

  // ── Image ─────────────────────────────────────────────────────────────────
  if (type === 'img') {
    const src = (attributes?.src as string) || '';
    const alt = (attributes?.alt as string) || node.content || '';
    if (!src) return [];
    return [`![${alt}](${src})`, ''];
  }

  // ── Video ─────────────────────────────────────────────────────────────────
  if (type === 'video') {
    const src = (attributes?.src as string) || '';
    const alt = node.content || 'video';
    if (!src) return [];
    // No standard Markdown video — use image syntax as fallback
    return [`![${alt}](${src})`, ''];
  }

  // ── Code / pre block ──────────────────────────────────────────────────────
  if (type === 'code' || type === 'pre') {
    const lang = (attributes?.language as string) || '';
    const inner = serializeTextNodeContent(node);
    if (!inner.trim()) return [];
    return ['```' + lang, inner, '```', ''];
  }

  // ── Table cells (th / td) — handled by structural node serializer ─────────
  if (type === 'th' || type === 'td') {
    return [serializeTextNodeContent(node)];
  }

  // ── Headings ──────────────────────────────────────────────────────────────
  if (type in HEADING_PREFIXES) {
    const inner = serializeTextNodeContent(node);
    if (!inner.trim()) return [];
    return [`${HEADING_PREFIXES[type]} ${inner}`, ''];
  }

  // ── Blockquote ────────────────────────────────────────────────────────────
  if (type === 'blockquote') {
    const inner = serializeTextNodeContent(node);
    if (!inner.trim()) return [];
    // Each line prefixed with "> "
    const prefixed = inner
      .split('\n')
      .map(line => `> ${line}`)
      .join('\n');
    return [prefixed, ''];
  }

  // ── Paragraph ─────────────────────────────────────────────────────────────
  if (type === 'p') {
    const inner = serializeTextNodeContent(node);
    if (!inner.trim()) return [];
    return [inner, ''];
  }

  // ── li / ol — handled by serializeChildrenToLines list grouping ───────────
  // These should not be called directly; they're handled by the list grouping
  // logic in serializeChildrenToLines. But as a fallback:
  if (type === 'li') {
    const inner = serializeTextNodeContent(node);
    if (!inner.trim()) return [];
    return [`- ${inner}`];
  }

  if (type === 'ol') {
    const inner = serializeTextNodeContent(node);
    if (!inner.trim()) return [];
    return [`1. ${inner}`];
  }

  // ── Fallback: any other text node types ───────────────────────────────────
  const inner = serializeTextNodeContent(node);
  if (!inner.trim()) return [];
  return [inner, ''];
}

// ============================================================================
// Table serialization
// ============================================================================

/**
 * Serializes a table StructuralNode to Markdown pipe table lines.
 */
function serializeTableToLines(table: StructuralNode): string[] {
  if (table.type !== 'table') return [];

  const lines: string[] = [];
  let hasHeader = false;

  for (const child of table.children) {
    if (!isStructuralNode(child)) continue;

    if (child.type === 'thead') {
      for (const row of child.children) {
        if (!isStructuralNode(row) || row.type !== 'tr') continue;
        const cells = row.children
          .filter(isTextNode)
          .map(cell => serializeTextNodeContent(cell as TextNode));
        hasHeader = true;
        lines.push(`| ${cells.join(' | ')} |`);
        lines.push(`| ${cells.map(() => '---').join(' | ')} |`);
      }
    }

    if (child.type === 'tbody') {
      for (const row of child.children) {
        if (!isStructuralNode(row) || row.type !== 'tr') continue;
        const cells = row.children
          .filter(isTextNode)
          .map(cell => serializeTextNodeContent(cell as TextNode));
        lines.push(`| ${cells.join(' | ')} |`);
      }
    }
  }

  // If no explicit thead, the first tr is the header
  if (!hasHeader && lines.length === 0) {
    for (const child of table.children) {
      if (isStructuralNode(child) && child.type === 'tr') {
        const cells = child.children
          .filter(isTextNode)
          .map(cell => serializeTextNodeContent(cell as TextNode));
        if (lines.length === 0) {
          lines.push(`| ${cells.join(' | ')} |`);
          lines.push(`| ${cells.map(() => '---').join(' | ')} |`);
        } else {
          lines.push(`| ${cells.join(' | ')} |`);
        }
      }
    }
  }

  if (lines.length > 0) {
    lines.push('');
  }

  return lines;
}

// ============================================================================
// Children serialization with list grouping
// ============================================================================

/**
 * Serializes an array of EditorNode children to Markdown lines,
 * grouping consecutive `li` / `ol` items into proper list blocks.
 */
function serializeChildrenToLines(children: EditorNode[], indent: number): string[] {
  const lines: string[] = [];
  let i = 0;

  while (i < children.length) {
    const child = children[i];

    // ── Unordered list grouping ────────────────────────────────────────────
    if (isTextNode(child) && child.type === 'li') {
      // Collect all consecutive li nodes
      while (i < children.length) {
        const item = children[i];
        if (isTextNode(item) && item.type === 'li') {
          const inner = serializeTextNodeContent(item);
          if (inner.trim()) {
            lines.push(`- ${inner}`);
          }
          i++;
        } else {
          break;
        }
      }
      lines.push('');
      continue;
    }

    // ── Ordered list grouping ─────────────────────────────────────────────
    if (isTextNode(child) && child.type === 'ol') {
      let counter = 1;
      while (i < children.length) {
        const item = children[i];
        if (isTextNode(item) && item.type === 'ol') {
          const inner = serializeTextNodeContent(item);
          if (inner.trim()) {
            lines.push(`${counter}. ${inner}`);
            counter++;
          }
          i++;
        } else {
          break;
        }
      }
      lines.push('');
      continue;
    }

    // ── Structural nodes (table family) ───────────────────────────────────
    if (isStructuralNode(child)) {
      if (child.type === 'table') {
        lines.push(...serializeTableToLines(child));
      }
      i++;
      continue;
    }

    // ── Container nodes ───────────────────────────────────────────────────
    if (isContainerNode(child)) {
      // Check for table wrapper container
      const firstChild = child.children[0];
      if (firstChild && isStructuralNode(firstChild) && firstChild.type === 'table') {
        lines.push(...serializeTableToLines(firstChild));
      } else {
        // Flex/generic containers — serialize children normally
        lines.push(...serializeChildrenToLines(child.children, indent));
      }
      i++;
      continue;
    }

    // ── Text nodes ────────────────────────────────────────────────────────
    if (isTextNode(child)) {
      lines.push(...serializeTextNodeToLines(child, indent));
      i++;
      continue;
    }

    i++;
  }

  return lines;
}

/**
 * Serialize Editor State to Clean Semantic HTML
 *
 * Converts the editor's block model to clean, semantic HTML with no
 * Tailwind or CSS-framework classes — suitable for any CMS target
 * (WordPress, Strapi, Contentful, etc.).
 *
 * Supports recursive rendering of nested containers and all block/inline
 * node types defined in the editor's type system.
 */

import {
  ContainerNode,
  StructuralNode,
  TextNode,
  EditorNode,
  InlineText,
  isTextNode,
  isContainerNode,
  isStructuralNode,
  hasInlineChildren,
} from '../types';

// ============================================================================
// Public API
// ============================================================================

export interface SemanticHtmlOptions {
  /**
   * Include inline styles for colors and font sizes.
   * When false, `style` attributes are omitted entirely.
   * @default true
   */
  includeStyles?: boolean;

  /**
   * Wrap the entire output in an `<article>` element.
   * @default false
   */
  wrapInArticle?: boolean;
}

/**
 * Serializes a ContainerNode tree to clean semantic HTML suitable for any CMS.
 *
 * @param container - The root container node from editor state
 * @param options   - Serialization options
 * @returns A clean HTML string with semantic tags and no CSS framework classes
 *
 * @example
 * ```typescript
 * const html = serializeToSemanticHtml(state.container);
 * // <h1>Title</h1>
 * // <p><strong>Bold</strong> normal text</p>
 * ```
 */
export function serializeToSemanticHtml(
  container: ContainerNode,
  options: SemanticHtmlOptions = {}
): string {
  const { includeStyles = true, wrapInArticle = false } = options;
  const ctx: SerializeContext = { includeStyles };

  const body = serializeChildren(container.children, ctx, '');

  if (wrapInArticle) {
    return `<article>\n${body}</article>\n`;
  }
  return body;
}

// ============================================================================
// Internal helpers
// ============================================================================

/** Shared context threaded through all serialization calls. */
interface SerializeContext {
  includeStyles: boolean;
}

// ---------------------------------------------------------------------------
// HTML entity escaping
// ---------------------------------------------------------------------------

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

// ---------------------------------------------------------------------------
// camelCase → kebab-case helper for CSS property names
// ---------------------------------------------------------------------------

function toKebabCase(str: string): string {
  return str.replace(/([A-Z])/g, '-$1').toLowerCase();
}

// ---------------------------------------------------------------------------
// Inline text serialization
// ---------------------------------------------------------------------------

/**
 * Wraps `inner` HTML in semantic formatting tags derived from an InlineText
 * segment's boolean flags.  Tags are applied outermost-first in a consistent
 * order so that combined formats nest predictably.
 */
function wrapInlineFormatting(
  inner: string,
  segment: InlineText,
  ctx: SerializeContext
): string {
  let html = inner;

  // code wraps first (innermost), then other formats wrap outside it
  if (segment.code) {
    html = `<code>${html}</code>`;
  }
  if (segment.strikethrough) {
    html = `<del>${html}</del>`;
  }
  if (segment.underline) {
    html = `<u>${html}</u>`;
  }
  if (segment.italic) {
    html = `<em>${html}</em>`;
  }
  if (segment.bold) {
    html = `<strong>${html}</strong>`;
  }

  // Link wraps around all other formatting
  if (segment.href) {
    html = `<a href="${escapeHtml(segment.href)}" target="_blank" rel="noopener noreferrer">${html}</a>`;
  }

  // Inline styles: color and fontSize
  if (ctx.includeStyles && segment.styles) {
    const styleParts: string[] = [];

    if (segment.styles.color) {
      styleParts.push(`color: ${segment.styles.color}`);
    }
    if (segment.styles.fontSize) {
      styleParts.push(`font-size: ${segment.styles.fontSize}`);
    }

    // Any remaining CSS properties (excluding color/fontSize already handled)
    for (const [key, value] of Object.entries(segment.styles)) {
      if (key !== 'color' && key !== 'fontSize') {
        styleParts.push(`${toKebabCase(key)}: ${value}`);
      }
    }

    if (styleParts.length > 0) {
      html = `<span style="${styleParts.join('; ')}">${html}</span>`;
    }
  }

  // Hex color stored in className (legacy pattern from Tailwind serializer)
  if (
    ctx.includeStyles &&
    segment.className &&
    segment.className.startsWith('#')
  ) {
    html = `<span style="color: ${segment.className}">${html}</span>`;
  }

  return html;
}

/**
 * Serializes a single InlineText segment to an HTML string.
 */
function serializeInlineSegment(
  segment: InlineText,
  ctx: SerializeContext
): string {
  const text = escapeHtml(segment.content || '');

  if (!text) return '';

  return wrapInlineFormatting(text, segment, ctx);
}

/**
 * Returns the inner HTML content for a TextNode, handling:
 *  - `content`  → plain string
 *  - `children` → array of InlineText segments
 *  - `lines`    → multiple BlockLines joined with `<br />`
 */
function serializeTextNodeContent(node: TextNode, ctx: SerializeContext): string {
  // Multi-line content (e.g. ordered list items with multiple lines)
  if (node.lines && node.lines.length > 0) {
    return node.lines
      .map(line => {
        if (line.children && line.children.length > 0) {
          return line.children.map(seg => serializeInlineSegment(seg, ctx)).join('');
        }
        return escapeHtml(line.content || '');
      })
      .join('<br />');
  }

  // Inline children (rich formatting)
  if (hasInlineChildren(node)) {
    return node.children!.map(seg => serializeInlineSegment(seg, ctx)).join('');
  }

  // Plain text
  return escapeHtml(node.content || '');
}

// ---------------------------------------------------------------------------
// Text node serialization
// ---------------------------------------------------------------------------

/**
 * Serializes a single TextNode to a semantic HTML element string.
 * Returns an empty string for nodes whose content is blank (so that callers
 * can decide to omit them).
 */
function serializeTextNode(
  node: TextNode,
  ctx: SerializeContext,
  indent: string
): string {
  const { type, attributes } = node;

  // ── Self-closing / structural elements ─────────────────────────────────

  if (type === 'hr') {
    return `${indent}<hr />\n`;
  }

  if (type === 'br') {
    // Standalone <br> blocks between paragraphs are meaningless — skip them
    return '';
  }

  // ── Image ───────────────────────────────────────────────────────────────

  if (type === 'img') {
    const src = (attributes?.src as string) || '';
    const alt = (attributes?.alt as string) || '';
    const caption = node.content || '';

    if (!src) return '';

    let imgAttrs = `src="${escapeHtml(src)}" alt="${escapeHtml(alt)}"`;

    // Preserve width only when includeStyles is true
    if (ctx.includeStyles && attributes?.styles) {
      const styles = attributes.styles as Record<string, string>;
      const styleParts: string[] = [];
      for (const [k, v] of Object.entries(styles)) {
        styleParts.push(`${toKebabCase(k)}: ${v}`);
      }
      if (styleParts.length > 0) {
        imgAttrs += ` style="${styleParts.join('; ')}"`;
      }
    }

    let html = `${indent}<figure>\n`;
    html += `${indent}  <img ${imgAttrs} />\n`;
    if (caption) {
      html += `${indent}  <figcaption>${escapeHtml(caption)}</figcaption>\n`;
    }
    html += `${indent}</figure>\n`;
    return html;
  }

  // ── Video ───────────────────────────────────────────────────────────────

  if (type === 'video') {
    const src = (attributes?.src as string) || '';
    const caption = node.content || '';

    if (!src) return '';

    let html = `${indent}<figure>\n`;
    html += `${indent}  <video controls src="${escapeHtml(src)}"></video>\n`;
    if (caption) {
      html += `${indent}  <figcaption>${escapeHtml(caption)}</figcaption>\n`;
    }
    html += `${indent}</figure>\n`;
    return html;
  }

  // ── Code block ─────────────────────────────────────────────────────────

  if (type === 'code' || type === 'pre') {
    const inner = serializeTextNodeContent(node, ctx);
    if (!inner.trim()) return '';
    return `${indent}<pre><code>${inner}</code></pre>\n`;
  }

  // ── Table cells (th / td) ──────────────────────────────────────────────
  // These are handled inside serializeStructuralNode; but in case they appear
  // as lone TextNodes we handle them here too.

  if (type === 'th' || type === 'td') {
    const inner = serializeTextNodeContent(node, ctx);
    return `${indent}<${type}>${inner}</${type}>\n`;
  }

  // ── Remaining block elements ────────────────────────────────────────────

  const inner = serializeTextNodeContent(node, ctx);

  // Skip empty blocks (don't emit <p></p> noise)
  if (!inner.trim()) return '';

  // Build optional style attribute from attributes.styles / backgroundColor / color
  const styleAttr = buildBlockStyleAttr(node, ctx);

  return `${indent}<${type}${styleAttr}>${inner}</${type}>\n`;
}

/**
 * Builds an inline `style="..."` attribute string for a block-level TextNode,
 * respecting the `includeStyles` flag.
 */
function buildBlockStyleAttr(node: TextNode, ctx: SerializeContext): string {
  if (!ctx.includeStyles) return '';

  const { attributes } = node;
  const parts: string[] = [];

  const bgColor = attributes?.backgroundColor as string | undefined;
  if (bgColor) parts.push(`background-color: ${bgColor}`);

  // Hex color stored as className
  const customClass = attributes?.className as string | undefined;
  if (customClass && customClass.startsWith('#')) {
    parts.push(`color: ${customClass}`);
  }

  if (attributes?.styles) {
    const styles = attributes.styles as Record<string, string>;
    for (const [k, v] of Object.entries(styles)) {
      parts.push(`${toKebabCase(k)}: ${v}`);
    }
  }

  return parts.length > 0 ? ` style="${parts.join('; ')}"` : '';
}

// ---------------------------------------------------------------------------
// Structural node serialization (table, thead, tbody, tr)
// ---------------------------------------------------------------------------

function serializeStructuralNode(
  node: StructuralNode,
  ctx: SerializeContext,
  indent: string
): string {
  const { type } = node;

  if (type === 'table') {
    let html = `${indent}<table>\n`;
    for (const child of node.children) {
      if (isStructuralNode(child)) {
        html += serializeStructuralNode(child, ctx, indent + '  ');
      }
    }
    html += `${indent}</table>\n`;
    return html;
  }

  if (type === 'thead' || type === 'tbody') {
    let html = `${indent}<${type}>\n`;
    for (const child of node.children) {
      if (isStructuralNode(child)) {
        html += serializeStructuralNode(child, ctx, indent + '  ');
      }
    }
    html += `${indent}</${type}>\n`;
    return html;
  }

  if (type === 'tr') {
    let html = `${indent}<tr>\n`;
    for (const child of node.children) {
      if (isTextNode(child)) {
        const cellTag = child.type === 'th' ? 'th' : 'td';
        const content = serializeTextNodeContent(child, ctx);
        html += `${indent}  <${cellTag}>${content}</${cellTag}>\n`;
      }
    }
    html += `${indent}</tr>\n`;
    return html;
  }

  return '';
}

// ---------------------------------------------------------------------------
// Container node serialization
// ---------------------------------------------------------------------------

/**
 * Serializes an array of EditorNode children, grouping consecutive `li` / `ol`
 * items into the correct `<ul>` / `<ol>` wrapper automatically.
 */
function serializeChildren(
  children: EditorNode[],
  ctx: SerializeContext,
  indent: string
): string {
  let html = '';
  let i = 0;

  while (i < children.length) {
    const child = children[i];

    // ── List item grouping ───────────────────────────────────────────────
    if (isTextNode(child) && (child.type === 'li' || child.type === 'ol')) {
      // Determine which wrapper to use.
      // type === 'li'  → <ul>
      // type === 'ol'  → <ol>
      const listTag = child.type === 'ol' ? 'ol' : 'ul';
      html += `${indent}<${listTag}>\n`;

      // Consume all consecutive nodes of the same list type
      while (i < children.length) {
        const item = children[i];
        if (isTextNode(item) && item.type === child.type) {
          const inner = serializeTextNodeContent(item, ctx);
          if (inner.trim()) {
            html += `${indent}  <li>${inner}</li>\n`;
          }
          i++;
        } else {
          break;
        }
      }

      html += `${indent}</${listTag}>\n`;
      continue;
    }

    // ── Structural nodes (table family) ─────────────────────────────────
    if (isStructuralNode(child)) {
      html += serializeStructuralNode(child, ctx, indent);
      i++;
      continue;
    }

    // ── Container nodes ──────────────────────────────────────────────────
    if (isContainerNode(child)) {
      html += serializeContainerNode(child, ctx, indent);
      i++;
      continue;
    }

    // ── Text nodes (all other block types) ───────────────────────────────
    if (isTextNode(child)) {
      html += serializeTextNode(child, ctx, indent);
      i++;
      continue;
    }

    i++;
  }

  return html;
}

/**
 * Serializes a ContainerNode recursively.
 *
 * Handles:
 * - Table wrapper containers (first child is `table`)
 * - Flex layout containers
 * - Regular nesting containers
 * - List containers (listType attribute)
 */
function serializeContainerNode(
  node: ContainerNode,
  ctx: SerializeContext,
  indent: string
): string {
  if (!node.children || node.children.length === 0) return '';

  // Table wrapper: first child is a structural table node
  const firstChild = node.children[0];
  if (firstChild && isStructuralNode(firstChild) && firstChild.type === 'table') {
    return serializeStructuralNode(firstChild, ctx, indent);
  }

  // Flex layout container
  const layoutType = node.attributes?.layoutType as string | undefined;
  const isFlexContainer = layoutType === 'flex';

  if (isFlexContainer && ctx.includeStyles) {
    const gap = (node.attributes?.gap as string) || '1rem';
    const flexWrap = (node.attributes?.flexWrap as string) || 'wrap';
    const gapValue = /^\d+$/.test(gap) ? `${Number(gap) * 4}px` : gap;
    const styleAttr = `style="display: flex; gap: ${gapValue}; flex-wrap: ${flexWrap};"`;
    let html = `${indent}<div ${styleAttr}>\n`;
    html += serializeChildren(node.children, ctx, indent + '  ');
    html += `${indent}</div>\n`;
    return html;
  }

  if (isFlexContainer) {
    // includeStyles is false — emit plain div wrapper
    let html = `${indent}<div>\n`;
    html += serializeChildren(node.children, ctx, indent + '  ');
    html += `${indent}</div>\n`;
    return html;
  }

  // List container (listType attribute set explicitly)
  const listType = node.attributes?.listType as string | undefined;
  if (listType === 'ul' || listType === 'ol') {
    let html = `${indent}<${listType}>\n`;
    for (const child of node.children) {
      if (isTextNode(child)) {
        const inner = serializeTextNodeContent(child, ctx);
        if (inner.trim()) {
          html += `${indent}  <li>${inner}</li>\n`;
        }
      }
    }
    html += `${indent}</${listType}>\n`;
    return html;
  }

  // Generic nested container — just recurse, no wrapper element
  return serializeChildren(node.children, ctx, indent);
}

/**
 * Serialize Editor State to HTML
 * 
 * Converts the editor's state container to HTML with Tailwind classes
 * Output matches exactly what the editor displays visually
 * Supports recursive rendering of nested containers
 */

import { ContainerNode, StructuralNode, TextNode, isTextNode, isContainerNode, isStructuralNode, hasInlineChildren } from '../types';

/**
 * Get Tailwind CSS classes for block-level element types
 */
function getBlockTypeClasses(type: string): string {
  switch (type) {
    case 'h1':
      return 'text-4xl font-bold text-foreground leading-[1.2] mb-2';
    case 'h2':
      return 'text-3xl font-bold text-foreground leading-[1.2] mb-1.5';
    case 'h3':
      return 'text-2xl font-bold text-foreground leading-[1.2] mb-1';
    case 'h4':
      return 'text-xl font-semibold text-foreground leading-[1.3] mb-1';
    case 'h5':
      return 'text-lg font-semibold text-foreground leading-[1.4] mb-0.5';
    case 'h6':
      return 'text-base font-semibold text-foreground leading-[1.4] mb-0.5';
    case 'p':
      return 'text-base text-foreground leading-[1.6]';
    case 'li':
      return 'text-base text-foreground leading-[1.6] list-disc list-inside';
    case 'blockquote':
      return 'text-base text-muted-foreground italic border-l-4 border-primary pl-6 py-1';
    case 'code':
      return 'font-mono text-sm bg-secondary text-secondary-foreground px-4 py-2 rounded-lg whitespace-pre-wrap break-words';
    case 'br':
      return '';
    default:
      return 'text-base text-foreground leading-[1.6]';
  }
}

/**
 * Get Tailwind CSS classes for inline element types (when used within text)
 */
function getInlineElementTypeClasses(elementType: string): string {
  switch (elementType) {
    case 'h1':
      return 'text-4xl font-bold text-foreground leading-[1.2]';
    case 'h2':
      return 'text-3xl font-bold text-foreground leading-[1.2]';
    case 'h3':
      return 'text-2xl font-bold text-foreground leading-[1.2]';
    case 'h4':
      return 'text-xl font-semibold text-foreground leading-[1.3]';
    case 'h5':
      return 'text-lg font-semibold text-foreground leading-[1.4]';
    case 'h6':
      return 'text-base font-semibold text-foreground leading-[1.4]';
    case 'code':
      return 'font-mono text-sm bg-secondary text-secondary-foreground px-4 py-2 rounded-lg whitespace-pre-wrap break-words';
    case 'blockquote':
      return 'text-base text-muted-foreground italic border-l-4 border-primary pl-6 py-1';
    default:
      return '';
  }
}

/**
 * Build inline formatting classes (bold, italic, underline, strikethrough, code)
 */
function getInlineFormattingClasses(
  bold?: boolean,
  italic?: boolean,
  underline?: boolean,
  strikethrough?: boolean,
  code?: boolean
): string {
  const classes: string[] = [];

  if (bold) classes.push('font-bold');
  if (italic) classes.push('italic');
  if (underline) classes.push('underline');
  if (strikethrough) classes.push('line-through');
  if (code) classes.push('font-mono bg-gray-100 dark:bg-gray-800 px-1 py-0.5 rounded');

  return classes.join(' ');
}

/**
 * Escape HTML special characters
 */
function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

/**
 * Serialize a text node with inline children (formatted content)
 */
function serializeInlineChildren(node: TextNode): string {
  if (!hasInlineChildren(node)) {
    return escapeHtml(node.content || '');
  }

  return node.children!.map(child => {
    const formattingClasses = getInlineFormattingClasses(
      child.bold,
      child.italic,
      child.underline,
      child.strikethrough,
      child.code
    );

    const elementTypeClasses = child.elementType 
      ? getInlineElementTypeClasses(child.elementType)
      : '';

    // Build inline styles from the styles object
    let inlineStyles = '';
    if (child.styles) {
      inlineStyles = Object.entries(child.styles)
        .map(([key, value]) => {
          // Convert camelCase to kebab-case (fontSize -> font-size)
          const kebabKey = key.replace(/([A-Z])/g, '-$1').toLowerCase();
          return `${kebabKey}: ${value}`;
        })
        .join('; ') + ';';
    }

    const allClasses = [elementTypeClasses, formattingClasses, child.className]
      .filter(Boolean)
      .join(' ');

    const content = escapeHtml(child.content || '');

    // If it's a link
    if (child.href) {
      const linkClasses = ['text-primary hover:underline cursor-pointer', allClasses]
        .filter(Boolean)
        .join(' ');
      const italicSpacing = child.italic ? 'inline' : '';
      const finalClasses = [linkClasses, italicSpacing].filter(Boolean).join(' ');
      const styleAttr = inlineStyles ? ` style="${inlineStyles}"` : '';
      return `<a href="${escapeHtml(child.href)}" target="_blank" rel="noopener noreferrer" class="${finalClasses}"${styleAttr}>${content}</a>`;
    }

    if (allClasses || inlineStyles) {
      // Add inline-blockfor italic text to prevent overlapping
      const italicSpacing = child.italic ? 'inline' : '';
      const finalClasses = [allClasses, italicSpacing].filter(Boolean).join(' ');
      const classAttr = finalClasses ? ` class="${finalClasses}"` : '';
      const styleAttr = inlineStyles ? ` style="${inlineStyles}"` : '';
      return `<span${classAttr}${styleAttr}>${content}</span>`;
    }

    return content;
  }).join('');
}

/**
 * Serialize a single text node to HTML
 */
function serializeTextNode(node: TextNode, indent: string = ''): string {
  const { type, attributes } = node;

  // Handle BR elements
  if (type === 'br') {
    return `${indent}<br />\n`;
  }

  // Handle image nodes
  if (type === 'img') {
    const src = attributes?.src as string || '';
    const alt = attributes?.alt as string || '';
    const caption = node.content || '';

    // Build inline styles for the image
    const imgStyles: string[] = ['width: auto', 'margin: auto'];

    // Add custom styles from attributes.styles if they exist
    if (attributes?.styles && typeof attributes.styles === 'object' && !Array.isArray(attributes.styles)) {
      const styles = attributes.styles as Record<string, string>;
      if (styles.width) {
        imgStyles[0] = `width: ${styles.width}`;
      }
    }

    const imgStyleAttr = ` style="${imgStyles.join('; ')};"`;

    let html = `${indent}<figure class="mb-4">\n`;
    html += `${indent}  <img src="${escapeHtml(src)}" alt="${escapeHtml(alt)}" class="h-auto rounded-lg object-cover max-h-[600px]"${imgStyleAttr} />\n`;

    if (caption) {
      html += `${indent}  <figcaption class="text-sm text-muted-foreground text-center mt-3 italic">${escapeHtml(caption)}</figcaption>\n`;
    }

    html += `${indent}</figure>\n`;
    return html;
  }

  // Handle video nodes
  if (type === 'video') {
    const src = attributes?.src as string || '';
    const caption = node.content || '';

    let html = `${indent}<figure class="mb-4">\n`;
    html += `${indent}  <video src="${escapeHtml(src)}" controls class="w-full h-auto rounded-lg object-cover max-h-[600px]" preload="metadata">\n`;
    html += `${indent}    Your browser does not support the video tag.\n`;
    html += `${indent}  </video>\n`;

    if (caption) {
      html += `${indent}  <figcaption class="text-sm text-muted-foreground text-center mt-3 italic">${escapeHtml(caption)}</figcaption>\n`;
    }

    html += `${indent}</figure>\n`;
    return html;
  }

  // Get block-level classes
  const blockClasses = getBlockTypeClasses(type);

  // Get custom className from attributes
  const customClassName = attributes?.className as string || '';

  // Check if className is a hex color (starts with #)
  const isHexColor = typeof customClassName === 'string' && customClassName.startsWith('#');
  const textColor = isHexColor ? customClassName : '';
  const className = isHexColor ? '' : customClassName;

  // Combine all classes
  const allClasses = [blockClasses, className]
    .filter(Boolean)
    .join(' ');

  // Get backgroundColor from attributes
  const backgroundColor = attributes?.backgroundColor as string | undefined;

  // Build inline styles
  const styles: string[] = [];
  if (backgroundColor) {
    styles.push(`background-color: ${backgroundColor}`);
  }
  if (textColor) {
    styles.push(`color: ${textColor}`);
  }

  const styleAttr = styles.length > 0 ? ` style="${styles.join('; ')};"` : '';

  // Get content (with inline formatting if present)
  const content = serializeInlineChildren(node);

  // Check if the block is empty (no content and no inline children with content)
  const isEmpty = !content || content.trim() === '';

  // If empty, render as <br/> tag
  if (isEmpty) {
    return `${indent}<br />\n`;
  }

  // Build the HTML element
  const classAttr = allClasses ? ` class="${allClasses}"` : '';

  // Use appropriate HTML tag
  const tag = type === 'code' ? 'pre' : type;

  return `${indent}<${tag}${classAttr}${styleAttr}>${content}</${tag}>\n`;
}

/**
 * Serialize a table node to HTML
 */
function serializeTableNode(node: StructuralNode | ContainerNode, indent: string = ''): string {
  // This function handles table, thead, tbody, tr, th, td nodes
  const tag = node.type;

  if (tag === 'table') {
    let html = `${indent}<table class="border-collapse border border-border w-full">\n`;

    // Serialize children (thead, tbody)
    for (const child of node.children) {
      if (isStructuralNode(child)) {
        html += serializeTableNode(child, indent + '  ');
      }
    }

    html += `${indent}</table>\n`;
    return html;
  } else if (tag === 'thead') {
    let html = `${indent}<thead>\n`;

    // Serialize children (tr)
    for (const child of node.children) {
      if (isStructuralNode(child)) {
        html += serializeTableNode(child, indent + '  ');
      }
    }

    html += `${indent}</thead>\n`;
    return html;
  } else if (tag === 'tbody') {
    let html = `${indent}<tbody>\n`;

    // Serialize children (tr)
    for (const child of node.children) {
      if (isStructuralNode(child)) {
        html += serializeTableNode(child, indent + '  ');
      }
    }

    html += `${indent}</tbody>\n`;
    return html;
  } else if (tag === 'tr') {
    let html = `${indent}<tr>\n`;

    // Serialize children (th, td)
    for (const child of node.children) {
      if (isTextNode(child)) {
        const cellNode = child as TextNode;
        const cellTag = cellNode.type; // 'th' or 'td'
        const content = escapeHtml(cellNode.content || '');
        const cellClass = cellTag === 'th' 
          ? 'border border-border bg-muted/50 p-2 font-semibold text-left min-w-[100px]'
          : 'border border-border p-2';
        html += `${indent}  <${cellTag} class="${cellClass}">${content}</${cellTag}>\n`;
      }
    }

    html += `${indent}</tr>\n`;
    return html;
  }

  return '';
}

/**
 * Serialize a container node to HTML (recursive)
 */
function serializeContainerNode(node: ContainerNode, indent: string = ''): string {
  // Check if this is a table wrapper container
  const firstChild = node.children[0];
  const isTableWrapper = firstChild?.type === 'table';

  if (isTableWrapper && isStructuralNode(firstChild)) {
    // Serialize the table directly
    return serializeTableNode(firstChild, indent);
  }

  // Check if this is a flex container for images
  const layoutType = node.attributes?.layoutType as string | undefined;
  const isFlexContainer = layoutType === 'flex';
  const gap = node.attributes?.gap as string | undefined;
  const flexWrap = node.attributes?.flexWrap as string | undefined;

  // Determine container type and classes
  const listTypeFromAttribute = node.attributes?.listType as string | undefined;
  const listType = listTypeFromAttribute ||
    (firstChild && isTextNode(firstChild) && (firstChild as TextNode).type === 'li' ? 'ol' : undefined);
  const isListContainer = !!listType;

  // Get custom className from attributes
  const customClassName = node.attributes?.className as string || '';

  // Build container classes matching the preview
  let containerClasses = isFlexContainer
    ? `flex flex-row gap-${gap || '4'} items-start ${flexWrap === 'wrap' ? 'flex-wrap items-center' : ''}`
    : isListContainer
    ? `list-none pl-0 ml-6`
    : `border-l-2 border-border/50 pl-2 ml-6 transition-all`;

  // Add custom classes
  if (customClassName) {
    containerClasses = `${containerClasses} ${customClassName}`.trim();
  }

  // Get backgroundColor from attributes
  const backgroundColor = node.attributes?.backgroundColor as string | undefined;

  // Build inline styles
  const styles: string[] = [];
  if (backgroundColor) {
    styles.push(`background-color: ${backgroundColor}`);
  }

  const styleAttr = styles.length > 0 ? ` style="${styles.join('; ')};"` : '';

  // Use ul/ol for list containers, div for regular/flex containers
  const containerTag = listType === 'ul' ? 'ul' : listType === 'ol' ? 'ol' : 'div';

  let html = `${indent}<${containerTag} class="${containerClasses}"${styleAttr}>\n`;

  // Recursively serialize children
  let i = 0;
  while (i < node.children.length) {
    const child = node.children[i];

    if (isTextNode(child)) {
      const textNode = child as TextNode;

      // For flex containers, wrap each child in a flex item div
      if (isFlexContainer) {
        html += `${indent}  <div class="flex-1 min-w-[280px] max-w-full">\n`;
        html += serializeTextNode(textNode, indent + '    ');
        html += `${indent}  </div>\n`;
        i++;
      }
      // Check if this is the start of a list (and not already in a list container)
      else if (textNode.type === 'li' && !isListContainer) {
        // Start ordered list
        html += `${indent}  <ol class="list-decimal list-inside space-y-1">\n`;

        // Add all consecutive list items
        while (i < node.children.length) {
          const listItem = node.children[i];
          if (isTextNode(listItem) && (listItem as TextNode).type === 'li') {
            const content = serializeInlineChildren(listItem as TextNode);
            const isEmpty = !content || content.trim() === '';

            if (!isEmpty) {
              const liIndent = indent + '    ';
              const liClasses = getBlockTypeClasses('li');
              html += `${liIndent}<li class="${liClasses}">${content}</li>\n`;
            }
            i++;
          } else {
            break;
          }
        }

        // Close ordered list
        html += `${indent}  </ol>\n`;
      } else {
        // Regular text node
        html += serializeTextNode(textNode, indent + '  ');
        i++;
      }
    } else if (isContainerNode(child)) {
      // For flex containers, wrap nested containers in flex items
      if (isFlexContainer) {
        html += `${indent}  <div class="flex-1 min-w-[280px] max-w-full">\n`;
        html += serializeContainerNode(child as ContainerNode, indent + '    ');
        html += `${indent}  </div>\n`;
        i++;
      } else {
        // Nested container - recurse!
        html += serializeContainerNode(child as ContainerNode, indent + '  ');
        i++;
      }
    } else {
      i++;
    }
  }

  html += `${indent}</${containerTag}>\n`;
  return html;
}

/**
 * Serialize the entire container to HTML
 * 
 * @param container - The root container node from editor state
 * @param options - Serialization options
 * @returns HTML string with Tailwind classes
 * 
 * @example
 * ```typescript
 * const html = serializeToHtml(state.container);
 *
 * // Output:
 * // <div class="editor-content">
 * //   <h1 class="text-5xl font-extrabold">Title</h1>
 * //   <p class="text-lg"><span class="font-bold">Bold text</span></p>
 * // </div>
 * ```
 */
export function serializeToHtml(
  container: ContainerNode,
  options: {
    wrapperClass?: string;
    includeWrapper?: boolean;
    indent?: string;
  } = {}
): string {
  const {
    wrapperClass = 'editor-content',
    includeWrapper = true,
    indent = '  ',
  } = options;

  let html = '';

  // Add wrapper div if requested
  if (includeWrapper) {
    html += `<div class="${wrapperClass}">\n`;
  }

  // Serialize each child node, grouping consecutive list items and handling containers
  let i = 0;
  while (i < container.children.length) {
    const child = container.children[i];

    if (isTextNode(child)) {
      const textNode = child as TextNode;

      // Check if this is the start of a list
      if (textNode.type === 'li') {
        // Start ordered list
        html += `${includeWrapper ? indent : ''}<ol class="list-decimal list-inside space-y-1">\n`;

        // Add all consecutive list items
        while (i < container.children.length) {
          const listItem = container.children[i];
          if (isTextNode(listItem) && (listItem as TextNode).type === 'li') {
            const content = serializeInlineChildren(listItem as TextNode);
            const isEmpty = !content || content.trim() === '';

            if (!isEmpty) {
              const liIndent = includeWrapper ? indent + '  ' : '  ';
              const liClasses = getBlockTypeClasses('li');
              html += `${liIndent}<li class="${liClasses}">${content}</li>\n`;
            }
            i++;
          } else {
            break;
          }
        }

        // Close ordered list
        html += `${includeWrapper ? indent : ''}</ol>\n`;
      } else {
        // Regular text node (not a list item)
        html += serializeTextNode(textNode, includeWrapper ? indent : '');
        i++;
      }
    } else if (isContainerNode(child)) {
      // Nested container - recurse!
      html += serializeContainerNode(child as ContainerNode, includeWrapper ? indent : '');
      i++;
    } else {
      i++;
    }
  }

  // Close wrapper div
  if (includeWrapper) {
    html += `</div>\n`;
  }

  return html;
}

/**
 * Serialize to HTML without wrapper div
 */
export function serializeToHtmlFragment(container: ContainerNode): string {
  return serializeToHtml(container, { includeWrapper: false, indent: '' });
}

/**
 * Serialize to HTML with custom wrapper class
 */
export function serializeToHtmlWithClass(
  container: ContainerNode,
  wrapperClass: string
): string {
  return serializeToHtml(container, { wrapperClass });
}

/**
 * Mina Rich Editor - Tree Operations Utilities
 *
 * Recursive utilities for traversing, searching, and manipulating
 * the document tree structure immutably.
 *
 * @packageDocumentation
 */

import { EditorNode, ContainerNode, StructuralNode, isContainerNode, isStructuralNode } from "../types";
import { generateId } from "./id-generator";

/**
 * Recursively finds a node by its ID in the tree.
 *
 * @param node - The root node to start searching from
 * @param targetId - The ID of the node to find
 * @returns The found node or undefined if not found
 *
 * @example
 * ```typescript
 * const found = findNodeById(rootContainer, 'paragraph-123');
 * if (found) {
 *
 * }
 * ```
 */
export function findNodeById(
  node: EditorNode,
  targetId: string
): EditorNode | undefined {
  // Base case: current node matches
  if (node.id === targetId) {
    return node;
  }

  // Recursive case: search children if it's a container or structural node
  if (isContainerNode(node) || isStructuralNode(node)) {
    for (const child of node.children) {
      const found = findNodeById(child, targetId);
      if (found) {
        return found;
      }
    }
  }

  return undefined;
}

/**
 * Finds the parent container of a node with the given ID.
 * Useful for operations that need to modify the parent.
 *
 * @param node - The root node to start searching from
 * @param targetId - The ID of the child node
 * @returns The parent ContainerNode or undefined if not found
 *
 * @example
 * ```typescript
 * const parent = findParentById(rootContainer, 'child-node-id');
 * if (parent) {
 *
 * }
 * ```
 */
export function findParentById(
  node: EditorNode,
  targetId: string
): ContainerNode | StructuralNode | undefined {
  if (!isContainerNode(node) && !isStructuralNode(node)) {
    return undefined;
  }

  // Check if target is a direct child
  for (const child of node.children) {
    if (child.id === targetId) {
      return node;
    }
  }

  // Recursively search in children
  for (const child of node.children) {
    if (isContainerNode(child) || isStructuralNode(child)) {
      const found = findParentById(child, targetId);
      if (found) {
        return found;
      }
    }
  }

  return undefined;
}

/**
 * Updates a node immutably by ID with a partial update.
 * Returns a new tree with the updated node.
 *
 * @param node - The root node
 * @param targetId - The ID of the node to update
 * @param updater - Function that receives the old node and returns updates
 * @returns A new tree with the node updated, or the original if not found
 *
 * @example
 * ```typescript
 * const newTree = updateNodeById(root, 'p-1', (node) => ({
 *   content: 'Updated content',
 *   attributes: { ...node.attributes, className: 'highlight' }
 * }));
 * ```
 */
export function updateNodeById(
  node: EditorNode,
  targetId: string,
  updater: (node: EditorNode) => Partial<EditorNode>
): EditorNode {
  // Base case: found the target node
  if (node.id === targetId) {
    const updates = updater(node);
    return { ...node, ...updates } as EditorNode;
  }

  // Recursive case: update children if it's a container or structural node
  if (isContainerNode(node) || isStructuralNode(node)) {
    const newChildren = node.children.map((child) =>
      updateNodeById(child, targetId, updater)
    );

    // Only create new object if children actually changed
    const childrenChanged = newChildren.some(
      (newChild, index) => newChild !== node.children[index]
    );

    if (childrenChanged) {
      return {
        ...node,
        children: newChildren,
      };
    }
  }

  // No changes, return original node
  return node;
}

/**
 * Deletes a node by ID immutably.
 * Returns a new tree without the specified node.
 *
 * @param node - The root node
 * @param targetId - The ID of the node to delete
 * @returns A new tree without the deleted node
 *
 * @example
 * ```typescript
 * const newTree = deleteNodeById(root, 'paragraph-to-remove');
 * ```
 */
export function deleteNodeById(
  node: EditorNode,
  targetId: string
): EditorNode | null {
  // If this is the target node, signal deletion
  if (node.id === targetId) {
    return null;
  }

  // If it's a container or structural node, filter out the target from children
  if (isContainerNode(node) || isStructuralNode(node)) {
    const mappedChildren = node.children
      .map((child) => deleteNodeById(child, targetId));
    const newChildren = mappedChildren
      .filter((child): child is EditorNode => child !== null);

    // Create new object if a direct child was removed OR if a descendant changed
    const childrenChanged =
      newChildren.length !== node.children.length ||
      newChildren.some((newChild, index) => newChild !== node.children[index]);

    if (childrenChanged) {
      return {
        ...node,
        children: newChildren,
      };
    }
  }

  return node;
}

/**
 * Position for inserting a node relative to another node.
 */
export type InsertPosition = "before" | "after" | "prepend" | "append";

/**
 * Inserts a new node relative to a target node.
 *
 * @param root - The root node
 * @param targetId - The ID of the reference node
 * @param newNode - The node to insert
 * @param position - Where to insert relative to target ('before', 'after', 'prepend', 'append')
 * @returns A new tree with the node inserted
 *
 * @example
 * ```typescript
 * // Insert after a specific paragraph
 * const newTree = insertNode(root, 'p-1', newParagraph, 'after');
 *
 * // Prepend to a container
 * const newTree = insertNode(root, 'container-1', newHeading, 'prepend');
 * ```
 */
export function insertNode(
  root: EditorNode,
  targetId: string,
  newNode: EditorNode,
  position: InsertPosition
): EditorNode {
  // For 'prepend' and 'append', insert inside the target container
  if (position === "prepend" || position === "append") {
    return updateNodeById(root, targetId, (node) => {
      if (!isContainerNode(node) && !isStructuralNode(node)) {
        return {};
      }

      return {
        children:
          position === "prepend"
            ? [newNode, ...node.children]
            : [...node.children, newNode],
      };
    });
  }

  // For 'before' and 'after', insert as sibling
  // We need to find the parent and insert at the right position
  return insertNodeRecursive(root, targetId, newNode, position);
}

/**
 * Helper function for inserting nodes as siblings.
 * @internal
 */
function insertNodeRecursive(
  node: EditorNode,
  targetId: string,
  newNode: EditorNode,
  position: "before" | "after"
): EditorNode {
  if (!isContainerNode(node) && !isStructuralNode(node)) {
    return node;
  }

  // Check if target is a direct child
  const targetIndex = node.children.findIndex((child) => child.id === targetId);

  if (targetIndex !== -1) {
    // Found the target, insert the new node
    const newChildren = [...node.children];
    const insertIndex = position === "before" ? targetIndex : targetIndex + 1;
    newChildren.splice(insertIndex, 0, newNode);

    return {
      ...node,
      children: newChildren,
    };
  }

  // Recursively search in children
  const newChildren = node.children.map((child) =>
    insertNodeRecursive(child, targetId, newNode, position)
  );

  // Only create new object if children changed
  const childrenChanged = newChildren.some(
    (newChild, index) => newChild !== node.children[index]
  );

  if (childrenChanged) {
    return {
      ...node,
      children: newChildren,
    };
  }

  return node;
}

/**
 * Moves a node to a new position in the tree.
 *
 * @param root - The root node
 * @param nodeId - The ID of the node to move
 * @param targetId - The ID of the reference node
 * @param position - Where to move relative to target
 * @returns A new tree with the node moved
 *
 * @example
 * ```typescript
 * // Move paragraph-2 before paragraph-1
 * const newTree = moveNode(root, 'p-2', 'p-1', 'before');
 * ```
 */
export function moveNode(
  root: EditorNode,
  nodeId: string,
  targetId: string,
  position: InsertPosition
): EditorNode {
  // Cannot move a node to itself
  if (nodeId === targetId) {
    return root;
  }

  // Find the node to move
  const nodeToMove = findNodeById(root, nodeId);
  if (!nodeToMove) {
    return root;
  }

  // Verify target exists
  const targetNode = findNodeById(root, targetId);
  if (!targetNode) {
    return root;
  }

  // First, remove the node from its current position
  const treeWithoutNode = deleteNodeById(root, nodeId);
  if (!treeWithoutNode) {
    return root;
  }

  // Then, insert it at the new position
  return insertNode(treeWithoutNode, targetId, nodeToMove, position);
}

/**
 * Deep clones a node (and all its children if it's a container).
 * Useful for duplicating content.
 *
 * @param node - The node to clone
 * @param newId - Optional new ID for the cloned node
 * @returns A deep clone of the node
 *
 * @example
 * ```typescript
 * const clone = cloneNode(originalNode, 'new-unique-id');
 * ```
 */
export function cloneNode(node: EditorNode, newId?: string): EditorNode {
  const cloned: EditorNode = {
    ...node,
    id: newId || generateId('node'),
  };

  if ((isContainerNode(cloned) || isStructuralNode(cloned)) && (isContainerNode(node) || isStructuralNode(node))) {
    cloned.children = node.children.map((child) => cloneNode(child));
  }

  return cloned;
}

/**
 * Traverses the tree and calls a callback for each node.
 * Useful for analytics, validation, or batch operations.
 *
 * @param node - The root node to traverse
 * @param callback - Function called for each node
 * @param depth - Current depth (starts at 0)
 *
 * @example
 * ```typescript
 * // Count all nodes
 * let count = 0;
 * traverseTree(root, () => count++);
 *
 *
 * // Find all images
 * const images: TextNode[] = [];
 * traverseTree(root, (node) => {
 *   if (node.type === 'img') images.push(node as TextNode);
 * });
 * ```
 */
export function traverseTree(
  node: EditorNode,
  callback: (node: EditorNode, depth: number) => void,
  depth: number = 0
): void {
  callback(node, depth);

  if (isContainerNode(node) || isStructuralNode(node)) {
    for (const child of node.children) {
      traverseTree(child, callback, depth + 1);
    }
  }
}

/**
 * Builds a flat Map from node ID to EditorNode for O(1) lookups.
 * The map is a derived cache — `state.current` (the tree) remains the source of truth.
 */
export function buildNodeMap(root: EditorNode): Map<string, EditorNode> {
  const map = new Map<string, EditorNode>();
  traverseTree(root, (node) => {
    if (node.id) map.set(node.id, node);
  });
  return map;
}

/**
 * Validates the tree structure.
 * Checks for duplicate IDs, orphaned nodes, etc.
 *
 * @param node - The root node to validate
 * @returns Validation result with errors if any
 *
 * @example
 * ```typescript
 * const result = validateTree(root);
 * if (!result.valid) {
 *   console.error('Tree validation errors:', result.errors);
 * }
 * ```
 */
export function validateTree(node: EditorNode): {
  valid: boolean;
  errors: string[];
} {
  const errors: string[] = [];
  const seenIds = new Set<string>();

  traverseTree(node, (currentNode) => {
    // Check for duplicate IDs
    if (seenIds.has(currentNode.id)) {
      errors.push(`Duplicate ID found: ${currentNode.id}`);
    }
    seenIds.add(currentNode.id);

    // Check for empty IDs
    if (!currentNode.id || currentNode.id.trim() === "") {
      errors.push("Node found with empty or missing ID");
    }

    // Check for invalid container/structural node children
    if ((isContainerNode(currentNode) || isStructuralNode(currentNode)) && !Array.isArray(currentNode.children)) {
      errors.push(`Container/Structural node ${currentNode.id} has invalid children property`);
    }
  });

  return {
    valid: errors.length === 0,
    errors,
  };
}
